import { closeBook, ui } from '@/state/ui';
import { updateState } from '@/memory/update';

const props = defineProps<{ placement: 'top' | 'bottom'; narrow?: boolean }>();

// шо╛ч╜ощб╡цЬЙхПпчФицЫ┤цЦ░цЧ╢,хЬиуАМшо╛ч╜оуАНхп╝шИкщб╣ф╕Кф║оф╕Аф╕кч║вчВ╣шзТцаЗ(цПРчд║чФицИ╖ш┐Ышо╛ч╜ощб╡цЫ┤цЦ░)уАВ
function showUpdateDot(id: string): boolean {
  return id === 'settings' && updateState.available;
}

// чз╗хКичлп:хЖНчВ╣ф╕Аф╕Лх╜УхЙНщб╡чЪДхп╝шИкцМЙщТохН│хЕ│щЧнцХ┤чкЧ(чЬБх╛ЧхО╗хдЯхП│ф╕КшзТчЪД ├Ч);щЭЮх╜УхЙНщб╡цнгх╕╕хИЗщб╡уАВ
// хПЧ ui.navTapClose х╝АхЕ│цОзхИ╢(щ╗Шшодх╝А,цАХшппшзжчЪДчФицИ╖хПпхЬишо╛ч╜ощЗМхЕ│)уАВ
function onNavClick(id: string) {
  if (props.narrow && ui.navTapClose && ui.activePage === id) {
    closeBook();
    return;
  }
  ui.activePage = id;
}
</script>

