/**
 * хРСщЗПх║УчЪДуАМщАЙх║У + щАЙ scopeуАНщА╗ш╛СуАВ
 *
 * шзТшЙ▓щЪФчж╗ = цпПшзТшЙ▓ф╕Аф╕кчЛмчлЛ <database>.sqlite:х║УхРНчФ▒шзТшЙ▓ avatar(чи│хоЪхФпф╕АщФо)чоЧхЗ║уАВ
 * хИашзТшЙ▓ = хИащВгф╕Аф╕кх║УцЦЗф╗╢,ф╕НчЙ╡ш┐ЮхЕ╢ф╗ЦшзТшЙ▓уАВ
 * х║УхЖЕчФи scope хМ║хИЖщЫЖхРИ:
 *   'chat:<chatId>'    х╜УхЙНшБКхдйш╛╣чОйш╛╣ч┤вх╝Х
 *   'bundle:<hash>'    х╕жцХ░цНох╗║цЦ░шБКхдйхЖ╗ч╗УчЪДх┐лчЕз(хЖЩхЬи metadata.bbs_bundles)
 */

import { getContext } from '@/st/context';

/** metadata ф╕КхнШхУИх╕МхМЕхИЧшбичЪДхнЧцо╡хРН(щЪП chat цЦЗф╗╢ш╡░,ST хОЯчФЯхИЖцФпф╝ЪчЙйчРЖцЛ╖ш┤Э) */
export const BUNDLES_META_KEY = 'bbs_bundles';

/**
 * цККф╗╗цДПхнЧчмжф╕▓(шзТшЙ▓ avatar)цКШцИРхРИц│Хх║УхРНуАВ
 * хРОчлп DATABASE_NAME_RE = /^[a-z0-9][a-z0-9._-]{0,79}$/,avatar хРлф╕нцЦЗ/хдзхЖЩ/цЦЬцЭаш┐Зф╕Нф║Ж,цХЕ hashуАВ
 * чФи FNV-1a(цЧащЬА crypto,хЙНчлпхРМцнечоЧ):чи│хоЪуАБхРМ avatar ц░╕ш┐ЬхРМх║УуАВ
 */
function avatarToDbName(avatar: string): string {
  let h = 0x811c9dc5;
  for (let i = 0; i < avatar.length; i++) {
    h ^= avatar.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  // хЖНцО║хЕещХ┐х║жхБЪш╜╗щЗПхО╗чв░цТЮ;ш╜мцЧачмжхП╖ 16 ш┐ЫхИ╢
  const hex = ((h >>> 0).toString(16) + (avatar.length & 0xffff).toString(16)).padStart(8, '0');
  return `bbs_vec_${hex}`;
}

/** х╜УхЙНшзТшЙ▓хп╣х║ФчЪДхРСщЗПх║УхРН;ч╛дшБК/цЬкш┐ЫхЕешзТшЙ▓цЧ╢ш┐ФхЫЮ null(ф╕Нч┤вх╝Х)уАВ */
export function currentVectorDb(): string | null {
  const ctx = getContext();
  if (!ctx) return null;
  if (ctx.groupId) return null; // ч╛дшБКцЪВф╕НцФпцМБ
  const idx = ctx.characterId;
  if (idx === undefined || idx === null || idx === '') return null;
  const ch = ctx.characters?.[Number(idx)];
  const avatar = ch?.avatar;
  if (!avatar) return null;
  return avatarToDbName(avatar);
}

/** х╜УхЙНшБКхдй id;цЬкш┐ЫхЕешБКхдйш┐ФхЫЮ nullуАВ */
export function currentChatId(): string | null {
  const ctx = getContext();
  return ctx?.getCurrentChatId?.() ?? null;
}

/** х╜УхЙНшБКхдйшЗкх╖▒чЪД scope('chat:<chatId>');цЬкш┐ЫхЕешБКхдйш┐ФхЫЮ nullуАВ */
export function currentChatScope(): string | null {
  const id = currentChatId();
  return id ? `chat:${id}` : null;
}

/** шп╗х╜УхЙНшБКхдй metadata ф╕КчЪДхУИх╕МхМЕхИЧшби(хО╗щЗН),цЧахИЩчй║цХ░ч╗ДуАВ */
export function currentBundleHashes(): string[] {
  const ctx = getContext();
  const meta = ctx?.chatMetadata as Record<string, unknown> | undefined;
  const raw = meta?.[BUNDLES_META_KEY];
  if (!Array.isArray(raw)) return [];
  const seen = new Set<string>();
  for (const h of raw) if (typeof h === 'string' && h) seen.add(h);
  return [...seen];
}

/** хПмхЫЮшМГхЫ┤ scopes = х╜УхЙНшБКхдй + хРД bundleуАВцЬкш┐ЫхЕешБКхдйш┐ФхЫЮчй║цХ░ч╗ДуАВ */
export function recallScopes(): string[] {
  const self = currentChatScope();
  if (!self) return [];
  return [self, ...currentBundleHashes().map(h => `bundle:${h}`)];
}

/**
 * хЬих╜УхЙНшБКхдй metadata ф╕Кш┐╜хКаф╕Аф╕к bundle хУИх╕М(ч┤пхКауАБхО╗щЗН),х╣╢шзжхПСцМБф╣ЕхМЦуАВ
 * чФиф║ОуАМх╕жцХ░цНох╗║цЦ░шБКхдйуАНхЖЩхЕецЦ░шБКхдйщВгф╕АхИ╗уАВ
 */
export function appendBundleHash(metadata: Record<string, unknown>, parentHashes: string[], newHash: string): void {
  const merged = new Set<string>([...parentHashes, newHash].filter(Boolean));
  metadata[BUNDLES_META_KEY] = [...merged];
}
