/** цККц╢ИцБпц╕▓цЯУцИРч╗ЩцСШшжБцибхЮЛчЪДцЦЗцЬм(cleanBody:шгБцнгцЦЗцо╡ + цХ┤хЭЧхИахЩкхг░цаЗчн╛ + цЧ╢щЧ┤цаЗчн╛ш╜мцЦЗцЬм) */
function renderMessages(chat: STMessage[], indices: number[], name1: string, name2: string): string {
  return indices
    .map(i => {
      const m = chat[i];
      if (!m) return '';
      // хПМцаЗ:цЧвцаЗхПСшиАцЦ╣(чФицИ╖/шзТшЙ▓),хПИх╕жф║║хРН тАФтАФ цСШшжБцнгцЦЗчФиф║║хРН,ч╛дшБКф╣ЯшГ╜хМ║хИЖш░Бшп┤чЪД
      const tag = m.is_user ? 'чФицИ╖' : 'шзТшЙ▓';
      const who = m.is_user ? name1 || 'User' : m.name || name2 || 'Char';
      // cleanBody:шгБхЙкхИ░ <bbs_start>тАж</bbs_end>(хЙФщЩдчК╢цАБцаПчнЙцнгцЦЗхдЦца╝х╝П)+ цХ┤хЭЧхИахЩкхг░цаЗчн╛
      //я╝ИцАЭч╗┤щУ╛/ц│ищЗК/чЙйхУБцЧБц│и/шЗкхоЪф╣ЙцаЗчн╛)+ цЧ╢щЧ┤цаЗчн╛ш╜мхПпшп╗цЦЗцЬмуАВф╕НхЖНшг╕хИацаЗчн╛уАВ
      return `уАР${tag}┬╖${who}уАС${cleanBody(m.mes)}`;
    })
    .filter(Boolean)
    .join('\n\n');
}

/**
 * цМЙцЬмш╜ох╛ЕцСШцЦЗцЬмц┐Ац┤╗ф╕ЦчХМф╣жцЭбчЫо(хЕ│щФошпНшзжхПС + constant шУЭчБп),ш┐ФхЫЮшо╛хоЪцЦЗцЬмуАВ
 * ш╡░ ST чЪД getWorldInfoPrompt(isDryRun=true,хПкцЙлцППф╕НшзжхПСхЙпф╜ЬчФиф║Лф╗╢)уАВ
 * хЕ│щФо:шУЭчБп/чЫ╕хЕ│цЭбчЫохПпшГ╜шР╜хЬи beforeуАБafterуАБdepth(@ц╖▒х║ж)уАБф╜ЬшАЕц│и ф╗╗ф╕Аф╜Нч╜о,хЕищГицПРхПЦ,
 * хРжхИЩф╝Ъц╝ПцОЙхдзщЗПуАМ@ц╖▒х║жуАНф╜Нч╜очЪДшУЭчБпцЭбчЫо(хПкхПЦ before/after ф╝ЪцЛ┐хИ░чй║)уАВ
 * хПЦф╕НхИ░ API / хЗ║щФЩ / цЧац┐Ац┤╗цЭбчЫо / шзТшЙ▓хНбцЧаф╕ЦчХМф╣ж тЖТ ш┐ФхЫЮчй║ф╕▓(щЩНч║з,ф╕Нх╜▒хУНцСШшжБцнгх╕╕ш┐РшбМ)уАВ
 */
async function fetchWorldInfo(chat: STMessage[], targets: number[], name1: string, name2: string): Promise<string> {
  const ctx = getContext();
  const fn = ctx?.getWorldInfoPrompt;
  if (typeof fn !== 'function') return '';
  try {
    // цЙлцППцЦЗцЬм:цЬмш╜охРДце╝цнгцЦЗ(ц╕Ец┤ЧхРО)уАВчФиф║║хРНхЙНч╝Ах╕охКйхЕ│щФошпНхС╜ф╕ншзТшЙ▓хРНуАВ
    const scanText = targets
      .map(i => {
        const m = chat[i];
        if (!m) return '';
        const who = m.is_user ? name1 || 'User' : m.name || name2 || 'Char';
        return `${who}: ${clampToTimeTags(m.mes)}`;
      })
      .filter(Boolean);
    if (!scanText.length) return '';
    // ST хЖЕщГи:WI хоЮщЩЕщвДчоЧ = world_info_budget(щ╗Шшод25%) ├Ч maxContext,ш╢ЕхЗ║хН│цИкцЦнцЭбчЫо(шУЭчБпф╣Яф╕Нф╛ЛхдЦ)уАВ
    // цСШшжБхЬ║цЩпшжБуАМц┐Ац┤╗чЪДф╕АцЭбщГ╜ф╕Нц╝ПуАН,цХЕф╝аф╕Аф╕кцЮБхдзчЪД maxContext,шойщвДчоЧхдзхИ░ф╕НхПпшГ╜ц║вхЗ║уАВ
    // (шЛечФицИ╖шо╛ф║Ж world_info_budget_cap ф╕КщЩР,ф╗Нф╝ЪшвлхоГх░Бщб╢тАФтАФщВгцШпчФицИ╖цШ╛х╝ПчЪДчбмф╕КщЩР,х░КщЗНф╣ЛуАВ)
    const HUGE_CONTEXT = 1_000_000_000;
    const res = await fn(scanText, HUGE_CONTEXT, true);
    if (!res) return '';

    const chunks: string[] = [];
    if (typeof res.worldInfoBefore === 'string') chunks.push(res.worldInfoBefore);
    if (typeof res.worldInfoAfter === 'string') chunks.push(res.worldInfoAfter);
    // @ц╖▒х║жцЭбчЫо:{depth, role, entries: string[]} тАФтАФ хдзщЗПшУЭчБпхЬицнд
    for (const d of res.worldInfoDepth ?? []) {
      for (const e of d?.entries ?? []) if (typeof e === 'string') chunks.push(e);
    }
    for (const e of res.anBefore ?? []) if (typeof e === 'string') chunks.push(e);
    for (const e of res.anAfter ?? []) if (typeof e === 'string') chunks.push(e);

    // хО╗щЗН + хО╗чй║
    const seen = new Set<string>();
    const out: string[] = [];
    for (const c of chunks) {
      const t = c.trim();
      if (t && !seen.has(t)) {
        seen.add(t);
        out.push(t);
      }
    }
    return out.join('\n\n').trim();
  } catch (e) {
    console.log('[цЯПхоЭф╣ж] ф╕ЦчХМф╣жц┐Ац┤╗хд▒ш┤е(щЩНч║зф╕║ф╕Нх╕жшо╛хоЪ):', e);
    return '';
  }
}

/**
 * хПЦх╜УхЙНшзТшЙ▓хНбчЪДф║║шо╛хнЧцо╡(description / personality / scenario)уАВ
 * цЬЙф║ЫхНбцККф║║шо╛хЖЩхЬишзТшЙ▓цППш┐░шАМщЭЮф╕ЦчХМф╣жщЗМ,цСШшжБф╣ЯщЬАцНоцндчРЖшзгшзТшЙ▓шиАшбМуАВ
 *   - ф╕Йф╕кхнЧцо╡щГ╜х░ЭшпХ,чй║чЪДшЗкхКиш╖│ш┐З(чО░ф╗гхНбх╕╕хПкхбл description);
 *   - хнЧцо╡щЗМхПпшГ╜хРл {{char}}/{{user}} хоП,чФи substituteParams х▒Хх╝А;
 *   - ч╛дшБК(characterId ф╕║чй║)цЪВф╕Нх╕жтАФтАФхдЪцИРхСШхРИх╣╢щА╗ш╛СхдНцЭВ,хРОч╗нхЖНхБЪуАВ
 * хПЦф╕НхИ░шзТшЙ▓ / хЕичй║ тЖТ ш┐ФхЫЮчй║ф╕▓(щЩНч║з,ф╕Нх╜▒хУНцСШшжБ)уАВ
 */
function fetchCharCard(): string {
  const ctx = getContext();
  if (!ctx || ctx.groupId) return ''; // ч╛дшБКцЪВф╕Нх╕ж
  const idx = ctx.characterId;
  if (idx === undefined || idx === null || idx === '') return '';
  const ch = ctx.characters?.[Number(idx)] as Record<string, unknown> | undefined;
  if (!ch) return '';
  const sub = typeof ctx.substituteParams === 'function' ? ctx.substituteParams : (s: string) => s;
  const fields: Array<[string, string]> = [
    ['цППш┐░', String(ch.description ?? '')],
    ['цАзца╝', String(ch.personality ?? '')],
    ['цГЕцЩп', String(ch.scenario ?? '')],
  ];
  const parts: string[] = [];
  for (const [label, raw] of fields) {
    const t = sub(raw).trim();
    if (t) parts.push(`уАР${label}уАС\n${t}`);
  }
  return parts.join('\n\n').trim();
}

/**
 * цШпхРжуАМхПпш┐╜ш╕кчЪД AI це╝х▒ВуАНуАВф╕ОуАМцШпхРжхп╣ф╕╗ LLM хПпшзБуАНшзгшАжтАФтАФщЪРшЧПф╕ОхРжщГ╜шжБчоЧ,хПкшжБхоГцШпчЬЯхоЮчЪД AI хЫЮхдНуАВ
 *
 * хЕ│щФохМ║хИЖ:`is_system=true` цЬЙф╕дчзНцЭец║Р,ф╕НшГ╜ф╕АцжВцОТщЩд:
 *   тСа швлщЪРшЧПчЪДчЬЯхоЮ AI хЫЮхдН(цИСф╗м /hide чЪД тЖТ х╕ж extra.bbs_hidden;цИЦчФицИ╖/хИлчЪДцЙйх▒Х /hide чЪД тЖТ цЧацаЗшо░)
 *      тАФтАФ ш┐Щф║ЫцШпшзТшЙ▓чЪДчЬЯхоЮхПСшиА,**х┐Ещб╗чоЧ AI це╝**,хРжхИЩщЪРшЧПш┐ЗчЪДце╝х░▒ц╝ПцСШ(чФицИ╖хоЮц╡ЛчЧЫчВ╣)уАВ
 *   тСб ST хОЯчФЯч│╗ч╗Яце╝(/sysуАБ/commentуАБхПЩф║Лц│ихЕечнЙ)тАФтАФ ш┐Щф║Ых╕ж extra.type,**ф╕НчоЧ**уАВ
 * цНоцнд:щЭЮчФицИ╖уАБцЬЙцнгцЦЗуАБф╕Фф╕НцШпуАМх╕ж type чЪДхОЯчФЯч│╗ч╗Яце╝уАНхН│ф╕║ AI це╝уАВцЩощАЪхПпшзБхЫЮхдН is_system=false шЗкчД╢хС╜ф╕нуАВ
 */
export function isAiFloor(m: STMessage | undefined): boolean {
  if (!m || m.is_user) return false;
  if (typeof m.mes !== 'string' || !m.mes.trim()) return false;
  if (m.extra?.bbs_hidden) return true; // швлцИСф╗мщЪРшЧПчЪДцЧз AI це╝
  // ST хОЯчФЯч│╗ч╗Яце╝х╕ж extra.type(narrator/sys чнЙ);чЬЯхоЮхЫЮхдН(хПпшзБцИЦшвл /hide)цЧа typeуАВ
  if (m.is_system && m.extra?.type) return false;
  return true;
}

/**
 * ц▒ВуАМф┐ЭчХЩчкЧхПгуАНчЪДш╡╖чВ╣ч┤вх╝Х:ф╗Ош┐ЩцЭбц╢ИцБпш╡╖(хРл)щГ╜хПСхЕицЦЗ,ф╣ЛхЙНчЪДхПпцСШшжБ/щЪРшЧПуАВ
 * хп╣щ╜Р Horae чЪД _resolveAutoSummaryKeepStartтАФтАФkeepRecent чО░хЬицХ░чЪДцШп **AI ц╢ИцБпцЭбцХ░**уАВ
 *   - цЧа AI це╝ тЖТ 0(ф╕НщЪРшЧП)
 *   - keep<=0 тЖТ chat.length(хЕищГихПпцСШшжБ)
 *   - AI це╝цХ░ <= keep тЖТ 0(хЕиф┐ЭчХЩ)
 *   - хРжхИЩ тЖТ хАТцХ░чмм keep ф╕к AI це╝чЪДч┤вх╝Х
 */
export function resolveKeepStart(chat: STMessage[]): number {
  const keep = Math.max(0, apiSettings.keepRecent);
  const aiIdx: number[] = [];
  for (let i = 0; i < chat.length; i++) {
    if (isAiFloor(chat[i])) aiIdx.push(i);
  }
  if (aiIdx.length === 0) return 0;
  if (keep <= 0) return chat.length;
  if (aiIdx.length <= keep) return 0;
  return aiIdx[aiIdx.length - keep];
}

/**
 * цЙ╛хЗ║"х╛ЕцСШшжБ"чЪД AI це╝х▒В:AI це╝ф╕Фц▓бцЬЙцЬЙцХИхП╢хнР(цЧахП╢ / щЩИцЧз)уАВчФ▒цЧзхИ░цЦ░уАВ
 * цЦ░ц╢ИцБпуАБregenerate цЦ░ swipeуАБч╝Цш╛Сш┐ЗчЪДце╝,щГ╜хЫа leafValid=false шЗкчД╢шР╜хЕеуАВ
 */
export function pendingAiFloors(chat: STMessage[]): number[] {
  const out: number[] = [];
  for (let i = 0; i < chat.length; i++) {
    if (isAiFloor(chat[i]) && !leafValid(chat[i])) out.push(i);
  }
  return out;
}

/**
 * уАМц┤ЮуАНце╝х▒В:ш┐ЭхПНца╕х┐Гф╕НхПШх╝ПуАМщЩдцЬАхРОф╕АцЭб AI хдЦ,хЕ╢ф╜Щ AI це╝щГ╜х┐Ещб╗цЬЙцЬЙцХИцСШшжБуАНчЪДх╛ЕцСШ AI це╝уАВ
 * = цЬлх░╛ AI це╝ф╣ЛхЙНчЪДцЙАцЬЙх╛ЕцСШ AI це╝уАВцЬлх░╛щВгцЭбш▒БхЕНтАФтАФхоГхИЪхоЪчи┐уАБцЬмх░▒ш┐Шц▓бцСШ,х▒Юцнгх╕╕х╛ЕцСШшАМщЭЮц┤ЮуАВ
 *
 * ш┐ЩцШпчФЯцИРцЛжцИкчЪДхИдцНо(шзБ handleGenerationIntercept)уАВц│ицДП:**ф╕НчЬЛф┐ЭчХЩчкЧхПг(keepRecent)**тАФтАФ
 * чкЧхПгхЖЕчЪДф╕нщЧ┤ц┤Ю(хжВцЯРце╝цСШшжБхд▒ш┤еуАБцИЦцЙЛхКихИаф║ЖцЯРце╝цСШшжБ)хРМца╖ча┤хЭПф╕НхПШх╝П,х┐Ещб╗цЛж,
 * хРжхИЩхРОхПСчЪДце╝ф╝ЪхЬиуАМхЙНщЭвч╝║цСШуАНцЧ╢чЕзх╕╕чФЯцИР,хп╝шЗ┤чК╢цАБ/шобхИТц│ихЕещФЩф╜Н(D2 ц│ихЕеф╜Нч╜охБЗшо╛ф║Жцндф╕НхПШх╝П)уАВ
 */
export function holesExceptLast(chat: STMessage[]): number[] {
  let lastAi = -1;
  for (let i = chat.length - 1; i >= 0; i--) {
    if (isAiFloor(chat[i])) { lastAi = i; break; }
  }
  if (lastAi < 0) return [];
  return pendingAiFloors(chat).filter(i => i < lastAi);
}

// цПРчд║це╝цнгцЦЗщЗМчЪДхЫ║хоЪхПе,цЧвч╗ЩчФицИ╖чЬЛ,ф╣ЯчФиф╜ЬуАМцЬлце╝цШпхРжх╖▓цШпцЬмцПРчд║це╝уАНчЪДхО╗щЗНхУихЕ╡
const BACKLOG_NOTICE_SENTINEL = 'цЬмцмбчФЯцИРх╖▓цЛжцИк';

/**
 * чФЯцИРцЛжцИкхЩи:цпПцмбуАМф║зхЗ║цЦ░цнгцЦЗуАНчЪДчФЯцИРхЙН,хоИф╜Пф╕НхПШх╝ПуАМщЩдцЬАхРОф╕АцЭб AI хдЦхЕ╢ф╜ЩщГ╜х┐Ещб╗цЬЙцСШшжБуАНуАВ
 * хИдцНо = holesExceptLast(цЬлх░╛ AI ф╣ЛхЙНчЪДх╛ЕцСШце╝х▒В),цМЙцХ░щЗПхИЖц╡Б:
 *  - 0 ф╕к тЖТ цФ╛шбМуАВ
 *  - цБ░хе╜ 1 ф╕к тЖТ чЬЛщВгхФпф╕АчЪДц┤ЮцШпхРжцнгхЬихРОхП░чФЯцИРцСШшжБ(currentRun щЭЮчй║):
 *      ┬╖ хЬищгЮ тЖТ toast цПРчд║х╣╢ await хоГч╗УцЭЯ(promise ц░╕ф╕Н reject,ф╕Нф╝ЪхНбцн╗);хоМцИРхРОщЗНхИд,ц┤Юхблф╕КхИЩцФ╛шбМ,хРжхИЩцЛжцИкуАВ
 *      ┬╖ ф╕НхЬищгЮ тЖТ чЫ┤цОецЛжцИк(хРОхП░ц▓бхЬишбехоГ,чнЙф╣Яц▓бцДПф╣Й)уАВ
 *  - >1 ф╕к тЖТ чЫ┤цОецЛжцИк(ф╕НчнЙх╛Е;хдЪф╕кц┤Юф║дч╗ЩхРОхП░ maybeSummarizePrevAiуАМцЬАцЧйф╝ШхЕИуАНщАРцЭбшбе,чФицИ╖шбехоМхЖНщЗНхПС)уАВ
 * цЛжцИк = abort(true) + /sendas цПТцПРчд║це╝уАВ
 *
 * хЕ│щФоцЧ╢х║П/хПгх╛Д(цФ╣хЙНхКбх┐ЕчРЖшзг,хРжхИЩцЮБцШУхдНхПСх╣╢шбМ bug):
 *  1) type хПгх╛Дх┐Ещб╗ф╕ОцСШшжБшзжхПС(bindEngine щЗМ GENERATION_STARTED чЫСхРмхЩи)ф╕АшЗ┤тАФтАФщГ╜цФ╛шбМ
 *     continue/quiet/impersonateуАБщГ╜чоб normal/regenerate/swipeуАВхРжхИЩщЗНчФЯ/ч┐╗щб╡цЧ╢уАМшбецСШуАНф╕ОуАМчФЯцИРуАНф╝Ъх╣╢шбМуАВ
 *  2) GENERATION_STARTED(шзжхПС maybeSummarizePrevAi)хЬи ST ф╕нхЕИф║ОцЬмцЛжцИкхЩи emit,ф╕Ф maybeSummarizePrevAi
 *     хИ░ runSummary ф╣ЛщЧ┤цШпхРМцнеф╗гчаБуАБrunSummary хРМцнеч╜охе╜ currentRun тЖТ цЬмцЛжцИкхЩиш╖СцЧ╢х╖▓шГ╜шп╗хИ░уАМхЬищгЮуАНф┐бхП╖уАВ
 *  3) ST ф╝Ъ await цЬмцЛжцИкхЩи(script.js runGenerationInterceptors),цХЕ await шГ╜чЬЯцнгщШ╗хбЮчФЯцИР;
 *     ф╕ФцЛжцИкхЩихЬи prompt ч╗ДшгЕф╣ЛхЙНш╖С,цСШшжБшР╜чЫШхРО,хРОч╗нч╗ДшгЕщШ╢цо╡чЪДц│ихЕешЗкчД╢х╕жф╕КцЦ░цХ░цНоуАВ
 * ш╖ЯщЪПуАМшЗкхКицСШшжБуАНх╝АхЕ│:хЕ│ф║ЖхИЩф╕Ах╣╢ф╕НцЛжуАВ
 */
export async function handleGenerationIntercept(
  type: string | undefined,
  abort: (immediately: boolean) => void,
): Promise<boolean> {
  if (!engineActiveHere()) return false; // цОТщЩдшзТшЙ▓/цА╗х╝АхЕ│хЕ│:ф╕НцЛж
  if (!apiSettings.autoSummaryEnabled) return false; // шЗкхКицСШшжБхЕ│ тЖТ цЛжцИкф╕Ах╣╢хЕ│
  // шжБф║зхЗ║цЦ░цнгцЦЗчЪДчФЯцИРцЙНцЛж:normal(хПСц╢ИцБп)/regenerate(щЗНцЦ░чФЯцИР)/swipe(ч┐╗щб╡)уАВ
  // ф╕ОцСШшжБшзжхПС(GENERATION_STARTED чЫСхРмхЩи)хРМхПгх╛Д,хРжхИЩщЗНчФЯ/ч┐╗щб╡цЧ╢уАМшбецСШуАНф╕ОуАМчФЯцИРуАНф╝Ъх╣╢шбМуАВ
  // continue(ч╗нхЖЩ)/quiet(хоЙщЭЩ)/impersonate(цЙоц╝Ф)цФ╛шбМ,ф╕Ншпешвлц┤ЮцМбуАВ
  if (type === 'continue' || type === 'quiet' || type === 'impersonate') return false;

  const ctx = getContext();
  if (!ctx) return false;
  if (!ctx.getCurrentChatId?.()) return false; // цмвш┐Ощб╡:цЧашБКхдйф╕НцЛж
  const chat = ctx.chat ?? [];

  let holes = holesExceptLast(chat);
  if (holes.length < 1) return false; // цЧац┤Ю:цФ╛шбМ

  // цБ░хе╜ 1 ф╕кц┤Ю,ф╕ФхоГцнгхЬихРОхП░чФЯцИР тЖТ чнЙхоГ,чнЙхоМщЗНхИд(цИРхКЯцФ╛шбМ / хд▒ш┤ешР╜хИ░цЛжцИк)уАВ
  if (holes.length === 1) {
    const inflight = currentSummaryPromise();
    if (inflight) {
      toast('цнгхЬишбецСШхЙНф╕Аце╝х▒В,шп╖чиНхАЩтАж', 'info');
      await inflight;
      holes = holesExceptLast(chat);
      if (holes.length < 1) return false; // шбехоМ,ц┤Юц▓бф║Ж тЖТ цФ╛шбМ
    }
  }

  abort(true); // ф╗НцЬЙц┤Ю(>1,цИЦщВгхФпф╕АчЪДц┤Юц▓бхЬищгЮ/шбехд▒ш┤е):члЛхН│ф╕нцнв

  // хО╗щЗН:цЬлце╝х╖▓цШпцЬмцПРчд║це╝х░▒ф╕НхЖНщЗНхдНцПТ(ш┐ЮчВ╣хПСщАБф╕НхИ╖х▒П)
  const last = chat[chat.length - 1];
  if (last && !last.is_user && typeof last.mes === 'string' && last.mes.includes(BACKLOG_NOTICE_SENTINEL)) {
    return true;
  }

  const exec = ctx.executeSlashCommandsWithOptions;
  if (typeof exec === 'function') {
    // хдЪшбМщЭа {{newline}} хоП(sendMessageAs ш╡░ substituteParams ф╝Ъш┐ШхОЯцИРцНвшбМ)
    const text = [
      `уАРцЯПхоЭф╣жуАС${BACKLOG_NOTICE_SENTINEL}`,
      `хПСчФЯф║Жф╗Аф╣И: хЫаф╕║хЙНщЭвцЬЙце╝х▒Вц▓бцЬЙцСШшжБя╝Мф╕║ф║Жф┐ЭшпБхЙзцГЕчЪДш┐Юч╗нцАзя╝МцЙАф╗еф╜ащЬАшжБхЕИхО╗ч╗ЩхоГшбехЕицСШшжБцЙНшГ╜ч╗зч╗нхПСщАБц╢ИцБп`,
      `х║ФшпецАОф╣ИхБЪ: чВ╣х╝Ах╖жф╕ЛшзТщнФц│ХцгТя╝МцЙУх╝АцЯПхоЭф╣жчХМщЭвя╝МхЬичммф╕Ащб╡ф╕ня╝Мф╝ЪцШ╛чд║тАЬцЬкцСШшжБце╝х▒ВтАЭя╝МчВ╣ф╕Аф╕Лце╝х▒ВхП╖я╝Мх░▒хПпф╗ешЗкхКишбехЕи`,
      `шбехЕихд▒ш┤е: хдЪхНКцШпAPIщЧощвШя╝МхдЪх░ЭшпХф╕НхРМчЪДAPI`,
      `шбехЕицИРхКЯ: хЬишбехЕицИРхКЯхРОя╝МхПкщЬАшжБцККш┐Щф╕Ах▒ВцПРчд║це╝х▒ВхИацОЙя╝Мх░▒хПпф╗еч╗зч╗нцнгх╕╕чФЯцИРф║Ж`
    ].join('{{newline}}');
    try {
      await exec(`/sendas name="цЯПхоЭф╣ж" ${text}`);
    } catch (e) {
      engineState.lastError = `чзпхОЛцПРчд║це╝цПТхЕехд▒ш┤е: ${e instanceof Error ? e.message : String(e)}`;
    }
  }
  return true;
}

/** цСШшжБхРОчЪДч╗Яф╕АцФ╢х░╛:хРМцнец╗СхКищЪРшЧП + хИ╖цЦ░ц│ихЕе(шЗкхКищЪРшЧПх╖▓х╣╢хЕецСШшжБц╡БчиЛ,ф╕НхЖНцЬЙчЛмчлЛх╝АхЕ│) */
async function afterSummaryHideAndInject(chat: STMessage[]): Promise<void> {
  await syncWindowHiddenState(chat);
  refreshInjection();
}

/**
 * хп╣хдЦчЪДуАМцгАц╡Лф╕АцмбщЪРшЧПуАН:цМЙх╜УхЙНхП╢хнРшжЖчЫЦцГЕхЖ╡хРМцнец╗СхКичкЧхПгщЪРшЧП + хИ╖цЦ░ц│ихЕеуАВ
 * ф╛Ыш┐Бчз╗чнЙцЙ╣щЗПхЖЩхЕехП╢хнРхРОш░ГчФи,хдНчФицСШшжБцФ╢х░╛хРМф╕АхеЧщА╗ш╛С;хоИхНлф╕ОцСШшжБц╡БчиЛф╕АшЗ┤
 * (х╝ХцУОхЬицндшБКхдйф╕НчФЯцХИ / шЗкхКицСШшжБхЕ│щЧнхИЩф╕НщЪРшЧП,ф╗ЕхИ╖цЦ░ц│ихЕе)уАВ
 */
export async function syncHiddenNow(): Promise<void> {
  const chat = getContext()?.chat ?? [];
  if (engineActiveHere() && apiSettings.autoSummaryEnabled) {
    await afterSummaryHideAndInject(chat);
  } else {
    refreshInjection();
  }
}

/**
 * хЕищЗПшбецСШ:ч╗ЩцЙАцЬЙуАМцЧацЬЙцХИхП╢хнРуАНчЪД AI це╝щАРф╕кчФЯцИРцСШшжБуАВ
 * **ф╗Еф╛ЫцСШшжБщб╡уАМчлЛхН│цСШшжБуАНцМЙщТоцЙЛхКиш░ГчФи**тАФтАФшЗкхКишзжхПСцФ╣чФи maybeSummarizePrevAi(хНХце╝хвЮщЗП)уАВ
 */
export async function checkAutoSummary(): Promise<void> {
  console.log('[цЯПхоЭф╣ж] checkAutoSummary(цЙЛхКихЕищЗП) ш┐ЫхЕе', { enabled: apiSettings.autoSummaryEnabled, busy });
  if (!engineActiveHere()) { console.log('[цЯПхоЭф╣ж] цЧйщАА:цПТф╗╢цА╗х╝АхЕ│хЕ│щЧнцИЦх╜УхЙНшзТшЙ▓швлцОТщЩд'); return; }
  if (!apiSettings.autoSummaryEnabled) { console.log('[цЯПхоЭф╣ж] цЧйщАА:шЗкхКицСШшжБцЬкх╝АхРп'); return; }
  if (busy) { console.log('[цЯПхоЭф╣ж] цЧйщАА:busy щФБ'); return; }

  const ctx = getContext();
  if (!ctx) { console.log('[цЯПхоЭф╣ж] цЧйщАА:цЧа ctx'); return; }
  const chat = ctx.chat ?? [];
  if (chat.length === 0) { console.log('[цЯПхоЭф╣ж] цЧйщАА:chat ф╕║чй║'); return; }

  const floors = pendingAiFloors(chat);
  console.log('[цЯПхоЭф╣ж] х╛ЕцСШшжБце╝х▒В =', floors);
  for (const floor of floors) {
    await runSummary(floor);
  }
  await afterSummaryHideAndInject(chat);
}

/**
 * цЙЛхКихп╣хНХф╕кце╝х▒ВшбецСШ(цСШшжБщб╡уАМцЬкцСШшжБце╝х▒ВуАНхИЧшбищАРце╝чВ╣хЗ╗)уАВ
 * ф╕ОшЗкхКишзжхПСшзгшАж:ф╕НчЬЛ autoSummaryEnabled,хПкшжБцА╗х╝АхЕ│х╝АчЭАх░▒цЙзшбМ;цСШхоМш╖СцФ╢х░╛(щЪРшЧП+ц│ихЕе)уАВ
 */
export async function summarizeFloor(floor: number): Promise<void> {
  if (!engineActiveHere()) return;
  if (busy) return;
  const ctx = getContext();
  if (!ctx) return;
  const chat = ctx.chat ?? [];
  if (!isAiFloor(chat[floor]) || leafValid(chat[floor])) return;
  await runSummary(floor);
  await afterSummaryHideAndInject(chat);
}

/**
 * шЗкхКишзжхПСчЪДхНХце╝хвЮщЗПцСШшжБ:**цЬАцЧйх╛ЕцСШф╝ШхЕИ**,ф╕АцмбхПкцСШф╕АцЭбуАВ
 * @param skipLastAi true цЧ╢ш╖│ш┐ЗцнгхЬицУНф╜ЬчЪДцЬлх░╛ AI ц╢ИцБп(ч┐╗щб╡/щЗНцЦ░чФЯцИРхЬ║цЩп),хоГф╕НхПВф╕ОчЫоцаЗщАЙхПЦуАВ
 *
 * ф╕НхПШх╝П:щЩдцЬАхРОф╕АцЭб AI хдЦ,хЕ╢ф╜Щ AI це╝щГ╜х║ФцЬЙцСШшжБуАВф╕║цндчЫоцаЗхПЦуАМхПпцСШшМГхЫ┤хЖЕцЬАцЧйчЪДх╛ЕцСШ AI це╝уАН,
 * шАМщЭЮуАМф╕Кф╕АцЭбуАНтАФтАФхРжхИЩхЙНщЭвцЬЙхд▒ш┤еце╝(ц┤Ю)цЧ╢,цЦ░це╝ф╝Ъш╢Кш┐ЗхоГхЕИцСШ,хп╝шЗ┤хАТх║П(шобхИТц╝ПхИачнЙ)уАВ
 *  - хПСц╢ИцБп:хПпцСШшМГхЫ┤ = чЫ┤хИ░цЬАхРОф╕АцЭб AI це╝уАВskipLastAi=falseуАВ
 *  - ч┐╗щб╡/щЗНцЦ░чФЯцИР:цЬлх░╛ AI цнгхЬишвлцФ╣хЖЩ,цОТщЩдхоГ,шМГхЫ┤ = чЫ┤хИ░ф╣ЛхЙНщВгцЭб AIуАВskipLastAi=trueуАВ
 * щЕНхРИчФЯцИРцЛжцИк(цЬЙц┤Юф╕ФцЬкшбехоМхЙНф╕НцФ╛шбМ),цпПш╜ошбеф╕АцЭбф╣Яф╕Нф╝Ъшойц┤Юш╢Кчзпш╢КхдЪуАВ
 */
export async function maybeSummarizePrevAi(skipLastAi: boolean): Promise<void> {
  if (!engineActiveHere()) return;
  if (!apiSettings.autoSummaryEnabled) return;
  if (busy) return;
  const ctx = getContext();
  if (!ctx) return;
  const chat = ctx.chat ?? [];
  if (chat.length === 0) return;

  // хПпцСШшМГхЫ┤ф╕КчХМ:хПСц╢ИцБп=цЬАхРОф╕АцЭб AI;ч┐╗щб╡/щЗНчФЯ=ф╣ЛхЙНщВгцЭб AI(цЬлх░╛цШУхПШ,цОТщЩд)уАВ
  const ceiling = prevAiFloor(chat, skipLastAi);
  if (ceiling < 0) return;
  // шМГхЫ┤хЖЕцЬАцЧйчЪДх╛ЕцСШ AI це╝(ц┤Юф╝ШхЕИ);ц▓бцЬЙхИЩф╗Еш╖СцФ╢х░╛(щЪРшЧПчкЧхПгхПпшГ╜хПШхМЦ)уАВ
  const target = pendingAiFloors(chat).find(f => f <= ceiling);
  if (target === undefined) {
    await afterSummaryHideAndInject(chat);
    return;
  }
  await runSummary(target);
  await afterSummaryHideAndInject(chat);
}

/**
 * цЙ╛уАМф╕Кф╕АцЭбх╖▓хоЪчи┐ AI ц╢ИцБпуАНчЪДч┤вх╝ХуАВ
 * skipLastAi=false тЖТ цЬАхРОф╕АцЭб AI це╝;skipLastAi=true тЖТ ш╖│ш┐ЗцЬАхРОф╕АцЭб AI це╝,хПЦхЖНф╣ЛхЙНщВгцЭбуАВ
 * цЙ╛ф╕НхИ░ш┐ФхЫЮ -1уАВ
 */
export function prevAiFloor(chat: STMessage[], skipLastAi: boolean): number {
  let lastAi = -1;
  for (let i = chat.length - 1; i >= 0; i--) {
    if (isAiFloor(chat[i])) {
      lastAi = i;
      break;
    }
  }
  if (lastAi < 0) return -1;
  if (!skipLastAi) return lastAi;
  for (let i = lastAi - 1; i >= 0; i--) {
    if (isAiFloor(chat[i])) return i;
  }
  return -1;
}

/** цККщАТхвЮчЪДч┤вх╝ХхИЧшбихРИх╣╢цИРш┐Юч╗нхМ║щЧ┤(ф╛Ы /hide 0-3 ш┐ЩчзНцЙ╣щЗПхПВцХ░чФи) */
export function coalesceRanges(indices: number[]): Array<[number, number]> {
  const sorted = [...new Set(indices)].sort((a, b) => a - b);
  const ranges: Array<[number, number]> = [];
  for (const i of sorted) {
    const last = ranges[ranges.length - 1];
    if (last && i === last[1] + 1) last[1] = i;
    else ranges.push([i, i]);
  }
  return ranges;
}

/**
 * хРМцнец╗СхКичкЧхПгщЪРшЧПчК╢цАБ:
 *  - щЪРшЧПуАМф┐ЭчХЩчкЧхПгф╣ЛхЙНуАБх╖▓швлцСШшжБшжЖчЫЦуАБх░ЪцЬкщЪРшЧПуАНчЪДц╢ИцБпуАВ
 *  - хПЦц╢ИщЪРшЧПуАМцЫ╛чФ▒цЬмцПТф╗╢щЪРшЧПуАБф╜ЖчО░хЬиф╕Нх║ФщЪРшЧПуАНчЪДц╢ИцБпуАВ
 * ш╡░ ST хОЯчФЯ /hide(хп╣щ╜Р HoraeуАБшЗкхКихРМцне DOMуАБш╡░хоШцЦ╣хЕехПг),
 * /unhide,хРМцЧ╢чФи extra.bbs_hidden чзБцЬЙцаЗшо░хМ║хИЖуАМцИСф╗мщЪРшЧПчЪДуАНф╕ОуАМST хОЯчФЯч│╗ч╗Яце╝уАНуАВ
 * хПкщЪРшЧПх╖▓швлцСШшжБшжЖчЫЦчЪД,ч╗Эф╕НхИ╢щАаф┐бцБпщ╗Сц┤ЮуАВ
 */
async function syncWindowHiddenState(chat: STMessage[]): Promise<void> {
  const keepStart = resolveKeepStart(chat);
  const covered = coveredSet(chat);
  const ctx = getContext();
  if (!ctx) return;

  const toHide: number[] = [];
  const toUnhide: number[] = [];
  for (let i = 0; i < chat.length; i++) {
    const m = chat[i];
    if (!m) continue;
    const shouldHide = i < keepStart && covered.has(i);
    if (shouldHide) {
      if (!m.extra?.bbs_hidden || m.is_system !== true) toHide.push(i);
    } else if (m.extra?.bbs_hidden) {
      toUnhide.push(i);
    }
  }
  if (toHide.length === 0 && toUnhide.length === 0) return;

  const exec = ctx.executeSlashCommandsWithOptions;
  if (typeof exec === 'function') {
    for (const [start, end] of coalesceRanges(toUnhide)) {
      const arg = start === end ? `${start}` : `${start}-${end}`;
      try {
        for (let i = start; i <= end; i++) {
          const m = chat[i];
          if (!m?.extra?.bbs_hidden) continue;
          const { bbs_hidden: _hidden, ...extra } = m.extra;
          m.extra = extra;
        }
        await exec(`/unhide ${arg}`);
      } catch (e) {
        // /unhide хд▒ш┤ехИЩхЫЮщААхИ░чЫ┤цОехЖЩ is_system,ф┐ЭшпБхПЦц╢ИщЪРшЧПф╕АхоЪшР╜хЬ░
        for (let i = start; i <= end; i++) {
          const m = chat[i];
          if (!m) continue;
          m.is_system = false;
          if (m.extra?.bbs_hidden) {
            const { bbs_hidden: _hidden, ...extra } = m.extra;
            m.extra = extra;
          }
        }
        engineState.lastError = `/unhide ${arg} хд▒ш┤е: ${e instanceof Error ? e.message : String(e)}`;
      }
    }

    for (const [start, end] of coalesceRanges(toHide)) {
      const arg = start === end ? `${start}` : `${start}-${end}`;
      try {
        // щвДхЖЩчзБцЬЙцаЗшо░ + хЖЕхнШцАБ,щШ▓цнв /hide х╝ВцнецЬЯщЧ┤чЪДчлЮцАБ saveChat шжЖчЫЦ
        for (let i = start; i <= end; i++) if (chat[i]) chat[i].extra = { ...(chat[i].extra ?? {}), bbs_hidden: true };
        await exec(`/hide ${arg}`);
      } catch (e) {
        // /hide хд▒ш┤ехИЩхЫЮщААхИ░чЫ┤цОехЖЩ is_system,ф┐ЭшпБщЪРшЧПф╕АхоЪшР╜хЬ░
        for (let i = start; i <= end; i++) if (chat[i]) chat[i].is_system = true;
        engineState.lastError = `/hide ${arg} хд▒ш┤е: ${e instanceof Error ? e.message : String(e)}`;
      }
    }
  } else {
    // цЧа slash цЙзшбМхЩи(цЧзчЙИ/цЬкх░▒ч╗к):хЫЮщААчЫ┤цОехЖЩ is_system + щЗНш╜╜
    for (const i of toUnhide) {
      const m = chat[i];
      if (!m) continue;
      m.is_system = false;
      if (m.extra?.bbs_hidden) {
        const { bbs_hidden: _hidden, ...extra } = m.extra;
        m.extra = extra;
      }
    }
    for (const i of toHide) {
      const m = chat[i];
      if (!m) continue;
      m.extra = { ...(m.extra ?? {}), bbs_hidden: true };
      m.is_system = true;
    }
    try {
      await ctx.saveChat();
      await ctx.reloadCurrentChat();
    } catch {
      /* хИ╖цЦ░хд▒ш┤еф╕НшЗ┤хС╜ */
    }
  }
}

/**
 * хп╣хНХф╕к AI це╝х▒ВцЙзшбМцСШшжБуАВ
 * ф╕Кф╕ЛцЦЗ:ф╕║ф║ЖшойцСШшжБш┐Юш┤п,цККшпе AI це╝х▒Вш┐ЮхРМхоГхЙНщЭвч┤зщВ╗чЪДуАБх░ЪцЬкшжЖчЫЦчЪДчФицИ╖хПСшиАф╕Аш╡╖хЦВч╗ЩцибхЮЛ,
 * ф╜ЖхПкцККш┐Щф╕Аф╕к AI це╝х▒В(хПКхЕ╢хЙНч╜очФицИ╖це╝х▒В)цаЗшо░ф╕║х╖▓шжЖчЫЦуАВ
 */
/**
 * шзгцЮРцЯРцСШшжБф╗╗хКбхоЮщЩЕцАОф╣ИхПСшп╖ц▒В:
 *  - цМЗц┤╛ф║ЖхЙп API ц╕ащБУ тЖТ чФишпец╕ащБУ(requestCompletion);
 *  - цЬкцМЗц┤╛(чй║)тЖТ ш╖ЯщЪПф╕╗ API(requestViaMainApi тЖТ generateRaw,чФиф╕╗чХМщЭвх╜УхЙНхЬичФичЪД API,ф╕Нх╕жшБКхдйхОЖхП▓)уАВ
 * ф╕╗ API ф╣Яф╕НхПпчФи(ST цЧа generateRaw)цЧ╢ш┐ФхЫЮ error,ш░ГчФицЦ╣цНоцндцЧйщААх╣╢хЖЩ lastErrorуАВ
 */
function resolveSender(
  task: TaskType,
): { send: (messages: ChatMsg[]) => Promise<string>; label: string } | { error: string } {
  const channel = getChannelForTask(task);
  if (channel) {
    return { send: messages => requestCompletion(channel, messages), label: `ц╕ащБУуАМ${channel.name}уАН(${channel.model})` };
  }
  if (!mainApiAvailable()) {
    return { error: 'цЬкцМЗц┤╛хЙп API ц╕ащБУ,ф╕Фх╜УхЙНф╕╗ API ф╕НхПпчФи(шп╖хблхе╜ф╕╗ API хРОщЗНшпХ,цИЦф╕║цЬмф╗╗хКбхНХчЛмцМЗц┤╛ц╕ащБУ)' };
  }
  return { send: messages => requestViaMainApi(messages), label: 'ф╕╗ API(ф╕╗чХМщЭвх╜УхЙНхЬичФи)' };
}

/**
 * хПСшп╖ц▒Вх╣╢шзгцЮР,хд▒ш┤ешЗкхКищЗНшпХуАВхд▒ш┤е = шп╖ц▒ВцКЫщФЩ цИЦ шзгцЮРхЗ╜цХ░цКЫщФЩ(JSON цЧацХИ/ч╝║хнЧцо╡)уАВ
 * цЬАхдЪщЗНшпХ apiSettings.summaryMaxRetries цмб(щ╗Шшод 1),хН│уАМщжЦшпХ + N цмбщЗНшпХуАНхЕ▒ N+1 цмбх░ЭшпХуАВ
 * хЕищГихд▒ш┤ехИЩцКЫхЗ║цЬАхРОф╕АцмбчЪДщФЩшпп,чФ▒ш░ГчФицЦ╣хЖЩ lastErrorуАВ
 */
async function sendAndParse<T>(
  send: (messages: ChatMsg[]) => Promise<string>,
  messages: ChatMsg[],
  parse: (raw: string) => T,
): Promise<T> {
  const maxRetries = Math.max(0, apiSettings.summaryMaxRetries | 0);
  let lastErr: unknown;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return parse(await send(messages));
    } catch (e) {
      lastErr = e;
      if (attempt < maxRetries) {
        console.log(`[цЯПхоЭф╣ж] чмм ${attempt + 1} цмбх░ЭшпХхд▒ш┤е,щЗНшпХ:`, e instanceof Error ? e.message : String(e));
      }
    }
  }
  throw lastErr instanceof Error ? lastErr : new Error(String(lastErr));
}

/**
 * хНХце╝цСШшжБуАВхп╣хдЦхМЕф╕Ах▒В,ч╗┤цКдуАМх╜УхЙНхЬищгЮцСШшжБуАНф┐бхП╖ currentRun,ф╛ЫчФЯцИРцЛжцИкхЩи await(шзБ handleGenerationIntercept)уАВ
 *  - currentRun хРМцнеч╜оф╕║цЬмцмб promise тЖТ цЛжцИкхЩихЬи GENERATION_STARTED(шзжхПСцСШшжБ)ф╣ЛхРОш╖СцЧ╢х╖▓шГ╜шп╗хИ░хоГуАВ
 *  - finally щЗМц╕ЕхЫЮ null(хПкц╕ЕшЗкх╖▒,щБ┐хЕНц╕ЕцОЙхРОф╕Ацмбш░ГчФишо╛чЪДцЦ░ promise)уАВ
 *  - чЬЯцнгчЪДшп╖ц▒В/шР╜чЫШхЬи runSummaryInner;хоГхЖЕщГих╖▓ try/catch,promise ц░╕ф╕Н reject тЖТ цЛжцИкхЩи await ф╕Нф╝ЪхНбцн╗уАВ
 * ц│и:цЧйщАА(busy/щЭЮ AI це╝чнЙ)ф╣Яф╝Ъч╗ПхОЖуАМч╜о p тЖТ члЛхН│ finally ц╕ЕхЫЮ nullуАН,хПкцШп p хЗаф╣ОчЮмщЧ┤ resolve,ф╕НцЮДцИРцЬЙцХИхЬищгЮуАВ
 */
export function runSummary(aiFloor: number): Promise<void> {
  const p = runSummaryInner(aiFloor).finally(() => {
    if (currentRun === p) currentRun = null;
  });
  currentRun = p;
  return p;
}

/**
 * ц▒ВцЯР AI це╝чЪДуАМшжЖчЫЦшМГхЫ┤уАН(хЦВцибхЮЛчЪДф╕Кф╕ЛцЦЗце╝цо╡):цЬм AI це╝ + хоГхЙНщЭвч┤зщВ╗чЪДуАБх░ЪцЬкшжЖчЫЦчЪД(чФицИ╖)це╝х▒ВуАВ
 * чв░хИ░х╖▓шжЖчЫЦце╝цИЦф╕Кф╕Аф╕к AI це╝хН│хБЬуАВхНХце╝ф╕ОцЙ╣щЗПхЕ▒чФи,ф┐ЭшпБф╕дш╖пх╛ДхЦВч╗ЩцибхЮЛчЪДцнгцЦЗцо╡ф╕АшЗ┤уАВ
 */
function floorTargets(chat: STMessage[], aiFloor: number, covered: Set<number>): number[] {
  const targets: number[] = [aiFloor];
  for (let i = aiFloor - 1; i >= 0; i--) {
    if (covered.has(i)) break;
    if (isAiFloor(chat[i])) break; // чв░хИ░ф╕Кф╕Аф╕к AI це╝х▒Вх░▒хБЬ
    if (chat[i]) targets.unshift(i);
  }
  return targets;
}

/**
 * цККф╕Аф╗╜ AI delta хЫ║хМЦцИРхП╢хнРх╣╢шР╜хИ░цЯР AI це╝(хНХце╝ф╕ОцЙ╣щЗПхЕ▒чФи,ф┐ЭшпБф╕дш╖пх╛ДшР╜хП╢хПгх╛Дф╕АшЗ┤)уАВ
 *  - цЧ╢щЧ┤:ф╝ШхЕИшп╗шпеце╝цнгцЦЗ <bbs_start>/<bbs_end> цаЗчн╛(цЭГхиБщФЪчВ╣);ч╝║чЪДщВгчлпчФи AI шбечЪДхЕЬх║ХуАВ
 *  - plans.resolve чЯнх║ПхП╖ тЖТ чи│хоЪ id:чФиф╝ахЕечЪД stateBefore(цЬмце╝ф╣ЛхЙНчК╢цАБ)чЪДцЬкф║Жч╗УшобхИТщб║х║Пч┐╗шпСуАВ
 *  - чЙйхУБхЗАхПШхКихЖЩш┐ЫцнгцЦЗ <bbs_items> цЧБц│и(хЯ║хЗЖ = stateBefore.items)уАВ
 * ф╕НхБЪ recompute/flush/ц│ихЕетАФтАФчФ▒ш░ГчФицЦ╣хЬихРИщАВцЧ╢цЬ║ч╗Яф╕АцФ╢х░╛(цЙ╣щЗПхПпцФТхИ░хЭЧх░╛ф╕АцмбхИ╖цЦ░)уАВ
 */
function applyLeafForFloor(
  chat: STMessage[],
  aiFloor: number,
  delta: SummaryDelta,
  stateBefore: ReturnType<typeof deriveMemory>,
): void {
  // цЧ╢щЧ┤щФЪчВ╣:ф╗Ошпеце╝цнгцЦЗцаЗчн╛шп╗ш╡╖цнв(хЕИшгБхЙкхИ░цнгцЦЗцо╡,ш╖│ш┐ЗцАЭч╗┤щУ╛/чК╢цАБцаПщЗМц╖╖хЕечЪДхРМхРНцаЗчн╛)
  const tag = parseTimeRange(clampToTimeTags(chat[aiFloor].mes));

  // цЬкф║Жч╗УшобхИТчЪДцЬЙх║ПхИЧшби:щб║х║ПхН│цПРчд║шпНщЗМчЪД p1/p2тАж,чФиф║ОцКК resolve чЯнх║ПхП╖ч┐╗шпСцИРчи│хоЪ id
  const openPlansOrdered = stateBefore.plans.filter(p => p.status === 'open');
  const storedDelta = finalizeDelta(delta, openPlansOrdered);

  // цЧ╢щЧ┤ш╡╖цнв:цаЗчн╛ф╝ШхЕИ(ф╕ОцЦ░хЙзцГЕхРМц║Рф╕Нц╝Вчз╗);цаЗчн╛ч╝║чЪДщВгчлпчФи AI шбечЪД timeStart/timeEnd хЕЬх║ХуАВ
  const timeStart = tag.start || delta.timeStart?.trim() || undefined;
  const timeEnd = tag.end || delta.timeEnd?.trim() || delta.time?.trim() || undefined;
  // чК╢цАБх╜УхЙНцЧ╢щЧ┤(шжЖчЫЦхЮЛ):чФич╗УцЭЯцЧ╢щЧ┤(цЬмцо╡цЬАхРОцЧ╢хИ╗);хПЦф╕НхИ░хИЩф┐ЭчХЩцЧвцЬЙчК╢цАБуАВ
  if (timeEnd) storedDelta.time = timeEnd;

  const leaf: LeafExtra = {
    id: makeLeafId(),
    text: (delta.summary ?? '').trim(),
    delta: storedDelta,
    timeStart,
    timeEnd,
    createdAt: Date.now(),
    // шо░х╜ХчФЯцИРцЧ╢цЙАхЬищб╡чаБ,ф╛Ы leafValid хИдхоЪх╜Тх▒Ю(ч┐╗хИ░хИлщб╡цЧ╢ф╕Нф╕▓цЙ░);ч╝║ swipe_id цМЙчммф╕Ащб╡ 0
    swipe: typeof chat[aiFloor].swipe_id === 'number' ? chat[aiFloor].swipe_id : 0,
    v: 1,
  };
  chat[aiFloor].extra = { ...(chat[aiFloor].extra ?? {}), bbs_leaf: leaf };

  // цККцЬмце╝чЙйхУБхЗАхПШхКихЖЩш┐ЫцнгцЦЗ </bbs_end> ф╣ЛхРО(<bbs_items> цЧБц│и,цнгхИЩщЪРшЧПуАБф╕Нш┐ЫхЙпAPIцСШшжБ)уАВ
  // чФи stateBefore.items(цЬмце╝ф╣ЛхЙНчЪДчЙйхУБ)ф╜ЬхЯ║хЗЖчоЧ fromтЖТto;цЧахПШхКихИЩхПкц╕ЕцЧзхЭЧуАВ
  const changes = itemChangesOf(storedDelta, stateBefore.items, timeEnd || timeStart || '');
  chat[aiFloor].mes = writeItemLogTag(chat[aiFloor].mes, fmtItemLogInline(changes));
}

/**
 * хНХце╝цСШшжБчЪДуАМч║пх╖еф╜ЬуАНщГихИЖ:хПСшп╖ц▒В + шзгцЮР + шР╜хП╢ + хИ╖цЦ░ц┤╛чФЯ/ц│ихЕеуАВ
 * **ф╕НчобчРЖ busy / ф╕НхБЪхоИхНл / ф╕НшзжхПС checkResummary**тАФтАФчФ▒ш░ГчФицЦ╣(runSummaryInner цИЦцЙ╣щЗПхЫЮщАА)ш┤Яш┤гуАВ
 * хд▒ш┤е(шп╖ц▒ВцКещФЩ / JSON цЧацХИ)чЫ┤цОецКЫхЗ║,ш░ГчФицЦ╣хЖ│хоЪхжВф╜ХхдДчРЖуАВ
 */
async function summarizeFloorWork(
  chat: STMessage[],
  aiFloor: number,
  sender: { send: (messages: ChatMsg[]) => Promise<string>; label: string },
): Promise<void> {
  const ctx = getContext();
  if (!ctx) throw new Error('цЧа ST ф╕Кф╕ЛцЦЗ');

  const covered = coveredSet(chat);
  const targets = floorTargets(chat, aiFloor, covered);
  const content = renderMessages(chat, targets, ctx.name1, ctx.name2);

  // ф╕дчлпцаЗчн╛щ╜РцЙНчоЧуАМцЬЙцаЗчн╛уАН,цПРчд║шпНцНоцндхЕНхО╗ AI чоЧцЧ╢щЧ┤уАВ
  const tag = parseTimeRange(clampToTimeTags(chat[aiFloor].mes));
  const hasTimeTags = !!(tag.start && tag.end);

  // цИкцнвхИ░уАМшвлхИЖцЮРце╝цо╡ф╣ЛхЙНуАНчЪДчК╢цАБф╕ОхОЖхП▓(ф╕Нц│Дц╝ПцЬкцЭе:щЗНцСШцЧйцЬЯце╝цЧ╢цОТщЩдхЕ╢хРОхП╢хнР)
  const beforeIndex = targets[0];
  const stateBefore = deriveMemory(chat, beforeIndex);
  const history = renderHistoryNodes(selectHistoryNodesBefore(memory.summaries, chat, beforeIndex));

  const worldInfo = await fetchWorldInfo(chat, targets, ctx.name1, ctx.name2);
  const charCard = fetchCharCard();

  const openPlansOrdered = stateBefore.plans.filter(p => p.status === 'open');
  const prompt = buildSummaryPrompt({
    user: ctx.name1,
    char: ctx.name2,
    time: stateBefore.state.time,
    location: stateBefore.state.location,
    items: stateBefore.items.map(i => ({ name: i.name, qty: i.qty, desc: i.desc, carried: i.carried, location: i.location })),
    itemLog: stateBefore.itemLog,
    scenes: stateBefore.scenes.map(s => ({ path: s.path, desc: s.desc })),
    npcs: stateBefore.npcs.map(n => ({ name: n.name, title: n.title, important: n.important, outfit: n.outfit, condition: n.condition, follow: n.follow, location: n.location })),
    openPlans: openPlansOrdered.map(p => ({ kind: p.kind, content: p.content, createdTime: p.createdTime, targetTime: p.targetTime })),
    history,
    content,
    hasTimeTags,
  });

  const messages: ChatMsg[] = [];
  const jb = apiSettings.prompts.jailbreak.trim() || JAILBREAK_PROMPT;
  if (jb) messages.push({ role: 'system', content: jb });
  if (charCard) messages.push({ role: 'system', content: buildCharCardSystem(charCard) });
  if (worldInfo) messages.push({ role: 'system', content: buildWorldInfoSystem(worldInfo) });
  messages.push(
    { role: 'user', content: prompt },
    { role: 'system', content: THINKING_CHECKLIST },
    { role: 'assistant', content: THINKING_PREFILL },
  );
  const delta = await sendAndParse(sender.send, messages, raw => {
    console.log('[цЯПхоЭф╣ж] цСШшжБхОЯхзЛш┐ФхЫЮ(цЬкц╕Ец┤Ч):\n', raw);
    const d = extractJsonObject<SummaryDelta>(raw);
    if (!d || !d.summary) {
      throw new Error(raw.trim() ? 'цСШшжБхд▒ш┤е:AIщБУцнЙцИЦцОЙца╝х╝П' : 'цСШшжБхд▒ш┤е:AIчй║хЫЮ');
    }
    return d as SummaryDelta & { summary: string };
  });

  applyLeafForFloor(chat, aiFloor, delta, stateBefore);
  engineState.lastRunAt = Date.now();

  // члЛхИ╗хПНцШахИ░ц┤╛чФЯф╕Оц│ихЕе;шР╜чЫШш╡░щШ▓цКЦ(щЪРшЧПчФ▒цФ╢х░╛чЪД syncWindowHiddenState ч╗Яф╕Аш┤Яш┤г)
  recomputeDerived();
  refreshInjection();
  scheduleLeafFlush();
  scheduleVectorIndex(); // цЦ░хП╢хнР тЖТ щШ▓цКЦхРМцнеш┐ЫхРСщЗПх║У(хд▒ш┤ещЭЩщ╗Ш,ф╕Нх╜▒хУНцСШшжБ)
}

async function runSummaryInner(aiFloor: number): Promise<void> {
  console.log('[цЯПхоЭф╣ж] runSummary це╝х▒В', aiFloor, '| busy =', busy);
  if (!engineActiveHere()) { console.log('[цЯПхоЭф╣ж] runSummary цЧйщАА:цПТф╗╢цА╗х╝АхЕ│хЕ│щЧнцИЦх╜УхЙНшзТшЙ▓швлцОТщЩд'); return; }
  if (busy) { console.log('[цЯПхоЭф╣ж] runSummary цЧйщАА:busy'); return; }
  const sender = resolveSender('summary');
  if ('error' in sender) {
    engineState.lastError = sender.error;
    console.log('[цЯПхоЭф╣ж] runSummary цЧйщАА:', sender.error);
    return;
  }
  const ctx = getContext();
  if (!ctx) return;
  const chat = ctx.chat ?? [];
  if (!isAiFloor(chat[aiFloor])) { console.log('[цЯПхоЭф╣ж] runSummary цЧйщАА:щЭЮ AI це╝', aiFloor); return; }
  console.log('[цЯПхоЭф╣ж] runSummary хН│х░ЖхПСшп╖ц▒В,', sender.label);

  busy = true;
  engineState.running = true;
  engineState.lastError = '';
  try {
    await summarizeFloorWork(chat, aiFloor, sender);
    // цСШшжБчзпч┤пхИ░щШИхА╝хИЩшзжхПСцА╗ч╗У
    await checkResummary();
  } catch (e) {
    engineState.lastError = e instanceof Error ? e.message : String(e);
  } finally {
    busy = false;
    engineState.running = false;
  }
}

/* ============ цЙ╣щЗПшбецСШ(хИЖхЭЧцЙ╣щЗП,ф╕Ацмбшп╖ц▒В тЖТ хдЪчЙЗхНХце╝хП╢хнР) ============ */

/** цЙ╣щЗПшбецСШщАЙщб╣ */
export interface BatchBackfillOpts {
  /** х╛ЕшбецСШчЪД AI це╝х▒В(чФ▒цЧзхИ░цЦ░);чЬБчХехИЩхПЦх╜УхЙНцЙАцЬЙх╛ЕцСШ AI це╝ */
  floors?: number[];
}

/** цЙ╣щЗПч╗УцЮЬц▒ЗцА╗ */
export interface BatchBackfillResult {
  /** цИРхКЯшР╜хП╢чЪДце╝цХ░ */
  done: number;
  /** шобхИТхдДчРЖчЪДцА╗це╝цХ░ */
  total: number;
  /** цШпхРжхЫахПЦц╢ИцПРхЙНч╗УцЭЯ */
  cancelled: boolean;
}

/**
 * цМЙхЖЕхо╣щЗПцККх╛ЕцСШце╝х▒ВхИЗцИРхдЪф╕кхЭЧ:цпПхЭЧцнгцЦЗч┤пшобхнЧчмжхИ░ maxChars цИЦце╝цХ░хИ░ maxFloors хН│хИЗуАВ
 * хНХце╝цнгцЦЗш╢Е maxChars цЧ╢шЗкцИРф╕АхЭЧ(ф╕НхПпхЖНхИЖ)уАВцпПхЭЧце╝х▒ВхНЗх║П,хЭЧщЧ┤хНЗх║ПуАВ
 * хнЧчмжщЗПхПгх╛ДчФи renderMessages(ф╕ОхЦВцибхЮЛхРМф╕Ац╕Ец┤Ч),хПкчоЧшпе AI це╝шЗкш║лцнгцЦЗ(хдЯш┐Сф╝╝,чЬБхО╗щЗНхдНчоЧхЙНч╜о user це╝)уАВ
 */
export function planBatches(chat: STMessage[], floors: number[], maxChars: number, maxFloors: number): number[][] {
  const ctx = getContext();
  const name1 = ctx?.name1 ?? '';
  const name2 = ctx?.name2 ?? '';
  const lo = Math.max(1, maxFloors | 0);
  const cap = Math.max(500, maxChars | 0);

  const batches: number[][] = [];
  let cur: number[] = [];
  let curChars = 0;
  for (const f of floors) {
    const len = renderMessages(chat, [f], name1, name2).length;
    // х╜УхЙНхЭЧщЭЮчй║,ф╕Ф(хКаш┐Щце╝ф╝Ъш╢ЕхнЧцХ░ цИЦ це╝цХ░х╖▓ш╛╛ф╕КщЩР)тЖТ хЕИхИЗхЭЧ
    if (cur.length && (curChars + len > cap || cur.length >= lo)) {
      batches.push(cur);
      cur = [];
      curChars = 0;
    }
    cur.push(f);
    curChars += len;
  }
  if (cur.length) batches.push(cur);
  return batches;
}

/**
 * хп╣ф╕Аф╕кхЭЧхПСф╕АцмбцЙ╣щЗПшп╖ц▒В,шзгцЮРхЗ║ floors цХ░ч╗Дх╣╢**щАРце╝шР╜хП╢**(хЭЧхЖЕщб║х║П,хРОце╝цЙ┐цОехЙНце╝чК╢цАБ)уАВ
 * цабщкМ floors щХ┐х║ж == хЭЧце╝цХ░;ф╕НчмжхИЩцКЫщФЩ(чФ▒ш░ГчФицЦ╣цМЙщЗНшпХ/хЫЮщААхдДчРЖ)уАВ
 */
async function summarizeBatchWork(
  chat: STMessage[],
  block: number[],
  sender: { send: (messages: ChatMsg[]) => Promise<string>; label: string },
): Promise<void> {
  const ctx = getContext();
  if (!ctx) throw new Error('цЧа ST ф╕Кф╕ЛцЦЗ');
  const covered = coveredSet(chat);

  // хЭЧх╝Ахд┤ф╣ЛхЙНчЪДчК╢цАБ/хОЖхП▓/ф╕ЦчХМф╣ж(цХ┤хЭЧч╗Яф╕АхПгх╛Д,хПкхПЦф╕Ацмб)
  const beforeIndex = floorTargets(chat, block[0], covered)[0];
  const stateBefore = deriveMemory(chat, beforeIndex);
  const history = renderHistoryNodes(selectHistoryNodesBefore(memory.summaries, chat, beforeIndex));

  // хдЪце╝цнгцЦЗ:цпПце╝х╕жуАМтФБтФБ чмм n це╝ тФБтФБуАНхИЖщЪФ,хЖЕхРлшпе AI це╝ + хЕ╢хЙНч╜оцЬкшжЖчЫЦ user це╝
  const allTargets: number[] = [];
  const segments: string[] = [];
  block.forEach((f, idx) => {
    const targets = floorTargets(chat, f, covered);
    allTargets.push(...targets);
    segments.push(`тФБтФБ чмм ${idx + 1} це╝ тФБтФБ\n${renderMessages(chat, targets, ctx.name1, ctx.name2)}`);
  });
  const content = segments.join('\n\n');

  // ф╕ЦчХМф╣жцМЙцХ┤хЭЧхРИх╣╢цнгцЦЗц┐Ац┤╗ф╕Ацмб(чЬБхО╗щАРце╝ц┐Ац┤╗)
  const worldInfo = await fetchWorldInfo(chat, allTargets, ctx.name1, ctx.name2);
  const charCard = fetchCharCard();

  const prompt = buildBatchSummaryPrompt({
    user: ctx.name1,
    char: ctx.name2,
    time: stateBefore.state.time,
    location: stateBefore.state.location,
    history,
    content,
    floorCount: block.length,
  });

  const { checklist, prefill } = buildBatchThinking(block.length);
  const messages: ChatMsg[] = [];
  const jb = apiSettings.prompts.jailbreak.trim() || JAILBREAK_PROMPT;
  if (jb) messages.push({ role: 'system', content: jb });
  if (charCard) messages.push({ role: 'system', content: buildCharCardSystem(charCard) });
  if (worldInfo) messages.push({ role: 'system', content: buildWorldInfoSystem(worldInfo) });
  messages.push(
    { role: 'user', content: prompt },
    { role: 'system', content: checklist },
    { role: 'assistant', content: prefill },
  );

  // шзгцЮР { floors: [...] };цабщкМщХ┐х║жчнЙф║ОхЭЧце╝цХ░(ч╝║це╝/хдЪце╝щГ╜чоЧхд▒ш┤е,шзжхПСщЗНшпХ/хЫЮщАА)
  const list = await sendAndParse(sender.send, messages, raw => {
    console.log('[цЯПхоЭф╣ж] цЙ╣щЗПцСШшжБхОЯхзЛш┐ФхЫЮ(цЬкц╕Ец┤Ч):\n', raw);
    const d = extractJsonObject<{ floors?: SummaryDelta[] }>(raw);
    const floors = d?.floors;
    if (!Array.isArray(floors) || !floors.length) {
      throw new Error(raw.trim() ? 'цЙ╣щЗПцСШшжБхд▒ш┤е:AIщБУцнЙцИЦцОЙца╝х╝П' : 'цЙ╣щЗПцСШшжБхд▒ш┤е:AIчй║хЫЮ');
    }
    if (floors.length !== block.length) {
      throw new Error(`цЙ╣щЗПцСШшжБхд▒ш┤е:ш┐ФхЫЮ ${floors.length} це╝,цЬЯцЬЫ ${block.length} це╝`);
    }
    if (floors.some(f => !f || !f.summary)) {
      throw new Error('цЙ╣щЗПцСШшжБхд▒ш┤е:цЬЙце╝х▒Вч╝║ summary');
    }
    return floors;
  });

  // щАРце╝шР╜хП╢(хЭЧхЖЕщб║х║П,ф╕еца╝цМЙ block хНЗх║П)уАВцЙ╣щЗПхПкхПЦ summary + ш╡╖цнвцЧ╢щЧ┤:
  // цШ╛х╝ПхЙецОЙ items/plans/location тАФтАФ ш┐Щф║Ыш╖ихдЪце╝щЪ╛ф┐Эщб║х║Пцнгчбо(цШУшЗ┤шобхИТ/цЧ╢щЧ┤щФЩф╣▒),
  // хН│ф╛┐ AI ф╕НхРмшпЭчбмф║зф║Жф╣Яф╕вх╝ГуАВч╗УцЮДхМЦцХ░цНоф║дч╗ЩхРОч╗нцнгх╕╕чЪДщАРце╝шЗкхКицСШшжБуАВ
  block.forEach((f, idx) => {
    const r = list[idx];
    const lean: SummaryDelta = {
      summary: r.summary,
      timeStart: r.timeStart,
      timeEnd: r.timeEnd,
    };
    const sb = deriveMemory(chat, f);
    applyLeafForFloor(chat, f, lean, sb);
  });

  engineState.lastRunAt = Date.now();
  recomputeDerived();
  refreshInjection();
  scheduleLeafFlush();
  scheduleVectorIndex();
}

/**
 * цЙ╣щЗПшбецСШ:цККх╛ЕцСШ AI це╝цМЙхЖЕхо╣щЗПхИЗхЭЧ,щАРхЭЧф╕▓шбМхПСшп╖ц▒ВуАБ**ф╕еца╝цМЙце╝х║ПщАРце╝шР╜хП╢**уАВ
 * чЬБ token хЕ│щФо:хЫ║хоЪф╕Кф╕ЛцЦЗ(ча┤щЩР/шо╛хоЪ/хЙНцГЕ)цМЙхЭЧхИЖцСК,шАМщЭЮцпПце╝щЗНхПСуАВ
 *  - цЙ╣щЗПхПкф║з summary + ш╡╖цнвцЧ╢щЧ┤(ф╕Нф║зчЙйхУБ/шобхИТ),щБ┐хЕНш╖ихдЪце╝чЪДч╗УцЮДхМЦцХ░цНощб║х║ПщФЩф╣▒;
 *    ч╗УцЮДхМЦцХ░цНоф║дч╗ЩхРОч╗нцнгх╕╕чЪДщАРце╝шЗкхКицСШшжБшбеуАВ
 *  - хЭЧщЧ┤ф╕▓шбМ + хЭЧхЖЕ AI щб║х║Пч╗┤цКдцЧ╢щЧ┤хНХш░Г,хРОхЭЧчФихЙНхЭЧшР╜чЫШхРОчЪДхЙНцГЕуАВ
 *  - цЯРхЭЧшзгцЮРхд▒ш┤е(х╖▓хРл summaryMaxRetries цмбщЗНшпХ)тЖТ хЫЮщАА:хп╣шпехЭЧщАРце╝ш╡░хНХце╝цСШшжБ(хНХце╝ш╖пх╛Дф╗Нф║зхоМцХ┤ч╗УцЮДхМЦцХ░цНо),ф╕Нф╕нцЦнцХ┤ф╜УуАВ
 *  - хПЦц╢ИхЬихЭЧш╛╣чХМчФЯцХИ(ф╕НцЙУцЦнш┐ЫшбМф╕нчЪДхЭЧ)уАВ
 * хЕищГихоМцИРхРОшзжхПС checkResummary(ш┐ЮщФБ L1/L2)+ цФ╢х░╛(щЪРшЧП + ц│ихЕе)уАВ
 */
export async function batchBackfill(opts: BatchBackfillOpts = {}): Promise<BatchBackfillResult> {
  if (!engineActiveHere()) return { done: 0, total: 0, cancelled: false };
  if (busy) return { done: 0, total: 0, cancelled: false };
  const sender = resolveSender('summary');
  if ('error' in sender) {
    engineState.lastError = sender.error;
    return { done: 0, total: 0, cancelled: false };
  }
  const ctx = getContext();
  if (!ctx) return { done: 0, total: 0, cancelled: false };
  const chat = ctx.chat ?? [];

  // чЫоцаЗце╝х▒В:цШ╛х╝Пф╝ахЕехИЩш┐Зц╗дцИРуАМх╜УхЙНчбохоЮх╛ЕцСШчЪД AI це╝уАН(щШ▓щЩИцЧз),хРжхИЩхПЦхЕищГих╛ЕцСШ
  const pending = new Set(pendingAiFloors(chat));
  const floors = (opts.floors ?? [...pending]).filter(f => pending.has(f)).sort((a, b) => a - b);
  const total = floors.length;
  if (total === 0) {
    await afterSummaryHideAndInject(chat);
    return { done: 0, total: 0, cancelled: false };
  }

  const batches = planBatches(chat, floors, apiSettings.batchMaxChars, apiSettings.batchMaxFloors);
  console.log('[цЯПхоЭф╣ж] цЙ╣щЗПшбецСШ:', total, 'це╝ тЖТ', batches.length, 'цЙ╣,', sender.label);

  busy = true;
  engineState.running = true;
  engineState.lastError = '';
  // цЙ╣щЗПчК╢цАБ(цибхЭЧч║зхНХф╛Л)тЖТ UI ш╖ихЕ│чкЧщЗНх╝АхПпцБвхдНш┐Ых║ж/хПЦц╢И
  batchState.running = true;
  batchState.cancelRequested = false;
  batchState.done = 0;
  batchState.total = total;
  let done = 0;
  let cancelled = false;
  try {
    for (const block of batches) {
      if (batchState.cancelRequested) { cancelled = true; break; }
      try {
        await summarizeBatchWork(chat, block, sender);
      } catch (e) {
        // цХ┤хЭЧхд▒ш┤е(х╖▓хРлщЗНшпХ)тЖТ хЫЮщАА:щАРце╝хНХчЛмцСШуАВхНХце╝ф╣ЯхПпшГ╜хд▒ш┤е(хЖЩ lastError),хд▒ш┤еце╝чХЩф╜Ьх╛ЕцСШ,ф╕Нф╕нцЦнхРОч╗нуАВ
        console.log('[цЯПхоЭф╣ж] цЙ╣щЗПхЭЧхд▒ш┤е,хЫЮщААщАРце╝:', e instanceof Error ? e.message : String(e));
        for (const f of block) {
          if (!isAiFloor(chat[f]) || leafValid(chat[f])) continue; // х╖▓швлхблцИЦщЭЮ AI це╝:ш╖│ш┐З
          try {
            await summarizeFloorWork(chat, f, sender);
          } catch (e2) {
            engineState.lastError = e2 instanceof Error ? e2.message : String(e2);
          }
        }
      }
      // цЬмхЭЧф║зхЗ║чЪДх╖▓шР╜хП╢це╝шобхЕеш┐Ых║ж(хПкцХ░чбохоЮшР╜ф╕КхП╢хнРчЪД,хд▒ш┤еце╝ф╕Ншоб)
      done = floors.filter(f => leafValid(chat[f])).length;
      batchState.done = done;
    }
    // ш┐ЮщФБшзжхПСцА╗ч╗У(хПпшГ╜ш╖ихдЪх▒В),хд▒ш┤ехЖЩ lastError ф╕Нх╜▒хУНх╖▓шР╜хП╢хнР
    await checkResummary();
  } catch (e) {
    engineState.lastError = e instanceof Error ? e.message : String(e);
  } finally {
    busy = false;
    engineState.running = false;
    batchState.running = false;
    batchState.cancelRequested = false;
  }
  await afterSummaryHideAndInject(chat);
  return { done, total, cancelled };
}

/**
 * х╜УхЙНх╖▓швлшжЖчЫЦчЪДце╝х▒Вч┤вх╝ХщЫЖхРИ(хЗаф╜ХхН│цЧ╢цОихп╝,ф╕Ншп╗хнШхВи)уАВ
 * ф╕АцЭб AI це╝шЛецЬЙцЬЙцХИхП╢хнР тЖТ хоГхПКхЕ╢хЙНч╜оуАМх░ЪцЬкшвлцЫ┤цЧй AI хП╢хнРшжЖчЫЦуАНчЪДце╝(хРл user це╝)щГ╜чоЧшвлшжЖчЫЦуАВ
 * хН│хМ║щЧ┤ (ф╕Кф╕АцЭбцЬЙцХИ AI хП╢хнР, цЬмцЭбцЬЙцХИ AI хП╢хнР] хЕишжЖчЫЦуАВх╛ЕцСШшжБ AI це╝ф╕НщЧнхРИхМ║щЧ┤уАВ
 */
export function coveredSet(chat: STMessage[]): Set<number> {
  const covered = new Set<number>();
  let segStart = 0;
  for (let i = 0; i < chat.length; i++) {
    if (!isAiFloor(chat[i])) continue;
    if (leafValid(chat[i])) {
      for (let k = segStart; k <= i; k++) covered.add(k);
      segStart = i + 1;
    }
    // х╛ЕцСШшжБ AI це╝(цЧацЬЙцХИхП╢хнР):цо╡ф╕НхЙНш┐Ы,чнЙхоГшвлцСШхРОхЖНшжЖчЫЦ
  }
  return covered;
}

/** цЯРх▒Вч║зшзжхПСхОЛч╝йцЙАщЬАчЪДщШИхА╝:хП╢хнРх▒ВчФи leafBatchThreshold,хЕ╢ф╜ЩчФи resummaryThreshold */
function thresholdForLevel(level: number): number {
  return level === 0 ? apiSettings.leafBatchThreshold : apiSettings.resummaryThreshold;
}

/** хОЛч╝йчФичЪДца╣шКВчВ╣шзЖхЫ╛:х╕жш╡╖цнвцЧ╢щЧ┤(хП╢хнРчЫ┤цОехПЦ,comp хПЦх╖▓шБЪхРИчЪДшМГхЫ┤),ф╛ЫхРСф╕КхРИх╣╢цЧ╢хПЦш╛╣чХМуАВ */
interface RootView {
  id: string;
  text: string;
  createdAt: number;
  timeStart?: string;
  timeEnd?: string;
}

/** цЯРх▒Вч║зуАМцЬкшвлцФ╢ч║│чЪДца╣шКВчВ╣уАН,цМЙцЧ╢щЧ┤/це╝х▒ВхНЗх║ПуАВlevel0=хП╢хнР(цЙл chat),levelтЙе1=цгоцЮЧуАВ */
function rootsAtLevel(level: number, chat: STMessage[]): RootView[] {
  const collected = new Set<string>();
  for (const s of memory.summaries) for (const c of s.childIds) collected.add(c);

  if (level === 0) {
    const out: RootView[] = [];
    for (let i = 0; i < chat.length; i++) {
      if (!leafValid(chat[i])) continue;
      const lf = getLeaf(chat[i]) as LeafExtra;
      if (collected.has(lf.id)) continue; // х╖▓швлцЯР L1 цФ╢ч║│
      out.push({ id: lf.id, text: lf.text, createdAt: lf.createdAt, timeStart: lf.timeStart, timeEnd: lf.timeEnd }); // х╖▓цМЙце╝х▒Вх║П
    }
    return out;
  }
  return memory.summaries
    .filter(s => s.level === level && !collected.has(s.id))
    .sort((a, b) => a.createdAt - b.createdAt || a.id.localeCompare(b.id))
    .map(s => ({ id: s.id, text: s.text, createdAt: s.createdAt, timeStart: s.timeStart, timeEnd: s.timeEnd }));
}

/**
 * хПпщАЖх▒Вч║зхОЛч╝й(ф╕НхИах║Хх▒В)уАВ
 * ф╗ОцЬАф╜Ох▒Вх╛Аф╕КщАРх▒ВцгАцЯе:цЯРх▒ВуАМцЬкшвлцФ╢ч║│чЪДца╣шКВчВ╣уАНцФТхдЯшпех▒ВщШИхА╝цЧ╢,
 * чФи AI цККш┐ЩцЙ╣чЪД**хПЩф║ЛцЦЗцЬм**шЮНхРИцИРф╕АцЭбф╕Кх▒ВшКВчВ╣,childIds цФ╢ч║│хоГф╗м(х║Хх▒ВхЕищГиф┐ЭчХЩ)уАВ
 * ф╕Ацмбш░ГчФиф╝ЪхРСф╕Кш┐ЮщФБ(хКахП╢хнРтЖТхПпшГ╜чФЯ L1тЖТхПпшГ╜чФЯ L2тАж),чФихРМф╕АхеЧхПМщШИхА╝щАТх╜ТуАВ
 */
export async function checkResummary(): Promise<number> {
  if (!engineActiveHere()) return 0;
  const ctx = getContext();
  if (!ctx) return 0;
  const chat = ctx.chat ?? [];

  let made = 0; // цЬмцмбш┐ЮщФБхЕ▒чФЯцИРчЪДцА╗ч╗УцЭбцХ░

  // цЬАщлШчО░хнШхОЛч╝йх▒Вч║з,ф╜Ьф╕║ш┐ЮщФБф╕КщЩР(+1 хо╣ч║│цЦ░чФЯцИРчЪДх▒В)
  const maxLevel = memory.summaries.reduce((m, s) => Math.max(m, s.level), 0);

  for (let level = 0; level <= maxLevel + 1; level++) {
    const threshold = thresholdForLevel(level);
    if (!threshold || threshold < 2) continue;

    const roots = rootsAtLevel(level, chat);
    if (roots.length < threshold) continue;

    const sender = resolveSender('resummary');
    if ('error' in sender) {
      engineState.lastError = sender.error;
      return made;
    }

    const batch = roots.slice(0, threshold);
    const content = batch.map((s, i) => `[${i + 1}] ${s.text}`).join('\n\n');
    // ф╝а**ш╛УхЗ║х▒Вч║з**(level+1):L1(цЩощАЪцА╗ч╗У,300-500хнЧ)/ L2+(ф║МцмбцА╗ч╗У,хнЧцХ░щЪПш╛УхЕехКицАБ)
    const prompt = buildResummaryPrompt({ user: ctx.name1, char: ctx.name2, content, level: level + 1 });

    try {
      const jb = apiSettings.prompts.jailbreak.trim() || JAILBREAK_PROMPT;
      const messages: ChatMsg[] = [];
      if (jb) messages.push({ role: 'system', content: jb });
      messages.push({ role: 'user', content: prompt });
      // хПСшп╖ц▒В + шзгцЮР,хд▒ш┤ецМЙшо╛ч╜ощЗНшпХ(шп╖ц▒ВцКещФЩцИЦ JSON цЧацХИ/ч╝║ summary щГ╜чоЧхд▒ш┤е)
      const delta = await sendAndParse(sender.send, messages, raw => {
        console.log('[цЯПхоЭф╣ж] цА╗ч╗УхОЯхзЛш┐ФхЫЮ(цЬкц╕Ец┤Ч):\n', raw);
        const d = extractJsonObject<{ summary?: string }>(raw);
        if (!d?.summary) {
          // ш╛УхЗ║х▒Вч║з level+1:ф╕║ 1 цШпцЩощАЪцА╗ч╗У,тЙе2 цШпф║МцмбцА╗ч╗У;цЬЙцЦЗцЬм=цОЙца╝х╝П,чй║чЩ╜=чй║хЫЮ
          const what = level + 1 === 1 ? 'цА╗ч╗У' : 'ф║МцмбцА╗ч╗У';
          throw new Error(raw.trim() ? `${what}хд▒ш┤е:AIщБУцнЙцИЦцОЙца╝х╝П` : `${what}хд▒ш┤е:AIчй║хЫЮ`);
        }
        return d as { summary: string };
      });

      // чФЯцИРф╕Кх▒ВшКВчВ╣цФ╢ч║│ш┐ЩцЙ╣(**ф╕НхИа batch**),цЧ╢щЧ┤цИ│хПЦцЙ╣хЖЕцЬАцЦ░,цОТхЬихоГф╗мф╣ЛхРО
      const newCreatedAt = Math.max(...batch.map(s => s.createdAt)) + 1;
      // ш╡╖цнвцЧ╢щЧ┤:batch х╖▓цМЙцЧ╢щЧ┤хНЗх║П тЖТ щжЦф╕кцЬЙш╡╖хзЛчЪДф╜Ь start,цЬлф╕кцЬЙч╗УцЭЯчЪДф╜Ь end
      const timeStart = batch.find(s => s.timeStart)?.timeStart;
      const timeEnd = [...batch].reverse().find(s => s.timeEnd)?.timeEnd;
      addSummary({
        text: delta.summary.trim(),
        level: level + 1,
        childIds: batch.map(s => s.id),
        auto: true,
        createdAt: newCreatedAt,
        timeStart,
        timeEnd,
      });
      made += 1;
      refreshInjection();
      // ф╕Н break:ч╗зч╗нхдЦх▒В for,ф╕Кф╕Ах▒ВхПпшГ╜ф╣ЯцФТхдЯф║Ж тЖТ ш┐ЮщФБхОЛцЫ┤щлШх▒В
    } catch (e) {
      engineState.lastError = e instanceof Error ? e.message : String(e);
      return made; // цЬмх▒Вхд▒ш┤ехИЩхБЬцнвш┐ЮщФБ,ф╕ЛцмбхЖНшпХ
    }
  }
  return made;
}

/**
 * цЙЛхКиуАМчлЛхН│цгАц╡Лх╣╢цА╗ч╗УуАН:ф╛ЫцСШшжБщб╡цМЙщТош░ГчФиуАВ
 * ф╕ОшЗкхКиш╖пх╛ДхРМф╕АхеЧщШИхА╝/ш┐ЮщФБщА╗ш╛С(checkResummary),ф╜Жх╕ж busy ф║ТцЦе,
 * щБ┐хЕНф╕ОцнгхЬиш╖СчЪДцСШшжБ/цА╗ч╗УцТЮш╜жуАВш┐ФхЫЮцЦ░чФЯцИРчЪДцА╗ч╗УцЭбцХ░(0 = цЬкш╛╛щШИхА╝,ф╗Аф╣ИщГ╜ц▓бхБЪ)уАВ
 */
export async function resummarizeNow(): Promise<number> {
  if (!engineActiveHere()) return 0;
  if (busy) return 0;
  busy = true;
  engineState.running = true;
  engineState.lastError = '';
  try {
    return await checkResummary();
  } finally {
    busy = false;
    engineState.running = false;
  }
}

/**
 * хУНх║Ф chat ч╗УцЮДхПШхКи(ч┐╗щб╡/хИащЩд/ч╝Цш╛С):цХ░цНох╖▓щЪПц╢ИцБпшЗкхКиш╖ЯщЪП,хПкщЬАц╕ЕхЭПщУ╛уАБщЗНчоЧц┤╛чФЯуАБхИ╖цЦ░,
 * ф╕НхБЪф╗╗ф╜Хч┤вх╝ХцЙЛцЬпуАБ**ф╕НшзжхПСцСШшжБчФЯцИР**(чФЯцИРчФ▒ maybeSummarizePrevAi цМЙшзДхИЩхНХчЛмхЖ│хоЪ)уАВ
 * debounce хРИх╣╢х┐лщАЯш┐Юч┐╗уАВ
 */
let reactTimer: ReturnType<typeof setTimeout> | null = null;
function reactToChatMutation(syncHidden = false): void {
  if (reactTimer) clearTimeout(reactTimer);
  reactTimer = setTimeout(() => {
    reactTimer = null;
    pruneBrokenComps(); // хП╢хнРхд▒цХИ тЖТ хИахМЕхРлхоГчЪДцХ┤цЭбчеЦхЕИхОЛч╝йщУ╛
    recomputeDerived(); // хИахП╢/щЩИцЧз тЖТ чЙйхУБ/шобхИТхЫЮщАА;UI(derivedMeta)цЫ┤цЦ░
    scheduleVectorIndex(); // хИаце╝/ч╝Цш╛С/ч┐╗щб╡ тЖТ щШ▓цКЦхп╣ш┤жхРСщЗПх║У(хИащЩИцЧзуАБшбецЦ░)
    if (syncHidden && engineActiveHere() && apiSettings.autoSummaryEnabled) {
      void syncWindowHiddenState(getContext()?.chat ?? [])
        .catch(e => {
          engineState.lastError = e instanceof Error ? e.message : String(e);
        })
        .finally(() => refreshInjection());
      return;
    }
    refreshInjection(); // ф╕НхЖНц│ихЕещЩИцЧз/х╖▓хИахП╢хнР
  }, 200);
}

/**
 * ч╗СхоЪф║Лф╗╢уАВцСШшжБшзжхПСшзДхИЩ:**хПкчбоф┐ЭуАМф╕Кф╕АцЭбх╖▓хоЪчи┐ AI ц╢ИцБпуАНцЬЙцСШшжБ**(хНХце╝хвЮщЗП,щЭЮхЕищЗП)уАВ
 * ш┐ЫхЕешБКхдй / ч┐╗хИ░ц▓бцСШшжБчЪДщб╡,щГ╜ф╕НхЖНшЗкхКичлЛхИ╗шбецСШуАВ
 *  - USER_MESSAGE_RENDERED:хПСцЦ░ц╢ИцБп тЖТ цСШуАМф╕Кф╕АцЭб AIуАН(skipLastAi=false)уАВ
 *  - GENERATION_STARTED(regenerate/swipe):цЬлх░╛ AI цнгхЬишвлцФ╣хЖЩ,ш╖│ш┐ЗхоГ тЖТ цСШуАМф╣ЛхЙНщВгцЭб AIуАН(skipLastAi=true)уАВ
 *  - MESSAGE_SWIPED / MESSAGE_EDITED:цХ░цНощЪПц╢ИцБпш╖ЯщЪП тЖТ reactToChatMutation(ц╕ЕхЭПщУ╛+щЗНчоЧ+хИ╖цЦ░),ф╕НхЬицндхдДчФЯцИРуАВ
 *  - MESSAGE_DELETED:хРМф╕К,х╣╢хРМцнеф╕Ацмбц╗СхКищЪРшЧП/хПЦц╢ИщЪРшЧПуАВ
 *  - CHAT_CHANGED:store ш┤Яш┤гщЗНш╜╜,ш┐ЩщЗМхИ╖цЦ░ц│ихЕеуАВ
 */
export function bindEngine(): void {
  const ctx = getContext();
  if (!ctx?.eventSource || !ctx?.eventTypes) return;
  const es = ctx.eventSource;
  const et = ctx.eventTypes;

  console.log('[цЯПхоЭф╣ж] bindEngine цЙзшбМ,чЫСхРм', et.USER_MESSAGE_RENDERED, et.GENERATION_STARTED);

  // хПСцЦ░ц╢ИцБп:цндхИ╗цЬлх░╛ AI цШпуАМф╕Кф╕АцЭбх╖▓хоЪчи┐уАНчЪДхЫЮхдН,цСШхоГуАВ
  es.on(et.USER_MESSAGE_RENDERED, () => {
    console.log('[цЯПхоЭф╣ж] USER_MESSAGE_RENDERED тЖТ цСШф╕Кф╕АцЭб AI');
    void maybeSummarizePrevAi(false);
  });

  // щЗНцЦ░чФЯцИР / ч┐╗щб╡:GENERATION_STARTED цЧ╢цЬлх░╛ AI хН│х░ЖшвлцФ╣хЖЩ(цШУхПШ),ш╖│ш┐ЗхоГ,цСШф╣ЛхЙНщВгцЭб AIуАВ
  // тЪая╕П ш┐ЩщЗМцФ╛шбМчЪД type(quiet/impersonate/continue)х┐Ещб╗ф╕О handleGenerationIntercept чммф╕АщБУщЧ╕ф╕еца╝ф╕АшЗ┤тАФтАФ
  //    ф╕дшАЕхПгх╛Дф╕АцЧжф╕НхРМцне,щЗНчФЯ/ч┐╗щб╡ф╝ЪхЗ║чО░уАМшбецСШуАНф╕ОуАМцнгцЦЗчФЯцИРуАНх╣╢шбМ(шзБцЛжцИкхЩиц│ищЗКчЪДуАМхЕ│щФоцЧ╢х║П/хПгх╛ДуАН)уАВ
  if (et.GENERATION_STARTED) {
    es.on(et.GENERATION_STARTED, (type?: string, _opts?: unknown, dryRun?: boolean) => {
      if (dryRun) return;
      if (type === 'quiet' || type === 'impersonate' || type === 'continue') return; // щЭЮчЬЯхоЮцЦ░хЫЮхдН
      console.log('[цЯПхоЭф╣ж] GENERATION_STARTED тЖТ цСШф╕Кф╕КцЭб AI, type =', type);
      void maybeSummarizePrevAi(true);
    });
  }

  // ф╗еф╕Лф╕Йф║Лф╗╢хПкшойцХ░цНо/UI ш╖ЯщЪП,ф╕Нф╕╗хКичФЯцИРцСШшжБуАВ
  if (et.MESSAGE_SWIPED) es.on(et.MESSAGE_SWIPED, () => reactToChatMutation());
  // ч╝Цш╛Сц╢ИцБп:хЕИцККшпеце╝цнгцЦЗщЗМ <bbs_items> цЧБц│ичЪДцФ╣хКихПНхРСхРМцнехЫЮхП╢хнР delta(чФицИ╖цЙЛцФ╣чЙйхУБ),
  // хЖНш╡░щАЪчФихЦДхРО(ц╕ЕхЭПщУ╛/щЗНчоЧ/хИ╖цЦ░)уАВх╗╢ш┐Яф╕АцЛНчбоф┐Э ST х╖▓цККч╝Цш╛СхЖЩхЫЮ chat[messageId].mesуАВ
  if (et.MESSAGE_EDITED) {
    es.on(et.MESSAGE_EDITED, (messageId?: number) => {
      setTimeout(() => {
        if (typeof messageId === 'number') {
          try { syncItemLogFromMessage(messageId); } catch (e) { console.warn('[цЯПхоЭф╣ж] чЙйхУБцЧБц│ихПНшзгцЮРхд▒ш┤е', e); }
        }
        reactToChatMutation();
      }, 0);
    });
  }
  if (et.MESSAGE_DELETED) es.on(et.MESSAGE_DELETED, () => reactToChatMutation(true));

  // AI цЦ░хЫЮхдНшР╜хоЪ:ф╕Нф╕АхоЪф╝ЪшзжхПСцСШшжБ(шЗкхКицСШшжБхЕ│щЧн / хоГф╕НцШпуАМф╕Кф╕АцЭб AIуАН),
  // ф╜ЖуАМцЬкцСШшжБце╝х▒ВуАНхИЧшбих┐Ещб╗ш╖Яф╕КцЦ░хвЮчЪД AI це╝,цХЕцЧацЭбф╗╢щЗНчоЧф╕Ацмбц┤╛чФЯч╝УхнШ(ф╕НхПСшп╖ц▒В)уАВ
  if (et.CHARACTER_MESSAGE_RENDERED) es.on(et.CHARACTER_MESSAGE_RENDERED, () => recomputeDerived());

  if (et.CHAT_CHANGED) {
    es.on(et.CHAT_CHANGED, () => {
      // шо░х┐ЖщЗНш╜╜чФ▒ store чЪД CHAT_CHANGED чЫСхРмш┤Яш┤г;цндхдДф╗ЕхЬихЕ╢хРОхИ╖цЦ░ц│ихЕе
      clearRecallInjection(); // хИЗшБКхдйхЕИцК╣цОЙф╕Кф╕кшБКхдйчЪДхПмхЫЮцоЛчХЩ(цЦ░шБКхдйф╕ЛцмбчФЯцИРхЖНщЗНчоЧ)
      setTimeout(() => refreshInjection(), 0);
    });
  }

  // цА╗х╝АхЕ│хИЗцНв:хЕ│щЧнтЖТц╕ЕцОЙх╖▓ц│ихЕечЪДшо░х┐Жцз╜(ф╕НхКих╖▓щЪРшЧПце╝х▒Вф╕Ох╖▓хнШцСШшжБ,чмжхРИуАМх╖▓цЬЙцХ░цНоф╕НхдДчРЖуАН);
  // х╝АхРптЖТцККх╜УхЙНшо░х┐ЖщЗНцЦ░ц│ихЕехЫЮф╕Кф╕ЛцЦЗуАВф╗ЕхУНх║ФхИЗцНв,ф╕НхЬищжЦх╕зшзжхПСуАВ
  watch(
    () => apiSettings.enabled,
    on => (on ? refreshInjection() : clearInjection()),
  );

  // шЗкхКицСШшжБх╝АхЕ│хИЗцНв:цЧ╢щЧ┤цаЗчн╛(щЪРшЧПцнгхИЩ + хЫ║хоЪцПРчд║шпН)щЪПхоГхРпхБЬ,ф╕НхЖНчЛмчлЛх╝АхЕ│уАВ
  watch(
    () => apiSettings.autoSummaryEnabled,
    () => {
      syncTimeTagRegex();
      refreshInjection();
    },
  );
}
