  /**
   * хПСщАБщвДхблхЕЕ(щ╗Шшодх╝А)уАВцСШшжБ/цЙ╣щЗПшп╖ц▒ВцЬлх░╛х╕жф╕АцЭб assistant щвДхблхЕЕц╢ИцБп,х╝Ххп╝цибхЮЛф╗ОцАЭч╗┤щУ╛ч╗нхЖЩуАБ
   * х╣╢хОЛхИ╢цЛТчнФуАВClaude чнЙхОЯчФЯцФпцМБщвДхблхЕЕчЪДхРОчлпцФ╢чЫКцШОцШ╛;шЛечлпчВ╣шжБц▒ВуАМцЬАхРОф╕АцЭбх┐Ещб╗цШп userуАН
   * цИЦф╕║ч║п OpenAI члпчВ╣(щвДхблхЕЕф╕Ншвлч╗нхЖЩуАБх╜вхРМц╡кш┤╣),хПпхЕ│цОЙтАФтАФхЕ│цОЙхПкцШпф╕НхПСщВгцЭбх░╛ assistant,
   * цАЭч╗┤щУ╛х╝Ххп╝ф╗НчФ▒ system цгАцЯец╕ЕхНХцЙ┐цЛЕ,ф╕Нх╜▒хУНхКЯшГ╜уАВ */
  prefill: boolean;
  /** цОТщЩдхПВцХ░:ш┐Щф║ЫхнЧцо╡хРНф╝ЪхЬицЮДщАашп╖ц▒Вф╜УцЧ╢ф╗О body ф╕нхИащЩд,
   *  чФиф║ОшзДщБ┐ф╕НцОехПЧцЯРф║ЫхПВцХ░(хжВ temperature/max_tokens)чЪДхЕ╝хо╣члпчВ╣цКещФЩуАВ */
  excludeParams: string[];
