export type TaskType = 'summary' | 'resummary';

/** шЗкхоЪф╣ЙцПРчд║шпН:чй║ф╕▓шбичд║ц▓┐чФи prompts.ts хЖЕч╜оцибцЭ┐,щЭЮчй║хИЩцХ┤ф╜УшжЖчЫЦшпеф╗╗хКбчЪДцибцЭ┐уАВ */
