/**
 * хПмхЫЮхПВцХ░уАВхПмхЫЮчобч║┐:
 *  тСа цЙАцЬЙхРСщЗПч┤вх╝ХхРДчоЧф╕Ацмб embedding чЫ╕ф╝╝х║ж,**ч║пцМЙх╛ЧхИЖцОТх║ПхПЦхЙН N(rerankCandidates)ш┐ЫхЕе rerank**тАФтАФ
 *     ш┐Щф╕Ацнеф╕НхеЧ embedding щШИхА╝,хУкцАХхЙН N хЕицШпф╜ОхИЖ(0.4/0.3тАж)ф╣ЯчЕзца╖ш┐ЫхАЩщАЙ;щШИхА╝хПкхЬи тСб чЪДцСШшжБцбгхЗЖхЕечФиуАВ
 *  тСб rerank цЙУхИЖхРОхИЖф╕дцбг:
 *     ┬╖ хЕицЦЗцбг = rerank х╛ЧхИЖ тЙе rerankThreshold,хПЦхЙН fullTextCount цЭб(хПСхОЯцЦЗхЕицЦЗ);
 *     ┬╖ цСШшжБцбг = rerank х╛ЧхИЖ < rerankThreshold ф╜Ж embedding х╛ЧхИЖ тЙе embeddingThreshold(хПСхП╢хнРцСШшжБ);
 *  тСв цЬАч╗ИхПмхЫЮцЭбцХ░ тЙд finalRecallCount(ф╕КщЩР):хЕИцФ╛хЕицЦЗцбг,ф╕Нш╢│хЖНчФицСШшжБцбгшбе,шбеф╕Нц╗бф╣ЯцЧахжиуАВ
 */
export interface VectorRecallSettings {
  /** ш┐ЫхЕе rerank чЪДхАЩщАЙцХ░:ч║пцМЙ embedding чЫ╕ф╝╝х║жхПЦ top-N(ф╕НхеЧщШИхА╝ш┐Зц╗д) */
  rerankCandidates: number;
  /** embedding чЫ╕ф╝╝х║жщШИхА╝:ф╗ЕчФиф║О тСб цСШшжБцбгхЗЖхЕещЧицзЫ(ф╜Оф║Оцндш┐ЮцСШшжБщГ╜ф╕НхПмхЫЮ);ф╕Нх╜▒хУН тСа хПЦхАЩщАЙ */
  embeddingThreshold: number;
  /** rerank х╛ЧхИЖщШИхА╝:тЙе ш┐ЫхЕицЦЗцбг,< щААцСШшжБцбг */
  rerankThreshold: number;
  /** хПмхЫЮхЕицЦЗцХ░:хЕицЦЗцбгхПЦхЙН N цЭб(хПСхОЯцЦЗ) */
  fullTextCount: number;
  /** цЬАч╗ИхПмхЫЮцЭбцХ░(ф╕КщЩР):хЕицЦЗцбг + цСШшжБцбгхРИшобф╕Нш╢Еш┐ЗхоГ */
  finalRecallCount: number;
}

/** хРСщЗПшо░х┐Жшо╛ч╜оуАВembedding ф╕║хЯ║хЗЖ,rerank/queryRewrite чЪД url чХЩчй║хИЩцХ┤ф╜УхдНчФи embeddingуАВ */
