  /** шЗкхКицСШшжБх╝АхЕ│уАВх╝АхРпхН│ф╕Ах╣╢хРпчФи:шЗкхКищЪРшЧПуАБцнгцЦЗцЧ╢щЧ┤цаЗчн╛уАБчзпхОЛцЛжцИк(ф╕НхЖНхРДшЗкчЛмчлЛх╝АхЕ│)уАВ */
  autoSummaryEnabled: boolean;
  /** ф┐ЭчХЩцЬАш┐С N цЭб AI ц╢ИцБпхПСхЕицЦЗ(ц╗СхКичкЧхПг);цЫ┤цЧйчЪДшЗкхКицСШшжБх╣╢щЪРшЧП */
  keepRecent: number;
  /** цОТщЩдчЪДшзТшЙ▓хРН:ш┐Щф║ЫхРНхнЧ(хРлщЗНхРНхНб)чЪДшБКхдйщЗМ,шо░х┐Жч│╗ч╗ЯцЙАцЬЙхКЯшГ╜щГ╜ф╕НчФЯцХИ */
  excludedChars: string[];
