  /** L1 хПКф╗еф╕КцпПчзпч┤пхИ░ N цЭбцЧ╢,хОЛцИРф╕Кф╕Ах▒ВцА╗ч╗У(LтЙе1тЖТL+1 щШИхА╝,0=хЕ│щЧн) */
  resummaryThreshold: number;
  /** цСШшжБ/цА╗ч╗Ухд▒ш┤е(шп╖ц▒ВцКещФЩцИЦ JSON шзгцЮРхд▒ш┤е)чЪДцЬАхдзщЗНшпХцмбцХ░уАВ0=ф╕НщЗНшпХ;щ╗Шшод 1(цЬАхдЪхЖНшпХф╕Ацмб)уАВ */
  summaryMaxRetries: number;
  /** цЙ╣щЗПшбецСШ:цпПцЙ╣цЬАхдзцнгцЦЗхнЧчмжцХ░(ц╕Ец┤ЧхРО)уАВцФТхдЯхН│хИЗхЭЧ,цОзхИ╢хНХцмбшп╖ц▒ВшзДциб(щШ▓ AI ц│ицДПхКЫц╢гцХг)уАВ */
  batchMaxChars: number;
  /** цЙ╣щЗПшбецСШ:цпПцЙ╣цЬАхдзце╝цХ░хЕЬх║ХуАВхН│ф╛┐хнЧчмжц▓бхИ░ф╕КщЩР,це╝цХ░хИ░цндф╣ЯхИЗхЭЧуАВ */
  batchMaxFloors: number;
  /**
   * чФицИ╖шЗкхоЪф╣ЙуАМцХ┤хЭЧхИащЩдуАНцаЗчн╛хРН(хПкхблцаЗчн╛хРН,ф╕Нх╕жх░ЦцЛмхП╖,хжВ snow)уАВц╕Ец┤ЧцнгцЦЗцЧ╢
   * `<snow>тАж</snow>` ш┐ЮхРМхЖЕщГихЖЕхо╣ф╕Ах╣╢хИацОЙуАВчФиф║ОхЙФщЩдхЕ╢хоГцПТф╗╢/ф╕ЦчХМф╣жхЖЩш┐ЫцнгцЦЗчЪДчК╢цАБцаПуАБ
   * цЧБц│ичнЙца╝х╝ПуАВцФ╣хКихп╣**хПмхЫЮцЧ╢**хН│цЧ╢чФЯцХИ(хРСщЗПх║УхнШчЪДцШпхОЯцЦЗ,хПмхЫЮхЖНц╕Ец┤Ч),цЧащЬАщЗНх╗║ч┤вх╝ХуАВ
   */
