// extension_settings щЗМчЪДхС╜хРНчй║щЧ┤щФо;localStorage цШпцЧзчЙИцоЛчХЩ,ф╗ЕчФиф║Оф╕АцмбцАзш┐Бчз╗уАВ
const SETTINGS_KEY = 'baibai_book';
const LEGACY_STORAGE_KEY = 'bbs.api.v1';
// цЧзчЙИчХМщЭвхБПхе╜(ф╕╗щвШ/хп╝шИкф╜Нч╜о/хИЖщб╡)цЫ╛хНХчЛмхнШш┐ЩщЗМ;чО░цККф╕╗щвШ+хп╝шИкш┐Бш┐Ы ui,хИЖщб╡ф╗НчХЩцЬмцЬ║(шзБ state/ui.ts)уАВ
const LEGACY_UI_STORAGE_KEY = 'bbs.ui.v1';

/** ф╗ОцЧз localStorage(bbs.ui.v1)хПЦхЗ║ф╕╗щвШ/хп╝шИкф╜Нч╜о,хблш┐Ы target.uiуАВф╗ЕхЬи server х░ЪцЧа ui цЧ╢ш░ГчФиф╕АцмбуАВ */
function migrateLegacyUiPrefs(target: ApiSettings): void {
  try {
    const raw = localStorage.getItem(LEGACY_UI_STORAGE_KEY);
    if (!raw) return;
    const obj = JSON.parse(raw) as Partial<UiPrefs>;
    if (typeof obj.theme === 'string') target.ui.theme = obj.theme;
    if (typeof obj.navPosition === 'string') target.ui.navPosition = obj.navPosition;
  } catch {
    /* шзгцЮРхд▒ш┤ехИЩч╗┤цМБщ╗Шшод,ф╕НщШ╗цЦн */
  }
}

