/**
 * хРСщЗПхПмхЫЮчЪДцЯешпвщЗНхЖЩ(Query Rewrite)уАВ
 *
 * хдНхИ╗ Horae чЪДуАМх░ПцибхЮЛцККх╜УхЙНхЙзцГЕщЗНхЖЩцИР INTENT + хдЪцЭбцгАч┤в QуАНцАЭш╖пф╕ОцПРчд║шпН(чФицИ╖х╖▓ф╝ШхМЦчЙИ),
 * ф╜Ж**ф╕Кф╕ЛцЦЗцЮДщАацШпцЯПхоЭф╣жшЗкх╖▒чЪД**(шзБ .carryover-plan.mdуАМцЯешпвщЗНхЖЩф╕Кф╕ЛцЦЗцЮДщАауАН):
 *  ч╗УцЮД = [хОЖхП▓хЙзцГЕцСШшжБ] + цЬАш┐СчкЧхПгхЕицЦЗ + [чК╢цАБх┐лчЕз] + [чФицИ╖ш╛УхЕе]
 *  - чК╢цАБф╕Ах╛Лш╡░ deriveMemory(ф╕НхБЗшо╛ getLatestState х╣▓хЗА);
 *  - чК╢цАБх┐лчЕзч▓╛чбоцФ╛ч╜о:ф╗ОчкЧхПгш╡╖чВ╣цЙлхИ░чммф╕Аф╕куАМцЧацЬЙцХИхП╢хнРуАНчЪДце╝хБЬф╕Л,
 *    х┐лчЕз = deriveMemory(chat, ц┤Юце╝index),цПТхЬиуАМш┐Юч╗нхП╢хнРхЙНч╝АцЬлх░╛уАНф╣ЛхРОуАБц┤Юце╝ф╣ЛхЙН;
 *  - х┐лчЕзхПкхРл**ц╗ЪхЗ║чкЧхПгчЪД items/plans**(цЧ╢щЧ┤/хЬ░чВ╣/хЬихЬ║х╖▓хЬихЕицЦЗщЗМ,ф╕НщЗНхдН)уАВ
 *
 * ф║зхЗ║хдЪцЭб query,хРДшЗк embed тЖТ хРОчлп vec/search хдЪш╖пцгАч┤в + RRF шЮНхРИ;INTENT хЕ╝ф╜Ь rerank чЪД queryуАВ
 * ф╗╗ф╜Ххд▒ш┤ещГ╜цКЫщФЩ,чФ▒хПмхЫЮф╛з catch хРОщЩНч║зф╕║уАМцЬАш┐Сф╕Кф╕ЛцЦЗх╜УхНХ queryуАНуАВ
 */

import type { STMessage } from '@/st/context';
import { getContext } from '@/st/context';
import { resolveVectorModel } from '@/api/settings';
import { deriveMemory, getLeaf, leafValid } from '../apply';
import { resolveKeepStart } from '../engine';
import { renderHistoryNodes, selectHistoryNodesBefore } from '../inject';
import { fmtItems, fmtNpcs, fmtPlans, QUERY_REWRITE_SYSTEM, QUERY_REWRITE_TAIL } from '../prompts';
import { memory } from '../store';
import { cleanBody } from '../timeTag';

/** rewrite цибхЮЛцЬАхдЪхПЦхЗацЭб query(хп╣щ╜Р Horae) */
const MAX_QUERIES = 6;
/** хНХцЭб query щЩРщХ┐ */
const MAX_QUERY_LEN = 220;

export interface RewriteResult {
  /** хЬ║цЩпцДПхЫ╛цППш┐░(хЕ╝ф╜Ь rerank чЪД query) */
  intent: string;
  /** хдЪцЭбцгАч┤в query(х╖▓хО╗щЗНщЩРщХ┐) */
  queries: string[];
}

interface ChatMsg {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

/** цККце╝х▒ВцнгцЦЗц╕Ец┤ЧцИРхПпшп╗цЦЗцЬм,ф╕ОхЦВцСШшжБцибхЮЛхРМхПгх╛Д(cleanBody:шгБцнгцЦЗцо╡ + цХ┤хЭЧхИахЩкхг░цаЗчн╛ + цЧ╢щЧ┤ш╜мцЦЗцЬм)уАВ */
function cleanFloor(m: STMessage): string {
  return cleanBody(m.mes);
}

/**
 * цЮДщАачК╢цАБх┐лчЕзцЦЗцЬм(хПкхРлц╗ЪхЗ║чкЧхПгуАБщХ┐цЬЯцЬЙцХИчЪД items/plans)уАВ
 * upTo = чммф╕Аф╕кцЧахП╢хнРце╝чЪДч┤вх╝Х(х┐лчЕзцИкхИ░хоГф╣ЛхЙН)уАВцЧацЬЙцДПф╣ЙхЖЕхо╣ш┐ФхЫЮчй║ф╕▓уАВ
 */
function buildStateSnapshot(chat: STMessage[], upTo: number): string {
  const st = deriveMemory(chat, upTo);
  const lines: string[] = [];
  if (st.items.length) {
    lines.push(`чЙйхУБц╕ЕхНХ:\n${fmtItems(st.items.map(i => ({ name: i.name, qty: i.qty, desc: i.desc, carried: i.carried, location: i.location })))}`);
  }
  if (st.npcs.length) {
    lines.push(`NPCхРНхЖМ:\n${fmtNpcs(st.npcs.map(n => ({ name: n.name, title: n.title, follow: n.follow, location: n.location })))}`);
  }
  const openPlans = st.plans.filter(p => p.status === 'open');
  if (openPlans.length) {
    lines.push(`цЬкф║Жч╗УчЪДшобхИТ/цВмх┐╡:\n${fmtPlans(openPlans.map(p => ({ kind: p.kind, content: p.content, createdTime: p.createdTime, targetTime: p.targetTime })))}`);
  }
  if (!lines.length) return '';
  return `[чК╢цАБх┐лчЕз:ф╗еф╕Лф╕║х╖▓ц╗ЪхЗ║цЬАш┐СчкЧхПгуАБф╜Жф╗НцЬЙцХИчЪДчЙйхУБуАБNPC ф╕ОцЬкф║Жч╗УшобхИТ,ф╛Ыф╜ашзгцЮРцибч│КцМЗф╗г]\n${lines.join('\n')}`;
}

/**
 * цЙ╛чК╢цАБх┐лчЕзчЪДцПТхЕечВ╣:ф╗ОчкЧхПгш╡╖чВ╣хРСхРОцЙл,ш┐ФхЫЮчммф╕Аф╕куАМцЧацЬЙцХИхП╢хнРуАНце╝чЪДч┤вх╝ХуАВ
 * хЕищГицЬЙхП╢хнРхИЩш┐ФхЫЮ chat.length(х┐лчЕзцИкхИ░хЕищГичкЧхПг,цФ╛цЬАцЬл)уАВ
 */
function findSnapshotCut(chat: STMessage[], windowStart: number): number {
  for (let i = windowStart; i < chat.length; i++) {
    if (!leafValid(chat[i])) return i;
  }
  return chat.length;
}

/**
 * цЮДщАахПСч╗Щ rewrite цибхЮЛчЪДц╢ИцБпх║ПхИЧуАВ
 *
 * тЪая╕П шо╕хдЪхРСщЗПц╕ащБУшжБц▒В system ц╢ИцБп**ф╗ЕхЕБшо╕хЗ║чО░хЬицХ░ч╗ДцЬАх╝Ахд┤**,ф╕нщЧ┤ф╕Нх╛ЧхЖНцЬЙ systemуАВ
 * цХЕхп╣щ╜Р Horae чЪДх╜вцАБ:**х╝Ахд┤хФпф╕Аф╕АцЭб system + ф╕нщЧ┤ч║п user/assistant хп╣шпЭ + ч╗Ух░╛ф╕АцЭб user**уАВ
 *  - хОЖхП▓хЙзцГЕцСШшжБх╣╢хЕех╝Ахд┤щВгцЭб system(х▒ЮшГМцЩпшо╛хоЪ,хРИц│ХхЬ░х╛ЕхЬих╝Ахд┤);
 *  - чК╢цАБх┐лчЕзф╕НчЛмчлЛцИР system,шАМцШп**цЛ╝ш┐Ыхп╣шпЭц╢ИцБпцнгцЦЗ**(цФ╛хЬи cut чВ╣хЙНф╕АцЭбф╣ЛхРОуАБц┤Юце╝ф╣ЛхЙН),
 *    ф┐ЭцМБф╕нщЧ┤цЧа system,ф╗ОшАМхЕ╝хо╣уАМsystem хПкшГ╜хЬих╝Ахд┤уАНчЪДц╕ащБУуАВ
 */
function buildMessages(chat: STMessage[]): ChatMsg[] {
  const windowStart = resolveKeepStart(chat);
  const cut = findSnapshotCut(chat, windowStart);

  // х╝Ахд┤хФпф╕А system:ч│╗ч╗ЯцПРчд║шпН +(хПпщАЙ)хОЖхП▓хЙзцГЕцСШшжБ,хРИх╣╢ф╕║ф╕АцЭб,ф┐ЭшпБ system хПкхЗ║чО░хЬих╝Ахд┤
  const history = renderHistoryNodes(selectHistoryNodesBefore(memory.summaries, chat, windowStart));
  const systemContent = history ? `${QUERY_REWRITE_SYSTEM}\n\n[хОЖхП▓хЙзцГЕцСШшжБ]\n${history}` : QUERY_REWRITE_SYSTEM;
  const messages: ChatMsg[] = [{ role: 'system', content: systemContent }];

  // х╣│щУ║чкЧхПгхп╣шпЭ(ч║п user/assistant),шо░х╜ХхОЯ msgIndex ф╗ехоЪф╜Нх┐лчЕзцПТхЕечВ╣
  const convo: Array<{ role: 'user' | 'assistant'; content: string; index: number }> = [];
  for (let i = windowStart; i < chat.length; i++) {
    const m = chat[i];
    if (!m) continue;
    if (m.is_system && m.extra?.type) continue; // хОЯчФЯч│╗ч╗Яце╝ш╖│ш┐З
    const text = cleanFloor(m);
    if (!text) continue;
    convo.push({ role: m.is_user ? 'user' : 'assistant', content: text, index: i });
  }

  // чК╢цАБх┐лчЕз:цЛ╝ш┐Ыхп╣шпЭц╢ИцБпцнгцЦЗ(ф╕НчЛмчлЛцИР system)уАВшпнф╣Й = цИкцнв cut(чммф╕Аф╕кцЧахП╢хнРце╝)ф╣ЛхЙНчЪДчбохЗ┐чК╢цАБуАВ
  const snapshot = buildStateSnapshot(chat, cut);
  if (snapshot) {
    if (!convo.length) {
      // чкЧхПгцЧахПпчФихп╣шпЭц╢ИцБп тЖТ хЕЬх║ХцФ╛ф╕АцЭб user цЙ┐ш╜╜(ф╗НщЭЮ system)
      messages.push({ role: 'user', content: snapshot });
    } else {
      const cutPos = convo.findIndex(c => c.index >= cut);
      if (cutPos === -1) {
        // cut хЬицЙАцЬЙхп╣шпЭф╣ЛхРО(чкЧхПгхЕицЬЙхП╢хнР)тЖТ цЛ╝ш┐ЫцЬАхРОф╕АцЭбцЬлх░╛
        const last = convo[convo.length - 1];
        last.content = `${last.content}\n\n${snapshot}`;
      } else if (cutPos === 0) {
        // cut чВ╣хН│щжЦцЭбхп╣шпЭ(ф╣ЛхЙНцЧахп╣шпЭхПпцЙ┐ш╜╜)тЖТ цЛ╝ш┐ЫхоГчЪДхЙНч╝А
        convo[0].content = `${snapshot}\n\n${convo[0].content}`;
      } else {
        // цЛ╝ш┐Ы cut чВ╣хЙНф╕АцЭбхп╣шпЭчЪДцЬлх░╛(ш┐Юч╗нхП╢хнРхЙНч╝АцЬлх░╛ф╣ЛхРОуАБц┤Юце╝ф╣ЛхЙН)
        const prev = convo[cutPos - 1];
        prev.content = `${prev.content}\n\n${snapshot}`;
      }
    }
  }

  for (const c of convo) messages.push({ role: c.role, content: c.content });

  // цФ╢х░╛цПРчд║шпН
  messages.push({ role: 'user', content: QUERY_REWRITE_TAIL });
  return messages;
}

/** base url шзДцХ┤хИ░ /chat/completions члпчВ╣ */
function chatCompletionsEndpoint(rawUrl: string): string {
  const base = String(rawUrl || '')
    .trim()
    .replace(/\/+$/, '')
    .replace(/\/embeddings$/i, '')
    .replace(/\/chat\/completions$/i, '');
  return base ? `${base}/chat/completions` : '';
}

/** шзгцЮР INTENT + хдЪшбМ Q(хп╣щ╜Р Horae:хО╗хЙНч╝АчмжхП╖уАБхО╗щЗНуАБщЩРщХ┐) */
function parseResponse(text: string): RewriteResult {
  const lines = String(text || '')
    .replace(/\r\n?/g, '\n')
    .replace(/\\n/g, '\n')
    // хПМф┐ЭщЩй:хН│ф╛┐шп╖ц▒ВхЕ│ф║Ж enable_thinking,ф╕кхИлцибхЮЛф╗Нф╝ЪхРР <think> хЭЧ,хЕИцХ┤цо╡хЙецОЙхЖНщАРшбМшзгцЮР,
    // хРжхИЩцАЭч╗┤щУ╛щЗМхЗ║чО░чЪД INTENT/Q хнЧца╖ф╝Ъц▒бцЯУшзгцЮРч╗УцЮЬуАВ
    .replace(/<think(?:ing)?\b[\s\S]*?<\/think(?:ing)?>/gi, '')
    .split('\n')
    .map(l => l.trim())
    .filter(Boolean);

  let intent = '';
  const queries: string[] = [];
  const seen = new Set<string>();

  for (const raw of lines) {
    // хО╗цОЙшбМщжЦчЪД -/*/тАвуАБцХ░хнЧч╝ЦхП╖
    const line = raw.replace(/^\s*(?:[-*тАв]\s*)?(?:\d+[.)уАБ]\s*)?/, '').trim();
    const im = line.match(/^INTENT\s*[:я╝Ъ]\s*(.+)$/i);
    if (im) {
      intent = sanitize(im[1]);
      continue;
    }
    const qm = line.match(/^Q\s*\d*\s*[:я╝Ъ]\s*(.+)$/i);
    if (qm) {
      const q = sanitize(qm[1]);
      if (!q) continue;
      const key = q.toLowerCase();
      if (seen.has(key)) continue;
      seen.add(key);
      queries.push(q);
      if (queries.length >= MAX_QUERIES) break;
    }
  }
  return { intent, queries };
}

function sanitize(text: string): string {
  return String(text || '')
    .trim()
    .replace(/^["'тАЬтАЭтАШтАЩ`]+|["'тАЬтАЭтАШтАЩ`]+$/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, MAX_QUERY_LEN);
}

/**
 * цЙзшбМцЯешпвщЗНхЖЩуАВqueryRewrite члпчВ╣цЬкщЕН model цЧ╢цКЫщФЩ(ш░ГчФицЦ╣щЩНч║з)уАВ
 * ш╡░хЙНчлпчЫ┤ш┐Ю chat/completions(ф╕О embed хРМц║РчнЦчХе,ц╕ащБУхЬ░хЭА/хпЖщТехПпчХЩчй║хдНчФи embedding)уАВ
 */
export async function rewriteQuery(signal?: AbortSignal): Promise<RewriteResult> {
  const ep = resolveVectorModel('queryRewrite');
  if (!ep.model) throw new Error('Query щЗНхЖЩцибхЮЛцЬкщЕНч╜о');
  const endpoint = chatCompletionsEndpoint(ep.url);
  if (!endpoint) throw new Error('Query щЗНхЖЩхЬ░хЭАцЬкщЕНч╜о');

  const ctx = getContext();
  const chat = ctx?.chat ?? [];
  if (!chat.length) throw new Error('цЧахп╣шпЭф╕Кф╕ЛцЦЗхПпщЗНхЖЩ');

  const messages = buildMessages(chat);

  let resp: Response;
  try {
    resp = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${ep.key || ''}` },
      body: JSON.stringify({
        model: ep.model,
        messages,
        // хп╣щ╜Р Horae:ф╜Оц╕йцЫ┤цЬНф╗Оца╝х╝П;enable_thinking:false хЕ│цАЭч╗┤щУ╛тАФтАФ
        // хЫ╜ф║зцибхЮЛ(Qwen3/GLM чнЙ)щ╗Шшодх╝АцАЭч╗┤щУ╛ф╝ЪхЕИхРР <think> цОичРЖ,хЖ▓ф╣▒ INTENT/Q шбМца╝х╝Пхп╝шЗ┤шзгцЮРхд▒ш┤еуАВ
        temperature: 0.1,
        top_p: 0.8,
        max_tokens: 8192,
        stream: false,
        enable_thinking: false,
      }),
      signal,
    });
  } catch (e) {
    throw new Error(`Query щЗНхЖЩч╜Сч╗Ьх╝Вх╕╕:${e instanceof Error ? e.message : String(e)}`);
  }
  if (!resp.ok) {
    const t = await resp.text().catch(() => '');
    throw new Error(`Query щЗНхЖЩ API ${resp.status}: ${t.slice(0, 200)}`);
  }
  const json = await resp.json();
  const content = json?.choices?.[0]?.message?.content;
  const raw = typeof content === 'string' ? content : '';
  if (!raw.trim()) throw new Error('Query щЗНхЖЩш┐ФхЫЮчй║хЖЕхо╣');

  const parsed = parseResponse(raw);
  if (!parsed.queries.length) throw new Error('Query щЗНхЖЩцЬкшзгцЮРхЗ║ф╗╗ф╜ХцгАч┤в query');
  return parsed;
}
