import { openBook } from '@/state/ui';

const MENU_ITEM_ID = 'bbs-menu-item';

/**
 * х╛А ST чЪД #extensionsMenu(щнФцЭЦшПЬхНХ)цЬлх░╛ц│ихЕе"цЯПхоЭф╣ж"хЕехПгуАВ
 * шПЬхНХцШпцЗТхКаш╜╜чЪД,чФиш╜ошпвчнЙхоГхЗ║чО░;ц│ихЕеф╕АцмбхН│хПпуАВ
 */
export function injectMenuButton() {
  const tryInject = () => {
    const $menu = $('#extensionsMenu');
    if ($menu.length === 0) return false;
    if ($(`#${MENU_ITEM_ID}`).length > 0) return true;

    const $item = $(`
      <div class="extension_container interactable" tabindex="0">
        <a id="${MENU_ITEM_ID}" class="list-group-item" href="#" title="цЯПхоЭф╣ж">
          <i class="fa-solid fa-book-bookmark"></i>
          <span>цЯПхоЭф╣ж</span>
        </a>
      </div>
    `);

    $item.on('click', (e: { preventDefault: () => void }) => {
      e.preventDefault();
      openBook();
      // чВ╣хЗ╗хРОцФ╢ш╡╖щнФцЭЦшПЬхНХ,ш┤┤хРИхОЯчФЯшбМф╕║
      $('#extensionsMenu').hide();
    });

    $menu.append($item);
    return true;
  };

  if (tryInject()) return;
  const timer = setInterval(() => {
    if (tryInject()) clearInterval(timer);
  }, 500);
}
