/**
 * хРСщЗПхПмхЫЮш░ГшпХх┐лчЕз(хЕих▒А,reactive)уАВ
 *
 * хПкф╕║уАМшо╛ч╜о тЖТ хРСщЗПшо░х┐Ж тЖТ ф╕КцмбхПмхЫЮшпжцГЕуАНщЭвцЭ┐цЬНхКб:цККф╕Кф╕АцмбхПмхЫЮхРДщШ╢цо╡чЪДф╕нщЧ┤ч╗УцЮЬ
 * чХЩф╕Аф╗╜хЬихЖЕхнШщЗМф╛Ы UI шовщШЕуАВч║пш░ГшпХшзВц╡Л,ф╕НхПВф╕ОхПмхЫЮщА╗ш╛С,хд▒ш┤е/щЩНч║зф╣ЯчЕзца╖шо░х╜Х(хЖЩцШО status)уАВ
 * хЕих▒АхНХф╛Л(щЭЮцМЙшБКхдй):хПкхЕ│х┐ГуАМцЬАш┐Сф╕АцмбуАН,хИЗшБКхдйхРОф╕Лф╕АцмбхПмхЫЮшЗкчД╢шжЖчЫЦуАВ
 */

import { reactive } from 'vue';

/** Embedding цгАч┤вхС╜ф╕н(хРОчлп max шЮНхРИхРО) */
export interface RecallDebugEmbedHit {
  leafId: string;
  similarity: number;
  /** цЭец║Р Q ф╕ЛцаЗ(хРОчлпхЫЮф╝а);-1 = цЬкчЯе(цЧзхРОчлпцЬкхЫЮф╝а) */
  queryIndex: number;
  /** цЭец║РцаЗшо░:цЬмшБКхдйхС╜ф╕нф╕║це╝х▒ВхП╖уАМ#5уАН,bundle х┐лчЕзф╕║уАМцЧзцбгуАН */
  source: string;
  storyTime: string;
  preview: string;
}

/** Rerank хАЩщАЙхПКхЕ╢хИЖцбгч╗УцЮЬ */
export interface RecallDebugRerankHit {
  leafId: string;
  rerankScore: number;
  similarity: number;
  /** хИЖцбг:full=хПСхЕицЦЗ,brief=хПСцСШшжБ,drop=ф╕дцбгщГ╜ф╕Нш╛╛цаЗшвлф╕вх╝Г */
  tier: 'full' | 'brief' | 'drop';
  /** цЭец║РцаЗшо░:цЬмшБКхдйхС╜ф╕нф╕║це╝х▒ВхП╖уАМ#5уАН,bundle х┐лчЕзф╕║уАМцЧзцбгуАН */
  source: string;
  storyTime: string;
  preview: string;
}

export interface RecallDebug {
  /** шо░х╜ХцЧ╢хИ╗(Date.now);0 = х░ЪцЧашо░х╜Х */
  at: number;
  /** чК╢цАБцЦЗцбИ:'хПмхЫЮхоМцИР' | 'ш┐ЫшбМф╕нтАж' | 'цЬкхПмхЫЮ:тАж' | 'хд▒ш┤е:тАж' */
  status: string;
  /** цЯешпвщЗНхЖЩчЪДхЬ║цЩпцДПхЫ╛(хЕ╝ф╜Ь rerank query) */
  intent: string;
  /** цЯешпвщЗНхЖЩф║зхЗ║чЪДхдЪцЭбцгАч┤в query */
  queries: string[];
  embedding: RecallDebugEmbedHit[];
  rerank: RecallDebugRerankHit[];
  /** цЬАч╗Иц│ихЕеф╕╗хп╣шпЭчЪДцЦЗцЬм(чй║ = цЬмхЫЮхРИцЬкц│ихЕе) */
  injectedText: string;
}

function empty(): RecallDebug {
  return { at: 0, status: '', intent: '', queries: [], embedding: [], rerank: [], injectedText: '' };
}

/** хЕих▒АхПмхЫЮш░ГшпХх┐лчЕзуАВUI чЫ┤цОешовщШЕ;recall.ts хЬихРДщШ╢цо╡хЖЩхЕеуАВ */
export const recallDebug = reactive<RecallDebug>(empty());

/** цСШшжБщвДшзИ:хПЦцСШшжБцЦЗцЬмцИкцЦн,ф╛ЫщЭвцЭ┐хНХшбМх▒Хчд║(хО╗цНвшбМ,щЩРщХ┐)уАВ */
export function previewOf(text: string | null | undefined, max = 80): string {
  const s = String(text ?? '').replace(/\s+/g, ' ').trim();
  return s.length > max ? `${s.slice(0, max)}тАж` : s;
}

/** х╝Аф╕АцмбцЦ░хПмхЫЮ:ц╕Ечй║хРДщШ╢цо╡уАБч╜оуАМш┐ЫшбМф╕нуАНуАВхЬи runVectorRecall ш┐ЫхЕецЬЙцХИш╖пх╛ДхРОш░ГчФиуАВ */
export function resetRecallDebug(): void {
  Object.assign(recallDebug, empty(), { at: Date.now(), status: 'ш┐ЫшбМф╕нтАж' });
}

/** ф╗ЕцЫ┤цЦ░чК╢цАБцЦЗцбИ(хРДцЧйщААш╖пх╛ДхЖЩцШОхОЯхЫа,хжВуАМцЬкхПмхЫЮ:Query щЗНхЖЩцЬкщЕНч╜оуАН)уАВ */
export function setRecallStatus(status: string): void {
  recallDebug.status = status;
  if (!recallDebug.at) recallDebug.at = Date.now();
}

export function setRecallRewrite(intent: string, queries: string[]): void {
  recallDebug.intent = intent;
  recallDebug.queries = [...queries];
}

export function setRecallEmbedding(hits: RecallDebugEmbedHit[]): void {
  recallDebug.embedding = hits;
}

export function setRecallRerank(hits: RecallDebugRerankHit[]): void {
  recallDebug.rerank = hits;
}

export function setRecallInjected(text: string): void {
  recallDebug.injectedText = text;
}

/** х┐лчЕзх╜УхЙНш░ГшпХч╗УцЮЬ(ц╖▒цЛ╖ш┤Э),ф╛ЫхПмхЫЮч╝УхнШчХЩхнШ,хС╜ф╕нцЧ╢хЖН restore хЫЮщЭвцЭ┐уАВ */
export function snapshotRecallDebug(): RecallDebug {
  return JSON.parse(JSON.stringify(recallDebug));
}

/** цККч╝УхнШчЪДш░ГшпХх┐лчЕзш┐ШхОЯхИ░щЭвцЭ┐(хС╜ф╕нч╝УхнШцЧ╢чФи,хЕНх╛Ч reset хРОщЭвцЭ┐чй║чЩ╜)уАВ */
export function restoreRecallDebug(snap: RecallDebug): void {
  Object.assign(recallDebug, snap);
}
