/**
 * хРСщЗПхМЦ / щЗНцОТчЪДхЙНчлпш░ГчФих▒ВуАВ
 *
 * embedding ф╕О rerank чЫ┤цОехЙНчлп fetch ф╕Кц╕╕(ц╕ащБУ url/key чФицИ╖шЗкхбл,ф╕ОхЙп API ц╕ащБУчЛмчлЛ)уАВ
 * ш╡░хЙНчлпшАМщЭЮ ST цЬНхКбчлпф╗гчРЖ:ST чЪД /api/vector члпчВ╣ч╗СхоЪхоГшЗкх╖▒чЪД source щЕНч╜о,цЧац│ХчФицИСф╗м
 * чЛмчлЛщЕНч╜очЪДхРСщЗПц╕ащБУ;Horae хРМца╖хЙНчлпчЫ┤ш┐Ю,х╖▓щкМшпБхПпшбМ(ф╗гф╗╖цШпф╕Кц╕╕щЬАхЕБшо╕ш╖ихЯЯ)уАВ
 *
 * хЕ╝хо╣ф╕дчзН embedding члпчВ╣:OpenAI /embeddings ф╕О Gemini batchEmbedContents(хАЯщЙ┤ Horae)уАВ
 * хРСщЗПхЬихЙНхРОчлпф╣ЛщЧ┤чФи base64(float32 х░Пчлп)ф╝аш╛УуАВ
 */

import type { VectorEndpoint } from '@/api/settings';
import { resolveVectorModel } from '@/api/settings';

export class EmbedError extends Error {}

/* ============ float32 тЖФ base64 ============ */

/** Float32Array(цИЦ number[]) тЖТ base64(х░ПчлпхнЧшКВх║П),чФиф║Оф╕Кф╝ахРОчлпхнШ BLOB */
export function encodeFloat32Base64(vec: number[] | Float32Array): string {
  const f32 = vec instanceof Float32Array ? vec : Float32Array.from(vec);
  const bytes = new Uint8Array(f32.buffer, f32.byteOffset, f32.byteLength);
  let bin = '';
  // хИЖхЭЧцЛ╝,щБ┐хЕНш╢ЕщХ┐ apply чИЖцаИ
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    bin += String.fromCharCode(...bytes.subarray(i, i + CHUNK));
  }
  return btoa(bin);
}

/** base64(х░Пчлп float32) тЖТ Float32Array */
export function decodeFloat32Base64(b64: string): Float32Array {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new Float32Array(bytes.buffer);
}

/* ============ endpoint щАВщЕН ============ */

function isGeminiEndpoint(url: string, model: string): boolean {
  return /gemini|googleapis|generativelanguage|v1beta/i.test(`${url} ${model}`);
}

function isGoogleUrl(url: string): boolean {
  return /googleapis\.com|generativelanguage/i.test(url || '');
}

/** хО╗цОЙ url х░╛щГичЪД /chat/completionsуАБ/embeddingsуАБ/v1 чнЙ,х╛ЧхИ░ base */
function embeddingBase(url: string): string {
  return String(url || '')
    .replace(/\/+$/, '')
    .replace(/\/chat\/completions$/i, '')
    .replace(/\/embeddings$/i, '');
}

interface EmbeddingRequest {
  endpoint: string;
  headers: Record<string, string>;
  body: string;
  parse: (json: any) => number[][];
}

function buildEmbeddingRequest(ep: VectorEndpoint, model: string, texts: string[]): EmbeddingRequest {
  const url = ep.url;
  const key = ep.key || '';

  if (!isGeminiEndpoint(url, model)) {
    const base = embeddingBase(url);
    return {
      endpoint: `${base}/embeddings`,
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${key}` },
      body: JSON.stringify({ model, input: texts }),
      parse: (json) => {
        if (!json?.data || !Array.isArray(json.data)) throw new EmbedError('embedding ш┐ФхЫЮч╝║х░С data цХ░ч╗Д');
        return json.data.slice().sort((a: any, b: any) => a.index - b.index).map((d: any) => d.embedding);
      },
    };
  }

  // Gemini batchEmbedContents
  const base = embeddingBase(url).replace(/\/v\d+(beta\d*|alpha\d*)?(?:\/.*)?$/i, '');
  const modelName = model.startsWith('models/') ? model : `models/${model}`;
  const google = isGoogleUrl(base);
  const endpoint = `${base}/v1beta/${modelName}:batchEmbedContents${google ? `?key=${encodeURIComponent(key)}` : ''}`;
  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
  if (!google) headers.Authorization = `Bearer ${key}`;
  return {
    endpoint,
    headers,
    body: JSON.stringify({ requests: texts.map((text) => ({ model: modelName, content: { parts: [{ text }] } })) }),
    parse: (json) => {
      if (!json?.embeddings || !Array.isArray(json.embeddings)) throw new EmbedError('Gemini embedding ш┐ФхЫЮч╝║х░С embeddings цХ░ч╗Д');
      return json.embeddings.map((e: any) => e.values);
    },
  };
}

/* ============ хп╣хдЦ:embed / rerank ============ */

/** хНХцмб embedding шп╖ц▒ВцЬАхдЪхбЮхЗацЭбцЦЗцЬм(хдЪцХ░ф╕Кц╕╕ batch ф╕КщЩР тЙд64,хПЦф┐ЭхоИхА╝хИЖцЙ╣)уАВ */
const EMBED_BATCH = 64;

/** хПСф╕АцЙ╣(тЙдEMBED_BATCH)цЦЗцЬмчЪД embedding шп╖ц▒В,ш┐ФхЫЮхРСщЗПцХ░ч╗Д(щб║х║Пхп╣х║Ф)уАВ */
async function embedBatch(ep: VectorEndpoint, model: string, texts: string[], signal?: AbortSignal): Promise<Float32Array[]> {
  const req = buildEmbeddingRequest(ep, model, texts);
  let resp: Response;
  try {
    resp = await fetch(req.endpoint, { method: 'POST', headers: req.headers, body: req.body, signal });
  } catch (e) {
    throw new EmbedError(`embedding ч╜Сч╗Ьх╝Вх╕╕:${e instanceof Error ? e.message : String(e)}`);
  }
  if (!resp.ok) {
    const t = await resp.text().catch(() => '');
    throw new EmbedError(`embedding API ${resp.status}: ${t.slice(0, 200)}`);
  }
  const json = await resp.json();
  const vectors = req.parse(json);
  if (!Array.isArray(vectors) || vectors.some((v) => !Array.isArray(v))) {
    throw new EmbedError('embedding ш┐ФхЫЮчЪДхРСщЗПцХ░цНоцЧацХИ');
  }
  return vectors.map((v) => Float32Array.from(v));
}

/**
 * хРСщЗПхМЦф╕АцЙ╣цЦЗцЬм,ш┐ФхЫЮ Float32Array[](щб║х║Пф╕Ош╛УхЕехп╣х║Ф)уАВц╕ащБУцЬкщЕНщ╜РхИЩцКЫщФЩуАВ
 * ш╢Еш┐З EMBED_BATCH цЭбшЗкхКихИЗчЙЗхИЖцЙ╣ф╕▓шбМшп╖ц▒В(ф╕Кц╕╕хНХцмб batch цЬЙф╕КщЩР,шбех╗║хЗачЩ╛цЭбцЧ╢х┐Еш╡░хдЪцЙ╣)уАВ
 */
export async function embedTexts(texts: string[], signal?: AbortSignal): Promise<Float32Array[]> {
  if (!texts.length) return [];
  const ep = resolveVectorModel('embedding');
  if (!ep.url) throw new EmbedError('хРСщЗПшо░х┐Ж:Embedding хЬ░хЭАцЬкщЕНч╜о');
  if (!ep.model) throw new EmbedError('хРСщЗПшо░х┐Ж:Embedding цибхЮЛцЬкщЕНч╜о');

  if (texts.length <= EMBED_BATCH) return embedBatch(ep, ep.model, texts, signal);

  const out: Float32Array[] = [];
  for (let i = 0; i < texts.length; i += EMBED_BATCH) {
    const part = await embedBatch(ep, ep.model, texts.slice(i, i + EMBED_BATCH), signal);
    out.push(...part);
  }
  return out;
}

/** хРСщЗПхМЦхНХцЭбцЦЗцЬм тЖТ base64,ч┤вх╝Х/цгАч┤вцЧ╢чФиуАВ */
export async function embedToBase64(text: string, signal?: AbortSignal): Promise<string> {
  const [v] = await embedTexts([text], signal);
  if (!v) throw new EmbedError('embedding ш┐ФхЫЮф╕║чй║');
  return encodeFloat32Base64(v);
}

export interface RerankResult {
  index: number;
  score: number;
}

/* ============ rerank token ф╝░чоЧ / хИЖцЙ╣(хАЯщЙ┤ Horae,хЕицЦЗч▓╛цОТцЧ╢хНХшп╖ц▒Вф╝Ъш╢Еф╕Кц╕╕ф╕Кф╕ЛцЦЗ) ============ */

/** rerank ф╕Кц╕╕хНХшп╖ц▒ВчЪДф╕Кф╕ЛцЦЗф╕КщЩР(token);хдЪцХ░ rerank цибхЮЛ 32k ш╡╖,хПЦф┐ЭхоИхА╝уАВ */
const RERANK_CONTEXT_LIMIT = 32768;
const RERANK_SAFE_RATIO = 0.68; // ф╗ЕчФищвДчоЧчЪД 68%,ч╗Щ prompt цибцЭ┐/хУНх║ФчХЩф╜ЩщЗП
const RERANK_STATIC_RESERVE = 1800; // хЫ║хоЪф┐ЭчХЩ(цибхЮЛцбЖцЮ╢х╝АщФА)
const RERANK_PER_DOC_OVERHEAD = 24; // цпПцЭбцЦЗцбгчЪДхИЖщЪФ/хМЕшг╣х╝АщФА

/** ч▓Чф╝░цЦЗцЬм token:CJK тЙИ1.35уАБхЕ╢хоГ тЙИ0.45,хЖНхКахоЙхЕич│╗цХ░(хп╣щ╜Р Horae,хоБхПпщлШф╝░)уАВ */
function estimateRerankTokens(text: string): number {
  if (!text) return 0;
  const str = String(text);
  let cjk = 0;
  for (const ch of str) {
    const cp = ch.codePointAt(0)!;
    if (
      (cp >= 0x3400 && cp <= 0x4dbf) || (cp >= 0x4e00 && cp <= 0x9fff) ||
      (cp >= 0xf900 && cp <= 0xfaff) || (cp >= 0x3040 && cp <= 0x30ff) ||
      (cp >= 0xac00 && cp <= 0xd7af)
    ) cjk++;
  }
  const other = Math.max(0, str.length - cjk);
  return Math.ceil((cjk * 1.35 + other * 0.45 + 8) * 1.18);
}

/** ф║МхИЖцИкцЦнхИ░ token ф╕КщЩРхЖЕ(ф┐ЭчХЩхЙНч╝А)уАВ */
function truncateByTokens(text: string, tokenLimit: number): string {
  if (!text || tokenLimit <= 0) return '';
  if (estimateRerankTokens(text) <= tokenLimit) return text;
  let lo = 0, hi = text.length, best = 0;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (estimateRerankTokens(text.slice(0, mid)) <= tokenLimit) { best = mid; lo = mid + 1; }
    else hi = mid - 1;
  }
  return text.slice(0, best).trimEnd();
}

/** rerank хИЖцЙ╣х╣╢хПСф╕КщЩР(цЙ╣цмбхЖНхдЪф╣ЯхПкхРМцЧ╢цЙУш┐Щф╣ИхдЪшп╖ц▒В)уАВ */
const RERANK_BATCH_CONCURRENCY = 4;

interface RerankBatch {
  indices: number[]; // шпецЙ╣цпПцЭбцЦЗцбгчЪДхЕих▒Аф╕ЛцаЗ
  documents: string[];
}

/** цМЙ token щвДчоЧцККцЦЗцбгхИЗцИРхдЪцЙ╣,ш╢ЕщХ┐хНХцЭбхЕИцИкцЦнуАВ */
function buildRerankBatches(query: string, documents: string[]): RerankBatch[] {
  const queryTokens = estimateRerankTokens(query);
  const docBudget = Math.max(1024, Math.floor(RERANK_CONTEXT_LIMIT * RERANK_SAFE_RATIO) - RERANK_STATIC_RESERVE - queryTokens);
  const maxSingleDocTokens = Math.max(768, docBudget - 256);

  const batches: RerankBatch[] = [];
  let curIdx: number[] = [], curDocs: string[] = [], curTokens = 0;
  const flush = () => {
    if (!curIdx.length) return;
    batches.push({ indices: curIdx, documents: curDocs });
    curIdx = []; curDocs = []; curTokens = 0;
  };

  for (let i = 0; i < documents.length; i++) {
    let text = documents[i] ?? '';
    let est = estimateRerankTokens(text) + RERANK_PER_DOC_OVERHEAD;
    if (est > maxSingleDocTokens) {
      text = truncateByTokens(text, Math.max(512, maxSingleDocTokens - RERANK_PER_DOC_OVERHEAD));
      est = estimateRerankTokens(text) + RERANK_PER_DOC_OVERHEAD;
    }
    if (curIdx.length && curTokens + est > docBudget) flush();
    curIdx.push(i);
    curDocs.push(text);
    curTokens += est;
  }
  flush();
  return batches;
}

/** хНХцЙ╣ rerank шп╖ц▒В,ш┐ФхЫЮшпецЙ╣хЖЕ {index(х▒АщГи), score}уАВ */
async function rerankBatch(
  endpoint: string, model: string, key: string, query: string, documents: string[], signal?: AbortSignal,
): Promise<RerankResult[]> {
  let resp: Response;
  try {
    resp = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${key}` },
      body: JSON.stringify({ model, query, documents, top_n: documents.length }),
      signal,
    });
  } catch (e) {
    throw new EmbedError(`rerank ч╜Сч╗Ьх╝Вх╕╕:${e instanceof Error ? e.message : String(e)}`);
  }
  if (!resp.ok) {
    const t = await resp.text().catch(() => '');
    throw new EmbedError(`rerank API ${resp.status}: ${t.slice(0, 200)}`);
  }
  const json = await resp.json();
  const results = json?.results ?? json?.data;
  if (!Array.isArray(results)) throw new EmbedError('rerank ш┐ФхЫЮч╝║х░С results цХ░ч╗Д');
  return results.map((r: any) => ({ index: r.index, score: r.relevance_score ?? r.score ?? 0 }));
}

/**
 * щЗНцОТ:цККхАЩщАЙцЦЗцбг(хЕицЦЗч▓╛цОТцЧ╢хН│це╝х▒ВхОЯцЦЗ)цМЙф╕О query чЪДчЫ╕хЕ│х║жцЙУхИЖуАВ
 * ш┐ФхЫЮцМЙ score щЩНх║ПчЪД {index, score}(index = ш╛УхЕе documents чЪДхЕих▒Аф╕ЛцаЗ)уАВ
 * цЦЗцбгцА╗щЗПш╢Е rerank ф╕Кф╕ЛцЦЗщвДчоЧцЧ╢шЗкхКицМЙ token хИЖцЙ╣уАБш╢ЕщХ┐хНХцЭбцИкцЦн,хРДцЙ╣ч╗УцЮЬцМЙхЕих▒Аф╕ЛцаЗхРИх╣╢уАВ
 * rerank ц╕ащБУцЬкщЕНщ╜РцЧ╢цКЫщФЩ(чФ▒ш░ГчФицЦ╣хЖ│хоЪщЩНч║з:ш╖│ш┐З rerankуАБчЫ┤цОечФи embedding х║П)уАВ
 */
export async function rerankDocuments(
  query: string,
  documents: string[],
  _topN: number,
  signal?: AbortSignal,
): Promise<RerankResult[]> {
  if (!documents.length) return [];
  const ep = resolveVectorModel('rerank');
  if (!ep.url) throw new EmbedError('хРСщЗПшо░х┐Ж:Rerank хЬ░хЭАцЬкщЕНч╜о');
  if (!ep.model) throw new EmbedError('хРСщЗПшо░х┐Ж:Rerank цибхЮЛцЬкщЕНч╜о');

  const endpoint = `${embeddingBase(ep.url)}/rerank`;
  const batches = buildRerankBatches(query, documents);
  const key = ep.key || '';
  const model = ep.model;

  // worker ц▒ах╣╢хПС:цЙ╣цмбхЖНхдЪф╣ЯхПкхРМцЧ╢цЙУ RERANK_BATCH_CONCURRENCY ф╕кшп╖ц▒В,хРДцЙ╣ч╗УцЮЬцМЙхЕих▒Аф╕ЛцаЗхРИх╣╢уАВ
  const merged: RerankResult[] = [];
  let next = 0;
  const worker = async () => {
    while (true) {
      const bi = next++;
      if (bi >= batches.length) break;
      const batch = batches[bi];
      const local = await rerankBatch(endpoint, model, key, query, batch.documents, signal);
      for (const r of local) {
        const globalIndex = batch.indices[r.index];
        if (globalIndex === undefined) continue;
        merged.push({ index: globalIndex, score: r.score });
      }
    }
  };
  const poolSize = Math.min(RERANK_BATCH_CONCURRENCY, batches.length);
  await Promise.all(Array.from({ length: poolSize }, () => worker()));

  return merged.sort((a, b) => b.score - a.score);
}
