/**
 * х╕жцХ░цНохИЫх╗║цЦ░хп╣шпЭ(Carryover)уАВ
 *
 * цККх╜УхЙНшБКхдй(ф╕АхаЖхОЖхП▓це╝х▒В + цЬАш┐СхЕицЦЗчкЧхПг)тЖТ цЦ░х╗║ф╕Аф╕кхп╣шпЭ,х╕жш┐ЗхО╗:
 *  - хРИх╣╢хОЖхП▓цСШшжБ(чкЧхПгф╣ЛхЙНчЪДхЙзцГЕ,щАЙцЬАщлШхнШц┤╗хОЛч╝йх▒ВцЛ╝цОе)= чзНхнРхП╢хнРчЪД text;
 *  - х╜УхЙНч╗УцЮДхМЦчК╢цАБ(цИкцнвчкЧхПгш╡╖чВ╣чЪД items/plans)тЖТ ч╝ЦчаБцИРуАМхЕищЗП addуАНdelta = чзНхнРхП╢хнРчЪД delta;
 *  - цЬАш┐Сф┐ЭчХЩчкЧхПгчЪДце╝х▒В(хОЯца╖хЕицЦЗ + хРДшЗкхП╢хнР)цРмш┐ЗхО╗уАВ
 *
 * цЦ░хп╣шпЭщЭачО░цИРщЗНцФ╛чобч║┐(deriveMemory:чй║чЩ╜ш╡╖цнещАРхП╢хнР fold)ш┐ШхОЯчК╢цАБтАФтАФцЧащЬАчЙ╣цоКш╜╜ф╜У,
 * хПкшжБщАаф╕АчЙЗцККчК╢цАБч╝ЦчаБцИРхЕищЗП add чЪДуАМчзНхнРхП╢хнРуАНцМВхЬи #0,х╣╢хПжч╜оф╕АцЭб L2 цА╗ч╗УцФ╢ч║│хоГ(цЙ┐ш╜╜хРИх╣╢цСШшжБцЦЗцЬм)уАВ
 *
 * хРМцЧ╢(шЛехРСщЗПшо░х┐Жх╝А):цККц║РшБКхдйчЪДхРСщЗПх┐лчЕзцИРф╕Аф╕к bundle,хУИх╕МхЖЩш┐ЫцЦ░шБКхдй metadata.bbs_bundles(ч┤пхКа),
 * ф╜┐цЦ░хп╣шпЭшГ╜хРСщЗПхПмхЫЮц║РшБКхдйчЪДцЧзхЙзцГЕуАВ
 */

import { getContext, getDoNewChat, type STMessage } from '@/st/context';
import { toast } from '@/st/toast';
import { apiSettings } from '@/api/settings';
import { deriveMemory, makeLeafId } from './apply';
import { resolveKeepStart } from './engine';
import { refreshInjection, renderHistoryNodes, selectHistoryNodesBefore } from './inject';
import { latestStoryTime } from './timeTag';
import { memory, recomputeDerived, saveMemory, flushLeavesNow } from './store';
import type { LeafExtra, MemSummary, StoredDelta } from './types';
import { isBaiBaoKuAvailable, vecBundleCreate } from '@/api/baibaoku';
import { appendBundleHash, BUNDLES_META_KEY, currentBundleHashes, currentVectorDb } from './vector/scope';

/** цР║х╕жшобхИТ:ф╛Ы UI щвДшзИуАМх░ЖцР║х╕жхдЪх░СуАНуАВ */
export interface CarryoverPlan {
  /** ф┐ЭчХЩчкЧхПгш╡╖чВ╣(цндч┤вх╝Хш╡╖чЪДце╝х▒ВцРмхО╗цЦ░хп╣шпЭ) */
  carryStart: number;
  /** хоЮщЩЕшжБцРмчЪДц╢ИцБпцЭбцХ░(чкЧхПгхЖЕщЭЮч│╗ч╗Яце╝) */
  carryCount: number;
  /** хЕ╢ф╕н AI це╝цЭбцХ░ */
  aiCount: number;
  /** хРИх╣╢хОЖхП▓цСШшжБхнЧчмжцХ░(0 = цЧахОЖхП▓хПпцСШ) */
  recapLen: number;
  /** х╜УхЙНцШпхРжцЬЙхПпцР║х╕жцХ░цНо */
  hasData: boolean;
}

/** цККуАМцИкцнвчкЧхПгш╡╖чВ╣чЪДц┤╛чФЯчК╢цАБуАНч╝ЦчаБцИРхЕищЗП add чЪД StoredDelta(чзНхнРхП╢хнРчЪД delta)уАВ */
function encodeStateAsDelta(state: ReturnType<typeof deriveMemory>): StoredDelta {
  const delta: StoredDelta = {};
  if (state.state.time) delta.time = state.state.time;
  if (state.state.location) {
    delta.location = state.state.location;
    if (state.state.locationPath?.length) delta.locationPath = state.state.locationPath;
  }

  if (state.items.length) {
    delta.items = {
      add: state.items.map(i => ({
        name: i.name,
        qty: i.qty,
        desc: i.desc,
        carried: i.carried,
        location: i.location,
      })),
    };
  }
  if (state.npcs.length) {
    delta.npcs = {
      add: state.npcs.map(n => ({
        name: n.name,
        title: n.title,
        desc: n.desc,
        personality: n.personality,
        outfit: n.outfit,
        condition: n.condition,
        important: n.important,
        follow: n.follow,
        location: n.location,
      })),
    };
  }
  const openPlans = state.plans.filter(p => p.status === 'open');
  if (openPlans.length) {
    delta.plans = {
      add: openPlans.map(p => ({
        kind: p.kind,
        content: p.content,
        createdTime: p.createdTime,
        targetTime: p.targetTime,
      })),
    };
  }
  return delta;
}

/** ц╖▒цЛ╖ш┤Эф╕АцЭбшжБцРмш┐РчЪДц╢ИцБп,хПЦц╢ИщЪРшЧПуАБф┐ЭчХЩхП╢хнРуАВ */
function sanitizeCarryMessage(m: STMessage): STMessage {
  const clone: STMessage = JSON.parse(JSON.stringify(m));
  clone.is_system = false;
  if (clone.extra && 'bbs_hidden' in clone.extra) {
    const { bbs_hidden: _h, ...rest } = clone.extra;
    clone.extra = rest;
  }
  return clone;
}

/** шобчоЧцР║х╕жшобхИТ(ф╕Нф║зчФЯхЙпф╜ЬчФи),ф╛Ы UI щвДшзИуАВ */
export function computeCarryoverPlan(): CarryoverPlan {
  const ctx = getContext();
  const chat = ctx?.chat ?? [];
  const carryStart = resolveKeepStart(chat);

  let carryCount = 0;
  let aiCount = 0;
  for (let i = carryStart; i < chat.length; i++) {
    const m = chat[i];
    if (!m) continue;
    // ST хОЯчФЯч│╗ч╗Яце╝(х╕ж type)ф╕НцРм;чЬЯхоЮце╝(хРлшвлщЪРшЧПчЪД)цРм
    if (m.is_system && m.extra?.type) continue;
    carryCount++;
    if (!m.is_user) aiCount++;
  }

  const recap = renderHistoryNodes(selectHistoryNodesBefore(memory.summaries, chat, carryStart));
  return {
    carryStart,
    carryCount,
    aiCount,
    recapLen: recap.length,
    hasData: chat.length > 0 && (carryCount > 0 || recap.length > 0 || memory.items.length > 0 || memory.npcs.length > 0 || memory.plans.length > 0),
  };
}

/**
 * цЙзшбМх╕жцХ░цНохИЫх╗║цЦ░хп╣шпЭуАВш┐ФхЫЮцШпхРжцИРхКЯуАВ
 * хЕичиЛ try/catch:хд▒ш┤е toast х╣╢х░╜щЗПф╕Нча┤хЭПх╜УхЙНшБКхдй(doNewChat хЙНхПкшп╗ф╕НхЖЩц║Р)уАВ
 */
export async function createNewChatWithCarryover(): Promise<boolean> {
  const ctx = getContext();
  if (!ctx) {
    toast('SillyTavern ф╕Кф╕ЛцЦЗф╕НхПпчФи', 'error');
    return false;
  }
  if (ctx.groupId) {
    toast('ч╛дшБКцЪВф╕НцФпцМБх╕жцХ░цНох╗║цЦ░хп╣шпЭ', 'warning');
    return false;
  }
  const sourceChat = ctx.chat ?? [];
  if (!sourceChat.length) {
    toast('х╜УхЙНхп╣шпЭц▓бцЬЙхПпцР║х╕жчЪДцХ░цНо', 'warning');
    return false;
  }

  const doNewChat = await getDoNewChat();
  if (!doNewChat) {
    toast('цЧац│ХхИЫх╗║цЦ░хп╣шпЭ(ST цОехПгф╕НхПпчФи)', 'error');
    return false;
  }

  // ===== 1. хЬих╗║цЦ░хп╣шпЭхЙН,ф╗Оц║РшБКхдйцПРхПЦшжБцР║х╕жчЪДф╕АхИЗ(хПкшп╗) =====
  const carryStart = resolveKeepStart(sourceChat);
  const sourceChatId = ctx.getCurrentChatId?.() ?? null;
  const parentBundles = currentBundleHashes(); // ц║РшБКхдйх╖▓цР║х╕жчЪД bundle хУИх╕М(х░Жч╗зцЙ┐ч╗ЩцЦ░шБКхдй)

  // цИкцнвчкЧхПгш╡╖чВ╣чЪДц┤╛чФЯчК╢цАБ тЖТ чзНхнРхП╢хнР delta(чкЧхПгце╝х▒ВшЗкх╖▒чЪДхП╢хнРф╝Ъч╗зч╗нч┤пхКа,цХЕцИкхИ░чкЧхПгхЙНщБ┐хЕНщЗНхдН)
  const stateBefore = deriveMemory(sourceChat, carryStart);
  const seedDelta = encodeStateAsDelta(stateBefore);

  // хРИх╣╢хОЖхП▓цСШшжБ(чкЧхПгф╣ЛхЙНчЪДхЙзцГЕ) = чзНхнРхП╢хнР text
  const mergedSummary = renderHistoryNodes(selectHistoryNodesBefore(memory.summaries, sourceChat, carryStart));

  // чзНхнРхП╢хнРчЪДцЧ╢щЧ┤щФЪ:цИкцнвчкЧхПгхЙНчЪДчК╢цАБцЧ╢щЧ┤(цЧахИЩцХЕф║ЛцЬАцЦ░цЧ╢щЧ┤)
  const seedTime = stateBefore.state.time || latestStoryTime(sourceChat) || '';

  // цРмш┐РчЪДчкЧхПгце╝х▒В(ц╖▒цЛ╖ш┤ЭуАБхПЦц╢ИщЪРшЧПуАБф┐ЭчХЩхП╢хнР)
  const carryMessages: STMessage[] = [];
  for (let i = carryStart; i < sourceChat.length; i++) {
    const m = sourceChat[i];
    if (!m) continue;
    if (m.is_system && m.extra?.type) continue; // хОЯчФЯч│╗ч╗Яце╝ф╕НцРм
    carryMessages.push(sanitizeCarryMessage(m));
  }

  if (!mergedSummary && !carryMessages.length && !seedDelta.items && !seedDelta.npcs && !seedDelta.plans) {
    toast('х╜УхЙНхп╣шпЭц▓бцЬЙхПпцР║х╕жчЪДцХ░цНо', 'warning');
    return false;
  }

  // ===== 2. хЕИх╗║ bundle цЛ┐хУИх╕М(хРСщЗПшо░х┐Жх╝А + ц║РшБКхдйцЬЙ id цЧ╢);хд▒ш┤еф╗ЕшнжхСК,ф╕НщШ╗цЦнх╗║шБКхдй =====
  let newBundleHash: string | null = null;
  const vecDb = currentVectorDb();
  if (apiSettings.vector.enabled && vecDb && sourceChatId) {
    try {
      if (await isBaiBaoKuAvailable()) {
        const { hash } = await vecBundleCreate(vecDb, sourceChatId);
        newBundleHash = hash;
      }
    } catch (e) {
      console.warn('[цЯПхоЭф╣жхРСщЗП] х╗║ bundle хд▒ш┤е(цЦ░хп╣шпЭх░Жф╕Нх╕жц║РхРСщЗПхПмхЫЮ):', e);
    }
  }

  // ===== 3. х╗║цЦ░хп╣шпЭх╣╢хИЗхЕе =====
  try {
    await ctx.saveChat();
    await doNewChat({ deleteCurrentChat: false });
  } catch (e) {
    toast(`хИЫх╗║цЦ░хп╣шпЭхд▒ш┤е:${e instanceof Error ? e.message : String(e)}`, 'error');
    return false;
  }

  // ===== 4. хЖЩхЕецЦ░хп╣шпЭ(цндхИ╗ ctx.chat х╖▓цМЗхРСцЦ░шБКхдй) =====
  try {
    const targetCtx = getContext();
    if (!targetCtx) throw new Error('цЦ░хп╣шпЭф╕Кф╕ЛцЦЗф╕НхПпчФи');
    const targetChat = targetCtx.chat ?? [];

    // чбоф┐ЭцЬЙ #0 щФЪчВ╣це╝:чзНхнРхП╢хнР(цЙ┐ш╜╜хЕищЗПчК╢цАБ delta + хРИх╣╢цСШшжБцЦЗцЬм)х┐Ещб╗цМВхЬиф╕АцЭб #0 ф╕КуАВ
    // хНбцЬЙх╝АхЬ║чЩ╜ тЖТ хдНчФи #0 х╜УщФЪчВ╣(ц╕Ечй║цнгцЦЗуАБшо╛ч│╗ч╗Яце╝,хИахЕ╢ф╜Щх╝АхЬ║чЩ╜);
    // хНб**чй║х╝АхЬ║чЩ╜** тЖТ getChat ф╕Нф╝Ъ push ф╗╗ф╜Хце╝,targetChat ф╕║чй║,цндхдДф╕╗хКищАаф╕АцЭбщФЪчВ╣це╝уАВ
    //   (ш┐ЩцШпф╣ЛхЙНц╝ПцОЙчЪДхИЖцФп:чй║х╝АхЬ║чЩ╜хНбф╝ЪшойцХ┤ф╕кщФЪчВ╣хЭЧшвлш╖│ш┐З,хп╝шЗ┤чкЧхПгхдЦцСШшжБ/чК╢цАБхЕиф╕вуАВ)
    let anchor: STMessage;
    if (targetChat.length > 0) {
      // хПкхЬиуАМцЦ░хп╣шпЭцШпхЕицЦ░цЧа user це╝уАНцЧ╢ц╕Ех╝АхЬ║чЩ╜,щБ┐хЕНшппхИачФицИ╖х╖▓цЬЙхЖЕхо╣
      const hasUser = targetChat.some(m => m.is_user);
      if (!hasUser && carryMessages.length > 0) {
        targetChat.splice(1); // чХЩ #0,хИахЕ╢ф╜Щх╝АхЬ║чЩ╜
      }
      anchor = targetChat[0];
    } else {
      // чй║х╝АхЬ║чЩ╜хНб:щАаф╕АцЭбщФЪчВ╣це╝цФ╛ш┐Ы #0
      anchor = {
        name: targetCtx.name2 || '',
        is_user: false,
        is_system: true,
        mes: '',
        extra: {},
      };
      targetChat.push(anchor);
    }
    anchor.is_system = true;
    anchor.mes = '';
    // чзНхнРхП╢хнРцМВ #0.extra
    const seedLeaf: LeafExtra = {
      id: makeLeafId(),
      text: mergedSummary,
      delta: seedDelta,
      timeEnd: seedTime || undefined,
      timeStart: seedTime || undefined,
      createdAt: Date.now(),
      v: 1,
    };
    anchor.extra = { ...(anchor.extra ?? {}), bbs_leaf: seedLeaf };

    // цЦ░хп╣шпЭцгоцЮЧ:щЗНч╜охРОцФ╛ф╕АцЭб L2 цА╗ч╗УцФ╢ч║│чзНхнРхП╢хнР(цЙ┐ш╜╜хРИх╣╢цСШшжБцЦЗцЬм)уАВ
    memory.summaries.splice(0, memory.summaries.length);
    if (mergedSummary) {
      const l2: MemSummary = {
        id: `sum_carry_${Date.now().toString(36)}`,
        text: mergedSummary,
        level: 2,
        createdAt: Date.now(),
        auto: true,
        timeStart: seedTime || undefined,
        timeEnd: seedTime || undefined,
        childIds: [seedLeaf.id],
      };
      memory.summaries.push(l2);
    }

    // цРмхЕечкЧхПгце╝х▒В
    for (const m of carryMessages) targetChat.push(m);

    // хЖЩцЦ░хп╣шпЭ metadata.bbs_bundles(ч╗зцЙ┐ц║Р + цЬмцмбцЦ░хУИх╕М,ч┤пхКахО╗щЗН)
    if (newBundleHash || parentBundles.length) {
      const meta = targetCtx.chatMetadata as Record<string, unknown>;
      if (newBundleHash) {
        appendBundleHash(meta, parentBundles, newBundleHash);
      } else {
        meta[BUNDLES_META_KEY] = [...parentBundles];
      }
    }

    // шР╜чЫШ + щЗНчоЧ + хИ╖цЦ░
    recomputeDerived();
    saveMemory();
    flushLeavesNow();
    await targetCtx.saveChat();
    if (typeof targetCtx.saveMetadata === 'function') await targetCtx.saveMetadata();
    if (typeof targetCtx.reloadCurrentChat === 'function') await targetCtx.reloadCurrentChat();
    refreshInjection();

    toast(`х╖▓хИЫх╗║цЦ░хп╣шпЭ:цР║х╕ж AI ${carryMessages.filter(m => !m.is_user).length} цЭб,цЧзхЙзцГЕцСШшжБ ${mergedSummary ? '1' : '0'} цЭб`, 'success');
    return true;
  } catch (e) {
    toast(`хЖЩхЕецЦ░хп╣шпЭхд▒ш┤е:${e instanceof Error ? e.message : String(e)}`, 'error');
    return false;
  }
}
