<script setup lang="ts">
import Icon from '@/components/Icon.vue';
import ConfirmDialog from '@/components/ConfirmDialog.vue';
import { editSceneDesc, findCurrentSceneId, removeScene, reparentScene, upsertScene } from '@/memory/apply';
import { derivedMeta, memory } from '@/memory/store';
import { getContext } from '@/st/context';
import type { MemScene } from '@/memory/types';
import { computed, nextTick, ref, watch } from 'vue';

// хЬ║цЩпцШпф╗ОхП╢хнРцСШшжБщЗНцФ╛хЗ║чЪДц┤╛чФЯцХ░цНо,цЙЛхКицУНф╜ЬхЖЩхЕеуАМцЬАцЦ░ф╕АцЭбцЬЙцХИхП╢хнРуАН;цЧацЬЙцХИхП╢хнРцЧ╢цЧахдДцМВш╜╜уАВ
const hasLeaf = computed(() => derivedMeta.hasLeaf);

// шзжх▒ПхИдхоЪ:ш╖│ш┐Зх╝╣чкЧшЗкхКишБЪчДж(чз╗хКичлпшЗкхКишБЪчДжф╝Ъх╝╣ш╛УхЕец│ХцМбчХМщЭв),ф╕ОцСШшжБщб╡ф╕АшЗ┤уАВ
const isTouch = typeof window !== 'undefined' && window.matchMedia?.('(hover: none)').matches;

/* тАФтАФ цКШхПачК╢цАБ:ч║пцЬмцЬ║ UI цАБ,цМЙшБКхдйхИЖцб╢хнШ localStorage(хИЗш╡░хЖНхЫЮф┐ЭцМБ) тАФтАФ */
const COLLAPSE_KEY = 'bbs.scenes.collapsed.v1';
function chatKey(): string {
  return getContext()?.getCurrentChatId?.() || '_';
}
function loadCollapsed(): Set<string> {
  try {
    const all = JSON.parse(localStorage.getItem(COLLAPSE_KEY) || '{}');
    return new Set<string>(Array.isArray(all[chatKey()]) ? all[chatKey()] : []);
  } catch {
    return new Set();
  }
}
// цКШхПачЪДшКВчВ╣ id щЫЖхРИ(хУНх║Фх╝П);щ╗ШшодхЕих▒Хх╝А
const collapsed = ref<Set<string>>(loadCollapsed());
function persistCollapsed() {
  try {
    const all = JSON.parse(localStorage.getItem(COLLAPSE_KEY) || '{}');
    all[chatKey()] = [...collapsed.value];
    localStorage.setItem(COLLAPSE_KEY, JSON.stringify(all));
  } catch {
    /* localStorage ф╕НхПпчФицЧ╢щЭЩщ╗Ш */
  }
}
function toggleCollapse(id: string) {
  const next = new Set(collapsed.value);
  if (next.has(id)) next.delete(id);
  else next.add(id);
  collapsed.value = next; // цНвх╝ХчФишзжхПСхУНх║Фх╝П
  persistCollapsed();
}

/* тАФтАФ цККцЙБх╣│ scenes цМЙ parentId ч╗ДшгЕцИРх╡МхеЧцаС,ц╖▒х║жф╝ШхЕИх▒Хх╣│цИРх╕ж depth чЪДхПпц╕▓цЯУшбМ тАФтАФ */
interface SceneRow {
  node: MemScene;
  depth: number;
  /** шпешбМцШпхРжхЬиуАМх╜УхЙНцЙАхЬиуАНчЪДчеЦхЕИшДЙч╗Ьф╕К(ца╣тЖТх╜УхЙНхЬ░чВ╣) */
  onCurrentPath: boolean;
  /** цШпхРжх░▒цШпх╜УхЙНцЙАхЬихЬ░чВ╣цЬмш║л */
  isCurrent: boolean;
  /** хРМч║зщЗМцШпхРжцЬАхРОф╕Аф╕к(чФ╗х╝Ххп╝ч║┐цФ╢х░╛чФи) */
  lastChild: boolean;
  /** цШпхРжцЬЙхнРшКВчВ╣(хЖ│хоЪцШпхРжцШ╛чд║цКШхПачонхд┤) */
  hasChildren: boolean;
  /** х╜УхЙНцШпхРжхдДф║ОцКШхПацАБ(хнРцаСх╖▓цФ╢ш╡╖) */
  isCollapsed: boolean;
}

// х╜УхЙНцЙАхЬишКВчВ╣:ф╕Оц│ихЕечлпхЕ▒чФи apply.findCurrentSceneId(ф╝ШхЕИцЭГхиБ locationPath,хРжхИЩцФ╢ч┤зцибч│КхМ╣щЕН)уАВ
// хНХф╕АцЭец║Р,ф┐ЭшпБхЬ║цЩпщб╡щлШф║о = цПРчд║шпНщЗМуАМх╜УхЙНцЙАхЬиуАНщУ╛,ф╕НхЖНхИЖхПЙуАВ
const currentId = computed(() =>
  findCurrentSceneId(memory.scenes, memory.state.location || '', memory.state.locationPath),
);

// х╜УхЙНцЙАхЬичЪДчеЦхЕИшДЙч╗Ь(хРлшЗкш║л)id щЫЖхРИ
const currentChain = computed(() => {
  const ids = new Set<string>();
  const byId = new Map(memory.scenes.map(s => [s.id, s]));
  let cur = byId.get(currentId.value);
  const seen = new Set<string>();
  while (cur && !seen.has(cur.id)) {
    seen.add(cur.id);
    ids.add(cur.id);
    cur = cur.parentId ? byId.get(cur.parentId) : undefined;
  }
  return ids;
});

// цЙАхЬихЬ░чВ╣хПШхМЦцЧ╢,шЗкхКих▒Хх╝АцЦ░шДЙч╗Ьф╕Ацмб(щБ┐хЕНуАМцИСхЬихУкуАНшвлцКШхПашЧПш╡╖);ф╜ЖхПкхЬи currentId чЬЯчЪД
// хПШф║ЖцЧ╢шзжхПС,ф╣ЛхРОчФицИ╖ф╗НшГ╜цЙЛхКицКШхПашпешДЙч╗ЬтАФтАФш┐ЩцнгцШпхТМцЧзуАМх╝║хИ╢х▒Хх╝АуАНчЪДхЕ│щФохМ║хИлуАВ
watch(
  () => currentId.value,
  () => {
    const next = new Set(collapsed.value);
    let changed = false;
    for (const cid of currentChain.value) {
      if (next.delete(cid)) changed = true;
    }
    if (changed) {
      collapsed.value = next;
      persistCollapsed();
    }
  },
);

function match(a: string, b: string): boolean {
  const x = a.trim();
  const y = b.trim();
  if (!x || !y) return false;
  return x.includes(y) || y.includes(x);
}

const rows = computed<SceneRow[]>(() => {
  const byParent = new Map<string, MemScene[]>();
  for (const s of memory.scenes) {
    const arr = byParent.get(s.parentId) ?? [];
    arr.push(s);
    byParent.set(s.parentId, arr);
  }
  for (const arr of byParent.values()) {
    // хРМч║з:х╜УхЙНшДЙч╗Ьф╕КчЪДцОТхЙН(шойц┤╗хКиф╕╗х╣▓чи│хоЪщЭаф╕К),хЖНцМЙхИЫх╗║х║П
    arr.sort((a, b) => a.createdAt - b.createdAt || a.name.localeCompare(b.name));
  }
  const out: SceneRow[] = [];
  const walk = (parentId: string, depth: number) => {
    const children = byParent.get(parentId) ?? [];
    children.forEach((node, i) => {
      const kids = byParent.get(node.id) ?? [];
      // onCurrentPath ф╗ЕчФиф║Оф╕╗х╣▓ч║┐щлШф║о;цКШхПахоМхЕичФ▒чФицИ╖чЪД collapsed хЖ│хоЪ(ф╕НхЖНх╝║хИ╢х▒Хх╝А,
      // хРжхИЩуАМцЙАхЬиуАНшДЙч╗Ьф╕КчЪДшбМчВ╣ф║ЖцФ╢ф╕Нш╡╖цЭе)уАВшДЙч╗ЬхПШхМЦцЧ╢чФ▒ watch шЗкхКих▒Хх╝Аф╕Ацмб,шзБф╕ЛцЦ╣уАВ
      const onCurrentPath = currentChain.value.has(node.id);
      const isCollapsed = kids.length > 0 && collapsed.value.has(node.id);
      out.push({
        node,
        depth,
        onCurrentPath,
        isCurrent: node.id === currentId.value,
        lastChild: i === children.length - 1,
        hasChildren: kids.length > 0,
        isCollapsed,
      });
      if (!isCollapsed) walk(node.id, depth + 1); // цКШхПахИЩш╖│ш┐ЗцХ┤цо╡хнРцаС
    });
  };
  walk('', 0); // ца╣ = parentId ф╕║чй║
  return out;
});

// хнШцФ╛хЬицЯРхЬ░чВ╣чЪДчЙйхУБ(location хМЕхРлх╝ПхМ╣щЕНшпешКВчВ╣хРН/ш╖пх╛Дф╗╗ф╕Ацо╡;хПкшп╗шБФхКих▒Хчд║)
function itemsAt(node: MemScene) {
  return memory.items.filter(i => {
    if (i.carried !== false || !i.location) return false;
    return match(i.location, node.name) || node.path.some(seg => match(i.location!, seg));
  });
}

// цКШхПацЧ╢х▒Хчд║чЪДхРОф╗гхЬ░чВ╣цХ░(цХ┤цо╡хнРцаС,id хЙНч╝АхМ╣щЕН)
function childCount(node: MemScene): string {
  const prefix = `${node.id}/`;
  const n = memory.scenes.filter(s => s.id.startsWith(prefix)).length;
  return n ? `+${n}` : '';
}

/** ф╕Кч║зхЬ░чВ╣ф╕ЛцЛЙщАЙщб╣:хЕищГишКВчВ╣цМЙхоМцХ┤ш╖пх╛ДцОТх║П(чИ╢хЕИф║ОхнР),depth хЖ│хоЪч╝йш┐ЫхЙНч╝АуАВф╕НхПЧцКШхПах╜▒хУНуАВ */
const sceneOptions = computed(() =>
  [...memory.scenes]
    .sort((a, b) => a.path.join('/').localeCompare(b.path.join('/')))
    .map(s => ({ id: s.id, name: s.name, depth: s.path.length - 1 })),
);

/* тАФтАФ цЦ░хвЮхЬ░чВ╣(х╝╣чкЧ):щАЙф╕Кч║з(х╖▓цЬЙш╖пх╛Д / щб╢ч║з)+ хблцЦ░хРН + цППш┐░ тАФтАФ */
const composerOpen = ref(false);
const newParentId = ref(''); // щАЙф╕нчЪДф╕Кч║з id;'' = щб╢ч║з
const newName = ref('');
const newDesc = ref('');
const nameInput = ref<HTMLInputElement | null>(null);

function openComposer() {
  if (!hasLeaf.value) return;
  newParentId.value = currentId.value || ''; // щ╗ШшодцМВхЬих╜УхЙНцЙАхЬихЬ░чВ╣ф╕Л,щб║цЙЛ
  newName.value = '';
  newDesc.value = '';
  composerOpen.value = true;
  if (!isTouch) void nextTick(() => nameInput.value?.focus());
}
function closeComposer() {
  composerOpen.value = false;
}
function addScene() {
  const name = newName.value.trim();
  // цППш┐░х┐Ехбл:хЖЩф╕НхЗ║цППш┐░чЪДхЬ░чВ╣ф╕Ншо░(ф╕О AI хРМшзДхИЩ)
  if (!name || !newDesc.value.trim()) return;
  const parent = memory.scenes.find(s => s.id === newParentId.value);
  const path = parent ? [...parent.path, name] : [name];
  if (!upsertScene(path, newDesc.value)) return;
  composerOpen.value = false;
}

/* тАФтАФ ч╝Цш╛Сх╝╣чкЧ:цФ╣цЬмч║зхРН + ф╕Кч║з(ф╕ЛцЛЙщАЙ)+ цППш┐░ тАФтАФ */
interface SceneEditing {
  id: string; // хОЯхзЛшКВчВ╣ id
  path: string[]; // хОЯхзЛхоМцХ┤ш╖пх╛Д
  name: string;
  parentId: string; // щАЙф╕нчЪДф╕Кч║з id;'' = щб╢ч║з
  desc: string;
}
const editing = ref<SceneEditing | null>(null);

function openEdit(node: MemScene) {
  editing.value = {
    id: node.id,
    path: node.path,
    name: node.name,
    parentId: node.parentId,
    desc: node.desc ?? '',
  };
}
function cancelEdit() {
  editing.value = null;
}

/** ч╝Цш╛СцАБф╕ЛчЪДхПпщАЙф╕Кч║з:цОТщЩдшКВчВ╣шЗкш║лхПКхЕ╢хРОф╗г(хРжхИЩф╝ЪцККшКВчВ╣хПШцИРшЗкх╖▒чЪДчеЦхЕИ,цИРчОп)уАВ */
const editParentOptions = computed(() => {
  const e = editing.value;
  if (!e) return sceneOptions.value;
  const selfPrefix = `${e.id}/`;
  return sceneOptions.value.filter(o => o.id !== e.id && !o.id.startsWith(selfPrefix));
});

function saveEdit() {
  const e = editing.value;
  const name = e?.name.trim();
  if (!e || !name || !e.desc.trim()) return; // цППш┐░х┐Ехбл
  const parent = memory.scenes.find(s => s.id === e.parentId);
  const newPath = parent ? [...parent.path, name] : [name];
  const pathChanged = newPath.join('/') !== e.path.join('/');

  if (pathChanged) {
    // цНвчИ╢ / цФ╣хРН / цПТх▒В:ф╕АцЭб reparent хОЯхнРхоМцИР,ш┐ЮхнРцаСх╣│чз╗ + щб║х╕жхЖЩцЦ░хРНцППш┐░
    reparentScene(e.path, newPath, { [name]: e.desc.trim() });
  } else {
    editSceneDesc(e.path, e.desc);
  }
  editing.value = null;
}

/* тАФтАФ хИащЩдчбошод(ш┐Юх╕жхнРч║з)тАФтАФ */
const removing = ref<MemScene | null>(null);
function askRemove(node: MemScene) {
  removing.value = node;
}
function confirmRemove() {
  if (removing.value) removeScene(removing.value.path);
  removing.value = null;
}
const removeChildCount = computed(() => {
  const n = removing.value;
  if (!n) return 0;
  const prefix = `${n.id}/`;
  return memory.scenes.filter(s => s.id.startsWith(prefix)).length;
});
</script>

<template>
  <section class="bbs-page">
    <div class="bbs-section-head">
      <h2 class="bbs-title bbs-title-sub">хЬ║цЩп</h2>
      <button
        class="bbs-add-mini"
        type="button"
        :disabled="!hasLeaf"
        :title="hasLeaf ? 'цЙЛхКиц╖╗хКахЬ░чВ╣' : 'щЬАхЕИцЬЙцСШшжБцЙНшГ╜цЙЛхКиц╖╗хКа'"
        @click="openComposer"
      >
        <Icon name="plus" />
      </button>
    </div>

    <hr class="bbs-rule" />

    <TransitionGroup v-if="rows.length" tag="div" name="scene" class="bbs-scene-tree">
      <div
        v-for="r in rows"
        :key="r.node.id"
        class="bbs-scene-row"
        :class="{ 'is-current': r.isCurrent, 'on-path': r.onCurrentPath }"
        :style="{ '--depth': r.depth }"
      >
        <!-- х▒Вч║зх╝Ххп╝ш╜и:цпПч║зф╕АцЭбч╗ЖчлЦч║┐,хЬих╜УхЙНшДЙч╗Ьф╕КчВ╣ф║оцИРф╕╗х╣▓ -->
        <span v-for="d in r.depth" :key="d" class="bbs-scene-rail" :class="{ active: r.onCurrentPath && d <= r.depth }"></span>

        <!-- цЬЙхнРшКВчВ╣чЪДцХ┤х╝ахНбчЙЗхПпчВ╣цКШхПа(хРлцППш┐░/чЙйхУБхМ║);хП╢хнРхНбф╕НхПпчВ╣уАВцУНф╜ЬцМЙщТо @click.stop ф╕НшзжхПС -->
        <div
          class="bbs-scene-card"
          :class="{ clickable: r.hasChildren }"
          @click="r.hasChildren && toggleCollapse(r.node.id)"
        >
          <div class="bbs-scene-head">
            <span
              v-if="r.hasChildren"
              class="bbs-scene-toggle"
              :class="{ collapsed: r.isCollapsed }"
              :title="r.isCollapsed ? 'х▒Хх╝Аф╕Лх▒ЮхЬ░чВ╣' : 'цФ╢ш╡╖ф╕Лх▒ЮхЬ░чВ╣'"
            >
              <Icon name="chevron" />
            </span>
            <span class="bbs-scene-name">{{ r.node.name }}</span>
            <span v-if="r.isCurrent" class="bbs-scene-here"><Icon name="scenes" />цЙАхЬи</span>
            <span v-else-if="r.isCollapsed" class="bbs-scene-count">{{ childCount(r.node) }}</span>
            <span class="bbs-scene-acts">
              <button class="bbs-item-act" type="button" title="ч╝Цш╛С" @click.stop="openEdit(r.node)"><Icon name="edit" /></button>
              <button class="bbs-item-act bbs-item-del" type="button" title="хИащЩд" @click.stop="askRemove(r.node)"><Icon name="trash" /></button>
            </span>
          </div>
          <p v-if="r.node.desc" class="bbs-scene-desc">{{ r.node.desc }}</p>
          <div v-if="itemsAt(r.node).length" class="bbs-scene-items">
            <span v-for="it in itemsAt(r.node)" :key="it.id" class="bbs-scene-chip">
              <Icon name="items" />{{ it.name }}<i v-if="typeof it.qty === 'number'">├Ч{{ it.qty }}</i>
            </span>
          </div>
        </div>
      </div>
    </TransitionGroup>

    <div v-else class="bbs-empty">
      <span class="bbs-empty-icon"><Icon name="scenes" /></span>
      <p>ш┐Шц▓бцЬЙхО╗ш┐ЗчЪДхЬ░чВ╣уАВцСШшжБцЧ╢ф╝Ъшо░ф╕Лш╡░ш┐ЗчЪДхЬ║цЩп,ф╣ЯхПпчВ╣хП│ф╕КшзТуАМ+уАНцЙЛхКиц╖╗хКауАВ</p>
    </div>

    <!-- ц╖╗хКах╝╣чкЧ:щАЙф╕Кч║з(х╖▓цЬЙхЬ░чВ╣ / щб╢ч║з)+ хблцЦ░хРН + цППш┐░ -->
    <div v-if="composerOpen" class="bbs-modal-mask" @click.self="closeComposer">
      <div class="bbs-modal" role="dialog" aria-modal="true" aria-label="ц╖╗хКахЬ░чВ╣">
        <header class="bbs-modal-head">
          <span class="bbs-modal-title">ц╖╗хКахЬ░чВ╣</span>
          <button class="bbs-item-act" type="button" title="хЕ│щЧн" @click="closeComposer"><Icon name="close" /></button>
        </header>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">ф╕Кч║зхЬ░чВ╣(ф╗Ох╖▓цЬЙхЬ░чВ╣щЗМщАЙ,цИЦшо╛ф╕║щб╢ч║з)</span>
          <select v-model="newParentId" class="bbs-input">
            <option value="">я╝Ищб╢ч║зхЬ░чВ╣я╝Й</option>
            <option v-for="o in sceneOptions" :key="o.id" :value="o.id">
              {{ 'уАА'.repeat(o.depth) }}{{ o.name }}
            </option>
          </select>
        </label>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">хРНчз░</span>
          <input ref="nameInput" v-model="newName" class="bbs-input" type="text" placeholder="цЦ░хЬ░чВ╣хРН" @keydown.enter="addScene" />
        </label>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">цППш┐░(х┐Ехбл)</span>
          <textarea v-model="newDesc" class="bbs-input bbs-modal-textarea" rows="3" placeholder="ш┐ЩхЬ░цЦ╣цШпф╗Аф╣ИуАБцЬЙф╜ХчЙ╣х╛Б"></textarea>
        </label>
        <footer class="bbs-modal-foot">
          <button class="bbs-btn" type="button" @click="closeComposer">хПЦц╢И</button>
          <button class="bbs-btn bbs-btn-primary" type="button" :disabled="!newName.trim() || !newDesc.trim()" @click="addScene">ц╖╗хКа</button>
        </footer>
      </div>
    </div>

    <!-- ч╝Цш╛Сх╝╣чкЧ:position:fixed хЖЕшБФ(ф╕НчФи Teleport,шзБ base.css шп┤цШО) -->
    <div v-if="editing" class="bbs-modal-mask" @click.self="cancelEdit">
      <div class="bbs-modal" role="dialog" aria-modal="true" aria-label="ч╝Цш╛СхЬ░чВ╣">
        <header class="bbs-modal-head">
          <span class="bbs-modal-title">ч╝Цш╛СхЬ░чВ╣</span>
          <button class="bbs-item-act" type="button" title="хЕ│щЧн" @click="cancelEdit"><Icon name="close" /></button>
        </header>
        <p class="bbs-scene-crumb">{{ editing.path.join(' тА║ ') }}</p>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">хРНчз░</span>
          <input v-model="editing.name" class="bbs-input" type="text" placeholder="хЬ░чВ╣хРН" />
        </label>
        <label class="bbs-modal-field">
