<script setup lang="ts">
import Icon from '@/components/Icon.vue';
import ConfirmDialog from '@/components/ConfirmDialog.vue';
import { appendOpToLatestLeaf, deleteLeafAt, deleteSummary, editLeafAt, editPlan, editSummary } from '@/memory/apply';
import { apiSettings } from '@/api/settings';
import { batchBackfill, batchState, cancelBatchBackfill, engineState, resummarizeNow, summarizeFloor } from '@/memory/engine';
import { refreshInjection, selectViewNodes, type ViewNode } from '@/memory/inject';
import { compactTimeLabel, formatRange, splitTimeLabel } from '@/memory/timeTag';
import { relativeTimeLabel } from '@/memory/timeRel';
import { derivedMeta, memory, recomputeDerived } from '@/memory/store';
import { computed, nextTick, onMounted, ref } from 'vue';

// цЙУх╝АцСШшжБщб╡цЧ╢х╝║хИ╢щЗНчоЧф╕Ацмбц┤╛чФЯ:цЬкцСШшжБце╝х▒ВчнЙц┤╛чФЯч╝УхнШхПкхЬичЙ╣хоЪф║Лф╗╢хИ╖цЦ░,
// ш╛╣шБКш╛╣цФТчЪДцЦ░ AI це╝хПпшГ╜ц▓бшзжхПСхИ╖цЦ░,ш┐Ыщб╡хЕИхп╣щ╜Рф╕Ацмб,щБ┐хЕНхИЧшбиц╝Пце╝уАВ
onMounted(() => recomputeDerived());

// шзжх▒ПхИдхоЪ:чФиф║Ош╖│ш┐Зх╝╣чкЧшЗкхКишБЪчДж(чз╗хКичлпшЗкхКишБЪчДжф╝Ъх╝╣хЗ║ш╛УхЕец│ХцМбф╜ПчХМщЭв)уАВ
const isTouch = typeof window !== 'undefined' && window.matchMedia?.('(hover: none)').matches;

/* ============ цВмх┐╡ч░┐(щб╢щГи)============ */
const newKind = ref<'plan' | 'suspense'>('plan');
const newContent = ref('');
const newTargetTime = ref(''); // цЙЛхКиц╖╗хКашобхИТцЧ╢чЪДхПпщАЙчЫоцаЗцЧ╢щЧ┤(цХЕф║ЛхЖЕцЧ╢щЧ┤)
// цЙЛхКиц╖╗хКацШпф╜ОщвСцУНф╜Ь:чФих╝╣чкЧцЙ┐ш╜╜,х╣│цЧ╢хПкщЬ▓ф╕Аф╕кх░ПуАМ+уАНцМЙщТо,ф╕НхНачЙИщЭвуАВ
const composerOpen = ref(false);
const contentInput = ref<HTMLTextAreaElement | null>(null);
function openComposer() {
  if (!hasLeaf.value) return;
  newKind.value = 'plan';
  newContent.value = '';
  newTargetTime.value = '';
  composerOpen.value = true;
  // ф╗ЕхЬищЭЮшзжх▒ПшЗкхКишБЪчДж:чз╗хКичлпшЗкхКишБЪчДжф╝ЪчлЛхИ╗х╝╣хЗ║ш╛УхЕец│Х,цМбф╜Пх╝╣чкЧуАБф╜УщкМх╖оуАВ
  if (!isTouch) void nextTick(() => contentInput.value?.focus());
}
function closeComposer() {
  composerOpen.value = false;
}
// шобхИТ/цВмх┐╡хПкх▒Хчд║уАМш┐ЫшбМф╕нуАНуАВчВ╣хИащЩдхН│чз╗щЩдтАФтАФф╕НхЖНцЬЙуАМф║Жч╗У/х╖▓ф║Жч╗УуАНцжВх┐╡уАВ
const openPlans = computed(() => memory.plans.filter(p => p.status === 'open'));
const hasLeaf = computed(() => derivedMeta.hasLeaf);

// хП╢хнР id тЖТ хИЫх╗║це╝х▒ВуАВшобхИТ id х╜вхжВ `plan:${хП╢хнРid}#${х║ПхП╖}`,чФ▒цндхПНцЯехИЫх╗║шпешобхИТ/цВмх┐╡
// цЧ╢цЙАхЬице╝х▒В(ф╕ОцСШшжБхИЧшбичЪД #це╝х▒В хРМц║Р)уАВцЙЛхКиц╖╗хКачЪДшобхИТцМВхЬицЬАцЦ░хП╢хнРф╕К,цШ╛чд║хЕ╢це╝х▒ВуАВ
const leafFloor = computed(() => {
  const m = new Map<string, number>();
  for (const l of derivedMeta.leaves) m.set(l.id, l.msgIndex);
  return m;
});
function planFloor(planId: string): number | undefined {
  const leafId = planId.replace(/^plan:/, '').replace(/#\d+$/, '');
  return leafFloor.value.get(leafId);
}

function addPlan() {
  const content = newContent.value.trim();
  if (!content) return;
  // хИЫх╗║цЧ╢щЧ┤чФих╜УхЙНх╖▓чЯецХЕф║ЛцЧ╢щЧ┤(ц▓бцЬЙх░▒чХЩчй║);чЫоцаЗцЧ╢щЧ┤ф╗ЕшобхИТхПпхбл,чФицИ╖хблф║ЖцЙНх╕жф╕К
  const createdTime = memory.state.time?.trim() || undefined;
  const targetTime = newKind.value === 'plan' ? newTargetTime.value.trim() || undefined : undefined;
  if (!appendOpToLatestLeaf({ plans: { add: [{ kind: newKind.value, content, createdTime, targetTime }] } })) return;
  newContent.value = '';
  newTargetTime.value = '';
  composerOpen.value = false;
}
function removePlan(id: string) {
  appendOpToLatestLeaf({ plans: { remove: [id] } });
}

/* тАФтАФ ч╝Цш╛СшобхИТ/цВмх┐╡(х╝╣чкЧ)тАФтАФ */
const editingPlan = ref<{ id: string; kind: 'plan' | 'suspense'; content: string; createdTime: string; targetTime: string } | null>(null);
function openPlanEdit(p: { id: string; kind: 'plan' | 'suspense'; content: string; createdTime?: string; targetTime?: string }) {
  editingPlan.value = {
    id: p.id,
    kind: p.kind,
    content: p.content,
    createdTime: p.createdTime ?? '',
    targetTime: p.targetTime ?? '',
  };
}
function cancelPlanEdit() {
  editingPlan.value = null;
}
function savePlanEdit() {
  const e = editingPlan.value;
  if (!e || !e.content.trim()) return;
  editPlan(e.id, {
    content: e.content,
    createdTime: e.createdTime,
    // чЫоцаЗцЧ╢щЧ┤ф╗ЕшобхИТцЬЙцДПф╣Й;цВмх┐╡ф┐ЭцМБчй║
    targetTime: e.kind === 'plan' ? e.targetTime : '',
  });
  refreshInjection();
  editingPlan.value = null;
}

/* ============ цЬкцСШшжБце╝х▒В ============
 * derivedMeta.pendingFloors = AI це╝ф╕ФцЧацЬЙцХИхП╢хнР,чФ▒цЧзхИ░цЦ░;цндхдДхАТх║Пх▒Хчд║(цЦ░це╝хЬихЙН)уАВ */
const pendingFloors = computed(() => [...derivedMeta.pendingFloors].sort((a, b) => b - a));
const summarizingFloor = ref<number | null>(null);
async function summarizeOne(floor: number) {
  if (engineState.running || summarizingFloor.value !== null) return;
  summarizingFloor.value = floor;
  try {
    await summarizeFloor(floor);
  } finally {
    summarizingFloor.value = null;
  }
}

/* ============ цЙ╣щЗПшбецСШ ============
 * цККцЙАцЬЙцЬкцСШце╝х▒ВцМЙхЖЕхо╣щЗПхИЖхЭЧуАБщАРхЭЧф╕▓шбМшбецСШ:чЬБ token(хЫ║хоЪф╕Кф╕ЛцЦЗцМЙхЭЧхИЖцСК)+ хЗПшп╖ц▒ВцХ░уАВ
 * хЕИх╝╣чбошод(цШ╛чд║х╛ЕцСШце╝цХ░),цЙзшбМф╕нцШ╛чд║ш┐Ых║ж + хПпхПЦц╢И(хЭЧш╛╣чХМчФЯцХИ)уАВ
 * ш┐РшбМчК╢цАБшп╗ engine чЪД batchState хНХф╛Л(щЭЮч╗Дф╗╢цЬмхЬ░ ref):хЕ│цОЙцЯПхоЭф╣жчкЧхПгхЖНщЗНх╝А,
 * ш┐Ых║жцЭбф╕ОхПЦц╢ИцМЙщТошГ╜цБвхдНтАФтАФхЫаф╕║ф╗╗хКбхЬи engine щЗМч╗зч╗нш╖С,хЕ│чкЧф╕НхПЦц╢ИуАВ */
const batchConfirmOpen = ref(false);

function openBatchConfirm() {
  if (engineState.running || !pendingFloors.value.length) return;
  batchConfirmOpen.value = true;
}
function runBatchBackfill() {
  batchConfirmOpen.value = false;
  if (engineState.running) return;
  // ф╕Н await:ф╗╗хКбхЬи engine щЗМш╖С,чК╢цАБш╡░ batchState хНХф╛Л;UI хПкшп╗хоГ,ф╕Нф╛Эш╡ЦцЬмхЗ╜цХ░хБЬчХЩ
  void batchBackfill({
    // чФ▒цЧзхИ░цЦ░шбе;pendingFloors цШпхАТх║Пх▒Хчд║чФи,ш┐ЩщЗМф╝ахНЗх║ПцЫ┤чи│(х╝ХцУОхЖЕщГиф╣Яф╝ЪхЖНш┐Зц╗дцОТх║П)
    floors: [...derivedMeta.pendingFloors].sort((a, b) => a - b),
  });
}

/* ============ члЛхН│цА╗ч╗У ============
 * цЙЛхКишзжхПСф╕АцмбуАМцгАц╡ЛцШпхРжш╛╛щШИхА╝ тЖТ ш╛╛хИ░х░▒цА╗ч╗У(хПпш┐ЮщФБхдЪх▒В)уАНуАВч╗УцЮЬчФиф╕АхПеф╕┤цЧ╢цПРчд║хПНщжИуАВ */
const resummaryRunning = ref(false);
const resummaryHint = ref('');
let resummaryHintTimer: ReturnType<typeof setTimeout> | null = null;

// цА╗ч╗УшКВхеП:хоЮщЩЕч║жцпПуАМф┐ЭчХЩцЬАш┐С AI ц╢ИцБпцХ░ + цпПцмбцА╗ч╗У AI ц╢ИцБпцХ░уАНце╝цА╗ч╗Уф╕АцмбтАФтАФ
// цЬАш┐С keepRecent цЭбхПСхЕицЦЗф╕НцСШ,цЫ┤цЧйчЪДцСШцИРхП╢хнР,хП╢хнРцФТхдЯ leafBatchThreshold цЭбхОЛф╕АцмбцА╗ч╗УуАВ
// щШИхА╝хЕ│щЧн(<2)цЧ╢ф╕НцШ╛чд║шКВхеПхПеуАВ
const resummaryEvery = computed(() => (Math.max(0, apiSettings.keepRecent) + apiSettings.leafBatchThreshold) * 2);
const showCadence = computed(() => apiSettings.leafBatchThreshold >= 2);

async function doResummarize() {
  if (resummaryRunning.value || engineState.running) return;
  resummaryRunning.value = true;
  resummaryHint.value = '';
  try {
    const made = await resummarizeNow();
    // цЬЙцКещФЩф╝ШхЕИцШ╛чд║щФЩшпп(хжВцЬкцМЗц┤╛цА╗ч╗Уц╕ащБУ);хРжхИЩцМЙчФЯцИРцЭбцХ░ч╗ЩхПНщжИ
    if (engineState.lastError) {
      resummaryHint.value = '';
    } else if (made > 0) {
      resummaryHint.value = `х╖▓чФЯцИР ${made} цЭбцА╗ч╗У`;
    } else {
      // цЬкш╛╛щШИхА╝:шбеф╕АхПехКицАБшКВхеП,хСКшпЙчФицИ╖хдзцжВцпПхдЪх░Сце╝цА╗ч╗Уф╕Ацмб
      const cadence = showCadence.value ? `,ч║жцпП ${resummaryEvery.value} це╝цА╗ч╗Уф╕Ацмб` : '';
      resummaryHint.value = `х╜УхЙНц▓бцЬЙш╛╛хИ░цА╗ч╗УщШИхА╝чЪДцСШшжБ${cadence}`;
    }
  } finally {
    resummaryRunning.value = false;
    if (resummaryHintTimer) clearTimeout(resummaryHintTimer);
    if (resummaryHint.value) resummaryHintTimer = setTimeout(() => (resummaryHint.value = ''), 4000);
  }
}

/* ============ цСШшжБхИЧшби(ф╕ЛцЦ╣)============ */
/** ч╗Яф╕АшбМ:хП╢хнР(цЭешЗк chat цЙлцППчЪД derivedMeta.leaves)+ хОЛч╝йшКВчВ╣(цЭешЗкцгоцЮЧ) */
interface Row {
  key: string;
  kind: 'leaf' | 'comp';
  level: number;
  text: string;
  timeStart?: string;
  timeEnd?: string;
  timeLabel?: string; // цЧзцХ░цНохЫЮщАА
  createdAt: number;
  sortKey: number;
  floorLo: number; // шжЖчЫЦце╝х▒ВшМГхЫ┤ф╕ЛчХМ
  floorHi: number; // шжЖчЫЦце╝х▒ВшМГхЫ┤ф╕КчХМ(leaf:ф╕О lo чЫ╕хРМ)
  msgIndex?: number; // leaf
  stale?: boolean; // leaf
}

const ordered = computed<Row[]>(() => {
  // ф╗О derivedMeta(reactive)цЮДх╗║ ViewNode цгоцЮЧ,хдНчФиц│ихЕеф╛зхРМф╕АхеЧуАМцЬАх░ПцЛЖшзгуАНщАЙцЛйуАВ
  // тЪая╕П х┐Ещб╗ш╡░ derivedMeta шАМщЭЮчЫ┤цОецЙл chat:chat щЭЮ reactive,UI шжБхПШцЫ┤щб╗ч╗П derivedMetaуАВ
  // хПкцФ╢**цЬЙцХИ**хП╢хнР(stale=false);хд▒цХИхП╢хнР(ч┐╗щб╡хИ░хИлщб╡чнЙ)шР╜хЕеуАМцЬкцСШшжБце╝х▒ВуАНхИЧшби,ф╕НхЬицндх▒Хчд║уАВ
  const byId = new Map<string, ViewNode>();
  for (const l of derivedMeta.leaves) {
    if (l.stale) continue;
    byId.set(l.id, {
      id: l.id,
      kind: 'leaf',
      level: 0,
      text: l.text,
      timeStart: l.timeStart,
      timeEnd: l.timeEnd,
      timeLabel: l.timeLabel,
      createdAt: l.createdAt,
      childIds: [],
      msgIndex: l.msgIndex,
      active: l.active,
    });
  }
  for (const s of memory.summaries) {
    byId.set(s.id, {
      id: s.id,
      kind: 'comp',
      level: s.level,
      text: s.text,
      timeStart: s.timeStart,
      timeEnd: s.timeEnd,
      timeLabel: s.timeLabel,
      createdAt: s.createdAt,
      childIds: s.childIds ?? [],
      msgIndex: -1,
      active: false,
    });
  }
  const referenced = new Set<string>();
  for (const s of memory.summaries) for (const c of s.childIds ?? []) referenced.add(c);
  const roots = [...byId.values()].filter(n => !referenced.has(n.id));

  // хИЧшбих▒Хчд║цЙАцЬЙцЬЙцХИхП╢хнРчЪДф╗гшби(leafEligible цБТчЬЯтАФтАФхд▒цХИхП╢хнРх╖▓хЬиф╕КщЭвцОТщЩд)уАВ
  // хРлхд▒цХИхРОф╗гхП╢хнРчЪДхОЛч╝йшКВчВ╣ф╕НхоМцХ┤ тЖТ шЗкхКищЩНч║з,хПкцЛЖхПЧх╜▒хУНчЪДщВгцЭбщУ╛:
  // цЧБцФпхоМхе╜чЪДхРМх▒В L1 цХ┤цЭбф┐ЭчХЩ,хд▒цХИщВгцЭбцЛЖцИРцИРхСШхП╢хнР(хд▒цХИхП╢хнРцЬмш║лф╕НхЬицндуАБх╖▓шР╜цЬкцСШхИЧшби)уАВ
  const chosen = selectViewNodes({ byId, roots }, () => true);

  // comp чЪДшжЖчЫЦце╝х▒ВшМГхЫ┤ = хоГхРОф╗гцЬЙцХИхП╢хнРчЪД msgIndex min..max
  const collectLeafFloors = (n: ViewNode, acc: number[], seen: Set<string>): void => {
    if (seen.has(n.id)) return;
    seen.add(n.id);
    if (n.kind === 'leaf') {
      acc.push(n.msgIndex);
      return;
    }
    for (const cid of n.childIds) {
      const c = byId.get(cid);
      if (c) collectLeafFloors(c, acc, seen);
    }
  };

  const rows: Row[] = chosen.map(n => {
    if (n.kind === 'leaf') {
      return {
        key: `leaf:${n.id}`,
        kind: 'leaf',
        level: 0,
        text: n.text,
        timeStart: n.timeStart,
        timeEnd: n.timeEnd,
        timeLabel: n.timeLabel,
        createdAt: n.createdAt,
        sortKey: n.msgIndex,
        floorLo: n.msgIndex,
        floorHi: n.msgIndex,
        msgIndex: n.msgIndex,
        stale: false,
      };
    }
    const floors: number[] = [];
    collectLeafFloors(n, floors, new Set());
    const lo = floors.length ? Math.min(...floors) : -1;
    const hi = floors.length ? Math.max(...floors) : -1;
    return {
      key: `comp:${n.id}`,
      kind: 'comp',
      level: n.level,
      text: n.text,
      timeStart: n.timeStart,
      timeEnd: n.timeEnd,
      timeLabel: n.timeLabel,
      createdAt: n.createdAt,
      // цОТх║ПчФишжЖчЫЦшМГхЫ┤ф╕КчХМ(цЬАцЦ░це╝х▒В),ф╕ОхП╢хнРце╝х▒ВхРМх░║х║ж,хАТх║ПцЧ╢шР╜хЬихп╣х║Фф╜Нч╜о
      sortKey: hi,
      floorLo: lo,
      floorHi: hi,
    };
  });
  // хАТх║П:це╝х▒Вш╢КщЭахРОш╢КхЬиф╕КщЭв
  return rows.sort((a, b) => b.sortKey - a.sortKey);
});

/** шбМчЪДх▒Хчд║цЧ╢щЧ┤:цЦ░цХ░цНочФи timeStart/timeEnd хРИцИРх╣╢хОЛч╝й;цЧзцХ░цНохЫЮщААхИ░х╖▓хЫ║хМЦчЪД timeLabel(ф╣ЯхОЛч╝йф╕Ацмб) */
function rowTime(r: Row): string {
  if (r.timeStart || r.timeEnd) return formatRange(r.timeStart, r.timeEnd);
  return r.timeLabel ? compactTimeLabel(r.timeLabel) : '';
}
/** шбМчЪДчЫ╕хп╣цЧ╢щЧ┤хЙНч╝А(хжВуАМцШихдйуАН):ф╗ЕхП╢хнР(хНХце╝цСШшжБ)цШ╛чд║;цА╗ч╗Уш╖ихдЪце╝уАБчЫ╕хп╣цЧ╢щЧ┤цЧацДПф╣Й,ш┐ФхЫЮчй║ф╕▓ */
function rowRelative(r: Row): string {
  if (r.kind !== 'leaf') return '';
  const event = r.timeEnd || r.timeStart || (r.timeLabel ? splitTimeLabel(r.timeLabel).end : '') || '';
  return relativeTimeLabel(event, derivedMeta.latestStoryTime);
}

// х╜УхЙНцЧ╢щЧ┤:ф╝ШхЕИшп╗цнгцЦЗцаЗчн╛хоЮцЧ╢чоЧхЗ║чЪДуАМцХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤уАН(ф╕НхПЧцЬАцЦ░це╝цШпхРжх╖▓цСШх╜▒хУН);
// хПЦф╕НхИ░хЖНхЫЮщААц┤╛чФЯчЪД state.time(шАБцХ░цНо/цЧацаЗчн╛хЬ║цЩп)уАВф┐оцОЙуАМцЬАцЦ░це╝цЬкцСШцЧ╢цШ╛чд║цЧзцЧ╢щЧ┤уАНчЪДщЧощвШуАВ
const currentTime = computed(() => derivedMeta.latestStoryTime || memory.state.time);

function levelLabel(level: number): string {
  if (level === 0) return 'цСШшжБ';
  return `цА╗ч╗УL${level}`;
}
/** це╝х▒ВшМГхЫ┤цаЗчн╛:хНХце╝ #5,ш╖ице╝ #0 - #10 */
function floorLabel(r: Row): string {
  if (r.floorLo < 0) return 'тАФ';
  return r.floorLo === r.floorHi ? `#${r.floorLo}` : `#${r.floorLo} - #${r.floorHi}`;
}

function onDelete(r: Row) {
  if (r.kind === 'leaf') {
    if (!confirm('хИащЩдш┐ЩцЭбцСШшжБ?хоГх╕жцЭечЪДчЙйхУБуАБшобхИТуАБцЧ╢щЧ┤хЬ░чВ╣хПШхМЦф╝ЪцМЙхЙйф╜ЩцСШшжБщЗНцЦ░шобчоЧ(хПпшГ╜хЫЮщАА);хМЕхРлхоГчЪДцА╗ч╗Уф╣Яф╝Ъф╕Ах╣╢хИащЩдуАВхОЯцЦЗце╝х▒Вф╗Нф┐ЭцМБщЪРшЧПуАВ')) return;
    if (typeof r.msgIndex === 'number') deleteLeafAt(r.msgIndex);
  } else {
    if (!confirm('хИащЩдш┐ЩцЭбцА╗ч╗У?швлхоГцФ╢ч║│чЪДф╕Лх▒ВцСШшжБф╝ЪщЗНцЦ░х▒Хх╝А,чЙйхУБ/шобхИТчнЙф╕НхПЧх╜▒хУНуАВ')) return;
    deleteSummary(r.key.slice('comp:'.length));
  }
  refreshInjection();
}

/* ============ ч╝Цш╛Сх╝╣чкЧ ============
 * хП╢хнР:хПпцФ╣уАМцХЕф║ЛхЖЕцЧ╢щЧ┤уАН+ цнгцЦЗ;цА╗ч╗У:хПкхОЛцЦЗцЬм,цХЕхПкцФ╣цнгцЦЗуАВ */
type Editing =
  | { kind: 'leaf'; msgIndex: number; text: string; timeStart: string; timeEnd: string }
  | { kind: 'comp'; compId: string; level: number; text: string };
const editing = ref<Editing | null>(null);

function openEdit(r: Row) {
  if (r.kind === 'leaf' && typeof r.msgIndex === 'number') {
    // цЧзцХ░цНоцЧа timeStart/timeEnd цЧ╢,ф╗Ох╖▓хЫ║хМЦчЪД timeLabel цЛЖхЗ║ш╡╖цнвхблхЕе
    const fb = !r.timeStart && !r.timeEnd ? splitTimeLabel(r.timeLabel) : {};
    editing.value = {
      kind: 'leaf',
      msgIndex: r.msgIndex,
      text: r.text,
      timeStart: r.timeStart ?? fb.start ?? '',
      timeEnd: r.timeEnd ?? fb.end ?? '',
    };
  } else if (r.kind === 'comp') {
    editing.value = { kind: 'comp', compId: r.key.slice('comp:'.length), level: r.level, text: r.text };
  }
}
function cancelEdit() {
  editing.value = null;
}
function saveEdit() {
  const e = editing.value;
  if (!e) return;
  if (e.kind === 'leaf') editLeafAt(e.msgIndex, e.text, e.timeStart, e.timeEnd);
  else editSummary(e.compId, e.text);
  refreshInjection();
  editing.value = null;
}
