}
.bbs-time-col {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
/* .bbs-section-head / .bbs-add-mini х╖▓цПРхНЗф╕║ base.css хЕих▒АхОЯхнР(цСШшжБуАБхЬ║цЩпхЕ▒чФи) */
.bbs-kind-toggle {
  display: inline-flex;
  flex: 0 0 auto;
  padding: 3px;
  background: var(--bbs-surface-2);
  border-radius: var(--bbs-radius-sm);
}
.bbs-kind {
  padding: 5px 12px;
  border: 0;
  border-radius: var(--bbs-radius-sm);
  background: transparent;
  color: var(--bbs-ink-soft);
  font-size: 12px;
  cursor: pointer;
}
.bbs-kind.is-on {
  background: var(--bbs-surface);
  color: var(--bbs-accent);
  box-shadow: 0 1px 2px oklch(0 0 0 / 0.08);
}
.bbs-plan-group {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-top: 14px;
}
/* хНбчЙЗчлЦцОТ:цаЗчн╛шбМхЬиф╕К(ч▒╗хЮЛшНпф╕╕ + хП│ф╛зх░ПхИащЩдщФо),хЖЕхо╣хНац╗бцХ┤хо╜хЬиф╕Л */
.bbs-plan {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 10px 12px;
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius);
  background: var(--bbs-surface);
}
/* цаЗчн╛шбМ:ч▒╗хЮЛшНпф╕╕щЭах╖ж,хИащЩдщФоцОихИ░цЬАхП│ */
.bbs-plan-head {
  display: flex;
  align-items: center;
  gap: 8px;
}
/* ч▒╗хЮЛцаЗчн╛:х░ПшНпф╕╕,чФищвЬшЙ▓хМ║хИЖшобхИТ/цВмх┐╡ */
.bbs-plan-kind {
  flex: 0 0 auto;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.02em;
  padding: 2px 9px;
  border-radius: var(--bbs-radius-pill);
}
.bbs-plan-kind.plan {
  color: var(--bbs-accent);
  background: var(--bbs-accent-soft);
}
.bbs-plan-kind.suspense {
  color: var(--bbs-warning);
  background: var(--bbs-warning-soft);
}
/* це╝х▒ВхП╖:хИЫх╗║шпешобхИТ/цВмх┐╡цЧ╢цЙАхЬице╝х▒В,цППш╛╣хоЪф╜НцаЗчн╛;ф╕ОцСШшжБхИЧшби #це╝х▒В хРМцм╛шзВцДЯ */
.bbs-plan-floor {
  flex: 0 0 auto;
  font-size: 11px;
  font-weight: 600;
  color: var(--bbs-ink-soft);
  background: var(--bbs-surface-2);
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius-sm);
  padding: 1px 7px;
  font-variant-numeric: tabular-nums;
}
/* хКиф╜Ьч╗Д(ч╝Цш╛С/хИащЩд)цОихИ░цЬАхП│;х╣│цЧ╢ф╜Ош░Г,цбМщЭв hover/шБЪчДжшпехНбцЙНц╡очО░ */
.bbs-plan-acts {
  margin-left: auto;
  flex: 0 0 auto;
  display: inline-flex;
  gap: 2px;
  opacity: 0;
  transition: opacity 0.15s;
}
.bbs-plan:hover .bbs-plan-acts,
.bbs-plan:focus-within .bbs-plan-acts {
  opacity: 1;
}
/* хНХф╕кхКиф╜ЬщФо:х░ПшАМ muted */
.bbs-plan-act {
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  padding: 0;
  border: 0;
  border-radius: var(--bbs-radius-sm);
  background: transparent;
  color: var(--bbs-ink-muted);
  font-size: 13px;
  cursor: pointer;
  transition: color 0.15s, background 0.15s;
}
.bbs-plan-act:hover {
  color: var(--bbs-accent);
  background: var(--bbs-surface-2);
}
.bbs-plan-del:hover {
  color: var(--bbs-danger);
  background: var(--bbs-danger-soft);
}
/* хЖЕхо╣:чЛмхНацХ┤хо╜,шЗкчД╢цНвшбМ */
.bbs-plan-content {
  margin: 0;
  font-size: 14px;
  line-height: 1.55;
  color: var(--bbs-ink);
  word-break: break-word;
}
/* шобхИТцЧ╢щЧ┤:члЛф║О/чЫоцаЗ ф╕дцЮЪх░ПцаЗчн╛,цППш╛╣ф╜Ош░Г,чЫоцаЗчФих╝║ш░ГшЙ▓хМ║хИЖ */
.bbs-plan-times {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}
.bbs-plan-time {
  font-size: 11px;
  color: var(--bbs-ink-soft);
  background: var(--bbs-surface-2);
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius-sm);
  padding: 1px 7px;
}
.bbs-plan-time-target {
  color: var(--bbs-accent);
  border-color: var(--bbs-accent);
}
.bbs-plan-empty {
  margin: 14px 0 0;
  font-size: 13px;
  color: var(--bbs-ink-muted);
}

/* тАФтАФ х╜УхЙНчК╢цАБ тАФтАФ */
.bbs-state {
  display: flex;
  flex-wrap: wrap;
  gap: 10px 20px;
  margin-top: 12px;
}
.bbs-state-item {
  display: flex;
  align-items: center;
  gap: 8px;
}
.bbs-state-key {
  font-size: 11px;
  color: var(--bbs-accent);
  border: 1px solid var(--bbs-accent);
  border-radius: var(--bbs-radius-pill);
  padding: 1px 8px;
}
.bbs-state-val {
  font-size: 14px;
  color: var(--bbs-ink);
}

.bbs-error {
  margin: 12px 0 0;
  font-size: 12px;
  color: var(--bbs-danger);
}

/* тАФтАФ члЛхН│цА╗ч╗УцМЙщТо:цСШшжБцаЗщвШхП│ф╛зчЪДцмбч║зцУНф╜Ь,х░Пф╕АхП╖,х╕жхЫ╛цаЗ тАФтАФ */
.bbs-resummary-btn {
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 11px;
  font-size: 12px;
}
/* хдНчФицЬкцСШшжБце╝х▒ВчЪДцЧЛш╜мчОп(.bbs-pending-spin),цндхдДх╛ош░Гх░║хп╕ш┤┤хРИцМЙщТоцЦЗхнЧ */
.bbs-resummary-btn .bbs-pending-spin {
  width: 12px;
  height: 12px;
}
.bbs-resummary-hint {
  margin: 10px 0 0;
  font-size: 12px;
  color: var(--bbs-ink-soft);
}

/* тАФтАФ цЬкцСШшжБце╝х▒В:х╛ЕхКЮщЭвцЭ┐,чФих╝║ш░ГшЙ▓цППш╛╣чЪДхНбчЙЗцбЖш╡╖цЭе,цПРчд║уАМш┐Щф║Ыце╝ш┐Шц▓бцСШуАН тАФтАФ */
.bbs-pending {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-top: 14px;
  padding: 12px 14px;
  border: 1px solid var(--bbs-accent);
  border-radius: var(--bbs-radius);
  background: var(--bbs-accent-soft);
}
/* цаЗщвШшбМ:цаЗчн╛щЭах╖ж,цЙ╣щЗПшбецСШцМЙщТо/ш┐Ых║жцОихИ░хП│ф╛з */
.bbs-pending-head {
  display: flex;
  align-items: center;
  gap: 10px;
}
.bbs-pending-label {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-size: 13px;
  font-weight: 600;
  color: var(--bbs-accent);
}
/* цЙ╣щЗПшбецСШцМЙщТо:цОихИ░цаЗщвШшбМцЬАхП│,х░Пф╕АхП╖х╕жхЫ╛цаЗ */
.bbs-batch-btn {
  margin-left: auto;
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 5px 11px;
  font-size: 12px;
}
/* цЙ╣щЗПш┐ЫшбМф╕нчЪДш┐Ых║жхЭЧ:цЧЛш╜мчОп + ш┐Ых║жцЦЗхнЧ + хПЦц╢ИщФо */
.bbs-batch-progress {
  margin-left: auto;
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  font-weight: 600;
  color: var(--bbs-accent);
  font-variant-numeric: tabular-nums;
}
.bbs-batch-progress .bbs-pending-spin {
  width: 12px;
  height: 12px;
}
.bbs-batch-cancel {
  padding: 3px 9px;
  border: 1px solid var(--bbs-line-strong);
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-surface);
  color: var(--bbs-ink-soft);
  font-size: 11px;
  cursor: pointer;
  transition: color 0.15s, border-color 0.15s, background 0.15s;
}
.bbs-batch-cancel:hover:not(:disabled) {
  color: var(--bbs-danger);
  border-color: var(--bbs-danger);
  background: var(--bbs-danger-soft);
}
.bbs-batch-cancel:disabled {
  opacity: 0.55;
  cursor: default;
}
/* цаЗчн╛хРОш╖Яф╕АцЮЪшобцХ░х░ПчВ╣,х╝║хМЦуАМцЬЙ N це╝х╛ЕхКЮуАН */
.bbs-pending-label::after {
  content: attr(data-count);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 18px;
  padding: 0 5px;
  border-radius: var(--bbs-radius-pill);
  background: var(--bbs-accent);
  color: var(--bbs-accent-ink);
  font-size: 11px;
  font-variant-numeric: tabular-nums;
}
.bbs-pending-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}
.bbs-pending-chip {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 40px;
  height: 28px;
  padding: 0 9px;
  border: 1px solid var(--bbs-accent);
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-surface);
  color: var(--bbs-accent);
  font-size: 12px;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
  cursor: pointer;
  transition: color 0.15s, background 0.15s;
}
.bbs-pending-chip:hover:not(:disabled) {
  color: var(--bbs-accent-ink);
  background: var(--bbs-accent);
}
.bbs-pending-chip:disabled {
  opacity: 0.55;
  cursor: default;
}
/* чФЯцИРф╕н:х░ПцЧЛш╜мчОпцЫ┐ф╗гце╝х▒ВхП╖ */
.bbs-pending-spin {
  width: 13px;
  height: 13px;
  border: 2px solid var(--bbs-line-strong);
  border-top-color: var(--bbs-accent);
  border-radius: 50%;
  animation: bbs-pending-rot 0.7s linear infinite;
}
@keyframes bbs-pending-rot {
  to {
    transform: rotate(360deg);
  }
}

/* тАФтАФ хИЖчлахИЖщЪФ:шобхИТ/цВмх┐╡ ф╕О цСШшжБ ф╕дхМ║ф╣ЛщЧ┤чЪДцШОчбочХМч║┐ тАФтАФ */
/* ф╕дф╛зч╗Жч║┐хЬиф╕нщЧ┤цЦнх╝А,х╡Мф╕АцЮЪщЗСшЙ▓х░ПшП▒х╜втАФтАФхПдч▒НхИЖчлачЪДщ▒╝х░╛цаЗшо░,хС╝х║Фч║╕хвиф╕╗щвШ */
.bbs-divider {
  display: flex;
  align-items: center;
  gap: 14px;
  margin: 26px 0;
}
.bbs-divider::before,
.bbs-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--bbs-line-strong);
}
.bbs-divider-mark {
  flex: 0 0 auto;
  width: 7px;
  height: 7px;
  transform: rotate(45deg);
  background: var(--bbs-accent);
  border-radius: 1px;
}

/* тАФтАФ цСШшжБхИЧшби тАФтАФ */
.bbs-summary-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-top: 14px;
}
.bbs-summary-card {
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius);
  background: var(--bbs-surface);
  padding: 14px 16px;
}
.bbs-summary-card.is-deep {
  border-left: 3px solid var(--bbs-accent);
}
.bbs-summary-card.is-stale {
  opacity: 0.6;
}
.bbs-summary-stale {
  font-size: 11px;
  color: var(--bbs-warning);
  background: var(--bbs-warning-soft);
  border-radius: var(--bbs-radius-sm);
  padding: 2px 8px;
}
.bbs-summary-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
  flex-wrap: wrap;
}
/* ч╗Эхп╣цЧ╢щЧ┤ф╜ЬщвШщжЦцЦЗцЬм,line-height:1 шойхоГф╕ОхРМшбМчнЙщлШцаЗчн╛чЪДшзЖшзЙф╕нх┐Гхп╣щ╜Р */
.bbs-summary-dateline,
.bbs-summary-time {
  line-height: 1;
}
/* цСШшжБщвШщжЦ:цХЕф║ЛхЖЕцЧ╢щЧ┤хНЗф╕║ф╕╗цаЗщвШ,чиНхдзуАБхНКч▓ЧуАБtabular цХ░хнЧхГПш┤жхЖМцЧецЬЯ */
.bbs-summary-dateline {
  font-size: 14px;
  font-weight: 600;
  color: var(--bbs-ink);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.01em;
}
/* цаЗчн╛ф╕Оце╝х▒ВхП╖:щлШх║жф╕АшЗ┤(хРМ height + х▒Еф╕н);це╝х▒ВхП╖цЬАх░Пхо╜ = цСШшжБцаЗчн╛хо╜,цХ░хнЧхПШщХ┐хЖНцТСх╝А */
.bbs-summary-badge,
.bbs-summary-loc {
  box-sizing: border-box;
  height: 22px;
  min-width: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0 8px;
  font-size: 11px;
  font-weight: 600;
  border-radius: var(--bbs-radius-sm);
}
.bbs-summary-badge {
  color: var(--bbs-accent-ink);
  background: var(--bbs-accent);
  border: 1px solid var(--bbs-accent); /* ф╕О loc хРМца╖цЬЙ 1px ш╛╣цбЖ,ф┐ЭшпБф╕дшАЕчнЙщлШ */
}
/* це╝х▒ВхП╖/цФ╢ч║│цХ░:цППш╛╣хоЪф╜НцаЗчн╛;tabular цХ░хнЧхп╣щ╜РуАВ
   ф╕НхКа margin тАФтАФ хоГф╝ЪцККцХ┤ф╕кчЫТхнРф╕ЛцОиуАБф╕ОхРМшбМчЪДчЫ╕хп╣цЧ╢щЧ┤цаЗчн╛щФЩф╜Н;чЫТхнРхп╣щ╜Рф╝ШхЕИф║ОхнЧх╜вх╛ош░ГуАВ */
.bbs-summary-loc {
  color: var(--bbs-ink-soft);
  background: var(--bbs-surface-2);
  border: 1px solid var(--bbs-line);
  font-variant-numeric: tabular-nums;
}
.bbs-summary-time {
  font-size: 12px;
  color: var(--bbs-ink-soft);
}
/* чЫ╕хп╣цЧ╢щЧ┤(цШихдй/3хдйхЙНтАж):хБЪцИРчнЙщлШх░ПцаЗчн╛,ф╕Оце╝х▒ВшНпф╕╕хРМщлШ,щЭачЫТхнРх▒Еф╕н,хЕНхО╗ CJK хнЧх╜вхЯ║ч║┐ф╕Лц▓ЙуАВ
   х╝║ш░ГшЙ▓цППш╛╣хблхЕЕ,хМ║хИлф║ОчБ░х║ХчЪДце╝х▒ВшНпф╕╕уАВ */
.bbs-summary-rel {
  box-sizing: border-box;
  height: 22px;
  display: inline-flex;
  align-items: center;
  padding: 0 8px;
  font-size: 11px;
  font-weight: 600;
  border-radius: var(--bbs-radius-sm);
  color: var(--bbs-accent);
  background: var(--bbs-accent-soft);
  border: 1px solid var(--bbs-accent);
}
/* хКиф╜Ьч╗ДщЭахП│;х╣│цЧ╢щЪРш║л,hover/шБЪчДжшпехНбцЙНц╡очО░ */
.bbs-summary-acts {
  margin-left: auto;
  display: inline-flex;
  gap: 2px;
  opacity: 0;
  transition: opacity 0.15s;
}
.bbs-summary-card:hover .bbs-summary-acts,
.bbs-summary-card:focus-within .bbs-summary-acts {
  opacity: 1;
}
.bbs-summary-act {
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  padding: 0;
  border: none;
  background: transparent;
  color: var(--bbs-ink-muted);
  border-radius: var(--bbs-radius-sm);
  cursor: pointer;
  transition: color 0.15s, background 0.15s;
}
.bbs-summary-act:hover {
  color: var(--bbs-accent);
  background: var(--bbs-surface-2);
}
.bbs-summary-del:hover {
  color: var(--bbs-danger);
  background: var(--bbs-danger-soft);
}
.bbs-summary-text {
  margin: 0;
  font-size: 13px;
  line-height: 1.8;
  letter-spacing: 0.025em;
  color: var(--bbs-ink-soft);
  white-space: pre-wrap;
}

.bbs-empty {
  flex: 1;
}

/* тАФтАФ ч╝Цш╛Сх╝╣чкЧ:хдЦхг│ца╖х╝Пх╖▓цПРхИ░ base.css щАЪчФи,ш┐ЩщЗМхПкшбецЬмщб╡ф╕УчФичЪД textarea тАФтАФ */
.bbs-modal-textarea {
  resize: vertical;
  min-height: 120px;
  line-height: 1.6;
  font-family: var(--bbs-font-sans);
}

/* ============ шзжх▒П:ц▓бцЬЙ hover,хКиф╜ЬщФох╕╕цШ╛ф╜Жф╜Ош░Г(щЭЮхдзшЙ▓хЭЧ) ============ */
@media (hover: none) {
  /* шзжх▒ПчЬЛф╕НхИ░ hover ц╡очО░,ч╝Цш╛С/хИащЩдщФох┐Ещб╗х╕╕цШ╛тАФтАФф╜Жф┐ЭцМБх░ПшАМ muted,ф╕НхЦзхо╛хд║ф╕╗ */
  .bbs-plan-acts,
  .bbs-summary-acts {
    opacity: 1;
  }
  /* шзжш╛╛хМ║чХецФ╛хдзхИ░ ~32px(хдЯчВ╣),хЫ╛цаЗч╗┤цМБх░Пх╖з;ф╕НхЖНцШп 40├Ч40 чЪДх╕╕ф║охдзхЭЧ */
  .bbs-plan-act,
  .bbs-summary-act {
    width: 32px;
    height: 32px;
    font-size: 15px;
  }
  .bbs-summary-act {
    color: var(--bbs-ink-muted);
  }
}

/* ============ чкДх▒П:ч▒╗хЮЛхИЗцНвцТСц╗буАБчК╢цАБцЭбцХ┤щ╜Р ============ */
@media (max-width: 640px) {
  /* ц╖╗хКах╝╣чкЧщЗМчЪДч▒╗хЮЛхИЗцНв:шобхИТ | цВмх┐╡ хРДхНаф╕АхНК,цТСц╗бцХ┤шбМ */
  .bbs-kind-toggle {
    width: 100%;
  }
  .bbs-kind {
    flex: 1;
  }

