export function fmtItems(items: BuildArgs['items']): string {
  if (!items.length) return '  (цЧа)';
  return items
    .map(i => {
      const qty = typeof i.qty === 'number' ? ` ├Ч${i.qty}` : '';
      const desc = i.desc ? ` тАФтАФ ${i.desc}` : '';
      // щЪПш║л/хнШцФ╛хЬ░цаЗц│и:щЪПш║л(щ╗Шшод)ф╕НцаЗ,щЭЮщЪПш║лцаЗ [хнШ:хЬ░чВ╣],шой AI чЯещБУчО░чК╢ф╗еф╛┐цнгчбочз╗хКичЙйхУБ
      const place = i.carried === false ? ` [хнШ:${i.location || 'цЯРхдД'}]` : '';
      return `  - ${i.name}${qty}${place}${desc}`;
    })
    .join('\n');
}

