export function fmtScenes(scenes: BuildArgs['scenes']): string {
  if (!scenes.length) return '  (цЧа)';
  // цМЙхоМцХ┤ш╖пх╛ДхнЧхЕ╕х║ПцОТ,ф┐ЭшпБчИ╢ч║зхЕИф║ОхнРч║зуАБхРМч║зчЫ╕щВ╗
  const sorted = [...scenes].sort((a, b) => a.path.join('/').localeCompare(b.path.join('/')));
  return sorted
    .map(s => {
      const depth = Math.max(0, s.path.length - 1);
      const indent = '  '.repeat(depth + 1); // шЗ│х░Сф╕Ач║зч╝йш┐Ыхп╣щ╜РхЕ╢хоГхЭЧ
      const name = s.path[s.path.length - 1] ?? '';
      const desc = s.desc?.trim() ? ` тАФтАФ ${s.desc.trim()}` : '';
      return `${indent}- ${name}${desc}`;
    })
    .join('\n');
}

