  char: string;
  /** ш┐ЩцЙ╣це╝х▒Вх╝Ахд┤ф╣ЛхЙНчЪДх╖▓чЯецЧ╢щЧ┤(хПкшп╗шГМцЩп,х╕о AI цОичоЧхРДце╝цЧ╢щЧ┤) */
  time: string;
  /** ш┐ЩцЙ╣це╝х▒Вх╝Ахд┤ф╣ЛхЙНчЪДх╖▓чЯехЬ░чВ╣(хПкшп╗шГМцЩп) */
  location: string;
  history: string;
  /** хдЪце╝цЛ╝цОецнгцЦЗ(цпПце╝хЙНх╕жуАМтФБтФБ чмм n це╝ тФБтФБуАНхИЖщЪФ) */
  content: string;
