/**
 * ф║МцмбцА╗ч╗УчЫоцаЗхнЧцХ░:хПВф╕ОхЖЕхо╣цА╗хнЧцХ░ ├Ч ч│╗цХ░,ф╜Ьф╕║хКицАБчпЗх╣Еф╕ЛщЩР;хЖНщТ│ф╕Аф╕кф┐Эх║Хф╕ЛщЩР,
 * щБ┐хЕНш╛УхЕех╛ИчЯнцЧ╢чЫоцаЗш┐Зх░Пхд▒хО╗цДПф╣ЙуАВч│╗цХ░ф╕Оф┐Эх║ХщЪПхнЧцХ░цбгф╜НхИЗцНв(шпжч╗Ж ├Ч0.5/ф┐Эх║Х800,ч▓╛чоА ├Ч0.35/ф┐Эх║Х400)уАВ
 */
export function resummary2Target(contentLen: number): number {
  const v = currentVerbosity();
  return Math.max(v.resummary2Floor, Math.round(contentLen * v.resummary2Ratio));
}

/**
 * цЮДщАацА╗ч╗УцПРчд║шпНуАВцМЙх▒Вч║зхИЖф╕дхеЧ:
 *  - level<=1(L0 хП╢хнР тЖТ L1):цЩощАЪцА╗ч╗У,хЫ║хоЪхнЧцХ░ тЖТ RESUMMARY_PROMPTуАВ
 *  - level>=2(L1+ тЖТ цЫ┤ф╕Кх▒В):ф║МцмбцА╗ч╗У,чЫоцаЗхнЧцХ░щЪПш╛УхЕешзДцибхКицАБч╗Щ тЖТ RESUMMARY2_PROMPTуАВ
 * хРДшЗкф╝ШхЕИчФихп╣х║ФчЪДшЗкхоЪф╣ЙцибцЭ┐,чй║хИЩхЫЮщААхЖЕч╜оуАВхнЧцХ░щЪПцбгф╜Н(шпжч╗Ж/ч▓╛чоА)хИЗцНвуАВ
 */
export function buildResummaryPrompt(
  a: Pick<BuildArgs, 'user' | 'char' | 'content'> & { level: number },
): string {
  const isSecond = a.level >= 2;
  const tpl = isSecond
    ? apiSettings.prompts.resummary2.trim() || RESUMMARY2_PROMPT
    : apiSettings.prompts.resummary.trim() || RESUMMARY_PROMPT;
  return fill(tpl, {
    user: a.user || 'ф╕╗шзТ',
    char: a.char || 'шзТшЙ▓',
    content: a.content,
    resummary_words: currentVerbosity().resummaryWords,
    target: isSecond ? String(resummary2Target(a.content.length)) : '',
  });
}

/** цККф╕ЦчХМф╣жшо╛хоЪхМЕцИРчЛмчлЛ system ц╢ИцБпчЪДхЖЕхо╣(чй║шо╛хоЪцЧ╢ш░ГчФицЦ╣х║Фш╖│ш┐З) */
