// ш┐Щф╕дшбМшой Vite цККхЕих▒Аца╖х╝ПцЙУш┐Ы dist/index.css(щЪПхРОц│ихЕе shadow root)
import '@/styles/base.css';
import '@/styles/theme.css';
import { createApp } from 'vue';

const HOST_ID = 'bbs-app-host';

/**
 * чФЯцИРцЛжцИкхЩи:ST хЬицпПцмбчФЯцИРхЙНф╝Ъ await ш░ГчФи manifest.generate_interceptor цМЗхРНчЪДхЕих▒АхЗ╜цХ░,
 * чн╛хРН (chat, contextSize, abort, type),ш░Г abort(true) хН│ф╕нцнвцЬмцмбчФЯцИРуАВ
 * ш┐ЩщЗМхзФцЙШч╗Щх╝ХцУОхИдцЦнуАМчзпхОЛце╝х▒Вш┐ЗхдЪуАНх╣╢цМЙщЬАцЛжцИк + цПТцПРчд║це╝уАВцМВхЬи globalThis ф╕Кф╛Ы ST цЙ╛хИ░уАВ
 */
(globalThis as Record<string, unknown>).bbs_generateInterceptor = async (
  _chat: unknown,
  _contextSize: number,
  abort: (immediately: boolean) => void,
  type: string | undefined,
): Promise<void> => {
  try {
    // хЕИш╡░чзпхОЛцЛжцИк:ш┐ФхЫЮ true = х╖▓ abort цЬмцмбчФЯцИР,цЧащЬАхПмхЫЮ(чФЯцИРф╕Нф╝ЪхПСчФЯ)уАВ
    const intercepted = await handleGenerationIntercept(type, abort);
    // цФ╛шбМф╕Фшпеч▒╗хЮЛщЬАшжБхПмхЫЮ тЖТ щШ╗хбЮх╝ПхРСщЗПхПмхЫЮ(хЖЩц│ихЕецз╜хРОхЖНцФ╛шбМчФЯцИР)уАВ
    // хПмхЫЮхЖЕщГишЗкх╕жхРСщЗПх╝АхЕ│/хПпчФицАзхИдцЦн,хд▒ш┤ещЭЩщ╗ШщЩНч║з,ч╗Эф╕Нх╜▒хУНчФЯцИРуАВ
    if (!intercepted && shouldRecallForType(type)) {
      await runVectorRecall();
    }
  } catch (e) {
    console.error('[цЯПхоЭф╣ж] чФЯцИРцЛжцИкхЩих╝Вх╕╕(цФ╛шбМцЬмцмбчФЯцИР)', e);
  }
};

/**
 * хПпч╗зцЙ┐чЪДцОТчЙИх▒ЮцАзтАФтАФshadow DOM ф╕НщЪФчж╗ч╗зцЙ┐,ш┐Щф║Ыф╝ЪщАПш┐З host ф╗О ST ц╝Пш┐ЫцЭеуАВ
 * хЬи host ф╕КчФихЖЕшБФ !important щТЙцн╗,ф╗Оца╣ф╕КхИЗцЦнч╗зцЙ┐щУ╛уАВ
 */
const INHERITED_RESET: Record<string, string> = {
  'font-family':
    "'MiSans','HarmonyOS Sans SC','PingFang SC','Microsoft YaHei',-apple-system,BlinkMacSystemFont,'Segoe UI','Inter',system-ui,sans-serif",
  'font-size': '14px',
  'font-weight': '400',
  'font-style': 'normal',
  'font-variant': 'normal',
  'line-height': '1.6',
  'letter-spacing': 'normal',
  'word-spacing': 'normal',
  'text-align': 'left',
  'text-transform': 'none',
  'text-indent': '0',
  'text-shadow': 'none',
  'white-space': 'normal',
  color: '#1c242c',
  direction: 'ltr',
};

function mount() {
  // host хЕГч┤ачХЩхЬи ST чЪД light DOM,Vue х║ФчФицХ┤ф╜Уц┤╗хЬихоГчЪД shadow root щЗМуАВ
  let host = document.getElementById(HOST_ID);
  if (!host) {
    host = document.createElement('div');
    host.id = HOST_ID;
    document.body.appendChild(host);
  }

  // host ф╕НхПВф╕Ох╕Гх▒А(чкЧхПгхЖЕщГичФи fixed хоЪф╜Н),х╣╢хИЗцЦнч╗зцЙ┐
  host.style.setProperty('display', 'contents', 'important');
  for (const [prop, value] of Object.entries(INHERITED_RESET)) {
    host.style.setProperty(prop, value, 'important');
  }

  const shadow = host.shadowRoot ?? host.attachShadow({ mode: 'open' });
  shadow.textContent = '';

  // цККцИСф╗мцЮДх╗║хЗ║чЪД dist/index.css ф╗е <link> ц│ихЕе shadow rootтАФтАФ
  // ш┐Щца╖ца╖х╝ПхПкхЬиш┐Щцг╡ shadow цаСхЖЕчФЯцХИ,ST хЕих▒Аца╖х╝Пш┐Ыф╕НцЭе,цИСф╗мчЪДф╣ЯхЗ║ф╕НхО╗уАВ
  const link = document.createElement('link');
  link.rel = 'stylesheet';
  // index.js ф╕О index.css хЬи dist хРМч║з,цНох╜УхЙНцибхЭЧ URL цОихп╝,щГич╜▓ш╖пх╛ДцЧахЕ│уАВ
  link.href = new URL('./index.css', import.meta.url).href;
  shadow.appendChild(link);

  const container = document.createElement('div');
  shadow.appendChild(container);

  const app = createApp(App);
  app.mount(container);

  $(window).on('pagehide', () => app.unmount());
}

$(() => {
  mount();
  injectMenuButton();
  // щб╢цаПх┐лщАЯцЙУх╝АцМЙщТо:цМЙх╝АхЕ│ц│ихЕе/чз╗щЩдуАВwatch хЬих╝АхЕ│хПШхМЦ(хРл hydrate хЫЮчБМчЬЯхА╝)цЧ╢хРМцнеуАВ
  syncTopBarButton(ui.showTopBar);
  watch(
    () => ui.showTopBar,
    on => syncTopBarButton(on),
  );
  // шБКхдйцбЖх┐лщАЯхЫЮхдНх╝ПцМЙщТо:хРМф╕КшМГх╝П
  syncQuickReplyButton(ui.showQuickReply);
  watch(
    () => ui.showQuickReply,
    on => syncQuickReplyButton(on),
  );
  // шо░х┐Жч│╗ч╗Я:чнЙ ST чЪД getContext х░▒ч╗кхРОхЖНч╗СхоЪ(хКаш╜╜щб║х║Пф╕НчбохоЪцЧ╢ш╜ошпв)
  bindMemoryWhenReady();
});

function bindMemoryWhenReady(attempt = 0) {
  if (window.SillyTavern?.getContext) {
    try {
      console.log('[цЯПхоЭф╣ж] хРпхКищУ╛х╝АхзЛч╗СхоЪ(getContext х░▒ч╗к)');
      // шо╛ч╜охЕИ hydrate:ф╗О extension_settings ш╜╜хЕе(цИЦф╗ОцЧз localStorage ш┐Бчз╗),ф╣ЛхРОцЙНш╖ишо╛хдЗхРМцне
      hydrateSettings();
      bindChatLifecycle();
      bindEngine();
      // цЧ╢щЧ┤цаЗчн╛:цМЙх╝АхЕ│ц│ихЖМ/чз╗щЩд ST щЪРшЧПцнгхИЩ(х╣ВчнЙ;х╝АхЕ│хПШхМЦчЪДхРОч╗нхРМцнехЬи bindEngine чЪД watch щЗМ)
      syncTimeTagRegex();
      // щжЦх▒П:цККх╜УхЙНшБКхдйх╖▓цЬЙчЪДшо░х┐ЖцМВф╕Кц│ихЕе
      refreshInjection();
      // хРОхП░цгАц╡ЛцЫ┤цЦ░(хоЮцЧ╢цпФхп╣цЬмхЬ░/ш┐Ьчлп manifest чЙИцЬм;хд▒ш┤ещЭЩщ╗Ш,ф╕НщШ╗цЦнхРпхКи)
      void checkForUpdate();
      console.log('[цЯПхоЭф╣ж] хРпхКищУ╛ч╗СхоЪхоМцИР');
    } catch (e) {
      console.error('[цЯПхоЭф╣ж] шо░х┐Жч│╗ч╗Яч╗СхоЪхд▒ш┤е', e);
    }
    return;
  }
  if (attempt > 40) return; // цЬАхдЪч║ж 20s
  setTimeout(() => bindMemoryWhenReady(attempt + 1), 500);
}
