/**
 * хнЧф╜УхЫ╛цаЗхЕЬх║Х:цЬЙф║ЫщЕТщжЖч╛ОхМЦф╕╗щвШф╝ЪцККщб╢цаП/шБКхдйцбЖщЗМ .drawer-icon.fa-solid::before(цИЦч▒╗ф╝╝)
 * чЪДхнЧф╜УхЫ╛цаЗц╕Ечй║(content:''уАБcolor:transparentуАБfont-size:0),цФ╣чФи background-image цМЙ
 * **цпПф╕кцМЙщТо id** хНХчЛмш┤┤шЗкхоЪф╣ЙхЫ╛цаЗуАВцИСф╗мц│ихЕечЪДцМЙщТоф╕НхЬихоГф╗мхРНхНХщЗМ,ф╝ЪхПШцИРф╕АчЙЗчй║чЩ╜уАВ
 *
 * ш┐ЩщЗМчФицЫ┤щлШчЙ╣х╝ВцАз(чеЦхЕИ id + шЗкш║л id)+ !important хОЛш┐ЗщВгцЭбщАЪчФишзДхИЩ,х╝║хИ╢ш┐ШхОЯхнЧх╜вуАВ
 * \e0bb = fa-book-bookmark чЪД Unicode(хПЦшЗк ST чЪД fontawesome.min.css,хИлхЗншо░х┐ЖчМЬ)уАВ
 *
 * хРДц│ихЕечВ╣хЕ▒чФицндхЗ╜цХ░:ф╝ахЕешЗкш║лцМЙщТо id ф╕ОхЫ╛цаЗхЕГч┤ачЪДщАЙцЛйхЩи,чФЯцИРф╕Ацо╡ф╕АцмбцАз <style>уАВ
 */
const BOOK_BOOKMARK = '\\e0bb';
const injected = new Set<string>();

/**
 * чбоф┐ЭцЯРцМЙщТочЪДхЫ╛цаЗхЕЬх║Хца╖х╝Пх╖▓ц│ихЕе(цМЙ styleId хО╗щЗН,хПпщЗНхдНш░ГчФи)уАВ
 * @param styleId   <style> хЕГч┤ачЪД id(хО╗щЗНщФо)
 * @param selector  хС╜ф╕ншпецМЙщТохЫ╛цаЗ ::before чЪДщлШчЙ╣х╝ВцАзщАЙцЛйхЩи(ф╕НхРл ::before)
 */
export function ensureIconFallback(styleId: string, selector: string): void {
  if (injected.has(styleId) || document.getElementById(styleId)) {
    injected.add(styleId);
    return;
  }
  const style = document.createElement('style');
  style.id = styleId;
  style.textContent = `
${selector}::before {
  content: '${BOOK_BOOKMARK}' !important;
  width: auto !important;
  height: auto !important;
  font-size: inherit !important;
  color: inherit !important;
  background: none !important;
}
`;
  document.head.appendChild(style);
  injected.add(styleId);
}
