import { apiSettings, onSettingsReady } from '@/api/settings';
import { reactive, watch } from 'vue';

/** хп╝шИкф╜Нч╜о:auto = PC щб╢щГиуАБчз╗хКичлпх║ХщГи */
export type NavPosition = 'top' | 'bottom' | 'auto';

/**
 * ф╕╗щвШуАВцЦ░хвЮф╕╗щвШхПкщЬА:
 *   1) theme.css щЗМхКаф╕АхеЧ .bbs-root[data-theme='xxx'] хПШщЗП;
 *   2) ш┐ЩщЗМч╗Щ ThemeName хКаф╕К 'xxx',х╣╢х╛А THEMES ц│ихЖМшбихКаф╕АцЭбуАВ
 * шо╛ч╜ощб╡ф╕ОщвШщжЦхИЗцНвцМЙщТощГ╜ф╗О THEMES шЗкхКишп╗хПЦ,цЧащЬАхЖНцФ╣хИлхдДуАВ
 */
export type ThemeName = 'day' | 'night' | 'pastel' | 'green';

export interface ThemeDef {
  value: ThemeName;
  label: string;
  /** Icon ч╗Дф╗╢хРН,шзБ components/Icon.vue */
  icon: string;
}

export const THEMES: ThemeDef[] = [
  { value: 'day', label: 'цЧещЧ┤', icon: 'sun' },
  { value: 'night', label: 'хдЬщЧ┤', icon: 'moon' },
  { value: 'pastel', label: 'ч▓Йх╜й', icon: 'sparkles' },
  { value: 'green', label: 'цЬичЩ╜', icon: 'sparkles' },
];

interface UiState {
  open: boolean;
  /** х╜УхЙНхИЖщб╡ id,хп╣х║Ф registry щЗМчЪД key */
  activePage: string;
  theme: ThemeName;
  navPosition: NavPosition;
  /** чз╗хКичлп:хЖНчВ╣х╜УхЙНщб╡хп╝шИкцМЙщТохН│хЕ│чкЧ(щ╗Шшодх╝А,цАХшппшзжхПпхЕ│) */
  navTapClose: boolean;
  /** хЬи ST щб╢цаПц│ихЕех┐лщАЯцЙУх╝АцМЙщТо(щ╗ШшодхЕ│) */
  showTopBar: boolean;
  /** шБКхдйцбЖф╕КцЦ╣х┐лщАЯхЫЮхдНх╝ПцМЙщТо(щ╗ШшодхЕ│) */
  showQuickReply: boolean;
  /** х▒Пх╣Хш╛╣ч╝ШцВмц╡очРГ(щ╗ШшодхЕ│) */
  showOrb: boolean;
  /** цВмц╡очРГшЗкхоЪф╣ЙхЫ╛цаЗ(ST цЬНхКбхЩихЫ╛чЙЗш╖пх╛Д;чй║=щ╗Шшодф╣жчн╛хЫ╛цаЗ) */
  orbImage: string;
  /** цВмц╡очРГх╜вчК╢:bookmark / circle / square */
  orbShape: OrbShape;
  /** цВмц╡очРГщЭЩцнвф╕НщАПцШОх║ж(чЩ╛хИЖцпФ 20тАУ100) */
  orbOpacity: number;
  /** цВмц╡очРГхЯ║хЗЖх░║хп╕(px,32тАУ80) */
  orbSize: number;
}

/** цВмц╡очРГх╜вчК╢ */
export type OrbShape = 'bookmark' | 'circle' | 'square';
export const ORB_SHAPES: { value: OrbShape; label: string }[] = [
  { value: 'bookmark', label: 'ф╣жчн╛' },
  { value: 'circle', label: 'хЬЖх╜в' },
  { value: 'square', label: 'цЦ╣х╜в' },
];
function validOrbShape(s: string): OrbShape {
  return s === 'bookmark' || s === 'circle' || s === 'square' ? s : 'bookmark';
}

// activePage(ф╕КцмбхБЬхЬихУкф╕Ащб╡)цШпч║пцЬмцЬ║ф╕┤цЧ╢хп╝шИкцАБ,ш╖ишо╛хдЗхРМцнецЧацДПф╣ЙуАБф╕Фч┐╗щб╡хН│хЫЮхЖЩцЬНхКбхЩихдкщвСч╣Б,
// цХЕф╗НхнШцЬмцЬ║ localStorage;ф╕╗щвШ/хп╝шИкф╜Нч╜оцШпчЬЯ┬╖шо╛ч╜о,цФ╣хнШш┐Ы apiSettings.ui(тЖТ ST ш╖ишо╛хдЗхРМцне)уАВ
const PAGE_STORAGE_KEY = 'bbs.ui.page.v1';

function loadActivePage(): string {
  try {
    return localStorage.getItem(PAGE_STORAGE_KEY) || 'summary';
  } catch {
    return 'summary';
  }
}

// ф╕╗щвШхРИц│ХцАзцабщкМ:apiSettings.ui.theme цШпшг╕хнЧчмжф╕▓,хПпшГ╜цЭешЗкцЧзчЙИцЬм/швлцЙЛцФ╣хЭП,шР╜хИ░ ui хЙНхЕИцабщкМуАВ
function validTheme(t: string): ThemeName {
  return THEMES.some(x => x.value === t) ? (t as ThemeName) : 'day';
}
function validNav(n: string): NavPosition {
  return n === 'top' || n === 'bottom' || n === 'auto' ? n : 'auto';
}

// хЕИчФи apiSettings х╜УхЙНхА╝х╗║ ui(import щШ╢цо╡хдЪф╕║щ╗Шшод;hydrate хоМцИРхРОчФ▒ onSettingsReady хЫЮчБМчЬЯхА╝)уАВ
export const ui = reactive<UiState>({
  open: false,
  activePage: loadActivePage(),
  theme: validTheme(apiSettings.ui.theme),
  navPosition: validNav(apiSettings.ui.navPosition),
  navTapClose: apiSettings.ui.navTapClose,
  showTopBar: apiSettings.ui.showTopBar,
  showQuickReply: apiSettings.ui.showQuickReply,
  showOrb: apiSettings.ui.showOrb,
  orbImage: apiSettings.ui.orbImage,
  orbShape: validOrbShape(apiSettings.ui.orbShape),
  orbOpacity: apiSettings.ui.orbOpacity,
  orbSize: apiSettings.ui.orbSize,
});

// settings ш╖ишо╛хдЗхРМцнехА╝х░▒ч╗кхРО,цККф╕╗щвШ/хп╝шИкхЫЮчБМш┐Ы ui(шжЖчЫЦ import щШ╢цо╡чЪДщ╗Шшод)
onSettingsReady(() => {
  ui.theme = validTheme(apiSettings.ui.theme);
  ui.navPosition = validNav(apiSettings.ui.navPosition);
  ui.navTapClose = apiSettings.ui.navTapClose;
  ui.showTopBar = apiSettings.ui.showTopBar;
  ui.showQuickReply = apiSettings.ui.showQuickReply;
  ui.showOrb = apiSettings.ui.showOrb;
  ui.orbImage = apiSettings.ui.orbImage;
  ui.orbShape = validOrbShape(apiSettings.ui.orbShape);
  ui.orbOpacity = apiSettings.ui.orbOpacity;
  ui.orbSize = apiSettings.ui.orbSize;
});

// ui цФ╣хПШ тЖТ хЖЩхЫЮ apiSettings.ui(чФ▒ settings чЪД watch щШ▓цКЦшР╜чЫШуАБш╖ишо╛хдЗхРМцне);activePage ф╗НхнШцЬмцЬ║уАВ
watch(
  () => [
    ui.theme,
    ui.navPosition,
    ui.navTapClose,
    ui.showTopBar,
    ui.showQuickReply,
    ui.showOrb,
    ui.orbImage,
    ui.orbShape,
    ui.orbOpacity,
    ui.orbSize,
  ],
  () => {
    apiSettings.ui.theme = ui.theme;
    apiSettings.ui.navPosition = ui.navPosition;
    apiSettings.ui.navTapClose = ui.navTapClose;
    apiSettings.ui.showTopBar = ui.showTopBar;
    apiSettings.ui.showQuickReply = ui.showQuickReply;
    apiSettings.ui.showOrb = ui.showOrb;
    apiSettings.ui.orbImage = ui.orbImage;
    apiSettings.ui.orbShape = ui.orbShape;
    apiSettings.ui.orbOpacity = ui.orbOpacity;
    apiSettings.ui.orbSize = ui.orbSize;
  },
);
watch(
  () => ui.activePage,
  () => {
    try {
      localStorage.setItem(PAGE_STORAGE_KEY, ui.activePage);
    } catch {
      /* localStorage ф╕НхПпчФицЧ╢щЭЩщ╗Ш */
    }
  },
);

/**
 * чкЧхПгцЬАш┐Сф╕АцмбцЙУх╝АчЪДцЧ╢щЧ┤цИ│уАВчФиф║ОхЬицЙУх╝АчЮмщЧ┤х┐╜чХещБоч╜йхЕ│щЧнтАФтАФ
 * чз╗хКичлпцЙУх╝АцЙЛхК┐цЬлх░╛хРИцИРчЪД click ф╝Ъчй┐щАПхИ░хИЪц╕▓цЯУчЪДщБоч╜й,щАацИР"чзТхЕ│"уАВ
 */
export let lastOpenedAt = 0;

export function openBook(page?: string) {
  if (page) ui.activePage = page;
  ui.open = true;
  lastOpenedAt = performance.now();
}

export function closeBook() {
  ui.open = false;
}

/** щвШщжЦцМЙщТо:хЬицЙАцЬЙх╖▓ц│ихЖМф╕╗щвШщЧ┤х╛кчОпхИЗцНв */
export function cycleTheme() {
  const i = THEMES.findIndex(t => t.value === ui.theme);
  ui.theme = THEMES[(i + 1) % THEMES.length].value;
}
