import { openBook } from '@/state/ui';
import { ensureIconFallback } from '@/st/iconFallback';

const BTN_ID = 'bbs-topbar-button';
const STYLE_ID = 'bbs-topbar-style';

function ensureStyle(): void {
  // ч╛ОхМЦф╕╗щвШхПпшГ╜ц╕Ечй║щб╢цаПхЫ╛цаЗхнЧх╜в,чФищлШчЙ╣х╝ВцАзщАЙцЛйхЩих╝║хИ╢ш┐ШхОЯ(шзБ iconFallback)
  ensureIconFallback(STYLE_ID, `#top-settings-holder #${BTN_ID} .drawer-icon.fa-solid`);
}

/**
 * х╛А ST щб╢цаП(#top-settings-holder)ц│ихЕеф╕Аф╕кх┐лщАЯцЙУх╝АцЯПхоЭф╣жчЪД drawer цМЙщТо,
 * ф╜Нч╜охЬиуАМчФицИ╖шо╛хоЪчобчРЖуАН(#persona-management-button)х╖жш╛╣уАВ
 *
 * ц│ихЕечЪДцМЙщТо**ф╕Нш┐Ы shadow DOM**тАФтАФчЫ┤цОечФи ST чЪД .drawer / .drawer-icon ч▒╗хРН,
 * ш╖ЯщЪПщЕТщжЖф╕╗щвШч╛ОхМЦуАВчВ╣хЗ╗хПкш┤Яш┤гцЙУх╝АцЯПхоЭф╣жчкЧхПг,ф╕Нх▒Хх╝Аф╗╗ф╜ХцК╜х▒Й(цХЕцЧа .drawer-toggle,
 * щБ┐хЕН ST чЪД doNavbarIconClick цККхоГх╜УцК╜х▒ЙцЭех╝АхРИ)уАВ
 *
 * хПЧшо╛ч╜ох╝АхЕ│цОзхИ╢:х╝А тЖТ чбоф┐Эх╖▓ц│ихЕе;хЕ│ тЖТ чз╗щЩдуАВш╜ошпвчнЙщб╢цаПхЗ║чО░(щб╢цаПцЗТхКаш╜╜)уАВ
 */
let pollTimer: ReturnType<typeof setInterval> | null = null;

function buildButton(): HTMLElement {
  const btn = document.createElement('div');
  btn.id = BTN_ID;
  btn.className = 'drawer';
  btn.innerHTML = `
    <div class="drawer-toggle">
      <div class="drawer-icon fa-solid fa-book-bookmark fa-fw closedIcon" title="цЯПхоЭф╣ж"></div>
    </div>
  `;
  // ф╗ЕцЙУх╝АчкЧхПг,ф╕Нш╡░ ST чЪДцК╜х▒Йх╝АхРИщА╗ш╛С(цХЕцЬкцМВ .drawer-toggle чЪД doNavbarIconClick)
  btn.querySelector('.drawer-toggle')?.addEventListener('click', e => {
    e.preventDefault();
    e.stopPropagation();
    openBook();
  });
  return btn;
}

/** чЬЯцнгцЙзшбМцПТхЕе:цИРхКЯцИЦх╖▓хнШхЬиш┐ФхЫЮ true,щб╢цаПцЬкх░▒ч╗кш┐ФхЫЮ false(чФ▒ш╜ошпвщЗНшпХ)уАВ */
function tryInject(): boolean {
  const holder = document.getElementById('top-settings-holder');
  if (!holder) return false;
  if (document.getElementById(BTN_ID)) return true;

  ensureStyle();
  const btn = buildButton();
  // цПТхИ░уАМчФицИ╖шо╛хоЪчобчРЖуАНх╖жш╛╣;хоГшЛеш┐Шц▓бц╕▓цЯУхИЩщААшАМцМВхИ░щб╢цаПцЬлх░╛уАВ
  const persona = document.getElementById('persona-management-button');
  if (persona) persona.before(btn);
  else holder.appendChild(btn);
  return true;
}

function removeButton(): void {
  document.getElementById(BTN_ID)?.remove();
}

/** цМЙх╝АхЕ│хРМцнещб╢цаПцМЙщТочЪДцЬЙцЧауАВх╝АхЕ│хПШхМЦцЧ╢ш░ГчФихН│хПп(х╣ВчнЙ)уАВ */
export function syncTopBarButton(enabled: boolean): void {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
  if (!enabled) {
    removeButton();
    return;
  }
  if (tryInject()) return;
  // щб╢цаПцЗТхКаш╜╜:ш╜ошпвчнЙхоГхЗ║чО░уАВщб╢цаПцШп index.html щЭЩцАБч╗УцЮД,щАЪх╕╕щжЦцмбхН│хС╜ф╕нуАБtimer ф╕НхРпхКи;
  // ф╕Зф╕АхзЛч╗Иф╕НхЗ║чО░,х░Бщб╢ ~20s(40 цмб)хРОцФ╛х╝Г,ч╗Эф╕Нх╕╕щй╗чй║ш╜м(хРМ index.ts чЪД bindMemoryWhenReady шМГх╝П)уАВ
  let attempts = 0;
  pollTimer = setInterval(() => {
    if (tryInject() || ++attempts > 40) {
      if (pollTimer) clearInterval(pollTimer);
      pollTimer = null;
    }
  }, 500);
}
