import { openBook } from '@/state/ui';

const BTN_ID = 'bbs-qr-button';
const BAR_CLASS = 'bbs-qr-bar'; // ф╗Ех╜У #qr--bar ф╕НхнШхЬицЧ╢,цИСф╗мшЗкх╗║чЪДцЭбхКаш┐Щф╕кцаЗшо░ч▒╗,ф╛┐ф║ОхЫЮцФ╢

/**
 * х╛АшБКхдйцбЖф╕КцЦ╣ц│ихЕеф╕Аф╕куАМцЯПхоЭф╣жуАНцМЙщТо,хдЦшзВф╕О ST хОЯчФЯх┐лщАЯхЫЮхдНцМЙщТо**хоМхЕиф╕АшЗ┤**уАВ
 *
 * хБЪц│ХчЕзцРмчЫ╕щВ╗цПТф╗╢ JS-Slash-Runner чЪДшМГх╝П(src/panel/script/use_button_destination_element.ts
 * ф╕О Script.vue):цМЙщТох░▒цШпф╕Аф╕к `<div class="qr--button menu_button interactable">цЦЗхнЧ</div>`,
 * хЖ│хоЪхдЦшзВчЪДцШп quick-reply цЙйх▒ХхоЪф╣ЙчЪД `.qr--button` ч▒╗тАФтАФцМВф╕КхоГхН│ф╕ОхОЯчФЯцМЙщТохРМцм╛,цЧащЬАхЫ╛цаЗуАБ
 * ф╕НхЖЩшЗкх╖▒чЪДца╖х╝П(шЗкх╖▒чФ╗/хПкш╣н menu_button щГ╜ф╝ЪхЫЫф╕НхГП,хоЮц╡Лш┐З)уАВ
 *
 * цМВш╜╜ч╗УцЮДхп╣щ╜РхОЯчФЯ:#qr--bar(х╖▓хнШхЬихИЩхдНчФи,хРжхИЩшЗкх╗║ф╕Аф╕к .flex-container.flexGap5 цЭб)
 *   тФФ .qr--buttons(хо╣хЩи)
 *       тФФ .qr--button(цИСф╗мчЪДцМЙщТо)
 *
 * хПЧшо╛ч╜ох╝АхЕ│цОзхИ╢:х╝А тЖТ чбоф┐Эх╖▓ц│ихЕе;хЕ│ тЖТ чз╗щЩдуАВш╜ошпвчнЙшБКхдйцбЖхЗ║чО░(SPA цЗТхКаш╜╜)уАВ
 *
 * ц│ицДП:.qr--button чЪДца╖х╝ПхЕищЭачеЦхЕИщАЙцЛйхЩи `#qr--bar > .qr--buttons .qr--button` чФЯцХИ,
 * цМЙщТо**х┐Ещб╗**шР╜хЬишпеч╗УцЮДхЖЕцЙНцЬЙхОЯчФЯхдЦшзВуАВшАМ ST чЪДх┐лщАЯхЫЮхдНф╝ЪхЬихИЗшБКхдй/цФ╣шо╛ч╜оцЧ╢щЗНх╗║ #qr--bar,
 * цККцИСф╗мчЪДцМЙщТоф╕Ах╣╢хЖ▓цОЙтАФтАФцХЕчФи MutationObserver чЫпф╜П #send_form,швлхЖ▓цОЙх░▒шбехЫЮ(хРМ JS-Slash-Runner)уАВ
 */
let pollTimer: ReturnType<typeof setInterval> | null = null;
let observer: MutationObserver | null = null;

/** хПЦ(цИЦх╗║)#qr--bar:ф╝ШхЕИхдНчФи ST хОЯчФЯщВгцЭб,ц▓бцЬЙцЙНшЗкх╗║ф╕АцЭбхРМцм╛уАВш┐ФхЫЮцМВцМЙщТочФичЪД .qr--buttons хо╣хЩиуАВ */
function ensureButtonHolder(sendForm: HTMLElement): HTMLElement {
  // id хФпф╕Ач║жцЭЯ,чФих▒ЮцАзчнЫщАЙшАМщЭЮ #qr--bar щАЙцЛйхЩи(хРМ JS-Slash-Runner чЪДхБЪц│Х)
  let bar = Array.from(sendForm.querySelectorAll('div')).find(d => d.id === 'qr--bar') as HTMLElement | undefined;
  if (!bar) {
    bar = document.createElement('div');
    bar.id = 'qr--bar';
    bar.className = `${BAR_CLASS} flex-container flexGap5`;
    sendForm.prepend(bar);
  }
  // хдНчФицЭбхЖЕх╖▓цЬЙчЪД .qr--buttons,ц▓бцЬЙх░▒х╗║ф╕Аф╕к(хОЯчФЯцЬкч╗ДхРИцибх╝ПцЧ╢хПпшГ╜ц▓бцЬЙ)
  let holder = bar.querySelector('.qr--buttons') as HTMLElement | null;
  if (!holder) {
    holder = document.createElement('div');
    holder.className = 'qr--buttons';
    bar.appendChild(holder);
  }
  return holder;
}

function buildButton(): HTMLElement {
  const btn = document.createElement('div');
  btn.id = BTN_ID;
  btn.className = 'qr--button menu_button interactable';
  btn.setAttribute('tabindex', '0');
  btn.title = 'цЙУх╝АцЯПхоЭф╣ж';
  btn.textContent = 'цЯПхоЭф╣ж';
  btn.addEventListener('click', e => {
    e.preventDefault();
    e.stopPropagation();
    openBook();
  });
  btn.addEventListener('keydown', e => {
    const k = (e as KeyboardEvent).key;
    if (k === 'Enter' || k === ' ') {
      e.preventDefault();
      openBook();
    }
  });
  return btn;
}

/** чЬЯцнгцЙзшбМцПТхЕе:цИРхКЯцИЦх╖▓хнШхЬиш┐ФхЫЮ true,шБКхдйцбЖцЬкх░▒ч╗кш┐ФхЫЮ false(чФ▒ш╜ошпвщЗНшпХ)уАВ */
function tryInject(): boolean {
  const sendForm = document.getElementById('send_form');
  if (!sendForm) return false;
  if (document.getElementById(BTN_ID)) return true;

  const holder = ensureButtonHolder(sendForm);
  holder.appendChild(buildButton());
  return true;
}

function removeButton(): void {
  document.getElementById(BTN_ID)?.remove();
  // шЛецШпцИСф╗мшЗкх╗║чЪДчй║ #qr--bar(хОЯчФЯц▓бцЬЙ QR),цМЙщТоцТдф║Жх░▒ф╕Ах╣╢хЫЮцФ╢,хИлчХЩчй║цЭб
  const bar = document.querySelector(`#qr--bar.${BAR_CLASS}`) as HTMLElement | null;
  if (bar && bar.querySelector('.qr--buttons')?.children.length === 0) bar.remove();
}

/** чЫпф╜П #send_form:ST щЗНх╗║ #qr--bar цККцИСф╗мчЪДцМЙщТохЖ▓цОЙцЧ╢,шбехЫЮ(х╣ВчнЙ,tryInject шЗкх╕жхнШхЬицгАцЯе)уАВ */
function startObserver(): void {
  if (observer) return;
  const sendForm = document.getElementById('send_form');
  if (!sendForm) return;
  observer = new MutationObserver(() => {
    if (!document.getElementById(BTN_ID)) tryInject();
  });
  observer.observe(sendForm, { childList: true, subtree: true });
}

function stopObserver(): void {
  observer?.disconnect();
  observer = null;
}

/** цМЙх╝АхЕ│хРМцнех┐лщАЯхЫЮхдНцМЙщТочЪДцЬЙцЧауАВх╝АхЕ│хПШхМЦцЧ╢ш░ГчФихН│хПп(х╣ВчнЙ)уАВ */
export function syncQuickReplyButton(enabled: boolean): void {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
  if (!enabled) {
    stopObserver();
    removeButton();
    return;
  }
  if (tryInject()) {
    startObserver();
    return;
  }
  // шБКхдйцбЖцЗТхКаш╜╜:ш╜ошпвчнЙхоГхЗ║чО░,х░Бщб╢ ~20s(40 цмб)хРОцФ╛х╝Г,ч╗Эф╕Нх╕╕щй╗чй║ш╜муАВ
  let attempts = 0;
  pollTimer = setInterval(() => {
    if (tryInject() || ++attempts > 40) {
      if (pollTimer) clearInterval(pollTimer);
      pollTimer = null;
      if (document.getElementById(BTN_ID)) startObserver();
    }
  }, 500);
}
