/**
 * хЫ╛чЙЗф╕Кф╝а:цККчФицИ╖щАЙчЪДцЬмхЬ░хЫ╛чЙЗ**хОЛч╝й**хРОхнШхИ░ ST цЬНхКбхЩи,цЛ┐хЫЮф╕Аф╕кчЯнш╖пх╛Дф╕▓
 * (хжВ /user/images/baibai_book/orb.webp)уАВ
 *
 * ф╕║ф╗Аф╣Иф╕НчЫ┤цОецКК base64 хнШш┐Ышо╛ч╜о:base64 ф╝ЪцККхЫ╛хбЮш┐Ы settings.json,хдзхЫ╛шойшпецЦЗф╗╢шЖишГАуАБ
 * цпПцмбф┐ЭхнШщГ╜х╕жф╕КхоГуАВцФ╣хнШуАМцЬНхКбхЩиш╖пх╛Дф╕▓уАНтАФтАФцЧвш╖ишо╛хдЗхРМцне(хРМф╕А ST хоЮф╛ЛхРДчлпхЕ▒ф║лхЫ╛чЙЗ),
 * хПИф╕НцТСхдз settingsуАВ
 *
 * ф╕дцЭбш╖п:
 *  ┬╖ щЭЩцАБхЫ╛(png/jpg/webpтАж)тЖТ canvas ч╝йцФ╛хОЛцИР webp,цОзхИ╢ф╜УчзпуАВ
 *  ┬╖ GIF тЖТ **хОЯца╖ф╕Кф╝а**(canvas хПкхПЦщжЦх╕зф╝Ъф╕вхКичФ╗),ф╗ЕхБЪф╜Учзпф╕КщЩРцабщкМуАВ
 *
 * хоЮчО░цЦ╣х╝П:**чЫ┤цОе POST хРОчлпчи│хоЪ REST члпчВ╣ /api/images/upload**,шодшпБхд┤хПЦшЗк
 * getContext().getRequestHeaders()(ST чи│хоЪ API)уАВф╕Н import щЕТщжЖхЖЕщГи JS цЦЗф╗╢тАФтАФ
 * щВгф║ЫцЦЗф╗╢чЪДхп╝хЗ║ф╝ЪщЪПчЙИцЬмхПШхКи(saveBase64AsFile хЬи utils.js,script.js х╣╢цЬк re-export,
 * цЧзхоЮчО░ф╗О /script.js хПЦх┐ЕчД╢хд▒ш┤е)уАВREST члпчВ╣хеСч║жцпФхЖЕщГихп╝хЗ║чи│хоЪх╛ЧхдЪуАВ
 */
import { getContext } from '@/st/context';

const MAX_SIDE = 256; // цВмц╡очРГх╛Их░П,256px ш╢│хдЯц╕ЕцЩ░
const QUALITY = 0.85;
const GIF_MAX_BYTES = 2 * 1024 * 1024; // GIF хОЯца╖ф╕Кф╝а,ф╜Учзпф╕КщЩР 2MB(ш┐ЗхдзцЛЦцЕвхКаш╜╜/цТСхдзцЬНхКбхЩи)

/** цКК File шп╗цИР dataURL(base64)уАВ */
function readAsDataURL(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const fr = new FileReader();
    fr.onload = () => resolve(String(fr.result));
    fr.onerror = () => reject(fr.error ?? new Error('шп╗хПЦцЦЗф╗╢хд▒ш┤е'));
    fr.readAsDataURL(file);
  });
}

/** ф╗О dataURL хПЦхЗ║ч║п base64(хО╗цОЙ data:*;base64, хЙНч╝А)уАВ */
function stripDataUrl(dataUrl: string): string {
  return dataUrl.split(',')[1] ?? '';
}

/** цШпхРж GIF(цМЙ MIME,хо╣щФЩцМЙцЙйх▒ХхРН)уАВ */
function isGif(file: File): boolean {
  return file.type === 'image/gif' || /\.gif$/i.test(file.name);
}

/** хКаш╜╜цИР <img>,ф╛Ы canvas хПЦхГПч┤ауАВ */
function loadImage(src: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error('хЫ╛чЙЗшзгчаБхд▒ш┤е'));
    img.src = src;
  });
}

/**
 * чнЙцпФч╝йцФ╛хИ░цЬАщХ┐ш╛╣ тЙд MAX_SIDE,ш╜м webp,ш┐ФхЫЮ**ч║п base64**(хО╗цОЙ data:*;base64, хЙНч╝А)уАВ
 * saveBase64AsFile цФ╢чЪДцШпф╕Нх╕жхЙНч╝АчЪДшг╕ base64(шзБ ST utils.js)уАВ
 */
async function compressToBase64(file: File): Promise<string> {
  const dataUrl = await readAsDataURL(file);
  const img = await loadImage(dataUrl);
  const scale = Math.min(1, MAX_SIDE / Math.max(img.width, img.height));
  const w = Math.max(1, Math.round(img.width * scale));
  const h = Math.max(1, Math.round(img.height * scale));
  const canvas = document.createElement('canvas');
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('canvas ф╕НхПпчФи');
  ctx.drawImage(img, 0, 0, w, h);
  const out = canvas.toDataURL('image/webp', QUALITY);
  return stripDataUrl(out);
}

/**
 * ф╕Кф╝аф╕Ах╝ацЬмхЬ░хЫ╛чЙЗф╜ЬцВмц╡очРГхЫ╛цаЗ,ш┐ФхЫЮцЬНхКбхЩиш╖пх╛Дф╕▓;хд▒ш┤ецКЫщФЩ(ш░ГчФицЦ╣цПРчд║чФицИ╖)уАВ
 * цЦЗф╗╢хРНх╕жф╕Аф╕кх║ПхП╖щБ┐хЕНшжЖчЫЦ(ч║пхЙНчлпцЛ╝,ф╕Нф╛Эш╡ЦцЧ╢щЧ┤цИ│тАФтАФDate.now хЬицЯРф║ЫчОпхвГхПЧщЩР)уАВ
 *
 * чЫ┤цОе POST /api/images/upload(хРОчлпчи│хоЪчлпчВ╣):
 *   body { image: ч║пbase64, format, ch_name: хнРчЫох╜Х, filename: ф╕НхРлцЙйх▒ХхРН }
 *   ш┐ФхЫЮ { path }уАВшодшпБхд┤ш╡░ getRequestHeaders(хРл CSRF token)уАВ
 *   GIF чФи format='gif' хОЯца╖ф╕Кф╝а(ф┐ЭчХЩхКичФ╗);хЕ╢ф╜ЩхОЛцИР 'webp'уАВ
 */
let seq = 0;
export async function uploadOrbImage(file: File): Promise<string> {
  if (!file.type.startsWith('image/')) throw new Error('шп╖щАЙцЛйхЫ╛чЙЗцЦЗф╗╢');

  let base64: string;
  let format: string;
  if (isGif(file)) {
    // GIF ф╕Нш┐З canvas(хПкф╝ЪхПЦщжЦх╕зф╕вхКичФ╗),хОЯца╖ф╕Кф╝а;хЕИцабщкМф╜Учзпф╕КщЩР
    if (file.size > GIF_MAX_BYTES) {
      throw new Error(`GIF ф╕НшГ╜ш╢Еш┐З ${Math.round(GIF_MAX_BYTES / 1024 / 1024)}MB`);
    }
    base64 = stripDataUrl(await readAsDataURL(file));
    format = 'gif';
  } else {
    base64 = await compressToBase64(file);
    format = 'webp';
  }
  if (!base64) throw new Error('хЫ╛чЙЗхдДчРЖхд▒ш┤е');

  const ctx = getContext();
  const headers = ctx?.getRequestHeaders?.();
  if (!headers) throw new Error('SillyTavern цЬкх░▒ч╗к,шп╖чиНхРОхЖНшпХ');

  const res = await fetch('/api/images/upload', {
    method: 'POST',
    headers,
    body: JSON.stringify({
      image: base64,
      format,
      ch_name: 'baibai_book',
      filename: `orb_${++seq}`,
    }),
  });
  if (!res.ok) {
    let detail = '';
    try {
      detail = (await res.json())?.error ?? '';
    } catch {
      /* хУНх║ФщЭЮ JSON */
    }
    throw new Error(detail || `ф╕Кф╝ахд▒ш┤е(${res.status})`);
  }
  const data = (await res.json()) as { path?: string };
  if (!data.path) throw new Error('цЬНхКбхЩицЬкш┐ФхЫЮхЫ╛чЙЗш╖пх╛Д');
  return data.path;
}
