<script setup lang="ts">
import Icon from '@/components/Icon.vue';
import { appendOpToLatestLeaf, editItem } from '@/memory/apply';
import { derivedMeta, memory } from '@/memory/store';
import { computed, ref } from 'vue';

const newName = ref('');

// чЙйхУБ/шобхИТцШпф╗ОхП╢хнРцСШшжБщЗНцФ╛хЗ║цЭечЪДц┤╛чФЯцХ░цНо,цЙЛхКицУНф╜ЬхЖЩхЕеуАМцЬАцЦ░ф╕АцЭбцЬЙцХИхП╢хнРуАНуАВ
// ц▓бцЬЙф╗╗ф╜ХцЬЙцХИхП╢хнРцЧ╢цЧахдДцМВш╜╜,чжБцнвцЙЛхКиц╖╗хКауАВ
const hasLeaf = computed(() => derivedMeta.hasLeaf);

function addItem() {
  const name = newName.value.trim();
  if (!name) return;
  if (!appendOpToLatestLeaf({ items: { add: [{ name }] } })) return;
  newName.value = '';
}

function removeItem(id: string) {
  const it = memory.items.find(i => i.id === id);
  if (!it) return;
  appendOpToLatestLeaf({ items: { remove: [it.name] } });
}

/* тАФтАФ ч╝Цш╛Сх╝╣чкЧ:цФ╣хРН/цХ░щЗП/цППш┐░уАВцХ░щЗПчХЩчй║=ч╗┤цМБ(update цЧац│Хц╕Ечй║,ц╕Ечй║цХ░щЗПшп╖хИахРОщЗНх╗║) тАФтАФ */
interface ItemEditing {
  oldName: string;
  name: string;
  qty: string; // цЦЗцЬмцЙ┐ш╜╜,чй║=ф╕НцФ╣цХ░щЗП
  desc: string;
  carried: boolean; // цШпхРжщЪПш║л
  location: string; // щЭЮщЪПш║лцЧ╢чЪДхнШцФ╛хЬ░
}
const editing = ref<ItemEditing | null>(null);

function openEdit(id: string) {
  const it = memory.items.find(i => i.id === id);
  if (!it) return;
  editing.value = {
    oldName: it.name,
    name: it.name,
    qty: typeof it.qty === 'number' ? String(it.qty) : '',
    desc: it.desc ?? '',
    carried: it.carried !== false, // чЬБчХе/true шзЖф╜ЬщЪПш║л
    location: it.location ?? '',
  };
}
function cancelEdit() {
  editing.value = null;
}
function saveEdit() {
  const e = editing.value;
  if (!e || !e.name.trim()) return;
  const qtyStr = e.qty.trim();
  const qty = qtyStr === '' ? undefined : Number(qtyStr);
  // щЪПш║л тЖТ ц╕Ечй║хнШцФ╛хЬ░;щЭЮщЪПш║л тЖТ чФихблхЖЩчЪДхЬ░чВ╣
  editItem(e.oldName, {
    name: e.name,
    qty: qty !== undefined && Number.isFinite(qty) ? qty : undefined,
    desc: e.desc,
    carried: e.carried,
    location: e.carried ? '' : e.location,
  });
  editing.value = null;
}
</script>

<template>
  <section class="bbs-page">
    <h2 class="bbs-title bbs-title-sub">чЙйхУБ</h2>

    <div class="bbs-additem">
      <input
        v-model="newName"
        class="bbs-input"
        type="text"
        :placeholder="hasLeaf ? 'цЙЛхКиц╖╗хКачЙйхУБтАж' : 'щЬАхЕИцЬЙцСШшжБцЙНшГ╜цЙЛхКиц╖╗хКа'"
        :disabled="!hasLeaf"
        @keydown.enter="addItem"
      />
      <button class="bbs-btn bbs-btn-primary" type="button" :disabled="!hasLeaf" @click="addItem">ц╖╗хКа</button>
    </div>

    <hr class="bbs-rule" />

    <div v-if="memory.items.length" class="bbs-item-list">
      <div v-for="it in memory.items" :key="it.id" class="bbs-item">
        <div class="bbs-item-head">
          <div class="bbs-item-main">
            <span class="bbs-item-name">{{ it.name }}</span>
            <span v-if="typeof it.qty === 'number'" class="bbs-item-qty">├Ч{{ it.qty }}</span>
            <span v-if="it.carried === false && it.location" class="bbs-item-loc">
              <Icon name="scenes" /><span class="bbs-item-loc-text">{{ it.location }}</span>
            </span>
          </div>
          <span class="bbs-item-acts">
            <button class="bbs-item-act" type="button" title="ч╝Цш╛С" @click="openEdit(it.id)">
              <Icon name="edit" />
            </button>
            <button class="bbs-item-act bbs-item-del" type="button" title="хИащЩд" @click="removeItem(it.id)">
              <Icon name="close" />
            </button>
          </span>
        </div>
        <span v-if="it.desc" class="bbs-item-desc">{{ it.desc }}</span>
      </div>
    </div>

    <div v-else class="bbs-empty">
      <span class="bbs-empty-icon"><Icon name="items" /></span>
      <p>цЪВцЧ╢чй║чй║хжВф╣ЯуАВцСШшжБцЧ╢х╛ЧхИ░чЪДчЙйхУБф╝ЪшЗкхКичЩ╗шо░,ф╣ЯхПпцЙЛхКиц╖╗хКауАВ</p>
    </div>

    <!-- ч╝Цш╛Сх╝╣чкЧ:ф╕НчФи Teleport(шзБ base.css шп┤цШО),position:fixed хЖЕшБФц╕▓цЯУ -->
    <div v-if="editing" class="bbs-modal-mask" @click.self="cancelEdit">
      <div class="bbs-modal" role="dialog" aria-modal="true" aria-label="ч╝Цш╛СчЙйхУБ">
        <header class="bbs-modal-head">
          <span class="bbs-modal-title">ч╝Цш╛СчЙйхУБ</span>
          <button class="bbs-item-act" type="button" title="хЕ│щЧн" @click="cancelEdit"><Icon name="close" /></button>
        </header>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">хРНчз░</span>
          <input v-model="editing.name" class="bbs-input" type="text" placeholder="чЙйхУБхРН" />
        </label>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">цХ░щЗП(чХЩчй║=ф╕НшобцХ░)</span>
          <input v-model="editing.qty" class="bbs-input" type="number" min="0" placeholder="ф╕НхблхИЩф╕НцШ╛чд║цХ░щЗП" />
        </label>
        <label class="bbs-modal-field bbs-modal-check">
          <input v-model="editing.carried" type="checkbox" />
          <span class="bbs-modal-label">щЪПш║лцР║х╕ж(хПЦц╢ИхЛ╛щАЙхПпцМЗхоЪхнШцФ╛хЬ░)</span>
        </label>
        <label v-if="!editing.carried" class="bbs-modal-field">
          <span class="bbs-modal-label">хнШцФ╛хЬ░чВ╣</span>
          <input v-model="editing.location" class="bbs-input" type="text" placeholder="хжВ:цнжхЩих║УуАБхо╢ф╕н" />
        </label>
        <label class="bbs-modal-field">
          <span class="bbs-modal-label">цППш┐░</span>
          <textarea v-model="editing.desc" class="bbs-input bbs-modal-textarea" rows="3" placeholder="хПпщАЙ"></textarea>
        </label>
        <footer class="bbs-modal-foot">
          <button class="bbs-btn" type="button" @click="cancelEdit">хПЦц╢И</button>
          <button class="bbs-btn bbs-btn-primary" type="button" :disabled="!editing.name.trim()" @click="saveEdit">ф┐ЭхнШ</button>
        </footer>
      </div>
    </div>
  </section>
</template>

