/**
 * хРСщЗПч┤вх╝Хч╝ЦцОТ:цККх╜УхЙНшБКхдйчЪДцЬЙцХИхП╢хнРхРМцнеш┐ЫхРОчлпхРСщЗПх║У(шпешзТшЙ▓чЪД chat:<chatId> scope)уАВ
 *
 * ц╡БчиЛ(хвЮщЗПуАБх╣ВчнЙ):
 *  1. цЙл chat цФ╢щЫЖцЬЙцХИхП╢хнР тЖТ present = [{leafId, docHash}](docHash цМЙхП╢хнРцСШшжБцЦЗцЬмчоЧ)уАВ
 *  2. vec/reconcile:хРОчлпхИацОЙщЩИцЧз(щЗНцСШцНв id/хИаце╝/ч╝Цш╛Схд▒цХИ),ш┐ФхЫЮщЬА embed чЪД leafId(цЦ░хвЮцИЦ hash хПШф║Ж)уАВ
 *  3. хп╣ч╝║хд▒хП╢хнР embed хЕ╢цСШшжБцЦЗцЬм тЖТ vec/upsertуАВ
 * хРМцЦЗцЬм(хРМ hash)ф╕НщЗНхдН embed тАФтАФ ш┐ЩцШпуАМш╛╣чОйш╛╣ч┤вх╝ХуАНф╕НхНбчЪДхЕ│щФоуАВ
 *
 * ш░ГчФицЧ╢цЬ║:хП╢хнРчФЯцИР/ч╝Цш╛С/хИащЩдхРО(щШ▓цКЦшзжхПС,шзБ schedule)уАВхЕичиЛ try/catch щЭЩщ╗Ш,
 * хРСщЗПцШпхвЮх╝║щб╣,хд▒ш┤еч╗Эф╕Нх╜▒хУНцСШшжБф╕╗ц╡БчиЛуАВ
 */

import { getContext, type STMessage } from '@/st/context';
import { apiSettings, engineActiveHere } from '@/api/settings';
import type { VecItem } from '@/api/baibaoku';
import { resetVectorStoreProbe, vecClearScope, vecReconcile, vecUpsert } from './store';
import { getLeaf, leafValid } from '../apply';
import { resolveKeepStart } from '../engine';
import { stripThinkBlocks } from '../timeTag';
import type { LeafExtra } from '../types';
import { embedTexts, encodeFloat32Base64 } from './embed';
import { currentChatId, currentVectorDb } from './scope';

/** ш╜╗щЗПчи│хоЪ hash(FNV-1a,16 ш┐ЫхИ╢);хП╢хнРцСШшжБцЦЗцЬмхПШф║Ж hash хН│хПШ,шзжхПСщЗН embedуАВ */
function docHashOf(text: string): string {
  let h = 0x811c9dc5;
  for (let i = 0; i < text.length; i++) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}

interface LeafForIndex {
  leafId: string;
  docHash: string;
  document: string; // хП╢хнРцСШшжБцЦЗцЬм(хРСщЗПхМЦхп╣ш▒б + цСШшжБцбгхЫЮф╝а)
  mesFull: string; // це╝х▒ВхОЯцЦЗ(хЕицЦЗцбгхЫЮф╝а)
  storyTime: string;
  msgIndex: number;
}

/**
 * хП╢хнРчЪДцХЕф║ЛцЧ╢щЧ┤,хнШф╕║**цЬкхОЛч╝й**чЪДхоМцХ┤ш╡╖цнвцо╡уАМш╡╖ - цнвуАН(ш╡╖цнвчЫ╕хРМ/ч╝║ф╕АчлпхИЩхНХчВ╣)уАВ
 * ф╕║ф╜Хф╕НхОЛч╝й(ф╕НхИач╗УцЭЯчлпщЗНхдНцЧецЬЯ):хПмхЫЮчлпшжБф╗Ош┐Щф╕▓щЗМцЛЖхЫЮ**хоМцХ┤ч╗УцЭЯцЧ╢щЧ┤**чоЧчЫ╕хп╣цЧ╢щЧ┤,
 * хОЛч╝йхРОч╗УцЭЯчлпф╝Ъч╝║цЧецЬЯ(хжВуАМ06:55уАН)хп╝шЗ┤чоЧф╕НхЗ║чЫ╕хп╣уАВцШ╛чд║цЧ╢хПмхЫЮчлпхЖН compactTimeLabel хОЛцИРхМ║щЧ┤уАВ
 */
function leafStoryTime(leaf: LeafExtra): string {
  const start = leaf.timeStart?.trim() || '';
  const end = leaf.timeEnd?.trim() || '';
  if (start && end) return start === end ? start : `${start} - ${end}`;
  return start || end || leaf.timeLabel?.trim() || '';
}

/** цЙлх╜УхЙН chat цФ╢щЫЖцЙАцЬЙцЬЙцХИхП╢хнРчЪДч┤вх╝Хч┤ацЭРуАВ */
function collectLeaves(chat: STMessage[]): LeafForIndex[] {
  const out: LeafForIndex[] = [];
  for (let i = 0; i < chat.length; i++) {
    if (!leafValid(chat[i])) continue;
    const leaf = getLeaf(chat[i]) as LeafExtra;
    const document = (leaf.text ?? '').trim();
    if (!document) continue; // чй║цСШшжБф╕Нч┤вх╝Х
    out.push({
      leafId: leaf.id,
      docHash: docHashOf(document),
      document,
      // хнШш┐Сф╣ОхОЯцЦЗ:хПкщвДхЙецАЭч╗┤щУ╛(чбохоЪцАзхЩкхг░,чЬБчй║щЧ┤ф╕ФщЫ╢щгОщЩй),хЕ╢ф╜Щц╕Ец┤Ч(шЗкхоЪф╣ЙцаЗчн╛чнЙ)
      // чХЩхИ░хПмхЫЮцЧ╢ш┐З cleanBodyтАФтАФш┐Щца╖чФицИ╖цЧехРОш░ГцХ┤уАМшЗкхоЪф╣Йц╕Ец┤ЧцаЗчн╛уАНшо╛ч╜о,шАБч┤вх╝Хф╣ЯхН│цЧ╢чФЯцХИ,цЧащЬАщЗНх╗║уАВ
      mesFull: stripThinkBlocks(chat[i].mes),
      storyTime: leafStoryTime(leaf),
      msgIndex: i,
    });
  }
  return out;
}

let indexing = false;
let timer: ReturnType<typeof setTimeout> | null = null;

/** хРСщЗПшо░х┐ЖцШпхРжхЬих╜УхЙНшБКхдйхПпч┤вх╝Х(цА╗х╝АхЕ│х╝А + х╜УхЙНшзТшЙ▓цЬкцОТщЩд + хРСщЗПх╝АхЕ│х╝А + ш┐ЫхЕеф║ЖхНХшзТшЙ▓шБКхдй)уАВ */
export function vectorIndexableHere(): boolean {
  if (!engineActiveHere()) return false; // цПТф╗╢цА╗х╝АхЕ│хЕ│ / х╜УхЙНшзТшЙ▓швлцОТщЩд тЖТ ф╕Нч┤вх╝Х
  if (!apiSettings.vector.enabled) return false;
  return !!currentVectorDb() && !!currentChatId();
}

/**
 * цККх╜УхЙНшБКхдйчЪДхП╢хнРхРМцнеш┐ЫхРСщЗПх║У(хвЮщЗП)уАВхПпшвлщШ▓цКЦ schedule цИЦцЙЛхКиуАМщЗНх╗║ч┤вх╝ХуАНчЫ┤цОеш░ГчФиуАВ
 * @returns хоЮщЩЕ embed+upsert чЪДцЭбцХ░(0 = хЕицШпхвЮщЗПхС╜ф╕нцИЦцЧахПпч┤вх╝Х)уАВ
 */
export async function syncVectorIndex(signal?: AbortSignal): Promise<number> {
  if (!vectorIndexableHere()) return 0;
  if (indexing) return 0;
  const database = currentVectorDb();
  const chatId = currentChatId();
  if (!database || !chatId) return 0;

  const ctx = getContext();
  const chat = ctx?.chat ?? [];
  const scope = `chat:${chatId}`;

  indexing = true;
  try {
    const leaves = collectLeaves(chat);
    const present = leaves.map(l => ({ leafId: l.leafId, docHash: l.docHash }));

    // reconcile:хИащЩИцЧзуАБх╛ЧхЗ║щЬА embed чЪД leafIdуАВчй║ present ф╣ЯшжБхПС(хПпшГ╜шжБц╕ЕцОЙхИахЕЙчЪДцЧзч┤вх╝Х)уАВ
    const { missing } = await vecReconcile(database, scope, present);
    if (!missing.length) return 0;

    const missingSet = new Set(missing);
    const todo = leaves.filter(l => missingSet.has(l.leafId));
    return await embedAndUpsert(database, scope, todo, signal);
  } catch (e) {
    console.warn('[цЯПхоЭф╣жхРСщЗП] ч┤вх╝ХхРМцнехд▒ш┤е(ф╕Нх╜▒хУНцСШшжБ):', e);
    return 0;
  } finally {
    indexing = false;
  }
}

/** embed ф╕АцЙ╣хП╢хнРх╣╢ upsert хИ░цМЗхоЪ scope;ш┐ФхЫЮхоЮщЩЕхЖЩхЕецЭбцХ░уАВembedTexts хЖЕщГицМЙ 64 хИЖцЙ╣уАВ */
async function embedAndUpsert(database: string, scope: string, todo: LeafForIndex[], signal?: AbortSignal): Promise<number> {
  if (!todo.length) return 0;
  const vectors = await embedTexts(todo.map(l => l.document), signal);
  const items: VecItem[] = todo.map((l, i) => {
    const vec = vectors[i];
    return {
      leafId: l.leafId,
      docHash: l.docHash,
      vector: encodeFloat32Base64(vec),
      dim: vec.length,
      document: l.document,
      mesFull: l.mesFull,
      storyTime: l.storyTime,
      msgIndex: l.msgIndex,
    };
  });
  await vecUpsert(database, scope, items);
  return items.length;
}

/**
 * хПмхЫЮхЙНчЪДуАМшбещ╜РчкЧхПгхдЦч╝║хд▒ч┤вх╝ХуАН:чбоф┐Эц╗СхКичкЧхПг**ф╣ЛхЙН**чЪДхП╢хнРщГ╜х╖▓ч┤вх╝Х,цЙНцФ╛шбМхПмхЫЮуАВ
 *
 * ф╕║ф╜ХхПкшбечкЧхПгхдЦ:чкЧхПгхЖЕчЪДхП╢хнРхПмхЫЮцЬмх░▒цОТщЩд(щБ┐хЕНф╕ОхЕицЦЗщЗНхдН),хоГф╗мчЪДч┤вх╝ХчХЩч╗ЩщШ▓цКЦхвЮщЗПхН│хПп,
 * ф╕Нх┐ЕщШ╗хбЮчФЯцИР;шАМчкЧхПгхдЦчЪДцЧзхП╢хнРцШпхПмхЫЮчЪДчЬЯцнгчЫоцаЗ,ч╝║ч┤вх╝Хф╝ЪчЫ┤цОец╝ПхПмхЫЮтАФтАФх┐Ещб╗хЕИшбеуАВ
 *
 * хдНчФи reconcile хЕищЗПхп╣ш┤ж(хРМцЧ╢ц╕ЕщЩИцЧзуАБх╛Ч missing),ф╜ЖхПкхп╣уАМчкЧхПгхдЦ missingуАНщШ╗хбЮ embedуАВ
 * хЕичиЛ try/catch щЭЩщ╗Ш:шбех╗║хд▒ш┤еф╕НщШ╗цЦнхПмхЫЮ(хПмхЫЮф╛зшЗкцЬЙщЩНч║з),цЫ┤ф╕Нх╜▒хУНчФЯцИРуАВ
 */
export async function ensureRecallIndex(signal?: AbortSignal): Promise<void> {
  if (!vectorIndexableHere()) return;
  if (indexing) return; // цнгхЬиш╖СщШ▓цКЦхРМцне,шойхоГхО╗хБЪ,щБ┐хЕНщЗНхдН embed
  const database = currentVectorDb();
  const chatId = currentChatId();
  if (!database || !chatId) return;

  const ctx = getContext();
  const chat = ctx?.chat ?? [];
  const scope = `chat:${chatId}`;

  indexing = true;
  try {
    const leaves = collectLeaves(chat);
    const present = leaves.map(l => ({ leafId: l.leafId, docHash: l.docHash }));
    const { missing } = await vecReconcile(database, scope, present);
    if (!missing.length) return;

    // хПкщШ╗хбЮшбечкЧхПгхдЦ(< keepStart)ч╝║хд▒чЪДхП╢хнР;чкЧхПгхЖЕч╝║хд▒ф║дч╗ЩщШ▓цКЦхвЮщЗП
    const keepStart = resolveKeepStart(chat);
    const missingSet = new Set(missing);
    const todo = leaves.filter(l => missingSet.has(l.leafId) && l.msgIndex < keepStart);
    if (todo.length) await embedAndUpsert(database, scope, todo, signal);
  } catch (e) {
    console.warn('[цЯПхоЭф╣жхРСщЗП] хПмхЫЮхЙНшбех╗║ч┤вх╝Ххд▒ш┤е(щЩНч║зф╕║ф╕Ншбе):', e);
  } finally {
    indexing = false;
  }
}

/**
 * ц╕Ечй║х╜УхЙНшБКхдйчЪДхРСщЗПч┤вх╝Х(хПкц╕Е chat:<chatId> scope,ф╕НхКич╗зцЙ┐чЪД bundle х┐лчЕз)уАВ
 * чФиф║ОуАМч┤вх╝ХшДПф║Ж/цГ│щЗНцЭеуАН:ц╕Ечй║хРОхПпчФиуАМщЗНх╗║уАНф╗Охд┤ч┤вх╝ХуАВш┐ФхЫЮхИащЩдцЭбцХ░уАВ
 * ф╕Нш╡░ vectorIndexableHere щЧ╕щЧи(чФицИ╖цЙЛхКицУНф╜Ь,хН│ф╛┐хРСщЗПх╝АхЕ│ф╕┤цЧ╢хЕ│ф╣Ях║ФхЕБшо╕ц╕ЕчРЖ),
 * ф╜Жф╗НщЬАх╜УхЙНх║У+шБКхдй id цЙНцЬЙчЫоцаЗ scopeуАВ
 */
export async function clearVectorIndex(): Promise<number> {
  const database = currentVectorDb();
  const chatId = currentChatId();
  if (!database || !chatId) return 0;
  resetVectorStoreProbe(); // цЙЛхКич╗┤цКдхЙНщЗНц╡ЛхРОчлп,хРОчлпхИЪх░▒ч╗к/хИЪхБЬщГ╜шГ╜хИЗхИ░хп╣чЪД store
  const { deleted } = await vecClearScope(database, `chat:${chatId}`);
  return deleted;
}

/** щШ▓цКЦшзжхПСч┤вх╝ХхРМцне:хП╢хнРчФЯцИР/ч╝Цш╛С/хИащЩдхРОш░ГчФи,хРИх╣╢ш┐Юч╗нхПШхКиф╕║ф╕АцмбуАВ */
export function scheduleVectorIndex(): void {
  if (!vectorIndexableHere()) return;
  if (timer) clearTimeout(timer);
  timer = setTimeout(() => {
    timer = null;
    void syncVectorIndex();
  }, 2500);
}
