/**
 * цгоцЮЧшКВчВ╣чЪДуАМцЬАх░ПцЛЖшзгуАНщАЙцЛйчоЧц│Х тАФтАФ ч║пхЗ╜цХ░уАБщЫ╢ф╛Эш╡Ц(ф╛┐ф║ОхНХц╡Л,ц│ихЕеф╕ОхИЧшбихЕ▒чФи)уАВ
 *
 * шГМцЩп:цСШшжБцШпф╕Ацг╡цгоцЮЧ,хП╢хнР(L0,цМВц╢ИцБп extra)+ хОЛч╝йшКВчВ╣(L1/L2тАж,childIds х╝ХчФиф╕Лх▒В)уАВ
 * ч╗ЩхоЪф╕Ач╗ДуАМхРИца╝уАНхП╢хнР(чФ▒ leafEligible хИдхоЪ),шжБф╕║цпПф╕кхРИца╝хП╢хнРщАЙф╕Аф╕к**цЬАщлШчЪДуАБшГ╜цХ┤ф╜Уф╗гшбихоГчЪД
 * шКВчВ╣**(чЬБ token):шЛецЯРхОЛч╝йшКВчВ╣чЪДхЕищГихРОф╗гхП╢хнРщГ╜хРИца╝,х░▒чФиш┐Щф╕Аф╕кшКВчВ╣ф╗гшбицХ┤цо╡;хРжхИЩщЩНч║зуАБщАРхнРщАТх╜ТуАВ
 *
 * хоМхе╜цАз(intact):хОЛч╝йшКВчВ╣чЪДцЯРф╕к childId цМЗхРСчЪДхП╢хнРшЛех╖▓хд▒цХИ(ч┐╗щб╡хИ░хИлчЪД swipe тЖТ ф╕НхЬи byId щЗМ),
 * хИЩшпешКВчВ╣**ф╕НхоМцХ┤**тАФтАФхоГчЪДхОЛч╝йцЦЗцЬмх╡МчЭАхд▒цХИщВгщб╡чЪДцЧзхПЩф║Л,ф╕НшГ╜ф╜Ьф╕║цХ┤ф╜Уф╗гшби(ф╝Ъф╕Ох╜УхЙНцнгцЦЗхЖ▓чкБ)уАВ
 * цндцЧ╢щЩНч║зщАТх╜Т,цФ╣чФихоГ**ф╗НхоМхе╜чЪДхнРшКВчВ╣**хРДшЗкф╗гшби:хПЧх╜▒хУНчЪДщВгцЭбщУ╛ф╕Аш╖пцЛЖхИ░хП╢хнРх▒ВуАБш╖│ш┐Зхд▒цХИхП╢хнР,
 * шАМцЧБцФпхоМхе╜чЪДхнРшКВчВ╣(хжВхРМх▒ВхПжф╕АцЭб L1)цХ┤цЭбф┐ЭчХЩуАВшКВчВ╣хд▒ц┤╗хПкцШпуАМх╜УхЙНф╕Нх▒Хчд║/ф╕Нц│ихЕеуАН,цгоцЮЧцХ░цНоф╕НхИащЩдуАВ
 */

/** ч╗Яф╕АшзЖхЫ╛шКВчВ╣:хП╢хнРцЭешЗк chat цЙлцПП,хОЛч╝йшКВчВ╣цЭешЗкцгоцЮЧ,childIds ш╖ихнШхВиш┐ЮцОе */
export interface ViewNode {
  id: string;
  kind: 'leaf' | 'comp';
  level: number; // leaf=0,comp=шпехОЛч╝йх▒Вч║з(ф╛ЫхИЧшбицШ╛чд║уАМцА╗ч╗УL{level}уАН)
  text: string;
  timeStart?: string;
  timeEnd?: string;
  timeLabel?: string; // цЧзцХ░цНохЫЮщАА
  createdAt: number;
  childIds: string[]; // comp цЙНцЬЙ
  msgIndex: number; // leaf цЙНцЬЙцДПф╣Й(цОТх║ПщФо);comp хПЦ -1
  active: boolean; // leaf:цЙАхЬиц╢ИцБпх╖▓щЪРшЧП
}

/**
 * хЬих╖▓цЮДх╗║чЪДцгоцЮЧшзЖхЫ╛ф╕КхБЪщАЙцЛй(ц│ихЕе/хИЧшбихЕ▒чФи)уАВщА╗ш╛СшзБцЦЗф╗╢хд┤ц│ищЗКуАВ
 * byId хПкцФ╢**цЬЙцХИ**хП╢хнР + хЕищГихОЛч╝йшКВчВ╣;roots = цЬкшвлф╗╗ф╜Х childIds х╝ХчФичЪДшКВчВ╣уАВ
 */
export function selectViewNodes(
  view: { byId: Map<string, ViewNode>; roots: ViewNode[] },
  leafEligible: (n: ViewNode) => boolean,
): ViewNode[] {
  const { byId, roots } = view;

  const collectLeaves = (n: ViewNode, acc: ViewNode[]): void => {
    if (n.kind === 'leaf') {
      acc.push(n);
      return;
    }
    for (const cid of n.childIds) {
      const c = byId.get(cid);
      if (c) collectLeaves(c, acc);
    }
  };
  // хоМхе╜:цпПф╕к childId щГ╜шГ╜шзгцЮР(цЧацВмчй║)ф╕ФхнРшКВчВ╣шЗкш║лф╣ЯхоМхе╜;хП╢хнРцБТхоМхе╜уАВmemoizedуАВ
  const intactMemo = new Map<string, boolean>();
  const isIntact = (n: ViewNode): boolean => {
    if (n.kind === 'leaf') return true;
    const cached = intactMemo.get(n.id);
    if (cached !== undefined) return cached;
    intactMemo.set(n.id, false); // щШ▓чОп:щАТх╜ТцЬкх╜ТхЙНхЕИхНаф╜Н false
    let ok = n.childIds.length > 0;
    for (const cid of n.childIds) {
      const c = byId.get(cid);
      if (!c || !isIntact(c)) { ok = false; break; } // цВмчй║ child тЗТ ф╕НхоМцХ┤
    }
    intactMemo.set(n.id, ok);
    return ok;
  };
  // хПпф╜Ьф╕║цХ┤ф╜Уф╗гшби:хоМхе╜ + хЕищГихРОф╗гхП╢хнРщГ╜хРИца╝уАВ
  const canRepresent = (n: ViewNode): boolean => {
    if (!isIntact(n)) return false;
    const ls: ViewNode[] = [];
    collectLeaves(n, ls);
    return ls.length > 0 && ls.every(leafEligible);
  };

  const chosen: ViewNode[] = [];
  const visited = new Set<string>(); // щШ▓чОп/щШ▓щЗН:цнгх╕╕цгоцЮЧцШпцаС,ф╜ЖчЧЕцАБчОпш╛УхЕеф╕ЛщБ┐хЕНчИЖцаИ
  const visit = (n: ViewNode): void => {
    if (visited.has(n.id)) return;
    visited.add(n.id);
    if (n.kind === 'leaf') {
      if (leafEligible(n)) chosen.push(n);
      return;
    }
    if (canRepresent(n)) {
      chosen.push(n);
      return;
    }
    for (const cid of n.childIds) {
      const c = byId.get(cid);
      if (c) visit(c);
    }
  };
  for (const r of roots) visit(r);

  // цЧ╢щЧ┤х║ПцЛ╝цОе:хП╢хнРчФице╝х▒Вх║П;хОЛч╝йшКВчВ╣чФихЕ╢цЬАцЧйхРОф╗гхП╢хнРчЪДце╝х▒Вх║П
  const sortKey = (n: ViewNode): number => {
    if (n.kind === 'leaf') return n.msgIndex;
    const ls: ViewNode[] = [];
    collectLeaves(n, ls);
    return ls.length ? Math.min(...ls.map(l => l.msgIndex)) : Number.MAX_SAFE_INTEGER;
  };
  return chosen.sort((a, b) => sortKey(a) - sortKey(b));
}
