/**
 * цЧ╢щЧ┤цаЗчн╛(щФЪчВ╣)тАФтАФшойф╕╗хп╣шпЭцибхЮЛхЬицпПцЭбцнгцЦЗхЙНхРОш╛УхЗ║ш╡╖цнвцЧ╢щЧ┤,цККуАМцЧ╢щЧ┤уАНф╗Оф║ЛхРОцОицЦнхПШцИРцнгцЦЗф║ЛхоЮуАВ
 *
 * шзгхЖ│ф╕дф╕кшАБщЧощвШ:
 *  1. ф╕Ах▒Вце╝цЧ╢щЧ┤ш╖их║жхдз,хНХф╕АцЧ╢щЧ┤х┐лчЕзхПЦф╕НхЗЖ тЖТ чО░хЬицЬЙш╡╖хзЛ + ч╗УцЭЯф╕дф╕кчХМуАВ
 *  2. цСШшжБшп╖ц▒Вф╕ОцЦ░хЙзцГЕчФЯцИРх╣╢шбМ,хРДшЗкцОицЦнцЧ╢щЧ┤хп╝шЗ┤щФЩф╣▒ тЖТ ф╕дш╛╣щГ╜шп╗цнгцЦЗщЗМхРМф╕Аф╕кцЭГхиБцЧ╢щЧ┤,шЗкчД╢хРМцнеуАВ
 *
 * цаЗчн╛ца╝х╝ПхЫ║хоЪф╕║ <bbs_start>тАж</bbs_start> / <bbs_end>тАж</bbs_end>(bbs_ хЙНч╝АщБ┐хЕНф╕ОхЕ╢хоГцПТф╗╢/ф╕ЦчХМф╣жцТЮ)уАВ
 * цаЗчн╛**чХЩхЬицнгцЦЗщЗМ**(хПСхЙп APIуАБхПСф╕╗цибхЮЛч╗нхЖЩщГ╜х╕жчЭА),хПкчФи ST цнгхИЩхЬиуАМцШ╛чд║х▒ВуАНщЪРшЧП тАФтАФ чЬЯхИаф╝ЪшойцЧ╢щЧ┤хЖНцмбхд▒хРМцнеуАВ
 */

import { apiSettings } from '@/api/settings';
import { getContext, type STMessage } from '@/st/context';
import type { LeafExtra } from './types';

/** цаЗчн╛хЫ║хоЪцаЗшпЖ(шзгцЮРцнгхИЩф╕ОщЪРшЧПцнгхИЩщГ╜ф╛Эш╡ЦхоГ) */
export const START_TAG = 'bbs_start';
export const END_TAG = 'bbs_end';
/** чЙйхУБхПШхКицЧБц│ицаЗчн╛:цСШшжБхРОцККцЬмце╝чЙйхУБхЗАхПШхКихЖЩш┐ЫцнгцЦЗ </bbs_end> ф╣ЛхРО,ф╛ЫчкЧхПгхЖЕхЕицЦЗце╝х▒Вшвлф╕╗цибхЮЛчЬЛхИ░ */
export const ITEMS_TAG = 'bbs_items';

/** ц│ихЕеф╕╗хп╣шпЭчЪДхЫ║хоЪцПРчд║шпНщ╗ШшодхА╝(хПпхЬишо╛ч╜ощЗМшжЖчЫЦ)уАВ */
export const TIME_TAG_PROMPT = `уАРцЧ╢щЧ┤щФЪчВ╣шжБц▒В(ч│╗ч╗Ях╝║хИ╢)уАС
хЬиф╜ацпПцмбш╛УхЗ║цнгцЦЗчЪДцЬАхЙНщЭвхТМцЬАхРОщЭв,хРДцФ╛ф╕Аф╕кцЧ╢щЧ┤цаЗчн╛,цаЗцШОш┐Щцо╡хЙзцГЕчЪДх╝АхзЛцЧ╢хИ╗ф╕Оч╗УцЭЯцЧ╢хИ╗:

<${START_TAG}>цЬмцо╡х╝АхзЛцЧ╢чЪДцХЕф║ЛхЖЕцЧ╢щЧ┤</${START_TAG}>
я╝ИцнгцЦЗтАжтАжя╝Й
<${END_TAG}>цЬмцо╡ч╗УцЭЯцЧ╢чЪДцХЕф║ЛхЖЕцЧ╢щЧ┤</${END_TAG}>

шзДхИЩ:
- цЧ╢щЧ┤шжБхЕ╖ф╜УуАБхПпцШОчбохоЪф╜Н,щгОца╝ф╕ОцнгцЦЗф╕ЦчХМшзВф╕АшЗ┤:чО░ф╗гщвШцЭРчФицХ░хнЧцЧецЬЯцЧ╢щЧ┤(хжВ 1988/9/29 21:30);хПдщгО/хеЗх╣╗щвШцЭРчФичЫ╕х║ФчЪДч║кх╣┤ф╕ОцЧ╢ш╛░(хжВ х║ЖхОЖхЫЫх╣┤цЪоцШе┬╖ш╛░цЧ╢ф╕ЙхИ╗)уАВщЗНчВ╣цШпуАМшГ╜хоЪф╜НхИ░цЯРф╕АхИ╗уАН,ф╕Нх╝║ц▒ВщШ┐цЛЙф╝пцХ░хнЧуАВ
- чжБцнв"чиНхРО""ф╕Нф╣Е""цЯРхдй""хРМф╕Ахдй"чнЙцЧац│ХхоЪф╜НхИ░хЕ╖ф╜УцЧ╢хИ╗чЪДцибч│Кшп┤ц│ХуАВ
- ф╗еф╕Кф╕Ацо╡чЪДч╗УцЭЯцЧ╢щЧ┤ф╕║хЯ║хЗЖ,ч╗УхРИцЬмцо╡хЙзцГЕхРИчРЖцОиш┐Ы(хп╣шпЭч║жхЗахИЖщТЯуАБчФищдРч║жф╕Ах░ПцЧ╢уАБш┐ЗхдЬш╖ихИ░цмбцЧечнЙ)уАВ
- шЛеш┐ЩцШпцХЕф║Лх╝АчпЗуАБцндхЙНц▓бцЬЙф╗╗ф╜Хх╖▓чЯецЧ╢щЧ┤,шп╖ф╜ашЗкшбМшо╛хоЪф╕Аф╕кчмжхРИцЬмф╕ЦчХМшзВчЪДхЕ╖ф╜Уш╡╖хзЛцЧ╢хИ╗,ф╣ЛхРОф╗ецндф╕║хЯ║хЗЖцОиш┐ЫтАФтАФш┐ЩцШпф╕║шо░х┐Жч│╗ч╗Ях╗║члЛцЧ╢щЧ┤щФЪчВ╣цЙАх┐ЕщЬАчЪДхРИчРЖшо╛хоЪ,ф╕НчоЧч╝ЦщАа;ф╜Жч╗Эф╕НшГ╜чФи"цЯРхдй"ш┐Щч▒╗цЧац│ХхоЪф╜НчЪДхНаф╜НшпНцХ╖шбНуАВ
- цаЗчн╛хПкхРДхЗ║чО░ф╕Ацмб,хИЖхИлч┤зш┤┤цнгцЦЗцЬАхЙНф╕ОцЬАхРО;цаЗчн╛хЖЕхПкцЬЙцЧ╢щЧ┤,ф╕НшжБхЖЩхИлчЪДуАВ
- ш┐Щф╕дф╕кцаЗчн╛цШпч╗Щшо░х┐Жч│╗ч╗Яшп╗хПЦчЪДщФЪчВ╣,шп╖хКбх┐ЕцпПцмбщГ╜ш╛УхЗ║уАВ`;

/** х╜УхЙНчФЯцХИчЪДхЫ║хоЪцПРчд║шпН(чФицИ╖шЗкхоЪф╣Йф╝ШхЕИ,чй║хИЩчФихЖЕч╜ощ╗Шшод)уАВ */
export function timeTagPrompt(): string {
  return apiSettings.prompts.timeTag.trim() || TIME_TAG_PROMPT;
}

// шзгцЮРчФицнгхИЩ:хо╣х┐НцаЗчн╛хРНхдзх░ПхЖЩф╕ОщжЦх░╛чй║чЩ╜;щЭЮш┤кхйкхПЦхЖЕщГицЦЗцЬмуАВ
const RE_START = new RegExp(`<${START_TAG}\\b[^>]*>([\\s\\S]*?)</${START_TAG}>`, 'i');
const RE_END = new RegExp(`<${END_TAG}\\b[^>]*>([\\s\\S]*?)</${END_TAG}>`, 'i');

/** ф╗Оф╕Ацо╡цнгцЦЗщЗМшзгцЮРш╡╖цнвцЧ╢щЧ┤;хПЦф╕НхИ░чЪДф╕║ undefined(щЩНч║з:ш░ГчФицЦ╣хРДшЗкхЕЬх║Х)уАВ */
export function parseTimeRange(mes: string): { start?: string; end?: string } {
  const s = String(mes ?? '');
  const start = s.match(RE_START)?.[1]?.trim() || undefined;
  const end = s.match(RE_END)?.[1]?.trim() || undefined;
  return { start, end };
}

/**
 * х╜УхЙНуАМцХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤уАН:ф╗О chat цЬлх░╛х╛АхЙНцЙл,хПЦчммф╕АцЭбшзгцЮРх╛ЧхИ░чЪДцЧ╢щЧ┤(end ф╝ШхЕИ,ч╝║хИЩ start)уАВ
 *
 * ф╕║ф╗Аф╣Иф╕НчЫ┤цОечФиц┤╛чФЯчЪД memory.state.time:щВгф╕кхПкщЗНцФ╛уАМх╖▓чФЯцИРхП╢хнРуАНчЪДце╝х▒В,цЬАцЦ░хЗах▒Вц▓бцСШцЧ╢х░▒хБЬхЬицЧзхА╝уАВ
 * шАМцЬАцЦ░ AI це╝цнгцЦЗщЗМцЬмх░▒х╕ж <bbs_end>,ш┐ЩщЗМчЫ┤цОешп╗хоГ,цЧашо║цСШц▓бцСШщГ╜цЛ┐хИ░чЬЯхоЮцЬАцЦ░цЧ╢щЧ┤уАВ
 *
 * хПЦхА╝ф╝ШхЕИч║з(цпПцЭбц╢ИцБп):тСа цнгцЦЗ <bbs_start>/<bbs_end> цаЗчн╛(цЬАцЭГхиБ,ф╕НхПЧцШпхРжх╖▓цСШх╜▒хУН);
 *   тСб цаЗчн╛ч╝║хд▒цЧ╢хЫЮщААхИ░шпеце╝хП╢хнРчЪД timeEnd/timeStart тАФтАФ шжЖчЫЦуАМцЧзшБКхдйшбецСШуАНхЬ║цЩп:щВгф║Ыце╝цнгцЦЗщЗМ
 *   ц▓бцЬЙцЧ╢щЧ┤цаЗчн╛(чФицПТф╗╢хЙНчФЯцИРчЪД),ф╜ЖшбецСШх╖▓цККцЧ╢щЧ┤хЖЩш┐ЫхП╢хнРуАВх░Сф║Жш┐Щф╕кхЕЬх║Х,цХ┤щб╡чЫ╕хп╣цЧ╢щЧ┤ф╝ЪхЫа
 *   хПВчЕзчВ╣(now)ф╕║чй║шАМхЕищГиф╕НцШ╛чд║уАВ
 * чФищАФ:тСа цСШшжБщб╡уАМх╜УхЙНцЧ╢щЧ┤уАНх▒Хчд║;тСб хОЖхП▓цСШшжБц│ихЕецЧ╢чЫ╕хп╣цЧ╢щЧ┤чЪДхПВчЕзчВ╣(уАМчО░хЬиуАН)уАВ
 * хЕищГишзгцЮРф╕НхИ░(ч║пцЮ╢чй║/цЧацаЗчн╛ф╕ФцЧахП╢хнР)тЖТ ш┐ФхЫЮчй║ф╕▓,ш░ГчФицЦ╣хРДшЗкхЫЮщААуАВ
 */
export function latestStoryTime(chat: STMessage[] | null): string {
  if (!chat) return '';
  for (let i = chat.length - 1; i >= 0; i--) {
    const m = chat[i];
    if (typeof m?.mes !== 'string' || !m.mes) continue;
    // тСа цнгцЦЗцаЗчн╛ф╝ШхЕИ
    const { start, end } = parseTimeRange(clampToTimeTags(m.mes));
    const tagTime = end || start;
    if (tagTime) return tagTime;
    // тСб цаЗчн╛ч╝║хд▒ тЖТ хЫЮщААшпеце╝цЬЙцХИхП╢хнРчЪДцЧ╢щЧ┤(цЧзшБКхдйшбецСШ:цнгцЦЗцЧацаЗчн╛ф╜ЖхП╢хнРцЬЙцЧ╢щЧ┤)
    const leaf = m.extra?.bbs_leaf as LeafExtra | undefined;
    if (leaf?.id && leaf.delta && leafSwipeMatches(leaf, m)) {
      const leafTime = leaf.timeEnd?.trim() || leaf.timeStart?.trim();
      if (leafTime) return leafTime;
    }
  }
  return '';
}

/** хП╢хнРщб╡чаБцШпхРжхМ╣щЕНх╜УхЙН swipe(ф╕О apply.leafValid хРМхПгх╛Д;хЖЕшБФщБ┐хЕН timeTagтЖФapply х╛кчОпф╛Эш╡Ц)уАВ */
function leafSwipeMatches(leaf: LeafExtra, m: STMessage): boolean {
  const leafSwipe = typeof leaf.swipe === 'number' ? leaf.swipe : 0;
  const msgSwipe = typeof m.swipe_id === 'number' ? m.swipe_id : 0;
  return leafSwipe === msgSwipe;
}

/**
 * цМЙцаЗчн╛хРНчФЯцИРуАМцХ┤хЭЧхИащЩдуАНцнгхИЩ(хРлцаЗчн╛цЬмш║лф╕ОхЖЕщГихЖЕхо╣)уАВtag х╖▓чФ▒ sanitizeTagName хЙФщЩдцнгхИЩхЕГхнЧчмж,
 * цЛ╝ш┐Ы RegExp хоЙхЕиуАВш╛╣чХМчФихЙНчЮ╗ (?=[\s/>]) шАМщЭЮ \b тАФтАФ \b хПкшод ASCII шпНхнЧчмж,ф╕нцЦЗцаЗчн╛(хжВ <щЫк>)
 * хЬи `щЫк` ф╕О `>` ф╣ЛщЧ┤цЧашпНш╛╣чХМф╝ЪхМ╣щЕНхд▒ш┤е;хЙНчЮ╗уАМцаЗчн╛хРНхРОщб╗ч┤зш╖Ячй║чЩ╜/цЦЬцЭа/хП│цЛмхП╖уАНхп╣ф╕ншЛ▒цЦЗщГ╜цИРчлЛ,
 * ф╕ФхРМца╖щШ▓цнв <snow> шппхРГ <snowball> хЙНч╝АуАВхРМцЧ╢хИащЕНхп╣хЭЧф╕ОшР╜хНХчЪДшЗкщЧн/хНХцаЗчн╛уАВ
 */
function blockStripRegexes(tag: string): RegExp[] {
  return [
    new RegExp(`<${tag}(?=[\\s/>])[^>]*>[\\s\\S]*?</${tag}>`, 'gi'), // щЕНхп╣хЭЧ
    new RegExp(`<\\/?${tag}(?=[\\s/>])[^>]*\\/?>`, 'gi'), // шР╜хНХчЪДх╝А/щЧн/шЗкщЧнцаЗчн╛
  ];
}

/** хИацОЙчФицИ╖хЬишо╛ч╜ощЗМщЕНч╜очЪДшЗкхоЪф╣ЙцаЗчн╛(цХ┤хЭЧ:цаЗчн╛ + хЖЕщГихЖЕхо╣)уАВчй║хРНхНХхИЩхОЯца╖ш┐ФхЫЮуАВ */
function stripCustomTags(s: string): string {
  let out = s;
  for (const tag of apiSettings.customStripTags) {
    if (!tag) continue;
    for (const re of blockStripRegexes(tag)) out = out.replace(re, '');
  }
  return out;
}

/**
 * цККф╕Ацо╡цнгцЦЗц╕Ец┤ЧцИРуАМх╣▓хЗАцнгцЦЗцо╡уАН:хЙФщЩдцнгцЦЗф╣ЛхдЦчЪДца╝х╝Пф╕ОхЩкхг░,ф╜Ж**ф╕НхБЪуАМшг╕хИацаЗчн╛чХЩхЖЕхо╣уАН**тАФтАФ
 * хПкцХ┤хЭЧхИащЩдцШОчбочЪДщЭЮцнгцЦЗцаЗчн╛(цАЭч╗┤щУ╛/ц│ищЗК/цЧз horae/чЙйхУБцЧБц│и/чФицИ╖шЗкхоЪф╣ЙцаЗчн╛),хЕ╢ф╜ЩхОЯца╖ф┐ЭчХЩуАВ
 *
 * ф╕дцне:
 *  тСа цХ┤хЭЧхИащЩдхЩкхг░цаЗчн╛(хРлхЖЕщГихЖЕхо╣);
 *  тСб шгБхЙкхИ░цЧ╢щЧ┤цаЗчн╛хМ║щЧ┤:хПЦуАМцЬАхРОф╕Аф╕к <bbs_start>уАН+уАМчммф╕Аф╕к </bbs_end>уАНф╣ЛщЧ┤(цаЗчн╛ф┐ЭчХЩ)тАФтАФ
 *     цАЭч╗┤щУ╛/чК╢цАБцаПхПпшГ╜ц╖╖хЕехРМхРНцаЗчн╛,х╝АхзЛцаЗчн╛хПЦцЬлцмбуАБч╗УцЭЯцаЗчн╛хПЦщжЦцмб,ч▓╛хЗЖцбЖхЗ║чЬЯцнгчЪДцнгцЦЗцо╡;
 *     ф╗ЕхЬихп╣х║ФцаЗчн╛хнШхЬицЧ╢цЙНшгБхЙк,ч╝║цаЗчн╛чЪДф╕Аф╛зф┐ЭцМБхОЯца╖(ф╕дф╛зщГ╜ц▓бцЬЙхИЩф╕НшгБ,шжЖчЫЦуАМцЧзшБКхдйцЧацаЗчн╛уАНхЬ║цЩп)уАВ
 *  тСв шзДшМГчй║чЩ╜уАВ
 *
 * ц│и:хОЖхП▓ф╕Кш┐ЩщЗМф╣ЛхРОш┐Шш╖Яф╕АщБУ stripHtml хБЪуАМхИацЙАцЬЙцаЗчн╛чХЩхЖЕхо╣уАН,хПНшАМцККшЗкхоЪф╣ЙцаЗчн╛хИац▓буАБф╗дцХ┤хЭЧц╕Ец┤Чхд▒цХИ;
 * чО░х╖▓х║Ях╝Г stripHtml,цФ╣ф╕║хПкцХ┤хЭЧхИауАБф┐ЭчХЩхЕ╢ф╜ЩцаЗчн╛хОЯцЦЗ(ф╕╗/хЙпцибхЮЛщГ╜шГ╜ц╢ИхМЦцоЛчХЩцаЗчн╛)уАВ
 */
// цАЭч╗┤щУ╛хЭЧцнгхИЩ(щЕНхп╣хЭЧ,хРлхЖЕщГихЖЕхо╣)уАВф╛Ы clampToTimeTags ф╕ОхЕех║УхЙНщвДц╕Ец┤ЧхЕ▒чФи,щБ┐хЕНф╕дхдДц╝Вчз╗уАВ
const RE_THINK_BLOCK = /<think(?:ing)?\b[\s\S]*?<\/think(?:ing)?>/gi;

/**
 * хПкхЙецАЭч╗┤щУ╛ <think>/<thinking> хЭЧ(хРлхЖЕщГихЖЕхо╣)уАВ
 * чФиф║ОхРСщЗПх║У**хЕех║УхЙН**щвДц╕Ец┤Ч:цАЭч╗┤щУ╛цШпчбохоЪцАзхЩкхг░(ф╕Нф╛Эш╡Цф╗╗ф╜ХчФицИ╖щЕНч╜о),
 * хЕех║УцЧ╢хИацОЙцЧвчЬБчй║щЧ┤хПИщЫ╢щгОщЩй;шАМшЗкхоЪф╣ЙцаЗчн╛чнЙуАМхПпхПШщЕНч╜оуАНчЪДц╕Ец┤Чф╗НчХЩхИ░хПмхЫЮцЧ╢хБЪ(цЙНшГ╜шойцФ╣шо╛ч╜охН│цЧ╢чФЯцХИ)уАВ
 */
export function stripThinkBlocks(mes: string): string {
  return String(mes ?? '').replace(RE_THINK_BLOCK, '');
}

export function clampToTimeTags(mes: string): string {
  let s = String(mes ?? '')
    .replace(RE_THINK_BLOCK, '') // цАЭч╗┤щУ╛
    .replace(/<!--[\s\S]+?-->/g, '') // HTML ц│ищЗК
    .replace(/<horae[\s\S]*?>[\s\S]*?<\/horae[\s\S]*?>/gi, '') // цЧз horae ца╝х╝П
    .replace(RE_ITEMS_BLOCK, ''); // чЙйхУБхПШхКицЧБц│и(цПТф╗╢хЖЩш┐ЫцнгцЦЗ,ф╕Ншпеш┐ЫцСШшжБ/ч┤вх╝Х)
  s = stripCustomTags(s); // чФицИ╖шЗкхоЪф╣ЙцаЗчн╛

  // цЬАхРОф╕Аф╕к <bbs_start> чЪДф╜Нч╜о:хЕих▒АцЙлф╕АщБНхПЦцЬлцмб
  const startRe = new RegExp(`<${START_TAG}\\b`, 'gi');
  let lastStart = -1;
  for (let m = startRe.exec(s); m; m = startRe.exec(s)) lastStart = m.index;
  if (lastStart >= 0) s = s.slice(lastStart);
  // чммф╕Аф╕к </bbs_end>(хЬих╖▓шгБш┐ЗхЙНч╝АчЪДф╕▓щЗМцЙ╛)
  const endMatch = s.match(new RegExp(`</${END_TAG}>`, 'i'));
  if (endMatch && endMatch.index !== undefined) {
    s = s.slice(0, endMatch.index + endMatch[0].length);
  }
  // шзДшМГчй║чЩ╜(хОЯчФ▒ stripHtml ш┤Яш┤г,чО░хЖЕч╜о)
  return s
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

/**
 * ч╗Яф╕АцнгцЦЗц╕Ец┤ЧхЕехПг(цЫ┐ф╗гцЧзчЪД stripHtml щУ╛ш╖п):шгБхЙкцнгцЦЗцо╡ тЖТ цККцЧ╢щЧ┤цаЗчн╛ш╜мхПпшп╗цЦЗцЬмуАВ
 * цСШшжБчФЯцИРуАБф╕ЦчХМф╣жцЙлцППуАБхРСщЗПхПмхЫЮц│ихЕехЕищГиш╡░хоГ,ф┐ЭшпБхПгх╛Дф╕АшЗ┤;ф╕НхЖНуАМшг╕хИацаЗчн╛уАН,цоЛчХЩцаЗчн╛хОЯца╖ф┐ЭчХЩуАВ
 */
export function cleanBody(mes: string): string {
  return inlineTimeTags(clampToTimeTags(mes));
}

/**
 * цККцнгцЦЗщЗМчЪДцЧ╢щЧ┤цаЗчн╛ш╜мцИРхПпшп╗хЖЕшБФцЦЗцЬм(cleanBody чЪДцЬАхРОф╕Ацне)уАВ
 * цЧ╢щЧ┤цаЗчн╛ <bbs_start>тАж</bbs_start> ф╕НхЬиуАМцХ┤хЭЧхИащЩдуАНф╣ЛхИЧ,ф╜ЖхЕ╢х░ЦцЛмхП╖х╜вцАБхп╣цибхЮЛф╕НхПЛхе╜,
 * цХЕш╜мцИРуАМ(ш╡╖хзЛцЧ╢щЧ┤:X)/(ч╗УцЭЯцЧ╢щЧ┤:X)уАНч║пцЦЗцЬм,ф┐ЭчХЩцЧ╢щЧ┤ф┐бцБпхПИхО╗цОЙцаЗчн╛хдЦх╜вуАВ
 */
export function inlineTimeTags(mes: string): string {
  return String(mes ?? '')
    .replace(RE_START, (_, t) => `(ш╡╖хзЛцЧ╢щЧ┤:${String(t).trim()})`)
    .replace(RE_END, (_, t) => `(ч╗УцЭЯцЧ╢щЧ┤:${String(t).trim()})`);
}

// цЧ╢щЧ┤цо╡хОЛч╝йчФичЪДуАМхИЖщЪФш╛╣чХМуАН:хЫЮщААхЕмхЕ▒хЙНч╝АхИ░ш┐Щф║ЫхнЧчмжф╣ЛхРО,щБ┐хЕНхИЗхИ░ token ф╕нщЧ┤уАВ
// хПкхРлуАМцЧецЬЯцо╡/цЧ╢хИ╗цо╡уАНф╣ЛщЧ┤чЪДхИЖщЪФчмж(чй║ца╝ / я╝Н ф╕Оф╕нцЦЗцЧецЬЯхНХф╜Н х╣┤цЬИцЧе),
// цХЕцДПф╕НхРл : ф╕О цЧ╢/чВ╣ тАФтАФ щВгф╝ЪцКК 06:45 чЪДцЧ╢хИЖф╣ЯхИЗчвО(хИЗцИР 55),хПкцГ│хОЛцОЙщЗНхдНчЪДцЧецЬЯхЙНч╝АуАВ
const RANGE_BOUNDARY = /[\s/я╝П\-я╝Нх╣┤цЬИцЧе]/;

/**
 * хОЛч╝йуАМш╡╖ - цнвуАНцЧ╢щЧ┤цо╡:хИацОЙч╗УцЭЯцЧ╢щЧ┤щЗМф╕Ох╝АхзЛцЧ╢щЧ┤щЗНхдНчЪДхЙНч╝А(хдЪф╕║цЧецЬЯ),
 * шой "2023/9/10 06:45 - 2023/9/10 06:55" цШ╛чд║цИР "2023/9/10 06:45 - 06:55"уАВ
 *
 * щАЪчФихБЪц│Х(ф╕НшзгцЮРхЕ╖ф╜УцЧецЬЯца╝х╝П):хПЦщжЦх░╛цЬАщХ┐хЕмхЕ▒хЙНч╝А,хЫЮщААхИ░цЬАш┐СчЪДхИЖщЪФш╛╣чХМ(хРл),
 * цККш┐Щцо╡хЙНч╝Аф╗Оч╗УцЭЯцЧ╢щЧ┤щЗМхИацОЙуАВцаЗхЗЖца╝х╝Пф╕ОхПдщгО("х║ЖхОЖхЫЫх╣┤цШе ш╛░цЧ╢")щГ╜щАВчФи;
 * ф╕дф╕▓хЙНч╝Аф╕НщЗНхРИцЧ╢хОЛф╕НхКи,хОЯца╖ф┐ЭчХЩхЕиф╕▓тАФтАФщЫ╢шппф╝д,цЧащЬАхИдцЦнуАМшГ╜хРжшзгцЮРуАНуАВ
 */
function compactPair(a: string, b: string): string {
  if (!a || !b) return a || b || '';
  if (a === b) return a;
  if (a.startsWith(b)) return a; // ч╗УцЭЯцЧ╢щЧ┤цШпх╝АхзЛцЧ╢щЧ┤чЪДхЙНч╝А(цЧацЦ░ф┐бцБп)тЖТ хПкцШ╛чд║х╝АхзЛ
  let n = 0;
  const max = Math.min(a.length, b.length);
  while (n < max && a[n] === b[n]) n++;
  // хЫЮщААхИ░хЕмхЕ▒хЙНч╝АхЖЕцЬАхРОф╕Аф╕кш╛╣чХМхнЧчмжф╣ЛхРО
  let cut = 0;
  for (let i = 0; i < n; i++) if (RANGE_BOUNDARY.test(a[i])) cut = i + 1;
  const tail = b.slice(cut).trim();
  return tail ? `${a} - ${tail}` : a;
}

/**
 * цККш╡╖цнвцЧ╢щЧ┤ца╝х╝ПхМЦцИРх▒Хчд║чФичЪДцЧ╢щЧ┤цо╡ф╕▓:
 *  - щГ╜цЬЙф╕Фф╕НхРМ тЖТ хОЛч╝йхРОчЪД "start - end";щГ╜цЬЙф╕ФчЫ╕хРМ тЖТ "start";хПкцЬЙф╕Аф╕к тЖТ щВгф╕Аф╕к;щГ╜цЧа тЖТ ''уАВ
 */
export function formatRange(start?: string, end?: string): string {
  const a = start?.trim();
  const b = end?.trim();
  if (a && b) return compactPair(a, b);
  return a || b || '';
}

/**
 * цККх╖▓хнШф╕║хоМцХ┤ф╕▓чЪДх▒Хчд║цаЗчн╛("ш╡╖ - цнв")хЖНхОЛч╝йф╕Ацмб,ф╛ЫхИЧшбицШ╛чд║чФиуАВ
 * чФиф║ОхОЖхП▓цХ░цНо:цЧзцСШшжБчЪД timeLabel х╖▓хЫ║хМЦцИРхоМцХ┤ф╕▓,х▒Хчд║цЧ╢хН│цЧ╢хОЛч╝й,цЧащЬАш┐Бчз╗уАВ
 * хп╣х╖▓хОЛч╝йчЪДцаЗчн╛х╣ВчнЙ(хЖНхИЗхЖНхОЛч╗УцЮЬф╕НхПШ)уАВцЧа " - " хИЖщЪФчЪДхНХчВ╣ф╕▓хОЯца╖ш┐ФхЫЮуАВ
 */
export function compactTimeLabel(label: string): string {
  const s = String(label ?? '').trim();
  const i = s.indexOf(' - ');
  if (i < 0) return s;
  return compactPair(s.slice(0, i).trim(), s.slice(i + 3).trim());
}

/**
 * цККцЧзцХ░цНощЗМхЫ║хМЦцИРхНХхнЧцо╡чЪД timeLabel цЛЖхЫЮ {start,end},ф╛Ыш┐Бчз╗хИ░ timeStart/timeEndуАВ
 * цЧа " - " хИЖщЪФчЪДхНХчВ╣ф╕▓ тЖТ start=end=шпеф╕▓уАВчй║ф╕▓ тЖТ ф╕дшАЕчЪЖ undefinedуАВ
 */
export function splitTimeLabel(label?: string): { start?: string; end?: string } {
  const s = String(label ?? '').trim();
  if (!s) return {};
  const i = s.indexOf(' - ');
  if (i < 0) return { start: s, end: s };
  return { start: s.slice(0, i).trim() || undefined, end: s.slice(i + 3).trim() || undefined };
}

// чЙйхУБхПШхКихЭЧ:хИацЧзчФи(цХ┤цо╡,хРлцаЗчн╛)
const RE_ITEMS_BLOCK = new RegExp(`\\n*<${ITEMS_TAG}\\b[^>]*>[\\s\\S]*?</${ITEMS_TAG}>`, 'gi');

// хоЪф╜НуАМцЬАхРОф╕Аф╕к </bbs_end>уАНчФи(хЕих▒АцЙл,хПЦцЬлцмб):цнгцЦЗцЬлх░╛чЪДцЧ╢щЧ┤цаЗчн╛цЙНцШпчЬЯцнгчЪДхЙзцГЕч╗УцЭЯ,
// цАЭч╗┤щУ╛/чК╢цАБцаПхПпшГ╜хЬихЙНщЭвц╖╖хЕехРМхРНцаЗчн╛,цХЕф╕НшГ╜чФичммф╕Аф╕к(шзБ clampToTimeTags хРМцм╛шАГщЗП)уАВ
const RE_END_CLOSE_G = new RegExp(`</${END_TAG}>`, 'gi');

/**
 * цККчЙйхУБхПШхКицЧБц│ихЖЩш┐ЫцнгцЦЗ:хЕИхИацОЙцЧзчЪД <bbs_items> хЭЧ(х╣ВчнЙ,щЗНцСШ/щЗНчФЯцИРф╕НхПахКа),
 * хЖНцККцЦ░хЭЧцПТхИ░**цЬАхРОф╕Аф╕к** </bbs_end> ф╣ЛхРО(цЧа end цаЗчн╛хИЩш┐╜хКахИ░цЬлх░╛)уАВ
 * inline ф╕║чй║ тЖТ хПкц╕ЕщЩдцЧзхЭЧуАБф╕НхЖЩцЦ░хЭЧ(цЬмце╝цЧачЙйхУБхПШхКицЧ╢)уАВ
 * ш┐ФхЫЮхдДчРЖхРОчЪДцнгцЦЗ(ш░ГчФицЦ╣ш┤Яш┤гхЖЩхЫЮ mes)уАВ
 */
export function writeItemLogTag(mes: string, inline: string): string {
  let s = String(mes ?? '').replace(RE_ITEMS_BLOCK, '');
  const text = inline.trim();
  if (!text) return s;
  // цаЗчн╛ф╕ОхЖЕхо╣хРДшЗкчЛмхНашбМ,хЭЧхЙНчХЩчй║шбМ,цОТчЙИц╕ЕчИ╜ф╕Фф╕Нф╕ОцЧ╢щЧ┤цаЗчн╛ч▓Шш┐Ю
  const block = `<${ITEMS_TAG}>\n${text}\n</${ITEMS_TAG}>`;
  // хПЦцЬАхРОф╕Аф╕к </bbs_end> чЪДч╗УцЭЯф╜Нч╜о
  let lastEnd = -1;
  RE_END_CLOSE_G.lastIndex = 0;
  for (let m = RE_END_CLOSE_G.exec(s); m; m = RE_END_CLOSE_G.exec(s)) lastEnd = m.index + m[0].length;
  if (lastEnd >= 0) {
    return `${s.slice(0, lastEnd)}\n${block}${s.slice(lastEnd)}`;
  }
  return `${s.trimEnd()}\n${block}`;
}

// цПРхПЦ <bbs_items> хЭЧхЖЕцЦЗцЬмчФи
const RE_ITEMS_INNER = new RegExp(`<${ITEMS_TAG}\\b[^>]*>([\\s\\S]*?)</${ITEMS_TAG}>`, 'i');

/**
 * шп╗хПЦцнгцЦЗщЗМчЪД <bbs_items> хЭЧхЖЕцЦЗцЬм(хО╗щжЦх░╛чй║чЩ╜)уАВ
 * цЧахЭЧш┐ФхЫЮ null(хМ║хИлф║ОуАМцЬЙхЭЧф╜Жчй║уАНтАФтАФхРОшАЕш┐ФхЫЮ ''),ф╛ЫхПНшзгцЮРхИдцЦнчФицИ╖цШпхРжхИаф║ЖцХ┤хЭЧуАВ
 */
export function readItemsTagText(mes: string): string | null {
  const m = String(mes ?? '').match(RE_ITEMS_INNER);
  return m ? m[1].trim() : null;
}

/* ============ шЗкхКиц│ихЖМуАМф╗ЕцШ╛чд║х▒ВщЪРшЧПуАНцнгхИЩхИ░ ST ============ */

// ST хЕих▒АцнгхИЩшДЪцЬмхнШхЬи extension_settings.regex(цХ░ч╗Д)уАВцИСф╗мчФихЫ║хоЪ id цаЗшпЖшЗкх╖▒ш┐ЩцЭб,хБЪхИ░х╣ВчнЙуАВ
// id ф┐ЭцМБхОЖхП▓хА╝ 'bbs-time-tag-hide' ф╕НхПШ(цФ╣ id ф╝Ъхп╝шЗ┤шАБчФицИ╖цЧзцнгхИЩцоЛчХЩ + цЦ░х╗║ф╕АцЭбщЗНхдН);
// цШ╛чд║хРНх╖▓цЫ┤цЦ░тАФтАФш┐ЩцЭбцнгхИЩхжВф╗КхРМцЧ╢щЪРшЧПцЧ╢щЧ┤цаЗчн╛ф╕ОчЙйхУБхПШхКицаЗчн╛уАВ
const HIDE_SCRIPT_ID = 'bbs-time-tag-hide';
const HIDE_SCRIPT_NAME = 'цЯПхоЭф╣ж ┬╖ щЪРшЧПшо░х┐ЖцаЗчн╛';
// regex_placement(шзБ ST regex/engine.js):0=MD_DISPLAY 1=USER_INPUT 2=AI_OUTPUT
const PLACEMENT_MD_DISPLAY = 0;
const PLACEMENT_USER_INPUT = 1;
const PLACEMENT_AI_OUTPUT = 2;

/** ф╕АцЭбхРМцЧ╢хРГцОЙ start/end/items цаЗчн╛(хРлхЕ╢хЖЕщГихЖЕхо╣)чЪДцнгхИЩхнЧчмжф╕▓(ST чФи /pattern/flags х╜вх╝П) */
function hideFindRegex(): string {
  return `/<\\/?(?:${START_TAG}|${END_TAG}|${ITEMS_TAG})\\b[^>]*>(?:[\\s\\S]*?<\\/(?:${START_TAG}|${END_TAG}|${ITEMS_TAG})>)?/gi`;
}

/**
 * чбоф┐Э ST щЗМхнШхЬицИСф╗мчЪДуАМщЪРшЧПшо░х┐ЖцаЗчн╛уАНцнгхИЩшДЪцЬм(щЪРшЧПцЧ╢щЧ┤цаЗчн╛ + чЙйхУБхПШхКицаЗчн╛,ф╗Ех╜▒хУНцШ╛чд║,ф╕Нх╜▒хУНцПРчд║шпН)уАВ
 * х╣ВчнЙ:цМЙхЫ║хоЪ id цЯе,ч╝║хИЩшбеуАБх╖▓хнШхЬихИЩцЫ┤цЦ░хЖЕхо╣(щШ▓цнвцЧзчЙИцЬмца╝х╝ПцоЛчХЩ)уАВчФицИ╖цЙЛхКихИаф║Жф╕ЛцмбхРпхКиф╝ЪхЖНхКахЫЮуАВ
 */
export function ensureHideRegexRegistered(): void {
  const ctx = getContext();
  const es = ctx?.extensionSettings as Record<string, unknown> | undefined;
  if (!es) return;
  if (!Array.isArray(es.regex)) es.regex = [];
  const list = es.regex as Array<Record<string, unknown>>;

  const script = {
    id: HIDE_SCRIPT_ID,
    scriptName: HIDE_SCRIPT_NAME,
    findRegex: hideFindRegex(),
    replaceString: '',
    trimStrings: [] as string[],
    // хПкф╜ЬчФиф║ОуАМцШ╛чд║уАН:MD_DISPLAY;хРМцЧ╢ц╕ЕцОЙчФицИ╖ш╛УхЕе/AI ш╛УхЗ║цШ╛чд║щЗМчЪДцоЛчХЩцаЗчн╛,ф╜Жф╕Нш┐ЫцПРчд║шпНуАВ
    placement: [PLACEMENT_MD_DISPLAY, PLACEMENT_USER_INPUT, PLACEMENT_AI_OUTPUT],
    disabled: false,
    markdownOnly: true, // = ф╗Еца╝х╝ПхМЦцШ╛чд║,ф╕НцФ╣хЖЩхПСч╗ЩцибхЮЛчЪДцПРчд║шпН(хЕ│щФо:цаЗчн╛х┐Ещб╗чХЩхЬицПРчд║шпНщЗМ)
    promptOnly: false,
    runOnEdit: true,
    substituteRegex: 0,
    minDepth: null,
    maxDepth: null,
  };

  const idx = list.findIndex(s => s?.id === HIDE_SCRIPT_ID);
  if (idx >= 0) list[idx] = { ...list[idx], ...script };
  else list.push(script);
  ctx?.saveSettingsDebounced?.();
}

/** чз╗щЩдцИСф╗мц│ихЖМчЪДщЪРшЧПцнгхИЩ(хЕ│щЧнцЧ╢щЧ┤цаЗчн╛хКЯшГ╜цЧ╢ш░ГчФи)уАВ */
export function removeHideRegex(): void {
  const ctx = getContext();
  const es = ctx?.extensionSettings as Record<string, unknown> | undefined;
  if (!es || !Array.isArray(es.regex)) return;
  const list = es.regex as Array<Record<string, unknown>>;
  const next = list.filter(s => s?.id !== HIDE_SCRIPT_ID);
  if (next.length !== list.length) {
    es.regex = next;
    ctx?.saveSettingsDebounced?.();
  }
}

/**
 * хРМцнецЧ╢щЧ┤цаЗчн╛хКЯшГ╜чЪДхЙпф╜ЬчФи(х╝АхЕ│хПШхМЦцИЦхРпхКицЧ╢ш░ГчФи):
 *  - х╝А:ц│ихЖМщЪРшЧПцнгхИЩ;хЕ│:чз╗щЩдуАВцПРчд║шпНц│ихЕечФ▒ inject.ts чЪД refreshInjection ш┤Яш┤гуАВ
 * ш╖ЯщЪПуАМшЗкхКицСШшжБуАНх╝АхЕ│(цЧ╢щЧ┤цаЗчн╛ф╕НхЖНчЛмчлЛ)уАВ
 */
export function syncTimeTagRegex(): void {
  if (apiSettings.autoSummaryEnabled) ensureHideRegexRegistered();
  else removeHideRegex();
}
