<script setup lang="ts">
import Icon from '@/components/Icon.vue';
import NavBar from '@/components/NavBar.vue';
import FloatingOrb from '@/components/FloatingOrb.vue';
import { getPage } from '@/pages/registry';
import { closeBook, cycleTheme, lastOpenedAt, THEMES, ui } from '@/state/ui';
import { computed, onMounted, onUnmounted, ref } from 'vue';

// щвШщжЦф╕╗щвШцМЙщТо:цШ╛чд║уАМф╕Лф╕Аф╕куАНф╕╗щвШчЪДхЫ╛цаЗф╕ОхРН,чВ╣хЗ╗хН│хИЗцНвхИ░хоГ
const nextTheme = computed(() => {
  const i = THEMES.findIndex(t => t.value === ui.theme);
  return THEMES[(i + 1) % THEMES.length];
});

// цШпхРжчкДх▒П(чз╗хКичлп):чФиф║О nav 'auto' чЪДцЦ╣хРСхИдхоЪ + цК╜х▒ЙцЙЛхК┐х╝АхЕ│уАВ
// matchMedia хПШхМЦ Vue ф╕Нф╝ЪшЗкхКиш┐╜ш╕к,чФи ref цбецОецИРхУНх║Фх╝ПуАВ
const isNarrow = window.matchMedia('(max-width: 640px)');
const narrowFlag = ref(isNarrow.matches);
const onMq = (e: MediaQueryListEvent) => (narrowFlag.value = e.matches);
onMounted(() => isNarrow.addEventListener('change', onMq));
onUnmounted(() => isNarrow.removeEventListener('change', onMq));

const navPlacement = computed<'top' | 'bottom'>(() => {
  if (ui.navPosition === 'top') return 'top';
  if (ui.navPosition === 'bottom') return 'bottom';
  return narrowFlag.value ? 'bottom' : 'top';
});

const current = computed(() => getPage(ui.activePage));

// тАФтАФ щБоч╜йчВ╣хЗ╗хЕ│щЧн:ф╗Ех╜УцМЙф╕Лф╕ОцЭ╛х╝АщГ╜хЬищБоч╜йцЬмш║луАВ
// щБ┐хЕН:1) чз╗хКичлпцЙУх╝АцЙЛхК┐чЪДхРИцИР click чй┐щАПчзТхЕ│;2) чкЧхЖЕцМЙф╕ЛцЛЦхИ░чкЧхдЦшппхЕ│уАВ
let pressedOnOverlay = false;

function onOverlayPointerDown(e: PointerEvent) {
  pressedOnOverlay = e.target === e.currentTarget;
}

function onOverlayClick(e: MouseEvent) {
  const justOpened = performance.now() - lastOpenedAt < 350;
  if (!justOpened && pressedOnOverlay && e.target === e.currentTarget) closeBook();
  pressedOnOverlay = false;
}

// тАФтАФ чз╗хКичлп:ф╕Лц╗СхЕ│щЧнцК╜х▒Й тАФтАФ
const dragY = ref(0); // х╜УхЙНф╕ЛцЛЙф╜Нчз╗(px)
const dragging = ref(false);
let startY = 0;
let activePointer: number | null = null;
const CLOSE_THRESHOLD = 110; // ш╢Еш┐Зцндф╜Нчз╗цЭ╛цЙЛхН│хЕ│щЧн

function onHandleDown(e: PointerEvent) {
  if (!narrowFlag.value) return;
  activePointer = e.pointerId;
  startY = e.clientY;
  dragging.value = true;
  (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
}

function onHandleMove(e: PointerEvent) {
  if (!dragging.value || e.pointerId !== activePointer) return;
  // хПкш╖ЯщЪПхРСф╕ЛчЪДф╜Нчз╗
  dragY.value = Math.max(0, e.clientY - startY);
}

function onHandleUp(e: PointerEvent) {
  if (!dragging.value || e.pointerId !== activePointer) return;
  dragging.value = false;
  activePointer = null;
  if (dragY.value > CLOSE_THRESHOLD) {
    closeBook();
  }
  dragY.value = 0;
}

// цК╜х▒Йш╖ЯцЙЛца╖х╝П:цЛЦхКицЧ╢чжБчФиш┐Зц╕б,цЭ╛цЙЛцЧ╢хЫЮх╝╣цЬЙш┐Зц╕б
const windowStyle = computed(() => {
  if (!narrowFlag.value || dragY.value === 0) return undefined;
  return {
    transform: `translateY(${dragY.value}px)`,
    transition: dragging.value ? 'none' : undefined,
  };
});
</script>

<template>
  <div class="bbs-root" :data-theme="ui.theme">
    <!-- цВмц╡очРГ:чХЩхЬи shadow хЖЕцЙНшГ╜чФи --bbs-* ф╕╗щвШхПШщЗП;шЗкш║л position:fixed ш┤┤ш╛╣,ф╕НхПЧ host х╜▒хУН -->
    <FloatingOrb v-if="ui.showOrb" />
    <Transition name="bbs-fade">
      <div
        v-if="ui.open"
        class="bbs-overlay"
        @pointerdown="onOverlayPointerDown"
        @click="onOverlayClick"
        @keydown.esc="closeBook"
        tabindex="-1"
      >
        <!-- чкЧхПгх╕╕щй╗ф║ОщБоч╜йхЖЕ(ф╕НчЛмчлЛ v-ifуАБф╕Нх╡МхеЧ Transition):
             х╡МхеЧ Transition хЬичИ╢хнР v-if хРМцЧ╢ч┐╗ш╜мцЧ╢,хнРчЪД leave ф╕Нф╝ЪшзжхПС(хоЮц╡ЛчкЧхПгчЫ┤цОещЪПчИ╢швлчз╗щЩд,
             цЧаф╗╗ф╜ХхКичФ╗)уАВцФ╣чФ▒щБоч╜й Transition чЪД class ф╜ЬхРОф╗гщАЙцЛйхЩищй▒хКичкЧхПгчЪДш┐ЫхЗ║хЬ║хКичФ╗
             (шзБ <style> щЗМ .bbs-fade-enter-from/.bbs-fade-leave-to ф╕ЛчЪД .bbs-window)уАВ -->
        <div class="bbs-window" :style="windowStyle" role="dialog" aria-modal="true" aria-label="цЯПхоЭф╣ж">
            <!-- чз╗хКичлпцКУцЙЛ:хПпф╕Лц╗СхЕ│щЧн -->
            <div
              v-if="navPlacement !== 'top' || narrowFlag"
              class="bbs-grabber"
              @pointerdown="onHandleDown"
              @pointermove="onHandleMove"
              @pointerup="onHandleUp"
              @pointercancel="onHandleUp"
            >
              <span class="bbs-grabber-bar"></span>
            </div>

            <!-- щвШщжЦ -->
            <header class="bbs-head">
              <span class="bbs-brand-name">цЯПхоЭф╣ж</span>
              <div class="bbs-head-actions">
                <button class="bbs-icon-btn" type="button" :title="`хИЗцНвф╕╗щвШ:${nextTheme.label}`" @click="cycleTheme">
                  <Icon :name="nextTheme.icon" />
                </button>
                <button class="bbs-icon-btn" type="button" title="хЕ│щЧн" @click="closeBook">
                  <Icon name="close" />
                </button>
              </div>
            </header>

            <NavBar v-if="navPlacement === 'top'" placement="top" :narrow="narrowFlag" />

            <main class="bbs-body">
              <Transition name="bbs-page" mode="out-in">
                <component :is="current.component" :key="current.id" />
              </Transition>
            </main>

            <NavBar v-if="navPlacement === 'bottom'" placement="bottom" :narrow="narrowFlag" />
        </div>
      </div>
    </Transition>
  </div>
</template>

<style scoped>
/* тАФтАФ чз╗хКичлпцКУцЙЛ:цбМщЭвщЪРшЧП тАФтАФ */
