  color: var(--bbs-ink);
  background: var(--bbs-line-strong);
}
.bbs-icon-btn:focus-visible {
  outline: 2px solid var(--bbs-accent);
  outline-offset: 2px;
}

/* тАФтАФ ш┐Зц╕б:щБоч╜йц╖бхЕец╖бхЗ║,чкЧхПгщЭащБоч╜йчЪДш┐Зц╕б class шБФхКи(шзБф╕Л) тАФтАФ */
.bbs-fade-enter-active,
.bbs-fade-leave-active {
  transition: opacity var(--bbs-dur) var(--bbs-ease);
}
.bbs-fade-enter-from,
.bbs-fade-leave-to {
  opacity: 0;
}

/* чкЧхПгш┐ЫхЗ║хЬ║:чФ▒щБоч╜й Transition чЪД class ф╜ЬхРОф╗гщАЙцЛйхЩищй▒хКи(чкЧхПгшЗкш║лф╕НхЖНхеЧ TransitionтАФтАФ
   чИ╢хнР v-if хРМцЧ╢ч┐╗ш╜мцЧ╢хнР Transition чЪД leave ф╕НшзжхПС,хоЮц╡ЛчкЧхПгф╝ЪцЧахКичФ╗чЫ┤цОешвлчз╗щЩд)уАВ
   ш┐ЫхЗ║хЬ║ф╕дчлпхРМцм╛ transform тЖТ хп╣чз░уАВPC х╛охНЗ+чХецФ╛хдз;чз╗хКичлпхЬи media query щЗМцФ╣цИРц╗СхЫЮх║ХщГиуАВ */
.bbs-fade-enter-from .bbs-window,
.bbs-fade-leave-to .bbs-window {
  opacity: 0;
  transform: translateY(16px) scale(0.985);
}

.bbs-page-enter-active,
.bbs-page-leave-active {
  transition:
    opacity 0.13s var(--bbs-ease),
    transform 0.13s var(--bbs-ease);
}
.bbs-page-enter-from {
  opacity: 0;
  transform: translateY(6px);
}
.bbs-page-leave-to {
  opacity: 0;
  transform: translateY(-6px);
}

/* чкЧхПгш┐Зц╕б:ш┐ЫхЗ║хЬ║(transform+opacity)ф╕ОцЛЦхКихЫЮх╝╣(transform)хЕ▒чФи;
   цЛЦхКиш╖ЯцЙЛцЧ╢чФ▒хЖЕшБФ style чЪД transition:none шжЖчЫЦ,цЭ╛цЙЛхЫЮх╝╣хЖНш╡░ш┐ЩцЭбуАВ */
.bbs-window {
  transition:
    transform var(--bbs-dur) var(--bbs-ease),
    opacity var(--bbs-dur) var(--bbs-ease);
}

/* ============ чз╗хКичлп:цКУцЙЛ + цК╜х▒Йф╕Кц╗СхЕехЬ║ ============ */
@media (max-width: 640px) {
  .bbs-grabber {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 auto;
    height: 26px;
    cursor: grab;
    touch-action: none;
  }
  .bbs-grabber-bar {
    width: 40px;
    height: 4px;
    border-radius: var(--bbs-radius-pill);
    background: var(--bbs-line-strong);
  }
  .bbs-head {
    padding: 4px 16px 12px;
  }
  /* цК╜х▒Йф╗Ох║ХщГиц╗СхЕе / ц╗СхЫЮх║ХщГи(ч║пф╜Нчз╗,ф╕Нц╖бщАПцШО) */
  .bbs-fade-enter-from .bbs-window,
  .bbs-fade-leave-to .bbs-window {
    opacity: 1;
    transform: translateY(100%) scale(1);
  }
  /* щБоч╜йчж╗хЬ║х╗╢хРОц╖бхЗ║:шойцК╜х▒ЙхЕИц╗СхЫЮх║ХщГи,шГМцЩпцо┐хРОхЖНцТд,хРжхИЩчкЧхПгщЪПщБоч╜йф╕Аш╡╖швлцЛЙщАПцШО,
     ц╗СхКиш┐ЗчиЛчЬЛф╕НшзБ(чкЧхПгцШпщБоч╜йхнРхЕГч┤а,чИ╢ opacity ф╝ЪхРИцИРхИ░хнР)уАВ */
  .bbs-fade-leave-active {
    transition: opacity 0.16s var(--bbs-ease) 0.18s;
  }
  /* чкЧхПгц╗СхЫЮх║ХщГишжБш╡░хоМцХ┤ --bbs-dur,ф╕Ншвлф╕КщЭвщБоч╜йчЪДчЯнцЧ╢щХ┐чЙ╡ш┐Ю(хРДшЗк transition чЛмчлЛ,ш┐ЩщЗМф╗Ех╝║ш░Г) */
}
</style>
