/**
 * ф╗О LLM цЦЗцЬмш╛УхЗ║щЗМхБехгохЬ░цПРхПЦ JSON хп╣ш▒буАВ
 * х║Фхп╣:```json хЫ┤цаПуАБцАЭч╗┤щУ╛хЙНхРОч╝АуАБцЩ║шГ╜х╝ХхП╖уАБх░╛щЪПщАЧхП╖уАВ
 */
export function extractJsonObject<T = unknown>(raw: string): T | null {
  if (!raw || typeof raw !== 'string') return null;

  let s = raw.trim();

  // хО╗цОЙ <think>тАж</think> / <thinking>тАж</thinking> цАЭч╗┤щУ╛(хдзх░ПхЖЩф╕НцХПцДЯ)
  s = s.replace(/<think(?:ing)?\b[\s\S]*?<\/think(?:ing)?>/gi, '').trim();

  // assistant prefill хЬ║цЩпф╕Л,ш┐ФхЫЮхПпшГ╜хПкхМЕхРлч╗нхЖЩчЪДцАЭч╗┤щУ╛цнгцЦЗ + </thinking> + JSON,
  // ц▓бцЬЙх╝Ахд┤ <thinking>уАВцндцЧ╢ф╕вх╝ГцЬАхРОф╕Аф╕кщЧнхРИцаЗчн╛хПКхЕ╢ф╣ЛхЙНчЪДхЕищГицЦЗцЬмуАВ
  const danglingThinkClose = s.match(/<\/think(?:ing)?>/gi);
  if (danglingThinkClose) {
    const lastClose = Math.max(
      s.toLowerCase().lastIndexOf('</think>'),
      s.toLowerCase().lastIndexOf('</thinking>'),
    );
    if (lastClose >= 0) {
      const close = s.slice(lastClose).match(/^<\/think(?:ing)?>/i)?.[0] ?? '';
      s = s.slice(lastClose + close.length).trim();
    }
  }

  // хО╗цОЙ ```json ... ``` / ``` ... ``` хЫ┤цаП
  const fence = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) s = fence[1].trim();

  // цИкхПЦчммф╕Аф╕к { хИ░цЬАхРОф╕Аф╕к } ф╣ЛщЧ┤(хО╗цОЙхЙНхРОшп┤цШОцЦЗхнЧ)
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first === -1 || last === -1 || last <= first) return null;
  let body = s.slice(first, last + 1);

  // чЫ┤цОех░ЭшпХ
  const direct = tryParse<T>(body);
  if (direct !== null) return direct;

  // хо╣щФЩц╕Ец┤Ч:цЩ║шГ╜х╝ХхП╖ -> чЫ┤х╝ХхП╖,хО╗х░╛щЪПщАЧхП╖
  body = body
    .replace(/[тАЬтАЭ]/g, '"')
    .replace(/[тАШтАЩ]/g, "'")
    .replace(/,\s*([}\]])/g, '$1');

  return tryParse<T>(body);
}

function tryParse<T>(s: string): T | null {
  try {
    return JSON.parse(s) as T;
  } catch {
    return null;
  }
}
