let idSeq = 0;
/** чФЯцИРчи│хоЪхФпф╕А id(ф╕Нф╛Эш╡Ц random;цЧ╢щЧ┤ш╡░ nowMs ф╛┐ф║Оц╡ЛшпХц│ихЕе) */
function uid(prefix: string): string {
  idSeq += 1;
  return `${prefix}_${nowMs()}_${idSeq}`;
}

// хНХчВ╣х░БшгЕцЧ╢щЧ┤шО╖хПЦ,ц╡ЛшпХхПп mock
function nowMs(): number {
  return Date.now();
}

function norm(s: string): string {
  return s.trim().toLowerCase();
}

/* ============ чбохоЪцАз id ============ */

/** чЙйхУБ id:цМЙшзДшМГхМЦхРН,цХЕщЗНцФ╛х╣ВчнЙуАБцЙЛхКи op хПпчи│хоЪх╝ХчФи */
export function itemId(name: string): string {
  return `item:${norm(name)}`;
}
/** NPC id:цМЙшзДшМГхМЦхРН,цХЕщЗНцФ╛х╣ВчнЙуАБцЙЛхКи op хПпчи│хоЪх╝ХчФи */
export function npcId(name: string): string {
  return `npc:${norm(name)}`;
}
/** шобхИТ id:ф║зчФЯхоГчЪДхП╢хнР id + хЬишпехП╢хнР add цХ░ч╗ДщЗМчЪДх║ПхП╖ */
export function planId(leafId: string, addIndex: number): string {
  return `plan:${leafId}#${addIndex}`;
}

/** шзДшМГхМЦхЬ║цЩпш╖пх╛Д:щАРцо╡ trim,ф╕вх╝Гчй║цо╡уАВш┐ФхЫЮх╣▓хЗАчЪДхОЯцЦЗш╖пх╛Д(ф┐ЭчХЩхдзх░ПхЖЩ,ф╗ЕхО╗щжЦх░╛чй║чЩ╜) */
export function normScenePath(path: string[] | undefined): string[] {
  if (!Array.isArray(path)) return [];
  return path.map(s => String(s ?? '').trim()).filter(Boolean);
}
/** хЬ║цЩп id:цМЙшзДшМГхМЦш╖пх╛Д(х░ПхЖЩуАБ'/'хИЖщЪФ),цХЕщЗНцФ╛х╣ВчнЙуАБцЙЛхКи op хПпчи│хоЪх╝ХчФи */
export function sceneId(path: string[]): string {
  return `scene:${normScenePath(path).map(norm).join('/')}`;
}

/**
 * х╜УхЙНхЬ░чВ╣ тЖФ хЬ║цЩпцаСчЪДуАМцЭГхиБхоЪф╜НуАН:ш┐ФхЫЮх╜УхЙНцЙАхЬишКВчВ╣ id(цЙ╛ф╕НхИ░ш┐ФхЫЮ '')уАВ
 * ц│ихЕечлпф╕ОхЬ║цЩпщб╡**хЕ▒чФицндхЗ╜цХ░**,цЭЬч╗Эф╕дхдДхИЖхПЙхп╝шЗ┤щб╡щЭв/цПРчд║шпНф╕Нф╕АшЗ┤уАВ
 *
 * хоЪф╜Нф╝ШхЕИч║з:
 *  1. locationPath(AI ч╗ЩчЪДцЭГхиБш╖пх╛Д):ч▓╛чбохС╜ф╕нцаСщЗМцЯРшКВчВ╣ тЖТ чФихоГ;хРжхИЩцМЙ**цЬАщХ┐хнШхЬихЙНч╝А**хЫЮщАА
 *     (path цпФцаСцЫ┤ч╗ЖцЧ╢,хБЬхЬишГ╜чбохоЪчЪДщВгф╕Ач║з,хжВ ["цЭнх╖Юх╕В","ц╗иц▒ЯхМ║цЯРшАБх░ПхМ║","302ходх▒ЛхЖЕ"] цаСщЗМ
 *      хПкхИ░ "302ходх▒ЛхЖЕ" х░▒чФихоГ,хПкхИ░ф╕Кч║зф╣ЯцОехПЧ)уАВ
 *  2. цЧа locationPath / хоГхЬицаСщЗМхоМхЕишР╜чй║:щААхЫЮцМЙ location хнЧчмжф╕▓чЪД**цФ╢ч┤зцибч│КхМ╣щЕН**тАФтАФ
 *     ф╗ЕцпФуАМцЬмч║зхРНуАНхТМуАМхоМцХ┤ш╖пх╛Дф╕▓уАН,**ф╕НхЖНцЛ┐хНХф╕кчеЦхЕИцо╡хО╗цпФ**(щВгцнгцШпуАМ302ходщЧихПгуАНщЭачеЦхЕИ
 *     "цЭнх╖Юх╕В" шппхС╜ф╕нуАБф╕ОхРМц╖▒х║жчЪДуАМ302ходх▒ЛхЖЕуАНцЙУх╣│хРОцКвш╡вчЪД bug ца╣хЫа)уАВхПЦхС╜ф╕нщЗМ path цЬАц╖▒шАЕуАВ
 */
export function findCurrentSceneId(scenes: MemScene[], here: string, locationPath?: string[]): string {
  const byId = new Map(scenes.map(s => [s.id, s]));

  // 1) цЭГхиБш╖пх╛Д:ч▓╛чбо тЖТ цЬАщХ┐хнШхЬихЙНч╝А
  const lp = normScenePath(locationPath);
  if (lp.length) {
    for (let depth = lp.length; depth >= 1; depth--) {
      const id = sceneId(lp.slice(0, depth));
      if (byId.has(id)) return id;
    }
  }

  // 2) цФ╢ч┤зцибч│КхМ╣щЕН(хЕЬх║Х):хПкчЬЛцЬмч║зхРН + хоМцХ┤ш╖пх╛Дф╕▓,хПЦцЬАц╖▒
  const h = (here ?? '').trim();
  if (!h) return '';
  let best: MemScene | null = null;
  for (const s of scenes) {
    const hit = sceneNameReachable(s.name, h) || sceneNameReachable(s.path.join(''), h);
    if (hit && (!best || s.path.length > best.path.length)) best = s;
  }
  return best?.id ?? '';
}

/** хМЕхРлх╝ПхПМхРСхМ╣щЕН(хЬ░хРНхС╜хРНч▓Чч╗Жф╕Нф╕АцЧ╢чЪДхЕЬх║Х);чй║ф╕▓ф╕НхМ╣щЕНуАВф╛Ы findCurrentSceneId хЖЕщГичФиуАВ */
function sceneNameReachable(a: string | undefined, b: string): boolean {
  const x = (a ?? '').trim();
  const y = b.trim();
  if (!x || !y) return false;
  return x.includes(y) || y.includes(x);
}

/** хП╢хнР id:ф╕Нч╗Сч┤вх╝ХуАБф╕Нч╗СхЖЕхо╣,хЖЩхЕехН│хЫ║хоЪ */
export function makeLeafId(): string {
  const rand = Math.floor(Math.random() * 36 ** 6).toString(36).padStart(6, '0');
  return `leaf_${nowMs().toString(36)}_${rand}`;
}

