// цнгцЦЗц╕Ец┤Чх╖▓ч╗Яф╕АхИ░ timeTag.ts чЪД cleanBody / clampToTimeTags(цХ┤хЭЧхИахЩкхг░цаЗчн╛,ф╕НхЖНуАМшг╕хИацаЗчн╛чХЩхЖЕхо╣уАН)уАВ

/** хПЦц╢ИцБпф╕КчЪДхП╢хнР(ф╕НцабщкМцЬЙцХИцАз) */
export function getLeaf(m: STMessage | undefined): LeafExtra | undefined {
  return m?.extra?.bbs_leaf as LeafExtra | undefined;
}

/** хП╢хнРч╗УцЮДцШпхРжхоМцХ┤(цЬЙ id + delta)уАВф╕НцабщкМщб╡чаБх╜Тх▒Ю;ф╛Ы pruneBrokenComps хИдуАМхП╢хнРцШпхРжчЙйчРЖхнШхЬиуАНуАВ */
export function leafIntact(m: STMessage | undefined): boolean {
  const leaf = getLeaf(m);
  return !!(leaf && leaf.id && leaf.delta);
}

/** хП╢хнРшо░х╜ХчЪДщб╡чаБ(ч╝║чЬБцМЙчммф╕Ащб╡ 0);ц╢ИцБпх╜УхЙНщб╡чаБхРМхПгх╛Д(swipe_id ч╝║чЬБ 0)уАВ */
function leafSwipe(leaf: LeafExtra): number {
  return typeof leaf.swipe === 'number' ? leaf.swipe : 0;
}
function msgSwipe(m: STMessage): number {
  return typeof m.swipe_id === 'number' ? m.swipe_id : 0;
}

/**
 * хП╢хнРцШпхРжхп╣уАМх╜УхЙНцШ╛чд║чЪДш┐Щф╕Ащб╡уАНцЬЙцХИ:ч╗УцЮДхоМцХ┤ + щб╡чаБх╜Тх▒Юх╜УхЙН swipeуАВ
 *
 * щб╡чаБцабщкМшзгхЖ│хдЪщб╡ф╕▓цЙ░:ST чФЯцИРцЦ░ swipe цЧ╢ structuredClone цЧз extra,ф╝ЪцККф╕Кф╕Ащб╡чЪД bbs_leaf
 * хдНхИ╢ш┐ЫцЦ░щб╡;щЭауАМхП╢хнР swipe тЙа х╜УхЙН swipe_idуАНшпЖхИлх╣╢хд▒цХИтАФтАФч┐╗хИ░ц▓бцСШш┐ЗчЪДщб╡цнгчбоцШ╛чд║уАМч╝║цСШшжБуАН,
 * ч┐╗хЫЮхОЯщб╡щб╡чаБхПИхМ╣щЕНуАБцСШшжБцБвхдНуАВхП╢хнРцХ░цНохзЛч╗ИчХЩхЬихРДшЗк swipe чЪД extra щЗМ,ф╕НхИащЩдуАВ
 *
 * тЪая╕П ф╕НцпФхп╣цнгцЦЗхУИх╕М:цФ╣цнгцЦЗ(щФЩхнЧ/ц╢жшЙ▓)ф╕НцФ╣ swipe_id,цХЕф╕Нф╝ЪхЫацндхд▒цХИтАФтАФш┐ЩцнгцШпчФищб╡чаБшАМщЭЮ
 * srcHash чЪДхе╜хдДуАВф╗гф╗╖хРМхЙН:ч╝Цш╛СцнгцЦЗф╕НшЗкхКищЗНцСШ,ц▓┐чФицЧзхП╢хнР;щЬАшжБцЧ╢цЙЛхКихИахП╢хнРхЖНщЗНцСШуАВ
 */
export function leafValid(m: STMessage | undefined): boolean {
  const leaf = getLeaf(m);
  if (!leaf || !leaf.id || !leaf.delta) return false;
  if (!m) return false;
  return leafSwipe(leaf) === msgSwipe(m);
}

