/**
 * цККф╕АцЭбхП╢хнРчЪД StoredDelta цЦ╜хКахИ░ц┤╛чФЯшо░х┐Ж mem ф╕КуАВцЧахЙпф╜ЬчФихЬ░ foldуАВ
 * цЦ╜хКащб║х║П(хРМф╕АхП╢хнРхЖЕ):items(addтЖТupdateтЖТremove)тЖТ plans(addтЖТresolveтЖТreopenтЖТremove)уАВ
 * щб║х║Пф┐ЭшпБуАМхРМхП╢хнРхЖЕхЕИц╖╗хКахРОцУНф╜ЬуАНцИРчлЛ(хжВцЙЛхКихЬицЬАцЦ░хП╢хнРщЗМхИацОЙхИЪхКачЪДщб╣)уАВ
 *
 * хЙпф╜ЬчФи:цпПцЭбчЙйхУБхПШхКих╛А mem.itemLog ш┐╜хКаф╕АцЭбх╕жуАМцХЕф║ЛхЖЕцЧ╢щЧ┤уАНчЪДшо░х╜Х(leaf.time)уАВ
 * цМЙце╝х▒Вх║ПщЗНцФ╛,цХЕ itemLog хдйчД╢цЧ╢х║ПцЬЙх║П;deriveMemory цЬлх░╛хЖНцИкцЬАш┐СшЛех╣▓цЭбуАВ
 */
/**
 * цКК delta щЗМчЪДщЪПш║л/хЬ░чВ╣ф┐бцБпцЦ╜хКахИ░чЙйхУБф╕К(ф╗ЕхЬи delta цШОчбоч╗Щф║ЖцЙНшжЖчЫЦ,last-write-wins)уАВ
 * carried=true цЧ╢ц╕ЕцОЙ location(щЪПш║лчЙйхУБцЧахнШцФ╛хЬ░);carried=false цЧ╢ф┐ЭчХЩ/щЗЗчФи locationуАВ
 */
function applyPlacement(it: { carried?: boolean; location?: string }, src: ItemDelta): void {
  if (typeof src.carried === 'boolean') {
    it.carried = src.carried;
    if (src.carried) it.location = undefined; // цЛ┐хЬиш║лф╕К тЖТ цЧахнШцФ╛хЬ░
  }
  if (typeof src.location === 'string') {
    const loc = src.location.trim();
    if (loc) {
      it.location = loc;
      if (it.carried === undefined) it.carried = false; // ч╗Щф║ЖхЬ░чВ╣хН│шзЖф╕║щЭЮщЪПш║л
    }
  }
}

/**
 * цКК delta щЗМчЪДщЪПшбМ/цЙАхЬихЬ░ф┐бцБпцЦ╜хКахИ░ NPC ф╕К(ф╗ЕхЬи delta цШОчбоч╗Щф║ЖцЙНшжЖчЫЦ,last-write-wins)уАВ
 * follow=true цЧ╢ц╕ЕцОЙ location(щЪПшбМ NPC цЧахЫ║хоЪцЙАхЬихЬ░);follow=false цЧ╢ф┐ЭчХЩ/щЗЗчФи locationуАВ
 * ф╕ОчЙйхУБ applyPlacement хРМцЮД(carriedтЖФfollow)уАВ
 */
function applyNpcPlacement(n: { follow?: boolean; location?: string }, src: NpcDelta): void {
  if (typeof src.follow === 'boolean') {
    n.follow = src.follow;
    if (src.follow) n.location = undefined; // щЪПшбМ тЖТ цЧахЫ║хоЪцЙАхЬихЬ░
  }
  if (typeof src.location === 'string') {
    const loc = src.location.trim();
    if (loc) {
      n.location = loc;
      if (n.follow === undefined) n.follow = false; // ч╗Щф║ЖцЙАхЬихЬ░хН│шзЖф╕║хоЪчВ╣
    }
  }
}

/**
 * цКК delta щЗМчЪДуАМхН│цЧ╢х▒ВуАНчК╢цАБ(outfit/condition)ф╕О important цЦ╜хКахИ░ NPC ф╕КуАВ
 * ф╕ОцбгцбИх▒В(desc/title)ф╕НхРМ:хН│цЧ╢х▒Вф╕АцЧж delta ч╗Щф║Жх░▒**чЫ┤цОешжЖчЫЦ**(хоГцЬмх░▒цШпх╜УхЙНх┐лчЕз,
 * ф╕НхГП desc щВгца╖уАМхоЮш┤ихПШхМЦцЙНхКиуАН);add ф╕О update хРМца╖хдДчРЖ,чбоф┐ЭцНвшгЕ/хПЧф╝дшГ╜хН│цЧ╢хИ╖цЦ░уАВ
 */
function applyNpcState(n: { outfit?: string; condition?: string; important?: boolean }, src: NpcDelta): void {
  if (typeof src.outfit === 'string') n.outfit = src.outfit.trim() || undefined;
  if (typeof src.condition === 'string') n.condition = src.condition.trim() || undefined;
  if (typeof src.important === 'boolean') n.important = src.important || undefined;
}

/**
 * щАРч║з upsert ф╕АцЭбхЬ║цЩпш╖пх╛ДхИ░ц┤╛чФЯхЬ║цЩпцаСуАВ
 * щБНхОЖ path чЪДцпПф╕кхЙНч╝Ачбоф┐ЭцпПч║зшКВчВ╣хнШхЬи(ч╝║хИЩхИЫх╗║,чИ╢ id чФ▒ф╕Кф╕Ач║зхЙНч╝АчоЧхЗ║);
 * ф╗Е**цЬАцЬлч║з**шКВчВ╣щЗЗчФи desc(setDesc ф╕║чЬЯ=update шжЖчЫЦ;хРжхИЩ add ф╗ЕхЬихОЯцЬмцЧацППш┐░цЧ╢шбе)уАВ
 * чИ╢хнРхЕ│ч│╗чФ▒чбохоЪцАз id щЪРх╝ПцИРчлЛ,цЧащЬА childIdsуАВ
 */
function upsertScenePath(mem: BaibaiMemory, path: string[], desc: string | undefined, setDesc: boolean, t: number): void {
  const clean = normScenePath(path);
  if (!clean.length) return;
  for (let depth = 1; depth <= clean.length; depth++) {
    const prefix = clean.slice(0, depth);
    const id = sceneId(prefix);
    const parentId = depth > 1 ? sceneId(clean.slice(0, depth - 1)) : '';
    const isLeafLevel = depth === clean.length;
    const node = mem.scenes.find(s => s.id === id);
    if (!node) {
      mem.scenes.push({
        id,
        name: prefix[prefix.length - 1],
        path: prefix,
        parentId,
        desc: isLeafLevel ? desc?.trim() || undefined : undefined,
        createdAt: t,
        updatedAt: t,
      });
    } else if (isLeafLevel && desc?.trim()) {
      if (setDesc || !node.desc) node.desc = desc.trim(); // update шжЖчЫЦ;add ф╗Ешбечй║
      node.updatedAt = t;
    }
  }
}

/** чз╗щЩдф╕АцЭбхЬ║цЩпш╖пх╛ДхПКхЕ╢цЙАцЬЙхРОф╗г(цМЙ id хЙНч╝АхМ╣щЕН) */
function removeScenePath(mem: BaibaiMemory, path: string[]): void {
  const clean = normScenePath(path);
  if (!clean.length) return;
  const id = sceneId(clean);
  const childPrefix = `${id}/`; // хРОф╗гчЪД id х╜вхжВ `${id}/хнРч║зтАж`
  mem.scenes = mem.scenes.filter(s => s.id !== id && !s.id.startsWith(childPrefix));
}

/**
 * щЗНшо╛чИ╢ч║з:цКК node(хПКхЕ╢цХ┤цг╡хнРцаС)х╣│чз╗хИ░ newPathуАВшжЖчЫЦуАМхКачИ╢ / цПТф╕нщЧ┤шКВчВ╣ / цНвчИ╢уАНф╕ЙцГЕх╜вуАВ
 *  - хЕИц▓┐ newPath чЪДчеЦхЕИщАРч║зшбех╗║чИ╢ч║з(х╕ж descs цППш┐░);
 *  - хЖНцКК node хнРцаСцпПф╕кшКВчВ╣чЪД path/id/parentId цХ┤ф╜УчФ▒ цЧзхЙНч╝А цФ╣хЖЩцИР цЦ░хЙНч╝АуАВ
 * щШ▓х╛б:тСа node ф╕НхнШхЬихИЩш╖│ш┐З(хПпшГ╜х╖▓швлхЙНщЭвчЪДце╝чз╗ш┐З,х╣ВчнЙ);
 *       тСб newPath чй┐ш┐З node шЗкш║л(цККчИ╢цМВхИ░шЗкх╖▒хнРцаСф╕Л)ф╝ЪцИРчОп тЖТ ш╖│ш┐З,ф┐ЭцКдцаСч╗УцЮДуАВ
 */
function reparentScenePath(mem: BaibaiMemory, r: SceneReparent, t: number): void {
  const from = normScenePath(r.node);
  const to = normScenePath(r.newPath);
  if (!from.length || !to.length) return;
  const fromId = sceneId(from);
  const node = mem.scenes.find(s => s.id === fromId);
  if (!node) return; // х╣ВчнЙ:чЫоцаЗшКВчВ╣ф╕НхнШхЬи

  const newId = sceneId(to);
  if (newId === fromId) return; // хОЯхЬ░ф╕НхКи
  // чОпцгАц╡Л:цЦ░ш╖пх╛Дф╕НшГ╜шР╜хЬишвлчз╗хКихнРцаСф╣ЛхЖЕ(newId чнЙф║О fromId цИЦф╗е fromId/ ф╕║хЙНч╝А)
  if (newId.startsWith(`${fromId}/`)) return;

  // шбех╗║ newPath ф╕КуАМщЩдцЬлцо╡хдЦуАНчЪДчеЦхЕИх▒Вч║з(цЬлцо╡хН│ node шЗкш║л,чиНхРОчФ▒х╣│чз╗ф║зчФЯ)
  for (let depth = 1; depth < to.length; depth++) {
    const prefix = to.slice(0, depth);
    const id = sceneId(prefix);
    if (mem.scenes.some(s => s.id === id)) continue;
    const segName = prefix[prefix.length - 1];
    mem.scenes.push({
      id,
      name: segName,
      path: prefix,
      parentId: depth > 1 ? sceneId(to.slice(0, depth - 1)) : '',
      desc: r.descs?.[segName]?.trim() || undefined,
      createdAt: t,
      updatedAt: t,
    });
  }

  // х╣│чз╗хнРцаС:цЧзхЙНч╝А fromId тЖТ цЦ░хЙНч╝А newId,цЧзш╖пх╛Д from тЖТ цЦ░ш╖пх╛Д to
  const childPrefix = `${fromId}/`;
  const newParentId = to.length > 1 ? sceneId(to.slice(0, to.length - 1)) : '';
  const newName = to[to.length - 1];
  for (const s of mem.scenes) {
    if (s.id === fromId) {
      s.id = newId;
      s.path = [...to];
      s.name = newName;
      s.parentId = newParentId;
      // descs шЛеч╗Щф║ЖшпешКВчВ╣цЦ░хРНчЪДцППш┐░,щб║х╕жцЫ┤цЦ░(цФпцМБуАМцФ╣чИ╢хРМцЧ╢цФ╣цППш┐░уАН);хРжхИЩф┐ЭчХЩхОЯцППш┐░
      const d = r.descs?.[newName]?.trim();
      if (d) s.desc = d;
      s.updatedAt = t;
    } else if (s.id.startsWith(childPrefix)) {
      // хРОф╗г:цККш╖пх╛ДхЙН from.length цо╡цЫ┐цНвцИР to,хЕ╢ф╜Щф┐ЭчХЩ
      const tail = s.path.slice(from.length);
      s.path = [...to, ...tail];
      s.id = sceneId(s.path);
      s.parentId = sceneId(s.path.slice(0, s.path.length - 1));
      s.updatedAt = t;
    }
  }
}

function applyStoredDeltaTo(mem: BaibaiMemory, d: StoredDelta, leaf: { id: string; createdAt: number; time: string }): void {
  const t = leaf.createdAt;
  const logTime = leaf.time;
  const log = (kind: ItemLogEntry['kind'], name: string, from?: number, to?: number): void => {
    mem.itemLog.push({ name, kind, from, to, time: logTime });
  };

  // шжЖчЫЦхЮЛ:чй║ф╕▓х┐╜чХе
  if (typeof d.time === 'string' && d.time.trim()) mem.state.time = d.time.trim();
  if (typeof d.location === 'string' && d.location.trim()) {
    mem.state.location = d.location.trim();
    // location ф╕АхПШ,locationPath ш╖ЯщЪПхРМф╕АцЭб delta:AI ч╗Щф║Жх░▒щЗЗчФи,ц▓бч╗ЩхИЩц╕Ечй║(щБ┐хЕН path цпФ location цЧз)
    const lp = normScenePath(d.locationPath);
    mem.state.locationPath = lp.length ? lp : undefined;
  } else if (d.locationPath !== undefined) {
    // х░СшзБ:хПкцЫ┤цЦ░ path ф╕НхКи location(цЙЛхКихЬ║цЩп);щЗЗчФицИЦц╕Ечй║
    const lp = normScenePath(d.locationPath);
    mem.state.locationPath = lp.length ? lp : undefined;
  }

  // чЙйхУБ(ф╕АхИЗшобцХ░:add щ╗Шшод +1,х╕жчмжхП╖ч┤пхКа,цХ░щЗП тЙд0 шЗкхКичз╗щЩд)
  if (d.items) {
    for (const add of d.items.add ?? []) {
      if (!add?.name?.trim()) continue;
      const id = itemId(add.name);
      const ex = mem.items.find(i => i.id === id);
      const step = typeof add.qty === 'number' ? add.qty : 1; // ч╝║цХ░щЗПщ╗Шшод 1
      if (ex) {
        const before = ex.qty;
        const next = (ex.qty ?? 1) + step; // хОЯф╕НшобцХ░цЧзцХ░цНоцМЙ 1 ш╡╖чоЧ
        if (add.desc) ex.desc = add.desc;
        applyPlacement(ex, add); // щЪПш║л/хЬ░чВ╣(цШОчбоч╗Щф║ЖцЙНшжЖчЫЦ)
        if (next <= 0) {
          mem.items.splice(mem.items.indexOf(ex), 1); // хЗПхИ░ 0 тЖТ чз╗щЩд
          log('remove', ex.name, before, 0);
        } else {
          ex.qty = next;
          ex.updatedAt = t;
          log('add', ex.name, before, next);
        }
      } else if (step > 0) {
        const it: BaibaiMemory['items'][number] = {
          id,
          name: add.name.trim(),
          desc: add.desc?.trim() || undefined,
          qty: step,
          createdAt: t,
          updatedAt: t,
        };
        applyPlacement(it, add);
        mem.items.push(it);
        log('add', add.name.trim(), undefined, step);
      }
      // step тЙд0 ф╕ФчЙйхУБф╕НхнШхЬи:цЧахПпхЗП,х┐╜чХе
    }
    for (const upd of d.items.update ?? []) {
      if (!upd?.name?.trim()) continue;
      const it = mem.items.find(i => i.id === itemId(upd.name));
      if (!it) continue; // хо╣щФЩ:цЫ┤цЦ░ф╕НхнШхЬичЪДщб╣хИЩх┐╜чХе
      const before = it.qty;
      if (upd.desc) it.desc = upd.desc;
      applyPlacement(it, upd); // щЪПш║л/хЬ░чВ╣хПШцЫ┤(чз╗хКичЙйхУБ)
      if (typeof upd.qty === 'number') {
        if (upd.qty <= 0) {
          mem.items.splice(mem.items.indexOf(it), 1); // шо╛ф╕║ тЙд0 тЖТ чз╗щЩд
          log('remove', it.name, before, 0);
          continue;
        }
        it.qty = upd.qty;
      }
      it.updatedAt = t;
      log('update', it.name, before, it.qty);
    }
    for (const name of d.items.remove ?? []) {
      if (!name?.trim()) continue;
      const idx = mem.items.findIndex(i => i.id === itemId(name));
      if (idx >= 0) {
        const [removed] = mem.items.splice(idx, 1);
        log('remove', removed.name, removed.qty, 0);
      }
    }
  }

  // хЬ║цЩп / хЬ░чВ╣уАВцЦ╜хКах║П:add тЖТ update тЖТ reparent тЖТ remove
  // (reparent хЬи add ф╣ЛхРО,ф┐ЭшпБшвлх╝ХчФишКВчВ╣х╖▓хнШхЬи;remove цЬАхРО,щБ┐хЕНчз╗хКихИЪшвлхИачЪДшКВчВ╣)уАВ
  if (d.scenes) {
    for (const a of d.scenes.add ?? []) upsertScenePath(mem, a.path, a.desc, false, t);
    for (const u of d.scenes.update ?? []) upsertScenePath(mem, u.path, u.desc, true, t);
    for (const r of d.scenes.reparent ?? []) reparentScenePath(mem, r, t);
    for (const p of d.scenes.remove ?? []) removeScenePath(mem, p);
  }

  // NPC(цМЗф╗дхЮЛ:add цЦ░чЩ╗хЬ║ / update цФ╣ш║лф╗╜ф╜Нч╜о / remove щААхЬ║)уАВцЦ╜хКах║П:add тЖТ update тЖТ removeуАВ
  if (d.npcs) {
    for (const add of d.npcs.add ?? []) {
      if (!add?.name?.trim()) continue;
      const id = npcId(add.name);
      const ex = mem.npcs.find(n => n.id === id);
      if (ex) {
        // х╖▓хнШхЬи:цбгцбИх▒В(title/desc/цАзца╝)add шзЖф╜ЬшбехЕи(ф╗Ехблчй║,ф╕НшжЖчЫЦцЧвцЬЙ);
        // хН│цЧ╢х▒В(outfit/condition/important)ф╗НчЫ┤цОешжЖчЫЦ(хоГцЬмх░▒цШпх╜УхЙНх┐лчЕз),хЖНцЦ╜хКаф╜Нч╜оуАВ
        if (add.title && !ex.title) ex.title = add.title.trim();
        if (add.desc && !ex.desc) ex.desc = add.desc.trim();
        if (add.personality && !ex.personality) ex.personality = add.personality.trim();
        applyNpcState(ex, add);
        applyNpcPlacement(ex, add);
        ex.updatedAt = t;
      } else {
        const npc: BaibaiMemory['npcs'][number] = {
          id,
          name: add.name.trim(),
          title: add.title?.trim() || undefined,
          desc: add.desc?.trim() || undefined,
          personality: add.personality?.trim() || undefined,
          createdAt: t,
          updatedAt: t,
        };
        applyNpcState(npc, add);
        applyNpcPlacement(npc, add);
        mem.npcs.push(npc);
      }
    }
    for (const upd of d.npcs.update ?? []) {
      if (!upd?.name?.trim()) continue;
      const n = mem.npcs.find(x => x.id === npcId(upd.name));
      if (!n) continue; // хо╣щФЩ:цЫ┤цЦ░ф╕НхнШхЬичЪД NPC хИЩх┐╜чХе
      if (upd.title) n.title = upd.title.trim();
      if (upd.desc) n.desc = upd.desc.trim();
      if (upd.personality) n.personality = upd.personality.trim();
      applyNpcState(n, upd); // хН│цЧ╢х▒В(чЭАшгЕ/чК╢цАБ/щЗНшжБцАз)шжЖчЫЦхИ╖цЦ░
      applyNpcPlacement(n, upd); // щЪПшбМ/цЙАхЬихЬ░хПШцЫ┤(NPC чз╗хКи)
      n.updatedAt = t;
    }
    for (const name of d.npcs.remove ?? []) {
      if (!name?.trim()) continue;
      const idx = mem.npcs.findIndex(x => x.id === npcId(name));
      if (idx >= 0) mem.npcs.splice(idx, 1);
    }
  }

  // шобхИТ / цВмх┐╡
  if (d.plans) {
    (d.plans.add ?? []).forEach((add, addIdx) => {
      if (!add?.content?.trim()) return;
      const id = planId(leaf.id, addIdx);
      if (mem.plans.some(p => p.id === id)) return; // хРМхП╢хнРщЗНцФ╛х╣ВчнЙ
      const plan: MemPlan = {
        id,
        kind: add.kind === 'suspense' ? 'suspense' : 'plan',
        content: add.content.trim(),
        status: 'open',
        createdAt: t,
        createdTime: add.createdTime?.trim() || undefined,
        targetTime: add.targetTime?.trim() || undefined,
      };
      mem.plans.push(plan);
    });
    for (const pid of d.plans.resolve ?? []) {
      const p = mem.plans.find(x => x.id === pid);
      if (p) {
        p.status = 'resolved';
        p.resolvedAt = t;
      }
    }
    for (const pid of d.plans.reopen ?? []) {
      const p = mem.plans.find(x => x.id === pid);
      if (p) {
        p.status = 'open';
        p.resolvedAt = undefined;
      }
    }
    for (const pid of d.plans.remove ?? []) {
      const idx = mem.plans.findIndex(x => x.id === pid);
      if (idx >= 0) mem.plans.splice(idx, 1);
    }
  }
}

/**
 * ф╗О chat щЗНцФ╛хЗ║ч╗УцЮДхМЦчК╢цАБуАВ
 * цМЙ**це╝х▒ВчЙйчРЖщб║х║П**цЙл chat,хп╣цпПцЭбцЬЙцХИхП╢хнР fold хЕ╢ delta(це╝х▒Вх║ПхН│хПЩф║Лх║П,хИац╢ИцБпхРОхдйчД╢цнгчбо)уАВ
 * хОЛч╝йшКВчВ╣хПкхОЛцЦЗцЬмуАБф╕Нх╕ж deltaуАБф╕НхПВф╕ОщЗНцФ╛уАВ
 * @param upToExclusive ф╗ЕщЗНцФ╛ч┤вх╝Х < шпехА╝чЪДце╝х▒В(цИкцЦнхИ░швлхИЖцЮРце╝ф╣ЛхЙН;чЬБчХе=хЕищГи)уАВ
 */
export function deriveMemory(
  chat: STMessage[] | null,
  upToExclusive?: number,
): Pick<BaibaiMemory, 'state' | 'items' | 'plans' | 'scenes' | 'npcs' | 'itemLog'> {
  const mem = createEmptyMemory();
  if (!chat) return { state: mem.state, items: mem.items, plans: mem.plans, scenes: mem.scenes, npcs: mem.npcs, itemLog: mem.itemLog };
  const end = typeof upToExclusive === 'number' ? Math.min(upToExclusive, chat.length) : chat.length;
  for (let i = 0; i < end; i++) {
    if (!leafValid(chat[i])) continue;
    const leaf = getLeaf(chat[i])!;
    // цЧех┐ЧчФиуАМцХЕф║ЛхЖЕцЧ╢щЧ┤уАН:ч╗УцЭЯцЧ╢щЧ┤ф╝ШхЕИ(цЬмцо╡цЬАхРОцЧ╢хИ╗),ч╝║хИЩш╡╖хзЛ,хЖНч╝║цЧз timeLabel,цЬАхРОчй║ф╕▓
    const time = leaf.timeEnd?.trim() || leaf.timeStart?.trim() || leaf.timeLabel?.trim() || '';
    applyStoredDeltaTo(mem, leaf.delta, { id: leaf.id, createdAt: leaf.createdAt, time });
  }
  // хПкчХЩцЬАш┐СшЛех╣▓цЭбхПШхКи(ц│ихЕе/хЦВцибхЮЛхдЯчФихН│хПп,чЬБ token)
  if (mem.itemLog.length > ITEM_LOG_KEEP) mem.itemLog = mem.itemLog.slice(-ITEM_LOG_KEEP);
  return { state: mem.state, items: mem.items, plans: mem.plans, scenes: mem.scenes, npcs: mem.npcs, itemLog: mem.itemLog };
}

/** хПШхКицЧех┐Чф┐ЭчХЩчЪДцЬАш┐СцЭбцХ░(ц│ихЕеф╕ОхЦВцСШшжБхЕ▒чФи)уАВ */
export const ITEM_LOG_KEEP = 8;

/**
 * чоЧуАМхНХцЭб delta чЫ╕хп╣ч╗ЩхоЪхЕИхЙНчЙйхУБчК╢цАБуАНф║зчФЯчЪДчЙйхУБхПШхКицЭбчЫо(ф╛ЫхЖЩш┐Ышпеце╝цнгцЦЗ)уАВ
 * хдНчФи applyStoredDeltaTo:чФихЕИхЙНчЙйхУБцТнчзНф╕Аф╕кф╕┤цЧ╢ mem,хПкцЦ╜хКаш┐Щф╕АцЭб delta,
 * цНХшО╖хЕ╢ itemLog хН│цЬмце╝хЗАхПШхКи(х╕ж fromтЖТto)уАВtime чФ▒ш░ГчФицЦ╣ф╝ахЕе(цЬмце╝цХЕф║Лч╗УцЭЯцЧ╢щЧ┤)уАВ
 */
export function itemChangesOf(
  delta: StoredDelta,
  priorItems: BaibaiMemory['items'],
  time: string,
): ItemLogEntry[] {
  const mem = createEmptyMemory();
  // ц╖▒цЛ╖ш┤ЭхЕИхЙНчЙйхУБф╜Ьш╡╖чВ╣(щБ┐хЕНц▒бцЯУш░ГчФицЦ╣);хПкхЕ│х┐Г items,plans/state ф╕Нх╜▒хУН itemLog
  mem.items = priorItems.map(i => ({ ...i }));
  applyStoredDeltaTo(mem, { items: delta.items }, { id: 'tmp', createdAt: 0, time });
  return mem.itemLog;
}

/* ============ <bbs_items> цЧБц│и тЖФ delta хПНхРСхРМцне(чФицИ╖цФ╣цнгцЦЗ) ============ */

/**
 * шзгцЮР <bbs_items> хЭЧчЪДуАМхКишпНх╝ПуАНхдЪшбМцЦЗцЬм тЖТ х╕жчмжхП╖чЙйхУБхвЮщЗПуАВ
 * цпПшбМ:`<хКишпН> <хРНхнЧ> [цХ░щЗП]`уАВхКишпН:шО╖х╛Ч=+,ц╢ИшАЧ/хд▒хО╗=-уАВч╝║цХ░щЗПщ╗Шшод 1уАВ
 * хРНхнЧхПпхРлчй║ца╝(хПЦхКишпНхРОуАБцЬлх░╛хПпщАЙцХ░хнЧхЙНчЪДхЕищГи);щЭЮц│ХшбМх┐╜чХеуАВ
 * ш┐ФхЫЮ add х╜вх╝П(qty х╕жчмжхП╖,хдНчФи applyStoredDeltaTo чЪДх╕жчмжхП╖ч┤пхКа + тЙд0 чз╗щЩдшпнф╣Й)уАВ
 */
export function parseItemLogText(text: string): { name: string; qty: number }[] {
  const out: { name: string; qty: number }[] = [];
  for (const raw of String(text ?? '').split('\n')) {
    const line = raw.trim();
    if (!line) continue;
    const m = line.match(/^(шО╖х╛Ч|ц╢ИшАЧ|хд▒хО╗)\s+(.+?)(?:\s+(\d+))?$/);
    if (!m) continue;
    const sign = m[1] === 'шО╖х╛Ч' ? 1 : -1;
    const name = m[2].trim();
    if (!name) continue;
    const n = m[3] ? Number(m[3]) : 1;
    if (!Number.isFinite(n) || n <= 0) continue;
    out.push({ name, qty: sign * n });
  }
  return out;
}

/**
 * чФицИ╖ч╝Цш╛Сф║ЖцЯРце╝цнгцЦЗхРО,цККхЕ╢ф╕н <bbs_items> цЧБц│ичЪДцФ╣хКихПНхРСхРМцнехЫЮшпеце╝хП╢хнРчЪД delta.itemsуАВ
 *
 * ф╕АшЗ┤цАзхИдхоЪш╡░уАМхРМф╕Ац╕▓цЯУчобч║┐уАН:цККхП╢хнРчО░цЬЙ delta ц╕▓цЯУцИРшзДшМГцЧБц│и,ф╕ОцнгцЦЗщЗМчЪДцЧБц│ицпФхп╣;
 * чЫ╕чнЙ тЖТ чФицИ╖ц▓бхКичЙйхУБ(хПкцФ╣ф║ЖхИлхдДцнгцЦЗ)тЖТ ш╖│ш┐З,ф╕Нчв░ deltaуАБф╕НщЗНхЖЩцнгцЦЗ(щБ┐хЕНшппцФ╣/цКЦхКи)уАВ
 * ф╕НчнЙ тЖТ ф╗ецнгцЦЗф╕║хЗЖ:шзгцЮРцИРх╕жчмжхП╖ add,**цЫ┐цНв**шпехП╢хнР delta чЪД items щГихИЖ(time/location/plans ф┐ЭчХЩ),
 *        щЗНчоЧц┤╛чФЯуАБхИахЭПщУ╛,х╣╢цККцнгцЦЗцЧБц│ищЗНхЖЩцИРшзДшМГца╝х╝П(щб║цЙЛц╕ЕцОЙчФицИ╖чЪДщЭЮшзДшМГхЖЩц│Х),цЬАхРОшР╜чЫШуАВ
 *
 * ц│и:цЧБц│иф╕НцЙ┐ш╜╜цППш┐░/цХ░щЗПч╗Эхп╣хА╝,хПНшзгцЮРцМЙуАМхвЮщЗПуАНшбиш╛╛;цХЕчФицИ╖цФ╣цЧБц│иф╝Ъф╕вхд▒хОЯ delta щЗМчЪД desc(хПпцОехПЧ,
 * цППш┐░шп╖ш╡░чЙйхУБхИЧшбич╝Цш╛С)уАВцЧа <bbs_items> хЭЧ(чФицИ╖хИаф║ЖцХ┤хЭЧ)тЖТ шзЖф╜Ьц╕Ечй║шпеце╝чЙйхУБхПШхКиуАВ
 * ш┐ФхЫЮцШпхРжхПСчФЯф║ЖцФ╣хЖЩуАВ
 */
export function syncItemLogFromMessage(index: number): boolean {
  const chat = getContext()?.chat;
  const leaf = getLeaf(chat?.[index]);
  if (!chat || !leaf || !leaf.delta) return false;

  // шпеце╝ф╣ЛхЙНчЪДчЙйхУБчК╢цАБ(чФиф║ОцКК delta ц╕▓цЯУцИРф╕ОцнгцЦЗхРМхПгх╛ДчЪДцЧБц│ихБЪцпФхп╣)
  const prior = deriveMemory(chat, index).items;
  const time = leaf.timeEnd?.trim() || leaf.timeStart?.trim() || leaf.timeLabel?.trim() || '';
  const currentInline = fmtItemLogInline(itemChangesOf(leaf.delta, prior, time));

  const tagText = readItemsTagText(chat[index].mes); // null = цЧахЭЧ
  const editedInline = tagText === null ? '' : fmtItemLogInline(parsedToLog(parseItemLogText(tagText), prior));

  if (currentInline === editedInline) return false; // чЙйхУБцЧБц│ицЬкхПШ,ш╖│ш┐З

  // ф╗ецнгцЦЗф╕║хЗЖ:шзгцЮРцИРх╕жчмжхП╖ add,цЫ┐цНв delta чЪД items щГихИЖуАВ
  // цЧБц│иф╕НцЙ┐ш╜╜щЪПш║л/хЬ░чВ╣,цМЙчЙйхУБхРНф╗ОцЧз delta чЪД add/update щЗМч╗зцЙ┐хЫЮцЭе,щБ┐хЕНцФ╣цХ░щЗПшппц╕Ечй║щЧ┤ф┐бцБпуАВ
  const placeBefore = new Map<string, { carried?: boolean; location?: string }>();
  for (const e of [...(leaf.delta.items?.add ?? []), ...(leaf.delta.items?.update ?? [])]) {
    if (e.carried !== undefined || e.location !== undefined) {
      placeBefore.set(itemId(e.name), { carried: e.carried, location: e.location });
    }
  }
  const parsed = parseItemLogText(tagText ?? '');
  if (parsed.length) {
    leaf.delta.items = {
      add: parsed.map(p => {
        const place = placeBefore.get(itemId(p.name));
        return { name: p.name, qty: p.qty, ...(place ?? {}) };
      }),
    };
  } else delete leaf.delta.items;

  chat[index].extra = { ...(chat[index].extra ?? {}), bbs_leaf: leaf };

  // цнгцЦЗцЧБц│ищЗНхЖЩцИРшзДшМГца╝х╝П(чФишзДшМГхМЦхРОчЪД delta щЗНцЦ░ц╕▓цЯУ)
  const canonical = fmtItemLogInline(itemChangesOf(leaf.delta, prior, time));
  chat[index].mes = writeItemLogTag(chat[index].mes, canonical);

  recomputeDerived();
  pruneBrokenComps();
  scheduleLeafFlush();
  return true;
}

/** цККшзгцЮРхЗ║чЪДх╕жчмжхП╖хвЮщЗПхеЧчФихИ░хЕИхЙНчК╢цАБ,х╛ЧхИ░ ItemLogEntry[](ф╛Ыц╕▓цЯУцпФхп╣,ф╕О itemChangesOf хРМхПгх╛Д)уАВ */
function parsedToLog(parsed: { name: string; qty: number }[], prior: BaibaiMemory['items']): ItemLogEntry[] {
  if (!parsed.length) return [];
  return itemChangesOf({ items: { add: parsed.map(p => ({ name: p.name, qty: p.qty })) } }, prior, '');
}

/* ============ AI delta тЖТ хЫ║хМЦ StoredDelta ============ */

/** шзгцЮР "p3" / "3" / "P3" -> 3 */
function parseShortRef(ref: string): number | null {
  const m = String(ref).trim().match(/^p?(\d+)$/i);
  if (!m) return null;
  const n = Number(m[1]);
  return Number.isFinite(n) && n > 0 ? n : null;
}

/**
 * цКК AI ш┐ФхЫЮчЪД SummaryDelta хЫ║хМЦцИРхПпцМБф╣ЕхМЦчЪД StoredDeltaуАВ
 * хЕ│щФо:plans.resolve чЪДш┐РшбМцЬЯчЯнх║ПхП╖(p1/p2тАж)цМЙ openPlansOrdered ч┐╗шпСцИР**чи│хоЪ plan id**уАВ
 */
export function finalizeDelta(delta: SummaryDelta, openPlansOrdered: { id: string }[]): StoredDelta {
  const out: StoredDelta = {};
  if (typeof delta.time === 'string' && delta.time.trim()) out.time = delta.time.trim();
  if (typeof delta.location === 'string' && delta.location.trim()) out.location = delta.location.trim();
  // цЭГхиБхоЪф╜Нш╖пх╛Д:шзДшМГхМЦхРОщЭЮчй║цЙНхЫ║хМЦ(хПкцЬЙч╗Щф║Ж location цЙНцЬЙцДПф╣Й,ф╜Жф╕Нх╝║хИ╢тАФтАФцЙЛхКихЬ║цЩпхПпхНХчЛмч╗Щ)
  const lp = normScenePath(delta.locationPath);
  if (lp.length) out.locationPath = lp;

  if (delta.items) {
    const items: NonNullable<StoredDelta['items']> = {};
    if (delta.items.add?.length) items.add = delta.items.add;
    if (delta.items.update?.length) items.update = delta.items.update;
    if (delta.items.remove?.length) items.remove = delta.items.remove;
    if (Object.keys(items).length) out.items = items;
  }

  if (delta.scenes) {
    // шзДшМГхМЦш╖пх╛Д;уАМdesc х┐ЕхблуАН:add/update ч╝║цППш┐░чЪДцЭбчЫоф╕вх╝Г(хЖЩф╕НхЗ║цППш┐░=ф╕НхА╝х╛Чшо░)уАВ
    const clean = (arr?: SceneDelta[]): SceneDelta[] =>
      (arr ?? [])
        .map(s => ({ path: normScenePath(s.path), desc: s.desc?.trim() || undefined }))
        .filter(s => s.path.length && s.desc); // цЧа path цИЦцЧа desc тЖТ ф╕вх╝Г
    const cleanReparent = (arr?: SceneReparent[]): SceneReparent[] =>
      (arr ?? [])
        .map(r => {
          const node = normScenePath(r.node);
          const newPath = normScenePath(r.newPath);
          const descs: Record<string, string> = {};
          for (const [k, v] of Object.entries(r.descs ?? {})) {
            const key = String(k).trim();
            const val = String(v ?? '').trim();
            if (key && val) descs[key] = val;
          }
          return { node, newPath, descs };
        })
        .filter(r => r.node.length && r.newPath.length);
    const scenes: NonNullable<StoredDelta['scenes']> = {};
    const add = clean(delta.scenes.add);
    const update = clean(delta.scenes.update);
    const reparent = cleanReparent(delta.scenes.reparent);
    if (add.length) scenes.add = add;
    if (update.length) scenes.update = update;
    if (reparent.length) scenes.reparent = reparent;
    if (Object.keys(scenes).length) out.scenes = scenes;
  }

  if (delta.npcs) {
    // шзДшМГхМЦ:add/update х┐Ещб╗цЬЙхРНхнЧцЙНф┐ЭчХЩ(цЧахРН NPC ф╕Ншо░)
    const clean = (arr?: NpcDelta[]): NpcDelta[] =>
      (arr ?? [])
        .map(n => ({
          name: String(n.name ?? '').trim(),
          title: n.title?.trim() || undefined,
          desc: n.desc?.trim() || undefined,
          personality: n.personality?.trim() || undefined,
          outfit: n.outfit?.trim() || undefined,
          condition: n.condition?.trim() || undefined,
          important: typeof n.important === 'boolean' ? n.important : undefined,
          follow: typeof n.follow === 'boolean' ? n.follow : undefined,
          location: n.location?.trim() || undefined,
        }))
        .filter(n => n.name);
    const npcs: NonNullable<StoredDelta['npcs']> = {};
    const add = clean(delta.npcs.add);
    const update = clean(delta.npcs.update);
    const remove = (delta.npcs.remove ?? []).map(s => String(s ?? '').trim()).filter(Boolean);
    if (add.length) npcs.add = add;
    if (update.length) npcs.update = update;
    if (remove.length) npcs.remove = remove;
    if (Object.keys(npcs).length) out.npcs = npcs;
  }

  if (delta.plans) {
    const plans: NonNullable<StoredDelta['plans']> = {};
    if (delta.plans.add?.length) plans.add = delta.plans.add;
    if (delta.plans.resolve?.length) {
      const ids: string[] = [];
      for (const ref of delta.plans.resolve) {
        const n = parseShortRef(ref);
        if (n === null) continue;
        const target = openPlansOrdered[n - 1];
        if (target) ids.push(target.id);
      }
      if (ids.length) plans.resolve = ids;
    }
    if (Object.keys(plans).length) out.plans = plans;
  }
  return out;
}

/* ============ хЖЩхЕехОЛч╝йшКВчВ╣(цгоцЮЧ) ============ */

/** ш┐╜хКаф╕АцЭбхОЛч╝йшКВчВ╣(levelтЙе1)уАВхП╢хнРф╕Нш╡░ш┐ЩщЗМ(хЬиц╢ИцБп extra ф╕К)уАВ */
export function addSummary(
  s: Omit<MemSummary, 'id' | 'createdAt'> & Partial<Pick<MemSummary, 'id' | 'createdAt'>>,
): MemSummary {
  const rec: MemSummary = {
    id: s.id ?? uid('sum'),
    text: s.text,
    level: s.level ?? 1,
    createdAt: s.createdAt ?? nowMs(),
    auto: s.auto ?? true,
    timeStart: s.timeStart,
    timeEnd: s.timeEnd,
    timeLabel: s.timeLabel,
    childIds: s.childIds ?? [],
  };
  memory.summaries.push(rec);
  saveMemory();
  return rec;
}

/* ============ хП╢хнР(хЬиц╢ИцБп extra ф╕К) ============ */

/** цЬАцЦ░ф╕АцЭбцЬЙцХИхП╢хнР(chat щЗМцЬАхРОф╕АцЭб leafValid чЪДц╢ИцБп);цЧахИЩ null */
export function latestLeaf(): { index: number; leaf: LeafExtra } | null {
  const chat = getContext()?.chat ?? [];
  for (let i = chat.length - 1; i >= 0; i--) {
    if (leafValid(chat[i])) return { index: i, leaf: getLeaf(chat[i])! };
  }
  return null;
}

/**
 * цККф╕Ацо╡цЙЛхКи op хРИх╣╢ш┐ЫуАМцЬАцЦ░цЬЙцХИхП╢хнРуАНчЪД delta,цФ╣хЖЕхнШ extra тЖТ щЗНчоЧ + шР╜чЫШ(chat цЦЗф╗╢)уАВ
 * цЧацЬЙцХИхП╢хнРцЧ╢ш┐ФхЫЮ false(щб╡щЭвцНоцндчжБчФицЙЛхКиц╖╗хКа)уАВ
 * resolve/reopen ф║ТцЦехО╗щЗН:хп╣хРМф╕А plan,хРОф╕АцмбцУНф╜ЬшжЖчЫЦхЙНф╕Ацмб(хРМхП╢хнРхЖЕ last-write-wins)уАВ
 * ф╕НцФ╣ srcHash(щФЪхоЪчЪДцШпцнгцЦЗ,ф╕НцШп delta)тЖТ ф╕Нх╜▒хУН leafValidуАВ
 */
export function appendOpToLatestLeaf(op: StoredDelta): boolean {
  const found = latestLeaf();
  if (!found) return false;
  const { index, leaf } = found;
  const d: StoredDelta = (leaf.delta ??= {});

  if (op.items) {
    // хЕ│щФо:хРМхРНчЙйхУБхЬи add/update ф╕О remove ф╣ЛщЧ┤х┐Ещб╗ф║ТцЦе(ш╖ицб╢цК╡ц╢И),хРжхИЩцФ╣хРН(removeцЧз+addцЦ░)
    // х╛Аш┐Фф╝Ъшой remove цб╢цоЛчХЩцЧзхРН,шАМщЗНцФ╛хЫ║хоЪцМЙ addтЖТupdateтЖТremove хИЖч╗ДтАФтАФцЬАхРОчЪД remove ф╝ЪцККхИЪ
    // add хЫЮцЭечЪДхРМхРНчЙйхУБхИацОЙ(чЙйхУБчж╗хеЗц╢Ихд▒)уАВadd цб╢хЖЕф╗Нф┐ЭчХЩ push ч┤пхКа,ф╕НхКиуАМцЙЛхКи+1уАНшпнф╣ЙуАВ
    const di = (d.items ??= {});
    for (const name of op.items.remove ?? []) {
      const id = itemId(name);
      // хИащЩдхОЛхАТцЬмхП╢хнРхЖЕхп╣шпехРНчЪД add/update;хЖНчЩ╗шо░х╛ЕхИа(хО╗щЗН,prior хП╢хнРчЪДшпечЙйхУБщЭахоГхИащЩд)
      if (di.add) di.add = di.add.filter(a => itemId(a.name) !== id);
      if (di.update) di.update = di.update.filter(u => itemId(u.name) !== id);
      di.remove = [...(di.remove ?? []).filter(n => itemId(n) !== id), name];
    }
    for (const a of op.items.add ?? []) {
      if (di.remove) di.remove = di.remove.filter(n => itemId(n) !== itemId(a.name)); // цТдщФАхРМхРНх╛ЕхИа
      (di.add ??= []).push(a);
    }
    for (const u of op.items.update ?? []) {
      if (di.remove) di.remove = di.remove.filter(n => itemId(n) !== itemId(u.name));
      (di.update ??= []).push(u);
    }
    if (di.add && !di.add.length) delete di.add;
    if (di.update && !di.update.length) delete di.update;
    if (di.remove && !di.remove.length) delete di.remove;
  }
  if (op.npcs) {
    // ф╕ОчЙйхУБхРМцм╛ш╖ицб╢ф║ТцЦе:хРМхРН NPC хЬи add/update ф╕О remove ф╣ЛщЧ┤ф╕НшГ╜х╣╢хнШ,
    // хРжхИЩцФ╣хРН(removeцЧз+addцЦ░)х╛Аш┐Фф╝Ъшой remove цб╢цоЛчХЩцЧзхРН,щЗНцФ╛цМЙ addтЖТupdateтЖТremove цККхИЪ add чЪДхИацОЙуАВ
    const dn = (d.npcs ??= {});
    for (const name of op.npcs.remove ?? []) {
      const id = npcId(name);
      if (dn.add) dn.add = dn.add.filter(a => npcId(a.name) !== id);
      if (dn.update) dn.update = dn.update.filter(u => npcId(u.name) !== id);
      dn.remove = [...(dn.remove ?? []).filter(n => npcId(n) !== id), name];
    }
    for (const a of op.npcs.add ?? []) {
      if (dn.remove) dn.remove = dn.remove.filter(n => npcId(n) !== npcId(a.name));
      (dn.add ??= []).push(a);
    }
    for (const u of op.npcs.update ?? []) {
      if (dn.remove) dn.remove = dn.remove.filter(n => npcId(n) !== npcId(u.name));
      (dn.update ??= []).push(u);
    }
    if (dn.add && !dn.add.length) delete dn.add;
    if (dn.update && !dn.update.length) delete dn.update;
    if (dn.remove && !dn.remove.length) delete dn.remove;
  }
  if (op.scenes) {
    const ds = (d.scenes ??= {});
    if (op.scenes.add?.length) (ds.add ??= []).push(...op.scenes.add);
    if (op.scenes.update?.length) (ds.update ??= []).push(...op.scenes.update);
    if (op.scenes.reparent?.length) (ds.reparent ??= []).push(...op.scenes.reparent);
    if (op.scenes.remove?.length) (ds.remove ??= []).push(...op.scenes.remove);
  }
  if (op.plans) {
    const dp = (d.plans ??= {});
    if (op.plans.add?.length) (dp.add ??= []).push(...op.plans.add);
    for (const id of op.plans.resolve ?? []) {
      dp.reopen = (dp.reopen ?? []).filter(x => x !== id); // ф║ТцЦе
      dp.resolve = [...(dp.resolve ?? []).filter(x => x !== id), id];
    }
    for (const id of op.plans.reopen ?? []) {
      dp.resolve = (dp.resolve ?? []).filter(x => x !== id); // ф║ТцЦе
      dp.reopen = [...(dp.reopen ?? []).filter(x => x !== id), id];
    }
    for (const id of op.plans.remove ?? []) {
      (dp.remove ??= []).push(id);
    }
  }

  // щЗНшо╛ extra х╝ХчФиф╗ечбоф┐ЭцМБф╣ЕхМЦх╕жф╕КцФ╣хКи
  const chat = getContext()!.chat;
  chat[index].extra = { ...(chat[index].extra ?? {}), bbs_leaf: leaf };

  recomputeDerived();
  pruneBrokenComps();
  scheduleLeafFlush();
  return true;
}

/**
 * цЙЛхКич╝Цш╛Сф╕Аф╕кчЙйхУБ(ц┤╛чФЯцХ░цНо,хЖЩхЫЮцЬАцЦ░хП╢хнРчЪД delta)уАВ
 *  - цФ╣хРН:чЙйхУБ id цМЙшзДшМГхМЦхРНчбохоЪ,цФ╣хРНчнЙф║ОцНв id тЖТ чФи remove(цЧзхРН) + add(цЦ░хРН,х╕ж qty/desc/ф╜Нч╜о) шбиш╛╛уАВ
 *  - ф╗ЕцФ╣ qty/desc/ф╜Нч╜о:чФи update(цМЙхОЯхРНхМ╣щЕН,шо╛ф╕║цЦ░хА╝)уАВ
 * ф╕дчзНщГ╜ч╗П appendOpToLatestLeaf шР╜хИ░цЬАцЦ░хП╢хнРуАВцЧацЬЙцХИхП╢хнРцЧ╢ш┐ФхЫЮ falseуАВ
 *
 * ф╜Нч╜о(carried/location):patch цЬкцШ╛х╝Пч╗ЩцЧ╢,цФ╣хРНхЬ║цЩпф╗Оц┤╛чФЯчЪДцЧзчЙйхУБч╗зцЙ┐тАФтАФхРжхИЩцФ╣ф╕кхРНхнЧ
 * х░▒цККуАМхЬицнжхЩих║УуАНш┐Щч▒╗хнШцФ╛ф┐бцБпф╕вф║Ж(чФи add щЗНх╗║ф╝Ъф╕вщЭЮ add хнЧцо╡)уАВ
 */
export function editItem(
  oldName: string,
  patch: { name?: string; qty?: number; desc?: string; carried?: boolean; location?: string },
): boolean {
  const newName = patch.name?.trim() || oldName;
  const desc = patch.desc?.trim() || undefined;
  const qty = typeof patch.qty === 'number' && Number.isFinite(patch.qty) ? patch.qty : undefined;

  // ф╜Нч╜о:patch цШОчбоч╗Щф║ЖчФи patch чЪД;хРжхИЩф╗ОцЧзчЙйхУБч╗зцЙ┐(цФ╣хРНф╕Нф╕вхнШцФ╛хЬ░)
  const prev = memory.items.find(i => i.id === itemId(oldName));
  const carried = patch.carried !== undefined ? patch.carried : prev?.carried;
  const location = patch.location !== undefined ? (patch.location.trim() || undefined) : prev?.location;

  if (norm(newName) !== norm(oldName)) {
    // цФ╣хРН:хЕИхИацЧз,хЖНф╗ецЦ░хРНщЗНх╗║(qty чФи add шпнф╣Й,ф╜ЖцЧзчЪДх╖▓хИа,чнЙф║Ошо╛ф╕║шпехА╝)
    return appendOpToLatestLeaf({
      items: { remove: [oldName], add: [{ name: newName, qty, desc, carried, location }] },
    });
  }
  // хРМхРН:цЫ┤цЦ░цХ░щЗП/цППш┐░/ф╜Нч╜о(update цШпуАМшо╛ф╕║цЦ░хА╝уАН)
  return appendOpToLatestLeaf({ items: { update: [{ name: newName, qty, desc, carried, location }] } });
}

/* ============ NPC цЙЛхКи op(хЖЩхЫЮцЬАцЦ░хП╢хнР,ф╕О editItem хРМшМГх╝П) ============ */

/** цЙЛхКицЦ░хвЮф╕Аф╕к NPCуАВцЧацЬЙцХИхП╢хнРш┐ФхЫЮ falseуАВ */
export function upsertNpc(
  fields: {
    name: string;
    title?: string;
    desc?: string;
    personality?: string;
    outfit?: string;
    condition?: string;
    important?: boolean;
    follow?: boolean;
    location?: string;
  },
): boolean {
  const name = fields.name.trim();
  if (!name) return false;
  return appendOpToLatestLeaf({
    npcs: {
      add: [{
        name,
        title: fields.title?.trim() || undefined,
        desc: fields.desc?.trim() || undefined,
        personality: fields.personality?.trim() || undefined,
        outfit: fields.outfit?.trim() || undefined,
        condition: fields.condition?.trim() || undefined,
        important: fields.important,
        follow: fields.follow,
        location: fields.location?.trim() || undefined,
      }],
    },
  });
}

/**
 * цЙЛхКич╝Цш╛Сф╕Аф╕к NPC(ц┤╛чФЯцХ░цНо,хЖЩхЫЮцЬАцЦ░хП╢хнРчЪД delta),ф╕О editItem хРМшМГх╝ПуАВ
 *  - цФ╣хРН:NPC id цМЙшзДшМГхМЦхРНчбохоЪ,цФ╣хРНчнЙф║ОцНв id тЖТ remove(цЧзхРН) + add(цЦ░хРН,х╕жхЕихнЧцо╡)уАВ
 *  - ф╗ЕцФ╣хнЧцо╡:update(цМЙхОЯхРНхМ╣щЕН,шо╛ф╕║цЦ░хА╝)уАВ
 * щЪПшбМ/цЙАхЬихЬ░(follow/location):patch цЬкцШ╛х╝Пч╗ЩцЧ╢,цФ╣хРНхЬ║цЩпф╗Оц┤╛чФЯчЪДцЧз NPC ч╗зцЙ┐(цФ╣хРНф╕Нф╕вф╜Нч╜о)уАВ
 * цЧацЬЙцХИхП╢хнРш┐ФхЫЮ falseуАВ
 */
export function editNpc(
  oldName: string,
  patch: {
    name?: string;
    title?: string;
    desc?: string;
    personality?: string;
    outfit?: string;
    condition?: string;
    important?: boolean;
    follow?: boolean;
    location?: string;
  },
): boolean {
  const newName = patch.name?.trim() || oldName;
  const title = patch.title?.trim() || undefined;
  const desc = patch.desc?.trim() || undefined;
  const personality = patch.personality?.trim() || undefined;

  // ф╜Нч╜о / хН│цЧ╢х▒В:patch цШОчбоч╗Щф║ЖчФи patch чЪД;хРжхИЩф╗ОцЧз NPC ч╗зцЙ┐(цФ╣хРНф╕Нф╕вцЙАхЬихЬ░/щЪПшбМ/чК╢цАБ/щЗНшжБцАз)
  const prev = memory.npcs.find(n => n.id === npcId(oldName));
  const follow = patch.follow !== undefined ? patch.follow : prev?.follow;
  const location = patch.location !== undefined ? (patch.location.trim() || undefined) : prev?.location;
  const outfit = patch.outfit !== undefined ? (patch.outfit.trim() || undefined) : prev?.outfit;
  const condition = patch.condition !== undefined ? (patch.condition.trim() || undefined) : prev?.condition;
  const important = patch.important !== undefined ? patch.important : prev?.important;

  const fields = { title, desc, personality, outfit, condition, important, follow, location };
  if (norm(newName) !== norm(oldName)) {
    return appendOpToLatestLeaf({
      npcs: { remove: [oldName], add: [{ name: newName, ...fields }] },
    });
  }
  return appendOpToLatestLeaf({ npcs: { update: [{ name: newName, ...fields }] } });
}

/**
 * хИЗцНвцЯР NPC чЪДщЪПшбМчК╢цАБ(хРМф╝┤/хПЦц╢ИхРМф╝┤)уАВ
 *  - follow=true:цаЗшо░щЪПшбМ(applyNpcPlacement ф╝Ъц╕ЕцОЙ location)уАВ
 *  - follow=false:хПЦц╢ИщЪПшбМ;хПпщАЙф╝ахЕе location цМЗхоЪуАМчХЩхЬихУкуАН,ф╕Нф╝ахИЩф┐ЭчХЩхОЯцЙАхЬихЬ░уАВ
 */
export function setNpcFollow(name: string, follow: boolean, location?: string): boolean {
  const nm = name.trim();
  if (!nm) return false;
  const loc = follow ? undefined : (location?.trim() || undefined);
  return appendOpToLatestLeaf({ npcs: { update: [{ name: nm, follow, location: loc }] } });
}

