/* ============ хЬ║цЩпцЙЛхКи op(хЖЩхЫЮцЬАцЦ░хП╢хнР,ф╕О editItem хРМшМГх╝П) ============ */

/** цЙЛхКицЦ░хвЮ/шбехЕиф╕Аф╕кхЬ░чВ╣(щАРч║зхЬ░чРЖш╖пх╛Д)уАВцЧацЬЙцХИхП╢хнРш┐ФхЫЮ falseуАВ */
export function upsertScene(path: string[], desc?: string): boolean {
  const clean = normScenePath(path);
  if (!clean.length) return false;
  return appendOpToLatestLeaf({ scenes: { add: [{ path: clean, desc: desc?.trim() || undefined }] } });
}

/** цЙЛхКицЫ┤цЦ░ф╕Аф╕кхЬ░чВ╣чЪДцППш┐░(шжЖчЫЦ)уАВ */
export function editSceneDesc(path: string[], desc: string): boolean {
  const clean = normScenePath(path);
  if (!clean.length) return false;
  return appendOpToLatestLeaf({ scenes: { update: [{ path: clean, desc: desc.trim() || undefined }] } });
}

/**
 * цФ╣цЯРхЬ░чВ╣чЪДхРНхнЧ(ш┐ЮхнРцаСф╕Аш╡╖цФ╣)уАВцФ╣хРН = хРМчИ╢ф╕ЛцНвцЬлцо╡хРН = reparent чЪДф╕Аф╕кцГЕх╜в:
 * newPath ф┐ЭчХЩхОЯф╕Кч║зуАБхПкцНвцЬлцо╡,reparentScenePath ф╝ЪцККцХ┤цг╡хнРцаСх╣│чз╗хИ░цЦ░хРНф╕Л,хнРшКВчВ╣ф╕Нф╕вхд▒уАВ
 * хРНхнЧц▓бхПШхИЩхПкцЫ┤цЦ░цППш┐░(шЛеч╗Щф║Ж)уАВ
 */
export function renameScene(oldPath: string[], newName: string, desc?: string): boolean {
  const clean = normScenePath(oldPath);
  const nm = newName.trim();
  if (!clean.length || !nm) return false;
  if (norm(nm) === norm(clean[clean.length - 1])) {
    return desc !== undefined ? editSceneDesc(clean, desc) : false; // хРНц▓бхПШ,хПкцФ╣цППш┐░
  }
  const newPath = [...clean.slice(0, -1), nm];
  const descs = desc?.trim() ? { [nm]: desc.trim() } : undefined;
  return appendOpToLatestLeaf({ scenes: { reparent: [{ node: clean, newPath, descs }] } });
}

/**
 * цЙЛхКищЗНшо╛чИ╢ч║з / цФ╣хРН / цПТх▒В(ш┐ЮхнРцаСх╣│чз╗),чФиф╕АцЭб reparent шбиш╛╛уАВ
 *  - newPath:чЫоцаЗхоМцХ┤ш╖пх╛Д(цЬлцо╡хПпф╕ОхОЯхРНф╕НхРМ = щб║х╕жцФ╣хРН;хЙНч╝АхН│цЦ░ф╕Кч║з,чй║хЙНч╝А=щб╢ч║з)уАВ
 *  - descs:newPath ф╕КхРДч║зчЪДцППш┐░(щФо=шпеч║зхЬ░хРН),чФиф║Ошбех╗║чИ╢ч║з + цЫ┤цЦ░швлчз╗хКишКВчВ╣шЗкш║лчЪДцППш┐░уАВ
 * хдНчФиф╕О AI хРМф╕АхеЧ reparent щЗНцФ╛щА╗ш╛СуАВ
 */
export function reparentScene(nodePath: string[], newPath: string[], descs?: Record<string, string>): boolean {
  const node = normScenePath(nodePath);
  const to = normScenePath(newPath);
  if (!node.length || !to.length) return false;
  if (sceneId(to) === sceneId(node)) return false; // ш╖пх╛Дц▓бхПШ
  return appendOpToLatestLeaf({ scenes: { reparent: [{ node, newPath: to, descs }] } });
}

/** цЙЛхКихИащЩдф╕Аф╕кхЬ░чВ╣(ш┐Юх╕жхЕ╢хРОф╗г)уАВ */
export function removeScene(path: string[]): boolean {
  const clean = normScenePath(path);
  if (!clean.length) return false;
  return appendOpToLatestLeaf({ scenes: { remove: [clean] } });
}

/** хИащЩдцЯРцЭбц╢ИцБпф╕КчЪДхП╢хнР(ц╕Е extra),чД╢хРОч║зшБФхИахЭПщУ╛ + щЗНчоЧ + шР╜чЫШ */
export function deleteLeafAt(index: number): boolean {
  const chat = getContext()?.chat;
  if (!chat || !chat[index]?.extra?.bbs_leaf) return false;
  delete (chat[index].extra as Record<string, unknown>).bbs_leaf;
  recomputeDerived();
  pruneBrokenComps();
  scheduleLeafFlush();
  return true;
}

/**
 * цЙЛхКич╝Цш╛СцЯРцЭбц╢ИцБпф╕КчЪДхП╢хнР:цСШшжБцнгцЦЗ + цХЕф║ЛхЖЕш╡╖цнвцЧ╢щЧ┤уАВ
 * ф╕НцФ╣ srcHash(щФЪхоЪчЪДцШпцнгцЦЗ,ф╕НцШпцСШшжБ),цХЕхП╢хнРф╗НцЬЙцХИуАВ
 * timeEnd хРМцнехЖЩш┐Ы delta.time(шжЖчЫЦхЮЛх╜УхЙНчК╢цАБ,щЗНцФ╛хН│чФЯцХИ);ч╝Цш╛СхРОц╕ЕцОЙцЧзчЪД timeLabel(х╖▓швлш╡╖цнвхПЦф╗г)уАВ
 */
export function editLeafAt(index: number, text: string, timeStart: string, timeEnd: string): boolean {
  const chat = getContext()?.chat;
  const leaf = getLeaf(chat?.[index]);
  if (!chat || !leaf) return false;
  leaf.text = text.trim();
  const s = timeStart.trim();
  const e = timeEnd.trim();
  leaf.timeStart = s || undefined;
  leaf.timeEnd = e || undefined;
  leaf.timeLabel = undefined; // ш╡╖цнвх╖▓цШпцЭГхиБ,цЧзхРИх╣╢ф╕▓ф╜Ьх║Я
  leaf.delta = leaf.delta ?? {};
  // шжЖчЫЦхЮЛх╜УхЙНцЧ╢щЧ┤хПЦч╗УцЭЯцЧ╢щЧ┤;ф╕дчлпчЪЖчй║цЙНц╕ЕщЩд
  if (e) leaf.delta.time = e;
  else if (s) leaf.delta.time = s;
  else delete leaf.delta.time;
  chat[index].extra = { ...(chat[index].extra ?? {}), bbs_leaf: leaf };
  recomputeDerived();
  scheduleLeafFlush();
  return true;
}

/**
 * ч╝Цш╛Сф╕АцЭбшобхИТ/цВмх┐╡:цФ╣ content / createdTime / targetTimeуАВ
 * шобхИТ id = `plan:${хП╢хнРid}#${хЬишпехП╢хнР add цХ░ч╗ДщЗМчЪДх║ПхП╖}`,цНоцндхоЪф╜НхИ░ф║зчФЯхоГчЪДхП╢хнРчЪД delta.plans.add[idx]уАВ
 * ф╕НцФ╣ srcHash(щФЪхоЪцнгцЦЗ,ф╕О delta цЧахЕ│),хП╢хнРф╗НцЬЙцХИ;цФ╣хоМщЗНчоЧц┤╛чФЯ + шР╜чЫШуАВ
 */
export function editPlan(
  planIdStr: string,
  patch: { content?: string; createdTime?: string; targetTime?: string },
): boolean {
  const m = planIdStr.match(/^plan:(.+)#(\d+)$/);
  if (!m) return false;
  const leafId = m[1];
  const addIdx = Number(m[2]);
  const chat = getContext()?.chat;
  if (!chat) return false;

  // цЙ╛хИ░ id хМ╣щЕНчЪДцЬЙцХИхП╢хнР
  let index = -1;
  for (let i = 0; i < chat.length; i++) {
    const lf = getLeaf(chat[i]);
    if (lf && lf.id === leafId && leafValid(chat[i])) {
      index = i;
      break;
    }
  }
  if (index < 0) return false;
  const leaf = getLeaf(chat[index])!;
  const add = leaf.delta?.plans?.add?.[addIdx];
  if (!add) return false;

  if (typeof patch.content === 'string') add.content = patch.content.trim();
  if (patch.createdTime !== undefined) add.createdTime = patch.createdTime.trim() || undefined;
  if (patch.targetTime !== undefined) add.targetTime = patch.targetTime.trim() || undefined;

  chat[index].extra = { ...(chat[index].extra ?? {}), bbs_leaf: leaf };
  recomputeDerived();
  scheduleLeafFlush();
  return true;
}

/**
 * ч╝Цш╛Сф╕Аф╕кхОЛч╝йшКВчВ╣(цА╗ч╗У)чЪДцнгцЦЗуАВцА╗ч╗УхПкхОЛцЦЗцЬмуАБф╕НхРлч╗УцЮДхМЦцХ░цНо,
 * цХЕхПкцФ╣ text хнЧцо╡хН│хПп,цЧащЬА recomputeуАВ
 */
export function editSummary(id: string, text: string): boolean {
  const comp = memory.summaries.find(s => s.id === id);
  if (!comp) return false;
  comp.text = text.trim();
  saveMemory();
  return true;
}

/* ============ хИащЩд / цЛЖх░Б ============ */

/**
 * хИащЩдф╕Аф╕кхОЛч╝йшКВчВ╣уАВ
 *  - ф╗ОцЙАцЬЙчИ╢шКВчВ╣чЪД childIds цСШщЩдцЬм id;
 *  - цХ░ч╗ДхИащЩдцЬмшКВчВ╣уАВхЕ╢хнРшКВчВ╣хЫачИ╢х╝ХчФицЦнх╝А,шЗкхКихПШхЫЮуАМцХгшгЕца╣уАНуАВ
 * ц│ицДП:хИахОЛч╝йшКВчВ╣ф╕Нх╜▒хУНч╗УцЮДхМЦцХ░цНо(хПкхОЛцЦЗцЬм),цЧащЬА recompute,ф╜ЖшжБхИ╖цЦ░ц│ихЕеуАВ
 */
export function deleteSummary(id: string): boolean {
  const idx = memory.summaries.findIndex(s => s.id === id);
  if (idx < 0) return false;
  for (const p of memory.summaries) {
    if (p.childIds.includes(id)) p.childIds = p.childIds.filter(c => c !== id);
  }
  memory.summaries.splice(idx, 1);
  saveMemory();
  return true;
}

/**
 * чеЦхЕИщУ╛цХ┤хИа:цЯРхП╢хнР id ф╕НхЖНцЬЙцХИ(швлхИа/щЩИцЧз/цНвцЦ░ id)цЧ╢,хЗбцШп(щАТх╜Т)хМЕхРлхоГчЪДхОЛч╝йшКВчВ╣хЕихИауАВ
 * хИдхоЪ:ф╕Аф╕кхОЛч╝йшКВчВ╣уАМхоМхе╜уАНтЯ║ хоГчЪДцпПф╕к child шжБф╣ИцШпчО░хнШцЬЙцХИхП╢хнР idуАБшжБф╣ИцШпхоМхе╜чЪДхОЛч╝йшКВчВ╣;
 * хРжхИЩуАМцНЯхЭПуАН,хИащЩдуАВmemoized DFSуАВхИащЩдхРО saveMemory(шЛецЬЙхПШхМЦ)уАВ
 *
 * тЪая╕П ш┐ЩщЗМчФи leafIntact шАМщЭЮ leafValid:хП╢хнРуАМхнШц┤╗уАНхПкчЬЛчЙйчРЖхнШхЬи(id+delta),**ф╕НчЬЛщб╡чаБх╜Тх▒Ю**уАВ
 * ч┐╗щб╡хИ░ц▓бцСШш┐ЗчЪД swipe цЧ╢,швлхОЛч╝йш┐Ы L1 чЪДхП╢хнРшЩ╜хп╣х╜УхЙНщб╡ leafValid=false,ф╜ЖхоГф╗НчЙйчРЖхнШхЬиф║О
 * шЗкх╖▒щВгф╕Ащб╡чЪД extra щЗМ(ч┐╗хЫЮхО╗х░▒цШ╛чд║)тАФтАФч╗Эф╕НшГ╜хЫауАМх╜УхЙНф╕НхЬиш┐Щщб╡уАНх░▒хИацОЙхоГцЙАх▒ЮчЪДхОЛч╝йщУ╛уАВ
 */
export function pruneBrokenComps(): boolean {
  const chat = getContext()?.chat ?? null;
  const liveLeafIds = new Set<string>();
  if (chat) {
    for (const m of chat) {
      if (leafIntact(m)) liveLeafIds.add(getLeaf(m)!.id);
    }
  }
  const byId = new Map(memory.summaries.map(s => [s.id, s]));
  const verdict = new Map<string, boolean>(); // id -> intact

  const isIntact = (id: string, stack: Set<string>): boolean => {
    if (verdict.has(id)) return verdict.get(id)!;
    const comp = byId.get(id);
    if (!comp) return liveLeafIds.has(id); // ф╕НцШпхОЛч╝йшКВчВ╣:чЬЛцШпф╕НцШпчО░хнШцЬЙцХИхП╢хнР
    if (stack.has(id)) return false; // щШ▓чОп
    stack.add(id);
    let ok = comp.childIds.length > 0;
    for (const c of comp.childIds) {
      if (!isIntact(c, stack)) {
        ok = false;
        break;
      }
    }
    stack.delete(id);
    verdict.set(id, ok);
    return ok;
  };

  const before = memory.summaries.length;
  memory.summaries = memory.summaries.filter(s => isIntact(s.id, new Set()));
  const changed = memory.summaries.length !== before;
  if (changed) saveMemory();
  return changed;
}

