<script setup lang="ts">
import Icon from '@/components/Icon.vue';
import { openBook, ui } from '@/state/ui';
import { computed, onMounted, onUnmounted, reactive, ref } from 'vue';

/**
 * цВмц╡очРГ тАФтАФ цЯПхоЭф╣жф╝╕ш┐Ыхо┐ф╕╗щб╡щЭвчЪДуАМф╣жчн╛хЭауАНуАВ
 *
 * х╜вцАБ:члЦхРСч╝Ох╕ж + х║ХщГичЗХх░╛ч╝║хПг(clip-path),хС╝х║ФхУБчЙМчЪД bookmark хЫ╛цаЗ;шЗкхоЪф╣ЙхЫ╛чЙЗф╣Яшвл
 * хИЗцИРхРМф╕Аф╣жчн╛ш╜ох╗У,ф╗╗цДПхЫ╛щГ╜цФ╢ш┐Ыч╗Яф╕Ах╜вчК╢(ш┐ЩцШпф╕ОуАМхПИф╕Аф╕кхЬЖ fabуАНцЛЙх╝Ах╖ош╖ЭчЪДчн╛хРНцЙЛц│Х)уАВ
 *
 * шбМф╕║(цМЙчФицИ╖шжБц▒В):шЗкчФ▒цЛЦхКи тАФтАФ цЛЦхИ░х▒Пх╣Хф╕нщЧ┤х░▒хБЬхЬиф╕нщЧ┤;цЛЦхИ░цОеш┐Сх╖ж/хП│ш╛╣ч╝ШцЙНхР╕щЩДш┤┤ш╛╣уАВ
 * ш┤┤ш╛╣цЧ╢хНКщЪРф║Ош╛╣ч╝Ш(хПкщЬ▓ф╕АчкДцЭб),hover/шБЪчДж/шзжцС╕цЙНцХ┤цЭбц╗СхЗ║;хБЬхЬиф╕нщЧ┤хИЩх╕╕цШ╛уАВ
 *
 * ф╜Нч╜охнШцЬмцЬ║ localStorage(ч║пшзЖшзЙцАБуАБхРДшо╛хдЗх▒Пх╣Хх░║хп╕ф╕НхРМ,хРМцнехПНшАМф╝Ъш╖СхИ░х▒Пх╣ХхдЦ)уАВ
 * х╝АхЕ│ф╕ОшЗкхоЪф╣ЙхЫ╛цаЗ(ui.orbImage,цЬНхКбхЩиш╖пх╛Д)ш╖ишо╛хдЗхРМцне,чФ▒шо╛ч╜оцЙ┐ш╜╜уАВ
 */

// х░║хп╕щЪПх╜вчК╢ + чФицИ╖хЯ║хЗЖх░║хп╕(ui.orbSize):ф╣жчн╛цМЙ 0.78 хо╜щлШцпФ(члЦщХ┐цЦ╣),хЬЖ/цЦ╣чнЙш╛╣цнгцЦ╣уАВ
// цЛЦхКи/хР╕щЩДшобчоЧф╕ОхЖЕшБФх░║хп╕щГ╜шп╗хоГуАВ
const orbW = computed(() => (ui.orbShape === 'bookmark' ? Math.round(ui.orbSize * 0.78) : ui.orbSize));
const orbH = computed(() => ui.orbSize);
const SNAP_ZONE = 56; // цЭ╛цЙЛцЧ╢ш╖Эх╖ж/хП│ш╛╣ч╝Ш тЙд цндхА╝хН│хР╕щЩДш┤┤ш╛╣
const CLICK_SLOP = 6; // ф╜Нчз╗ < цндхА╝шзЖф╕║чВ╣хЗ╗шАМщЭЮцЛЦхКи
const POS_KEY = 'bbs.orb.pos.v1';

type Dock = 'left' | 'right' | 'none';
interface OrbPos {
  dock: Dock;
  /** ш┤┤ш╛╣цЧ╢цЧацДПф╣Й;free цЧ╢ф╕║х╖жф╕КшзТ x(px) */
  x: number;
  /** х╖жф╕КшзТ y(px),ф╕ЙчзНчК╢цАБщГ╜чФи */
  y: number;
}

function loadPos(): OrbPos {
  try {
    const raw = localStorage.getItem(POS_KEY);
    if (raw) {
      const p = JSON.parse(raw) as Partial<OrbPos>;
      if (p && (p.dock === 'left' || p.dock === 'right' || p.dock === 'none')) {
        return { dock: p.dock, x: Number(p.x) || 0, y: Number(p.y) || 0 };
      }
    }
  } catch {
    /* ignore */
  }
  // щ╗Шшод:хП│ф╛зш┤┤ш╛╣уАБч║╡хРСх▒Еф╕нхБПф╕Л
  return { dock: 'right', x: 0, y: Math.round(window.innerHeight * 0.6) };
}

const pos = reactive<OrbPos>(loadPos());
const dragging = ref(false);
const awake = ref(false); // hover/шБЪчДж/цЛЦхКи тЖТ ш┤┤ш╛╣цАБцХ┤цЭбц╗СхЗ║
let activePointer: number | null = null;
let startX = 0;
let startY = 0;
let moved = 0; // ч┤пшобф╜Нчз╗,чФиф║ОчВ╣хЗ╗/цЛЦхКихИдхоЪ

// ш┐ЫхЕешзЖхПгхРОцККхЭРцаЗхд╣ш┐ЫхПпшзЖшМГхЫ┤(цНвф║ЖцЫ┤х░ПчЪДх▒Пх╣Х/цЧЛш╜мхРОф╕НшЗ│ф║Ош╖СхЗ║хО╗)
function clampToViewport(): void {
  const maxY = Math.max(0, window.innerHeight - orbH.value);
  pos.y = Math.min(Math.max(0, pos.y), maxY);
  if (pos.dock === 'none') {
    const maxX = Math.max(0, window.innerWidth - orbW.value);
    pos.x = Math.min(Math.max(0, pos.x), maxX);
  }
}

function savePos(): void {
  try {
    localStorage.setItem(POS_KEY, JSON.stringify(pos));
  } catch {
    /* ignore */
  }
}

// тАФтАФ хоЪф╜Нца╖х╝П:ш┤┤ш╛╣чФи left/right щФЪхоЪ + translateX цОзхИ╢щЪР/чО░;free чФич╗Эхп╣ x/y тАФтАФ
const orbStyle = computed(() => {
  const base: Record<string, string> = {
    top: `${pos.y}px`,
    width: `${orbW.value}px`,
    height: `${orbH.value}px`,
    // щЭЩцнвф╕НщАПцШОх║жш╡░ CSS хПШщЗП,хФдш╡╖/цЛЦхКицАБчФ▒ч▒╗шжЖчЫЦхЫЮхЕицШ╛
    '--orb-rest-opacity': String(Math.min(100, Math.max(20, ui.orbOpacity)) / 100),
    // хЫ╛цаЗхнЧхП╖щЪПхЯ║хЗЖх░║хп╕ч╝йцФ╛(хОЯ 48 чРГ тЙИ 22px),ф┐ЭцМБхЫ╛цаЗф╕ОчРГф╜УцпФф╛ЛхНПш░Г
    '--orb-icon-size': `${Math.round(ui.orbSize * 0.46)}px`,
  };
  if (pos.dock === 'left') {
    base.left = '0px';
    // щЭЩцнвхНКщЪР(щЬ▓ ~40%);цЛЦхКи/хФдш╡╖цЧ╢цХ┤цЭбц╗СхЗ║
    base.transform = dragging.value || awake.value ? 'translateX(0)' : 'translateX(-58%)';
  } else if (pos.dock === 'right') {
    base.right = '0px';
    base.transform = dragging.value || awake.value ? 'translateX(0)' : 'translateX(58%)';
  } else {
    base.left = `${pos.x}px`;
    base.transform = 'translateX(0)';
  }
  return base;
});

const orbImage = computed(() => ui.orbImage.trim());

// тАФтАФ цЛЦхКи тАФтАФ
function onDown(e: PointerEvent) {
  activePointer = e.pointerId;
  dragging.value = true;
  moved = 0;
  startX = e.clientX;
  startY = e.clientY;
  // шо░х╜ХцЙЛцМЗчЫ╕хп╣х╖жф╕КшзТчЪДцКУхПЦчВ╣,цЛЦхКицЧ╢ф┐ЭцМБ
  grabDX = e.clientX - currentLeft();
  grabDY = e.clientY - pos.y;
  (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
}

let grabDX = 0;
let grabDY = 0;

/** х╜УхЙНх╖жф╕КшзТчЪДхоЮщЩЕ x(ш┤┤ш╛╣цАБчФ▒ right/translate цКШчоЧцИРч╗Эхп╣хГПч┤а,ф╛ЫцЛЦхКиш╡╖цнечФи) */
function currentLeft(): number {
  if (pos.dock === 'right') return window.innerWidth - orbW.value;
  if (pos.dock === 'left') return 0;
  return pos.x;
}

function onMove(e: PointerEvent) {
  if (!dragging.value || e.pointerId !== activePointer) return;
  moved = Math.max(moved, Math.abs(e.clientX - startX) + Math.abs(e.clientY - startY));
  // цЛЦхКиф╕нф╕Ах╛ЛхИЗ free ш╖ЯцЙЛ(цХ┤цЭбхПпшзБ)
  pos.dock = 'none';
  pos.x = e.clientX - grabDX;
  pos.y = e.clientY - grabDY;
  clampToViewport();
}

function onUp(e: PointerEvent) {
  if (!dragging.value || e.pointerId !== activePointer) return;
  dragging.value = false;
  activePointer = null;

  if (moved < CLICK_SLOP) {
    // шзЖф╕║чВ╣хЗ╗ тЖТ цЙУх╝АцЯПхоЭф╣ж(ш┤┤ш╛╣цАБф┐ЭцМБ)
    openBook();
    return;
  }

  // цЭ╛цЙЛхР╕щЩДхИдхоЪ:щЭаш┐Сх╖ж/хП│ш╛╣ч╝ШцЙНш┤┤ш╛╣,хРжхИЩхБЬхЬихОЯхЬ░(ф╕нщЧ┤)
  const left = pos.x;
  const right = window.innerWidth - (pos.x + orbW.value);
  if (left <= SNAP_ZONE) pos.dock = 'left';
  else if (right <= SNAP_ZONE) pos.dock = 'right';
  else pos.dock = 'none';
  clampToViewport();
  savePos();
}

// тАФтАФ щФочЫШхПпш╛╛ тАФтАФ
function onKey(e: KeyboardEvent) {
  if (e.key === 'Enter' || e.key === ' ') {
    e.preventDefault();
    openBook();
  }
}

const onResize = () => {
  clampToViewport();
  savePos();
};
onMounted(() => {
  clampToViewport();
  window.addEventListener('resize', onResize);
});
onUnmounted(() => window.removeEventListener('resize', onResize));
</script>

<template>
  <div
    class="bbs-orb"
    :class="[`shape-${ui.orbShape}`, { 'is-dragging': dragging, 'has-image': !!orbImage }]"
    :style="orbStyle"
    role="button"
    tabindex="0"
    aria-label="цЙУх╝АцЯПхоЭф╣ж"
    @pointerdown="onDown"
    @pointermove="onMove"
    @pointerup="onUp"
    @pointercancel="onUp"
    @pointerenter="awake = true"
    @pointerleave="awake = false"
    @focus="awake = true"
    @blur="awake = false"
    @keydown="onKey"
  >
    <img v-if="orbImage" :src="orbImage" class="bbs-orb-img" alt="" draggable="false" />
    <Icon v-else name="bookmark" class="bbs-orb-icon" />
  </div>
</template>

<style scoped>
.bbs-orb {
  position: fixed;
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bbs-surface);
  color: var(--bbs-accent);
  cursor: grab;
  touch-action: none;
  user-select: none;
  /* drop-shadow хп╣ clip-path(ф╣жчн╛)ф╕О border-radius(хЬЖ/цЦ╣)щГ╜ш╖ЯщЪПш╜ох╗У,ч╗Яф╕АчФихоГ */
  filter: drop-shadow(0 6px 14px oklch(0 0 0 / 0.28));
  opacity: var(--orb-rest-opacity, 0.62);
  transition:
    transform var(--bbs-dur) var(--bbs-ease),
    opacity var(--bbs-dur) var(--bbs-ease);
}

/* тАФтАФ х╜вчК╢ тАФтАФ */
/* ф╣жчн╛:ч╝Ох╕жш╜ох╗У + х║ХщГичЗХх░╛ч╝║хПгуАВclip-path хдйчД╢шгБхИЗшЗкхоЪф╣ЙхЫ╛уАВ */
.bbs-orb.shape-bookmark {
  clip-path: polygon(0 0, 100% 0, 100% 100%, 50% 78%, 0 100%);
}
/* хЬЖ / цЦ╣:border-radius + overflow шгБхИЗшЗкхоЪф╣ЙхЫ╛ */
.bbs-orb.shape-circle {
  border-radius: 999px;
  overflow: hidden;
}
.bbs-orb.shape-square {
  border-radius: 12px;
  overflow: hidden;
}

/* хФдш╡╖(hover/шБЪчДж/цЛЦхКи)цИЦхБЬхЬиф╕нщЧ┤(free) тЖТ хЕицШ╛ */
.bbs-orb:hover,
.bbs-orb:focus-visible,
.bbs-orb.is-dragging {
  opacity: 1;
}
.bbs-orb:focus-visible {
  outline: none;
  color: var(--bbs-accent);
}
.bbs-orb:active {
  cursor: grabbing;
}

.bbs-orb-icon {
  font-size: var(--orb-icon-size, 22px);
  pointer-events: none;
}
/* ф╣жчн╛:хЫ╛цаЗф╕Кчз╗,щБ┐х╝Ах║ХщГичЗХх░╛ч╝║хПг(хЬЖ/цЦ╣цЧач╝║хПг,х▒Еф╕нхН│хПп) */
.bbs-orb.shape-bookmark .bbs-orb-icon {
  margin-bottom: 6px;
}

.bbs-orb-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  pointer-events: none;
}

@media (prefers-reduced-motion: reduce) {
  .bbs-orb {
    transition: none;
  }
}
</style>
