/** цЧзчЙИхНХцз╜ф╜Н key;хИ╖цЦ░цЧ╢ц╕Ечй║,щБ┐хЕНхНЗч║зхРО D2 цоЛчХЩщЗНхдНц│ихЕе */
const LEGACY_INJECT_KEY = 'baibai_book_memory';
/** цЛЖхИЖхРОчЪД setExtensionPrompt keys;хРМ key щЗНхдН set хН│шжЖчЫЦ,хдйчД╢х╣ВчнЙ */
const HISTORY_INJECT_KEY = 'baibai_book_memory_history';
const STATE_INJECT_KEY = 'baibai_book_memory_state';
/** цЧ╢щЧ┤цаЗчн╛хЫ║хоЪцПРчд║шпНцз╜:ц│ихЕеф╕╗хп╣шпЭ,шжБц▒ВцпПцЭбцнгцЦЗхЙНхРОш╛УхЗ║ <bbs_start>/<bbs_end> */
const TIMETAG_INJECT_KEY = 'baibai_book_time_tag';
/** хОЖхП▓цСШшжБх░╜щЗПцФ╛хИ░шБКхдйф╕Кф╕ЛцЦЗщб╢щГи;х╜УхЙНчК╢цАБш┤┤ш┐СцЬАш┐Схп╣шпЭ */
const HISTORY_INJECT_DEPTH = 9999;
const STATE_INJECT_DEPTH_AFTER_LATEST_AI = 1;
const STATE_INJECT_DEPTH_BEFORE_LATEST_AI = 2;
/** цЧ╢щЧ┤цаЗчн╛цПРчд║шпНчЛмчлЛц│ихЕехИ░ D0(цЬАх║ХуАБцЬАш┤┤ш┐Сф╕Лф╕АцЭбхЫЮхдН),ф╜Ьф╕║хп╣уАМф╕Лф╕АцЭбхЫЮхдНуАНчЪДцЬАх╝║цМЗф╗д,
 *  ф╕Нф╕ОчК╢цАБх┐лчЕз(D1/D2)хРМх▒В */
const TIMETAG_INJECT_DEPTH = 0;

/**
 * ф╕АцЭбхП╢хнРцШпхРжуАМх╖▓хРпчФиуАН(х║Фц│ихЕе)уАВ
 * чФЯцИРф╕Оф╜┐чФишзгшАж:хП╢хнРхп╣цЙАцЬЙце╝х▒ВцПРхЙНчФЯцИР,ф╜ЖхПкцЬЙх╜УхоГцЙАхЬиц╢ИцБпх╖▓швлщЪРшЧП(is_system,
 * хОЯцЦЗчз╗хЗ║ф╕╗ф╕Кф╕ЛцЦЗ)цЧ╢цЙНц│ихЕещб╢цЫ┐хОЯцЦЗ;ф╗НхЬиф┐ЭчХЩчкЧхПгхПСхЕицЦЗчЪДхП╢хнРцЪВф╕Нц│ихЕе,щБ┐хЕНф╕ОхЕицЦЗщЗНхдНуАВ
 */
function leafActiveAt(chat: STMessage[] | null, i: number): boolean {
  if (!chat) return false;
  return chat[i]?.is_system === true;
}

/** чФиф║ОхЖ│хоЪчК╢цАБх┐лчЕзчЫ╕хп╣цЬАцЦ░ AI це╝чЪДф╜Нч╜о;ф╕О engine.ts чЪДхПпш┐╜ш╕к AI це╝шзДхИЩф┐ЭцМБф╕АшЗ┤уАВ */
function isTrackableAiMessage(m: STMessage | undefined): boolean {
  if (!m || m.is_user) return false;
  if (typeof m.mes !== 'string' || !m.mes.trim()) return false;
  if (m.extra?.bbs_hidden) return true;
  return !m.is_system;
}

/**
 * х╜УхЙНчК╢цАБчЪДц│ихЕеф╜Нч╜о:
 *  - цЬАцЦ░ AI х╖▓цЬЙцЬЙцХИцСШшжБ тЖТ чК╢цАБх╖▓хМЕхРлхоГ,цФ╛хЬихоГф╣ЛхРО(D1)уАВ
 *  - цЬАцЦ░ AI х░ЪцЧацЬЙцХИцСШшжБ тЖТ чК╢цАБф╕НхМЕхРлхоГ,ф┐ЭцМБцФ╛хЬихоГф╣ЛхЙН(D2)уАВ
 */
function resolveStateInjectionDepth(chat: STMessage[] | null): number {
  if (!chat) return STATE_INJECT_DEPTH_BEFORE_LATEST_AI;
  for (let i = chat.length - 1; i >= 0; i--) {
    if (!isTrackableAiMessage(chat[i])) continue;
    return leafValid(chat[i]) ? STATE_INJECT_DEPTH_AFTER_LATEST_AI : STATE_INJECT_DEPTH_BEFORE_LATEST_AI;
  }
  return STATE_INJECT_DEPTH_BEFORE_LATEST_AI;
}

/** цЮДх╗║ч╗Яф╕АцгоцЮЧшзЖхЫ╛:хП╢хнР(leafValid)+ хОЛч╝йшКВчВ╣,ца╣ = цЬкшвлф╗╗ф╜Х childIds х╝ХчФишАЕ */
function buildView(
  summaries: MemSummary[],
  chat: STMessage[] | null,
): { byId: Map<string, ViewNode>; roots: ViewNode[] } {
  const byId = new Map<string, ViewNode>();

  if (chat) {
    for (let i = 0; i < chat.length; i++) {
      if (!leafValid(chat[i])) continue; // щЩИцЧзхП╢хнРф╕Нш┐ЫшзЖхЫ╛ тЖТ ф╕Нц│ихЕе
      const leaf = getLeaf(chat[i]) as LeafExtra;
      byId.set(leaf.id, {
        id: leaf.id,
        kind: 'leaf',
        level: 0,
        text: leaf.text,
        timeStart: leaf.timeStart,
        timeEnd: leaf.timeEnd,
        timeLabel: leaf.timeLabel,
        createdAt: leaf.createdAt,
        childIds: [],
        msgIndex: i,
        active: leafActiveAt(chat, i),
      });
    }
  }
  for (const s of summaries) {
    byId.set(s.id, {
      id: s.id,
      kind: 'comp',
      level: s.level,
      text: s.text,
      timeStart: s.timeStart,
      timeEnd: s.timeEnd,
      timeLabel: s.timeLabel,
      createdAt: s.createdAt,
      childIds: s.childIds ?? [],
      msgIndex: -1,
      active: false,
    });
  }

  const referenced = new Set<string>();
  for (const s of summaries) for (const c of s.childIds ?? []) referenced.add(c);
  const roots = [...byId.values()].filter(n => !referenced.has(n.id));
  return { byId, roots };
}

/**
 * щАЪчФишКВчВ╣щАЙцЛй:цпПф╕куАМхРИца╝уАНхП╢хнРчФ▒хЕ╢чеЦхЕИщУ╛ф╕К**цЬАщлШчЪДуАБхЕищГихРОф╗гхП╢хнРщГ╜хРИца╝**чЪДшКВчВ╣ф╗гшбиф╕Ацмб
 * (чЬБ token);хРжхИЩхОЛч╝йшКВчВ╣щЩНч║зуАБщАРхнРщАТх╜ТуАВхП╢хнРуАМхРИца╝уАНчФ▒ leafEligible хИдхоЪуАВ
 *  - ц│ихЕехЬ║цЩп:хРИца╝ = х╖▓щЪРшЧП(active),чФи selectInjectionNodesуАВ
 *  - хИЖцЮРхОЖхП▓хЬ║цЩп:хРИца╝ = це╝х▒ВхЬишвлхИЖцЮРце╝ф╣ЛхЙН,чФи selectHistoryNodesBeforeуАВ
 *
 * тЪая╕П хоМхе╜цАз(intact):ф╕Аф╕кхОЛч╝йшКВчВ╣чЪДцЯРф╕к childId цМЗхРСчЪДхП╢хнРшЛех╖▓хд▒цХИ(ч┐╗щб╡хИ░хИлчЪД swipe тЖТ
 * leafValid=false тЖТ ф╕НхЬи byId щЗМ),хИЩшпешКВчВ╣**ф╕НхоМцХ┤**,ф╕НшГ╜ф╜Ьф╕║цХ┤ф╜Уф╗гшбиц│ихЕе(хоГчЪДхОЛч╝йцЦЗцЬм
 * х╡МчЭАхд▒цХИщВгщб╡чЪДцЧзхПЩф║Л,ф╝Ъф╕Ох╜УхЙНцнгцЦЗхЖ▓чкБ)уАВцндцЧ╢щЩНч║зщАТх╜Т,цФ╣чФихоГ**ф╗НхоМхе╜чЪДхнРшКВчВ╣**хРДшЗкф╗гшби:
 * хПЧх╜▒хУНчЪДщВгцЭбщУ╛ф╕Аш╖пцЛЖхИ░хП╢хнРх▒ВуАБш╖│ш┐Зхд▒цХИхП╢хнР,шАМцЧБцФпхоМхе╜чЪДхнРшКВчВ╣(хжВхРМх▒ВхПжф╕АцЭб L1)цХ┤цЭбф┐ЭчХЩуАВ
 * шКВчВ╣хд▒ц┤╗хПкцШпуАМх╜УхЙНф╕Нх▒Хчд║/ф╕Нц│ихЕеуАН,цгоцЮЧцХ░цНоф╕НхИащЩдтАФтАФч┐╗хЫЮхОЯщб╡ leafValid цБвхдН,хН│шЗкхКихдНц┤╗уАВ
 */
function selectNodes(
  summaries: MemSummary[],
  chat: STMessage[] | null,
  leafEligible: (n: ViewNode) => boolean,
): ViewNode[] {
  return selectViewNodes(buildView(summaries, chat), leafEligible);
}

/**
 * щАЙхЗ║ц│ихЕечФичЪДшКВчВ╣:цпПф╕куАМх╖▓хРпчФи(х╖▓щЪРшЧП)уАНхП╢хнРчФ▒хЕ╢чеЦхЕИщУ╛цЬАщлШчЪДхЕи-хРпчФишКВчВ╣ф╗гшбиф╕Ацмб;
 * чкЧхПгхЖЕф╗НхПСхЕицЦЗчЪДхП╢хнРф╕Нц│ихЕеуАВ
 */
export function selectInjectionNodes(summaries: MemSummary[], chat: STMessage[] | null): ViewNode[] {
  return selectNodes(summaries, chat, n => n.active);
}

/**
 * щАЙхЗ║уАМшвлхИЖцЮРце╝ф╣ЛхЙНуАНчЪДхОЖхП▓шКВчВ╣,ф╛ЫчФЯцИРцСШшжБцЧ╢ц│ихЕеф╕Кф╕ЛцЦЗ:
 * це╝х▒В < beforeIndex чЪДхП╢хнР,чФ▒хЕ╢чеЦхЕИщУ╛цЬАщлШчЪДуАМхЕищГихРОф╗гщГ╜хЬи beforeIndex ф╣ЛхЙНуАНчЪДшКВчВ╣ф╗гшбиф╕Ацмб
 * (цЬЙцА╗ч╗Ух░▒чФицА╗ч╗УчЪДхОЛч╝йцЦЗцЬм)уАВф╕НшжБц▒ВщЪРшЧПуАВ
 */
export function selectHistoryNodesBefore(
  summaries: MemSummary[],
  chat: STMessage[] | null,
  beforeIndex: number,
): ViewNode[] {
  return selectNodes(summaries, chat, n => n.msgIndex >= 0 && n.msgIndex < beforeIndex);
}

/** шКВчВ╣х▒Хчд║цЧ╢щЧ┤:цЦ░цХ░цНочФиш╡╖цнвхРИцИР,цЧзцХ░цНохЫЮщАА timeLabel */
function nodeTime(n: ViewNode): string {
  if (n.timeStart || n.timeEnd) return formatRange(n.timeStart, n.timeEnd);
  return n.timeLabel ? compactTimeLabel(n.timeLabel) : '';
}

/** цККщАЙхЗ║чЪДшКВчВ╣цЛ╝цИРхОЖхП▓цСШшжБцЦЗцЬмхЭЧ(х╕жцЧ╢щЧ┤цаЗчн╛хЙНч╝А);чй║хИЩш┐ФхЫЮчй║ф╕▓ */
export function renderHistoryNodes(nodes: ViewNode[]): string {
  return nodes
    .map(n => {
      const t = nodeTime(n);
      return t ? `уАР${t}уАС${n.text}` : n.text;
    })
    .join('\n\n');
}

/** шКВчВ╣чЪДуАМф║Лф╗╢цЧ╢щЧ┤уАН:чФич╗УцЭЯцЧ╢щЧ┤(хЙзцГЕх╖▓хИ░ш╛╛чЪДцЧ╢хИ╗);ч╝║хИЩхЫЮщААш╡╖хзЛ,хЖНхЫЮщААцЧз timeLabel чЪДч╗УцЭЯчлп */
function nodeEventTime(n: ViewNode): string {
  if (n.timeEnd) return n.timeEnd;
  if (n.timeStart) return n.timeStart;
  return n.timeLabel ? splitTimeLabel(n.timeLabel).end ?? '' : '';
}

/**
 * ц│ихЕеф╕УчФи:хЬич╗Эхп╣цЧ╢щЧ┤хЙНхЖНхКаф╕Аф╕кчЫ╕хп╣хЙНч╝А(хжВуАР(цШихдй) 1988/9/29 21:30уАС),х╕оф╕╗цибхЮЛцДЯчЯецЧ╢щЧ┤ш╖Эчж╗уАВ
 * хПВчЕзчВ╣ now = цХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤;цЧац│ХшзгцЮРчЫ╕хп╣х╖очЪД(цЮ╢чй║ч║кх╣┤чнЙ)щЩНч║зф╕║хПкцШ╛чд║ч╗Эхп╣цЧ╢щЧ┤уАВ
 * ф╕Нх╣╢хЕе renderHistoryNodes тАФтАФ щВгф╕кшвлцСШшжБцибхЮЛф╕Кф╕ЛцЦЗхдНчФи,ф╕НшГ╜х╕жчЫ╕хп╣хЙНч╝А(ф╝Ъц▒бцЯУф╕ФхПВчЕзчВ╣ф╕НхРМ)уАВ
 *
 * тЪая╕П ф╗Е**хП╢хнР**(цЬкхОЛч╝йчЪДхНХце╝цСШшжБ)хКачЫ╕хп╣хЙНч╝А:хоГцМЗхРСцЯРф╕АхИ╗уАБчЫ╕хп╣ш╖Эчж╗цЬЙцДПф╣ЙуАВ
 * хОЛч╝йшКВчВ╣(цА╗ч╗У)ш╖ихдЪце╝уАБцЬмш║лх░▒цШпф╕Ацо╡цЧ╢щЧ┤шМГхЫ┤,цаЗф╕куАМ(цШихдй)уАНхПНшАМшппхп╝ф╕╗цибхЮЛуАБцШУхЗ║щФЩ тАФтАФ хПкч╗Щч╗Эхп╣цЧ╢щЧ┤уАВ
 */
function renderHistoryNodesWithRelative(nodes: ViewNode[], now: string): string {
  return nodes
    .map(n => {
      const t = nodeTime(n);
      if (!t) return n.text;
      const rel = n.kind === 'leaf' ? relativeTimeLabel(nodeEventTime(n), now) : '';
      return rel ? `уАР(${rel}) ${t}уАС${n.text}` : `уАР${t}уАС${n.text}`;
    })
    .join('\n\n');
}

/** ч╗ДхРИхОЖхП▓цСШшжБц│ихЕецЦЗцЬм;цЧахРпчФицСШшжБцЧ╢ш┐ФхЫЮчй║ф╕▓(ц│ихЕечй║ф╕▓чнЙф║Оц╕ЕщЩд)уАВ */
export function buildHistoryInjectionText(): string {
  const chat = getContext()?.chat ?? null;

  // ф╗ОцгоцЮЧщАЙуАМцЬАщлШхнШц┤╗хОЛч╝йх▒ВуАНшКВчВ╣(швлцФ╢ч║│чЪДф╕НщЗНхдНуАБчкЧхПгхЖЕхЕицЦЗхП╢хнРф╕Нц│ихЕе)
  const sums = selectInjectionNodes(memory.summaries, chat);
  if (!sums.length) return '';
  // ц│ихЕеш╖пх╛Дх╕жчЫ╕хп╣цЧ╢щЧ┤хЙНч╝А;хПВчЕзчВ╣ = цХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤(шп╗цнгцЦЗцаЗчн╛,ф╕НхПЧцШпхРжх╖▓цСШх╜▒хУН)
  // щжЦх░╛чзБхпЖчоАцКецбЖхоЪ,щБ┐хЕНф╕╗цибхЮЛцККцСШшжБх╜УцИРшжБхдНш┐░/ш╛УхЗ║чЪДцибцЭ┐
  return `${MEMORY_BRIEFING_NOTE}\n[хОЖхП▓хЙзцГЕцСШшжБ]\n${renderHistoryNodesWithRelative(sums, latestStoryTime(chat))}\n${MEMORY_BRIEFING_END}`;
}

/**
 * чЙйхУБхнШцФ╛хЬ░цШпхРжф╕Ох╜УхЙНхЬ░чВ╣хМ╣щЕН(хПпш╛╛):хМЕхРлх╝Пцибч│КхМ╣щЕН,ф╗╗ф╕АцЦ╣хМЕхРлхПжф╕АцЦ╣хН│чоЧуАВ
 * хЕ╝хо╣ AI хС╜хРНч▓Чч╗Жф╕Нф╕А(уАМховцаИуАНтКВуАМхЯОше┐ховцаИф║Мце╝уАН)уАВчй║хЬ░чВ╣ф╕НхМ╣щЕНуАВ
 */
function locationReachable(itemLoc: string | undefined, here: string): boolean {
  const a = (itemLoc ?? '').trim();
  const b = here.trim();
  if (!a || !b) return false;
  return a.includes(b) || b.includes(a);
}

/**
 * хЬихЬ║цЩпцаСщЗМхоЪф╜НуАМх╜УхЙНшКВчВ╣уАН:ф╝ШхЕИ AI ч╗ЩчЪДцЭГхиБ locationPath,хРжхИЩцМЙ here цФ╢ч┤зцибч│КхМ╣щЕНуАВ
 * ф╕ОхЬ║цЩпщб╡хЕ▒чФи apply.findCurrentSceneId(хНХф╕АцЭец║Р,цЭЬч╗Эщб╡щЭв/ц│ихЕехИЖхПЙ),ш┐ЩщЗМхЖНцКК id шзгцЮРхЫЮшКВчВ╣уАВ
 * цЙ╛ф╕НхИ░ш┐ФхЫЮ null(щААхЫЮч║пхнЧчмжф╕▓шбМф╕║)уАВ
 */
function findCurrentScene(scenes: MemScene[], here: string, locationPath?: string[]): MemScene | null {
  const id = findCurrentSceneId(scenes, here, locationPath);
  if (!id) return null;
  return scenes.find(s => s.id === id) ?? null;
}

/** хЫЮц║пчеЦхЕИщУ╛(чФ▒ч▓ЧхИ░ч╗Ж,хРлх╜УхЙНшКВчВ╣цЬмш║л)уАВ */
function sceneChain(scenes: MemScene[], node: MemScene | null): MemScene[] {
  if (!node) return [];
  const byId = new Map(scenes.map(s => [s.id, s]));
  const chain: MemScene[] = [];
  let cur: MemScene | undefined = node;
  const seen = new Set<string>();
  while (cur && !seen.has(cur.id)) {
    seen.add(cur.id);
    chain.unshift(cur);
    cur = cur.parentId ? byId.get(cur.parentId) : undefined;
  }
  return chain;
}

/**
 * чЙйхУБцШпхРжхЬиуАМх╜УхЙНхЬ░чВ╣цИЦхЕ╢чеЦхЕИщУ╛ф╗╗ф╕Ач║зуАНхПпш╛╛уАВ
 * шБФхКи:х╜УхЙНхЬиуАМх╜ТщЫБховцаИф║Мце╝уАН,хнШцФ╛хЬиуАМх╜ТщЫБховцаИуАН(хЕ╢чеЦхЕИ)чЪДчЙйхУБф╣ЯчоЧхПпш╛╛ тЖТ щЪПхЬ░чВ╣ф╕Аш╡╖хПСуАВ
 * chain ф╕║чй║(цЧахЬ║цЩпцХ░цНо)цЧ╢щААхЫЮч║пхнЧчмжф╕▓ locationReachable(here),ф┐ЭшпБцЧзцХ░цНоф╕НхЫЮх╜ТуАВ
 */
function itemReachableInScene(itemLoc: string | undefined, here: string, chain: MemScene[]): boolean {
  if (!chain.length) return locationReachable(itemLoc, here);
  const a = (itemLoc ?? '').trim();
  if (!a) return false;
  return chain.some(n => locationReachable(itemLoc, n.name) || locationReachable(itemLoc, n.path.join('')));
}

/**
 * ц╕▓цЯУхЬ║цЩпц│ихЕехЭЧ(хИЖф╕ЙцбгчЬБ token):
 *  - х╜УхЙНхЬ░чВ╣ + чеЦхЕИщУ╛:щАРч║зуАМхРНчз░(цППш┐░)уАНшпжч╗ЖуАВ
 *  - хЕ╢ф╗ЦхО╗ш┐ЗчЪДхЬ░чВ╣:ф╗ЕхИЧхРНчз░(хоМцХ┤ш╖пх╛ДхРН),х╕о AI хдНчФицЧвцЬЙхС╜хРНуАБщБ┐хЕНщЗНхдНшо░х╜ХуАВ
 * цЧахЬ║цЩпцХ░цНош┐ФхЫЮчй║ф╕▓уАВ
 */
function fmtSceneContext(scenes: MemScene[], here: string, locationPath?: string[]): string {
  if (!scenes.length) return '';
  const current = findCurrentScene(scenes, here, locationPath);
  const chain = sceneChain(scenes, current);
  const chainIds = new Set(chain.map(s => s.id));

  const lines: string[] = [];
  if (chain.length) {
    const detailed = chain
      .map(n => (n.desc ? `${n.name}(${n.desc})` : n.name))
      .join(' тА║ ');
    lines.push(`х╜УхЙНцЙАхЬи(чФ▒хдзхИ░х░П):${detailed}`);
  }
  // хЕ╢ф╗ЦхЬ░чВ╣:ф╗ЕхРНчз░(чФихоМцХ┤ш╖пх╛Дшбиш╛╛х▒Вч║з),цОТщЩдх╖▓хЬичеЦхЕИщУ╛щЗМшпжш┐░чЪД
  const others = scenes
    .filter(s => !chainIds.has(s.id))
    .map(s => s.path.join(' тА║ '));
  if (others.length) {
    lines.push(`хЕ╢ф╗Цх╖▓чЯехЬ░чВ╣(ф╗ЕхРНчз░,хЛ┐щЗНхдНшо░х╜Х):\n${others.map(o => `  - ${o}`).join('\n')}`);
  }
  return lines.join('\n');
}

/**
 * NPC цШпхРжуАМхЬихЬ║уАН:щЪПшбМ(follow=true)ц░╕ш┐ЬхЬихЬ║;хРжхИЩцМЙцЙАхЬихЬ░ф╕Ох╜УхЙНхЬ░чВ╣(хПКчеЦхЕИщУ╛)хПпш╛╛хИдхоЪуАВ
 * хдНчФичЙйхУБхРМцм╛ itemReachableInScene(carriedтЖФfollowуАБlocation хРМф╣Й)уАВ
 */
function npcOnScene(npc: MemNpc, here: string, chain: MemScene[]): boolean {
  if (npc.follow === true) return true;
  return itemReachableInScene(npc.location, here, chain);
}

/** цКК NPC чЪДуАМхН│цЧ╢чК╢цАБуАН(чЭАшгЕ/чК╢цАБ/цЙАхЬи)цЛ╝цИРф╕Ацо╡х░╛ц│и;цЧахИЩчй║ф╕▓уАВф╛ЫхЬихЬ║ф╕Оф╕╗шжБшзТшЙ▓ч╗ДхдНчФиуАВ */
function npcStateTail(n: MemNpc, withPlace: boolean): string {
  const tail: string[] = [];
  if (n.outfit?.trim()) tail.push(`чЭАшгЕ:${n.outfit.trim()}`);
  if (n.condition?.trim()) tail.push(`чК╢цАБ:${n.condition.trim()}`);
  if (withPlace) {
    if (n.follow) tail.push('щЪПшбМ');
    else if (n.location?.trim()) tail.push(`хЬи:${n.location.trim()}`);
  }
  return tail.length ? ` уАФ${tail.join(';')}уАХ` : '';
}

/**
 * ц╕▓цЯУ NPC хРНхЖМц│ихЕехЭЧ(хИЖф╕ЙцбгчЬБ token):
 *  - **ф╕╗шжБшзТшЙ▓**(important):ц░╕ш┐ЬхЕищЗПч╜ощб╢,**чкБхЗ║хН│цЧ╢чК╢цАБщЭвцЭ┐**(чЭАшгЕ/чК╢цАБ/цЙАхЬи),ш║лф╗╜/цАзца╝/хдЦш▓Мф╗ОчоАуАВ
 *  - хЬихЬ║(щЪПшбМ / цЙАхЬихЬ░шР╜х╜УхЙНхЬ░чВ╣цИЦчеЦхЕИщУ╛)тЖТ хЕищЗП:хРН + ш║лф╗╜ + цАзца╝ + хдЦш▓М + хН│цЧ╢чК╢цАБуАВ
 *  - ф╕НхЬихЬ║ тЖТ хПкхПС хРН + ш║лф╗╜(title),чаНцОЙхдЦш▓М/цАзца╝ш┐Щф╕дф╕кхдзхд┤(ф╜Жф╕╗шжБшзТшЙ▓хН│ф╛┐ф╕НхЬихЬ║ф╣Ях╖▓хЬиф╕КщЭвхЕищЗПхПСф║Ж)уАВ
 * цЧа NPC ш┐ФхЫЮчй║ф╕▓уАВ
 */
function fmtNpcContext(npcs: MemNpc[], here: string, chain: MemScene[]): string {
  if (!npcs.length) return '';
  const main: MemNpc[] = [];
  const present: MemNpc[] = [];
  const absent: MemNpc[] = [];
  for (const n of npcs) {
    if (n.important) main.push(n); // ф╕╗шжБшзТшЙ▓хНХхИЧ,ф╕НхЖНш┐ЫхЬихЬ║/ф╕НхЬихЬ║хИдхоЪ
    else if (npcOnScene(n, here, chain)) present.push(n);
    else absent.push(n);
  }

  const lines: string[] = [];
  if (main.length) {
    // ф╕╗шжБшзТшЙ▓:чК╢цАБщЭвцЭ┐ф╝ШхЕИуАВш║лф╗╜чХЩф╕АхПех╕охоЪф╜Н,хдЦш▓М/цАзца╝ф╗ОчоА(хНбщЗМщАЪх╕╕х╖▓цЬЙ),щЗНчВ╣цШпхН│цЧ╢чК╢цАБуАВ
    const detailed = main
      .map(n => {
        const head = n.title?.trim() ? `${n.name}(${n.title.trim()})` : n.name;
        return `  - ${head}${npcStateTail(n, true)}`;
      })
      .join('\n');
    lines.push(`ф╕╗шжБшзТшЙ▓(ца╕х┐Гф╕╗ц╝Ф,щЬАхзЛч╗Иф┐ЭцМБхЕ╢х╜УхЙНчК╢цАБш┐Юш┤п):\n${detailed}`);
  }
  if (present.length) {
    const detailed = present
      .map(n => {
        const parts = [n.name];
        if (n.title?.trim()) parts.push(`(${n.title.trim()})`);
        const profile: string[] = [];
        if (n.personality?.trim()) profile.push(`цАзца╝:${n.personality.trim()}`);
        if (n.desc?.trim()) profile.push(n.desc.trim());
        const profileStr = profile.length ? ` тАФтАФ ${profile.join(';')}` : '';
        const place = n.follow ? ' [щЪПшбМ]' : '';
        return `  - ${parts.join('')}${place}${profileStr}${npcStateTail(n, false)}`;
      })
      .join('\n');
    lines.push(`хЬихЬ║шзТшЙ▓:\n${detailed}`);
  }
  if (absent.length) {
    // ф╕НхЬихЬ║:ф╗ЕхРН + ш║лф╗╜,цМЙцЙАхЬихЬ░цЛмц│и;цЧахдЦш▓М/цАзца╝/чК╢цАБ
    const brief = absent
      .map(n => {
        const title = n.title?.trim() ? `(${n.title.trim()})` : '';
        return `  - ${n.name}${title}${n.location ? ` [хЬи:${n.location}]` : ''}`;
      })
      .join('\n');
    lines.push(`хЕ╢ф╗Цх╖▓чЯешзТшЙ▓(ф╕НхЬих╜УхЙНхЬ║цЩп,ф╗ЕхРНф╕Ош║лф╗╜):\n${brief}`);
  }
  return lines.join('\n');
}

/** ч╗ДхРИх╜УхЙНч╗УцЮДхМЦчК╢цАБц│ихЕецЦЗцЬм;цЧацЬЙцДПф╣ЙчК╢цАБцЧ╢ш┐ФхЫЮчй║ф╕▓уАВ */
export function buildStateInjectionText(): string {
  const st: string[] = [];
  if (memory.state.time) st.push(`х╜УхЙНцЧ╢щЧ┤:${memory.state.time}`);
  if (memory.state.location) st.push(`х╜УхЙНхЬ░чВ╣:${memory.state.location}`);

  const here = memory.state.location || '';
  const locPath = memory.state.locationPath;
  // хЬ║цЩпцаС:х╜УхЙНхЬ░чВ╣ + чеЦхЕИщУ╛(шпжч╗Ж) + хЕ╢ф╗ЦхЬ░чВ╣(ф╗ЕхРНчз░)уАВчеЦхЕИщУ╛хРМцЧ╢чФиф║ОчЙйхУБ/NPC хПпш╛╛хИдхоЪуАВ
  const sceneBlock = fmtSceneContext(memory.scenes, here, locPath);
  if (sceneBlock) st.push(`хЬ░чВ╣шо░х┐Ж:\n${sceneBlock}`);
  const chain = sceneChain(memory.scenes, findCurrentScene(memory.scenes, here, locPath));

  // чЙйхУБхИЖф╕дч╗ДчЬБ token:хПпш╛╛(щЪПш║л / хнШцФ╛хЬ░шР╜хЬих╜УхЙНхЬ░чВ╣цИЦхЕ╢чеЦхЕИщУ╛)хПСхЕищЗП(хРН+щЗП+цППш┐░);
  // ф╗ЦхдДхпДхнШчЪДхПкхПСхРН+цХ░щЗП(чаНцОЙцППш┐░ш┐Щф╕кхдзхд┤),цЧвчЬБ token хПИф╕НшЗ│ф║Ошойф╕╗цибхЮЛф╗еф╕║ф╕Ьше┐ц▓бф║ЖуАВ
  const reachable = memory.items.filter(i => i.carried !== false || itemReachableInScene(i.location, here, chain));
  const elsewhere = memory.items.filter(i => !(i.carried !== false || itemReachableInScene(i.location, here, chain)));
  st.push(`чЙйхУБц╕ЕхНХ:\n${fmtItems(reachable.map(i => ({ name: i.name, qty: i.qty, desc: i.desc, carried: i.carried, location: i.location })))}`);
  if (elsewhere.length) {
    // ф╗ЕхРН+цХ░щЗП,цМЙхЬ░чВ╣цЛмц│и;цЧацППш┐░
    const brief = elsewhere
      .map(i => `  - ${i.name}${typeof i.qty === 'number' ? ` ├Ч${i.qty}` : ''}(хнШ:${i.location || 'цЯРхдД'})`)
      .join('\n');
    st.push(`ф╗ЦхдДхпДхнШчЙйхУБ(хЫЮхИ░хп╣х║ФхЬ░чВ╣цЙНцЬЙхоМцХ┤ф┐бцБп):\n${brief}`);
  }
  // ц│и:ш┐СцЬЯчЙйхУБхПШхКиф╕НхЬицндц│ихЕеуАВцФ╣ф╕║цСШшжБхРОхЖЩш┐Ыхп╣х║Фце╝х▒ВцнгцЦЗ </bbs_end> ф╣ЛхРО(шзБ engine.ts),
  // чкЧхПгхЖЕхЕицЦЗце╝х▒ВхдйчД╢хПпшзБуАБц╗ЪхЗ║чкЧхПгшЗкчД╢ц╢Ихд▒ тАФтАФ чмжхРИуАМчЙйхУБхПШхКихПкхЬищВгцо╡цЧ╢щЧ┤цЬЙчФиуАНчЪДхПЦшИНуАВ

  // NPC хРНхЖМ:хЬихЬ║(щЪПшбМ/цЙАхЬихЬ░шР╜х╜УхЙНхЬ░чВ╣цИЦчеЦхЕИщУ╛)хПСхЕищЗП(хРН+ш║лф╗╜+цАзца╝+цППш┐░);
  // ф╕НхЬихЬ║хПкхПСхРН+ш║лф╗╜(чаНцОЙцППш┐░/цАзца╝),NPC ш╢КхдЪчЬБх╛Чш╢КхдЪуАВ
  const npcBlock = fmtNpcContext(memory.npcs, here, chain);
  if (npcBlock) st.push(`NPCхРНхЖМ:\n${npcBlock}`);

  const openPlans = memory.plans
    .filter(p => p.status === 'open')
    .map(p => ({ kind: p.kind, content: p.content, createdTime: p.createdTime, targetTime: p.targetTime }));
  st.push(`цЬкф║Жч╗УчЪДшобхИТ/цВмх┐╡:\n${fmtPlans(openPlans)}`);

  // чК╢цАБхЭЧхЬицЬЙф╗╗ф╜ХцЬЙцДПф╣ЙхЖЕхо╣цЧ╢цЙНц│ихЕе(чЙйхУБ/шобхИТхН│ф╜┐чй║ф╣Яф╝ЪцЬЙуАМ(цЧа)уАНхНаф╜Н,
  // ф╜ЖхПкшжБхнШхЬицСШшжБцИЦцЧ╢щЧ┤/хЬ░чВ╣х░▒хА╝х╛Чх╕жф╕КцХ┤хЭЧ)
  const hasState = memory.state.time || memory.state.location || memory.items.length || memory.scenes.length || memory.npcs.length || openPlans.length;
  if (!hasState) return '';
  // щжЦх░╛чзБхпЖчоАцКецбЖхоЪ,щБ┐хЕНф╕╗цибхЮЛцККчК╢цАБх┐лчЕзх╜УцИРшжБхдНш┐░/ш╛УхЗ║чЪДцибцЭ┐(цнгцЦЗхРОш╖ЯхРРф╕Аф╗╜чК╢цАБ)
  return `${MEMORY_BRIEFING_NOTE}\n[х╜УхЙНчК╢цАБ]\n${st.join('\n')}\n${MEMORY_BRIEFING_END}`;
}

/**
 * ч╗ДхРИц│ихЕецЦЗцЬм:х╖▓хРпчФичЪДхОЖхП▓цСШшжБ + х╜УхЙНч╗УцЮДхМЦчК╢цАБ(цЧ╢щЧ┤/хЬ░чВ╣/чЙйхУБ/цЬкф║Жч╗УшобхИТ)уАВ
 * ф┐ЭчХЩч╗Щш░ГшпХ/хЕ╝хо╣ш░ГчФи;хоЮщЩЕц│ихЕечФ▒ refreshInjection цЛЖцИРф╕дф╕к ST цз╜ф╜НуАВ
 */
export function buildInjectionText(): string {
  return [buildHistoryInjectionText(), buildStateInjectionText()].filter(Boolean).join('\n\n').trim();
}

/** цККх╜УхЙНшо░х┐ЖхИ╖цЦ░хИ░ ST чЪДцЙйх▒ХцПРчд║цз╜уАВST цЬкх░▒ч╗к/цЧзчЙИцЧацнд API цЧ╢щЭЩщ╗Шш╖│ш┐ЗуАВ */
export function refreshInjection(): void {
  // х╝ХцУОхЬицндшБКхдйф╕НчФЯцХИ(цА╗х╝АхЕ│хЕ│ / х╜УхЙНшзТшЙ▓швлцОТщЩд):ц╕ЕцОЙх╖▓ц│ихЕечЪДцз╜уАВ
  // чФи clearInjection шАМщЭЮчЫ┤цОе return тАФтАФ хИЗхИ░швлцОТщЩдшзТшЙ▓цЧ╢х┐Ещб╗цК╣цОЙф╕Кф╕кшБКхдйцоЛчХЩчЪДц│ихЕеуАВ
  if (!engineActiveHere()) {
    clearInjection();
    return;
  }
  const ctx = getContext();
  const fn = ctx?.setExtensionPrompt;
  if (typeof fn !== 'function') return;
  const stateDepth = resolveStateInjectionDepth(ctx?.chat ?? null);
  fn(LEGACY_INJECT_KEY, '', IN_CHAT, STATE_INJECT_DEPTH_BEFORE_LATEST_AI, false, ROLE_SYSTEM, null);
  fn(HISTORY_INJECT_KEY, buildHistoryInjectionText(), IN_CHAT, HISTORY_INJECT_DEPTH, false, ROLE_SYSTEM, null);
  fn(STATE_INJECT_KEY, buildStateInjectionText(), IN_CHAT, stateDepth, false, ROLE_SYSTEM, null);
  // цЧ╢щЧ┤цаЗчн╛хЫ║хоЪцПРчд║шпН:ш╖ЯщЪПшЗкхКицСШшжБх╝АхЕ│ц│ихЕеф╕╗хп╣шпЭ,хЕ│щЧнцЧ╢ц│ихЕечй║ф╕▓(чнЙф║Оц╕ЕщЩд)
  fn(TIMETAG_INJECT_KEY, apiSettings.autoSummaryEnabled ? timeTagPrompt() : '', IN_CHAT, TIMETAG_INJECT_DEPTH, false, ROLE_SYSTEM, null);
}

/** ц╕ЕщЩдц│ихЕе(ц│ихЕечй║ф╕▓)уАВхИЗхИ░цЧашо░х┐ЖчЪДшБКхдйцЧ╢чФ▒ refreshInjection шЗкхКихоМцИР,цндхдДф╛ЫцШ╛х╝Пш░ГчФиуАВ */
export function clearInjection(): void {
  const ctx = getContext();
  const stateDepth = resolveStateInjectionDepth(ctx?.chat ?? null);
  ctx?.setExtensionPrompt?.(LEGACY_INJECT_KEY, '', IN_CHAT, STATE_INJECT_DEPTH_BEFORE_LATEST_AI, false, ROLE_SYSTEM, null);
  ctx?.setExtensionPrompt?.(HISTORY_INJECT_KEY, '', IN_CHAT, HISTORY_INJECT_DEPTH, false, ROLE_SYSTEM, null);
  ctx?.setExtensionPrompt?.(STATE_INJECT_KEY, '', IN_CHAT, stateDepth, false, ROLE_SYSTEM, null);
  ctx?.setExtensionPrompt?.(TIMETAG_INJECT_KEY, '', IN_CHAT, TIMETAG_INJECT_DEPTH, false, ROLE_SYSTEM, null);
}
