// ц│ихЕецз╜ф╜Н:ш┤┤ш┐СхОЖхП▓цСШшжБх▒В(щб╢щГищЩДш┐С),ф╕О inject.ts чЪДхОЖхП▓цСШшжБхРМф╕АхМ║хЯЯф╜ЖчЛмчлЛ keyуАВ
const RECALL_INJECT_KEY = 'baibai_book_vector_recall';
const IN_CHAT = 1;
const ROLE_SYSTEM = 0;
const RECALL_INJECT_DEPTH = 0; // D0:ш┤┤цЬАх║Х(ч┤зщВ╗чФицИ╖цЬАцЦ░ш╛УхЕе),шойхПмхЫЮчЪДчЫ╕хЕ│хЫЮх┐Жчж╗х╜УхЙНшпнхвГцЬАш┐С

/**
 * хС╜ф╕нцЭец║РцаЗшо░:
 *  - scope чнЙф║Ох╜УхЙНшБКхдй тЖТ цЬмшБКхдйхС╜ф╕н,цШ╛чд║це╝х▒ВхП╖уАМ#5уАН(msgIndex хН│х╜УхЙНце╝х▒ВхП╖);
 *  - хРжхИЩ(bundle:<hash>)тЖТ цЭешЗкуАМх╕жцХ░цНох╗║цЦ░хп╣шпЭуАНхЖ╗ч╗УчЪДцЧзшБКхдйх┐лчЕз,цШ╛чд║уАМцЧзцбгуАНуАВ
 * цЧзшБКхдйчЪДчЬЯхоЮхРНхнЧ/це╝х▒ВхП╖цЬкш┐╜ш╕к(bundle хПкхнШ hash),цХЕч╗Яф╕АцаЗуАМцЧзцбгуАНшойчФицИ╖чЯещБУщЭЮцЬмшБКхдйуАВ
 */
function sourceLabel(hit: VecHit, selfScope: string | null): string {
  if (selfScope && hit.scope === selfScope) {
    return typeof hit.msgIndex === 'number' && hit.msgIndex >= 0 ? `#${hit.msgIndex}` : 'цЬмшБКхдй';
  }
  return 'цЧзцбг';
}

/** х╜УхЙНф┐ЭчХЩчкЧхПгхЖЕуАБх╖▓хПСхЕицЦЗчЪДхП╢хнР id(хПмхЫЮшжБцОТщЩдхоГф╗м,щБ┐хЕНф╕ОхЕицЦЗщЗНхдН)уАВ */
function windowLeafIds(chat: STMessage[]): string[] {
  const keepStart = resolveKeepStart(chat);
  const ids: string[] = [];
  for (let i = keepStart; i < chat.length; i++) {
    if (leafValid(chat[i])) ids.push(getLeaf(chat[i])!.id);
  }
  return ids;
}

/** ш╜╗щЗПчи│хоЪ hash(FNV-1a,16 ш┐ЫхИ╢),ф╕О index.ts хРМхПгх╛ДуАВчФиф║Оч╝УхнШ key чЪДхЖЕхо╣цМЗч║╣уАВ */
function fnv1a(text: string): string {
  let h = 0x811c9dc5;
  for (let i = 0; i < text.length; i++) {
    h ^= text.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}

/**
 * хПмхЫЮч╗УцЮЬч╝УхнШ:щЗНцЦ░чФЯцИР / ч┐╗щб╡(swipe)цЧ╢хПмхЫЮш╛УхЕеф╕АхнЧф╕НхПШ,чЫ┤цОехдНчФиф╕Кцмбч╗УцЮЬ,
 * чЬБцОЙщЗНхЖЩ+embed+search+rerank чЪДщвЭх║жф╕ОцЧ╢щЧ┤уАВхПкхнШуАМцЬАш┐Сф╕АцмбуАНф╕АцЭб,key ф╕НхМ╣щЕНхН│шжЖчЫЦуАВ
 *
 * key = chatId | цЬАцЦ░userце╝х▒ВхП╖ | hash(цЬАцЦ░userцЦЗцЬм) | hash(ф╕Кф╕АцЭбAIцЦЗцЬм) | хПмхЫЮхПВцХ░цМЗч║╣
 *  - х╕ж user цЦЗцЬм hash:ч╝Цш╛СцЬАцЦ░ш╛УхЕехРОщЗНчФЯцИР,це╝х▒ВхП╖ц▓бхПШф╜ЖхЖЕхо╣хПШф║Ж,щЭахоГхд▒цХИ(хРжхИЩщФЩшппхдНчФи)уАВ
 *  - х╕ж AI цЦЗцЬм hash:ч╝Цш╛Сф╕Кф╕АцЭб AI це╝хРОщЗНчФЯцИР,щЭахоГхд▒цХИуАВ
 *  - х╕жхПмхЫЮхПВцХ░цМЗч║╣:rerank/embedding щШИхА╝уАБцЭбцХ░чнЙф╗╗ф╕АцФ╣хКихИЩхд▒цХИ;хПкцФ╣хИлчЪДшо╛ч╜о(ц╕ащБУ/х╝АхЕ│)ф╕Нхд▒цХИуАВ
 *  - х╕ж chatId:цНвшБКхдйхРОце╝х▒ВхП╖/хУИх╕МхБ╢чД╢чЫ╕хРМф╣Яф╕Нш╖ишБКхдйшппхС╜ф╕нуАВ
 */
interface RecallCache {
  key: string;
  text: string;
  debug: RecallDebug;
}

// цЪВхнШхИ░ localStorage:хИЗхРОхП░швлц╡ПшзИхЩиф╕вх╝ГуАБхИ╖цЦ░уАБх╝АцЦ░цаЗчн╛щб╡хРОхПмхЫЮч╝УхнШф╗НхЬи,хЕНх╛ЧчЩ╜чЩ╜щЗНхПмхЫЮуАВ
// ш╖ихдй/ш╖ицаЗчн╛чЪДцоЛчХЩцЧахЙпф╜ЬчФи:key х╖▓хРл chatId+це╝х▒В+хЖЕхо╣хУИх╕М+хПВцХ░цМЗч║╣,хп╣ф╕Нф╕КхПкф╝ЪщЗНчоЧ,ч╗Эф╕НшппхС╜ф╕нуАВ
// (ф╕Нш┐ЭхПНуАМшо╛ч╜охИлчФи localStorageуАНщВгцЭбтАФтАФщВгцШпшо╛ч╜ошжБш╖ишо╛хдЗхРМцнех┐Еш╡░цЬНхКбхЩи;хПмхЫЮч╝УхнШцШпцЬмцЬ║ф╕┤цЧ╢ч╗УцЮЬ,цЧащЬАхРМцнеуАВ)
// хд▒ш┤ехЕищЭЩщ╗Ш(щЪРчзБцибх╝П/щЕНщвЭц╗б):щААхМЦф╕║цЧач╝УхнШ,ч╗Эф╕Нх╜▒хУНхПмхЫЮф╕╗ц╡БчиЛуАВ
const RECALL_CACHE_STORAGE_KEY = 'bbs_vec_recall_cache';

function loadRecallCache(): RecallCache | null {
  try {
    const raw = localStorage.getItem(RECALL_CACHE_STORAGE_KEY);
    return raw ? (JSON.parse(raw) as RecallCache) : null;
  } catch {
    return null;
  }
}

function saveRecallCache(cache: RecallCache): void {
  try {
    localStorage.setItem(RECALL_CACHE_STORAGE_KEY, JSON.stringify(cache));
  } catch {
    /* щЕНщвЭц╗б/ф╕НхПпчФи:цФ╛х╝ГцМБф╣ЕхМЦ,цЬмцмбф╗ЕцЬмш┐ЫчиЛхЖЕцЬЙцХИ */
  }
}

/** хПмхЫЮхПВцХ░цМЗч║╣:шжЖчЫЦхЕищГих╜▒хУНцЬАч╗Иц│ихЕецЦЗцЬмчЪДцбгф╜НхПВцХ░(ц│ихЕец╖▒х║жцШпх╕╕щЗП,ф╕Ншоб)уАВ */
function recallParamFingerprint(cfg: typeof apiSettings.vector.recall): string {
  return [
    cfg.rerankCandidates,
    cfg.embeddingThreshold,
    cfg.rerankThreshold,
    cfg.fullTextCount,
    cfg.finalRecallCount,
  ].join(',');
}

/**
 * цЮДщАах╜УхЙНш╜очЪДч╝УхнШ keyуАВхПЦуАМцЬАцЦ░ user це╝х▒ВуАНщЬАф╗ОхРОх╛АхЙНцЙлчммф╕АцЭб is_userтАФтАФ
 * щЗНчФЯцИРцЧ╢цЬлх░╛хПпшГ╜цШпх╛ЕцЫ┐цНвчЪД AI це╝/ч│╗ч╗Яце╝,чЫ┤цОехПЦ chat[length-1] ф╝ЪхПЦщФЩуАВ
 * ф╕Кф╕АцЭб AI цЦЗцЬм = шпе user це╝**ф╣ЛхЙН**чммф╕АцЭбщЭЮ user це╝(ц▓бцЬЙхИЩчй║)уАВ
 * тЪая╕П ф╕НшГ╜хПЦ user ф╣ЛхРОщВгцЭб:swipe цЧ╢щВгцнгцШпшвлщЗНчФЯцИРуАБхЖЕхо╣цпПцмбщГ╜хПШчЪДх╜УхЙН AI це╝,
 *    хПЦф║ЖхоГч╝УхнШц░╕ф╕НхС╜ф╕нуАБчЩ╜хБЪуАВхПЦ user ф╣ЛхЙНчЪДчи│хоЪ AI це╝цЙНхп╣уАВ
 * ч╝║ chatId цИЦцЧа user це╝ тЖТ ш┐ФхЫЮ null,цЬмш╜оф╕Нш╡░ч╝УхнШ(чЕзх╕╕хоЮчоЧ)уАВ
 */
function buildRecallCacheKey(chat: STMessage[], cfg: typeof apiSettings.vector.recall): string | null {
  const chatId = currentChatId();
  if (!chatId) return null;

  let userIdx = -1;
  for (let i = chat.length - 1; i >= 0; i--) {
    if (chat[i]?.is_user) {
      userIdx = i;
      break;
    }
  }
  if (userIdx < 0) return null;

  const userText = chat[userIdx]?.mes ?? '';
  let aiText = '';
  for (let i = userIdx - 1; i >= 0; i--) {
    if (!chat[i]?.is_user) {
      aiText = chat[i]?.mes ?? '';
      break;
    }
  }

  return `${chatId}|${userIdx}|${fnv1a(userText)}|${fnv1a(aiText)}|${recallParamFingerprint(cfg)}`;
}

let recalling = false;

/** хПмхЫЮцШпхРжхЬих╜УхЙНшБКхдйчФЯцХИуАВ */
function recallActiveHere(): boolean {
  if (!engineActiveHere()) return false; // цПТф╗╢цА╗х╝АхЕ│хЕ│ / х╜УхЙНшзТшЙ▓швлцОТщЩд тЖТ ф╕НхПмхЫЮ
  if (!apiSettings.vector.enabled) return false;
  return !!currentVectorDb() && recallScopes().length > 0;
}

/** ш┐ЩчзНчФЯцИРч▒╗хЮЛцШпхРжшпешзжхПСхПмхЫЮ:хПкхЬиф║зхЗ║цЦ░цнгцЦЗчЪДчФЯцИРхЙНхПмхЫЮуАВ */
export function shouldRecallForType(type: string | undefined): boolean {
  // ч╗нхЖЩ/хоЙщЭЩ/цЙоц╝Фф╕НщЬАшжБхПмхЫЮцЧзшо░х┐Ж(continue цОечЭАхЖЩуАБquiet/impersonate щЭЮхЙзцГЕцОиш┐Ы)
  return type !== 'continue' && type !== 'quiet' && type !== 'impersonate';
}

/** ц╕Ечй║хПмхЫЮц│ихЕецз╜(щЩНч║з/цЬкхС╜ф╕н/хИЗшБКхдйцЧ╢)уАВ */
export function clearRecallInjection(): void {
  getContext()?.setExtensionPrompt?.(RECALL_INJECT_KEY, '', IN_CHAT, RECALL_INJECT_DEPTH, false, ROLE_SYSTEM, null);
}

/**
 * цЙзшбМф╕АцмбщШ╗хбЮхПмхЫЮх╣╢хЖЩц│ихЕецз╜уАВхЬичФЯцИРцЛжцИкхЩицФ╛шбМш╖пх╛ДщЗМ awaitуАВ
 * ф╗╗ф╜Ххд▒ш┤ещГ╜ц╕Ечй║цз╜х╣╢ш┐ФхЫЮ(щЭЩщ╗ШщЩНч║з)уАВ
 */
export async function runVectorRecall(signal?: AbortSignal): Promise<void> {
  if (!recallActiveHere()) {
    clearRecallInjection();
    return;
  }
  if (recalling) return;
  const database = currentVectorDb();
  if (!database) return;

  const ctx = getContext();
  const chat = ctx?.chat ?? [];
  const fn = ctx?.setExtensionPrompt;
  if (typeof fn !== 'function' || !chat.length) return;

  const cfg = apiSettings.vector.recall;
  const scopes = recallScopes();

  // ч╝УхнШхС╜ф╕н(щЗНчФЯцИР/ч┐╗щб╡ф╕ФхПмхЫЮш╛УхЕецЬкхПШ):чЫ┤цОехдНчФиф╕Кцмбц│ихЕецЦЗцЬм + ш░ГшпХх┐лчЕз,ш╖│ш┐ЗцХ┤цЭбчобч║┐уАВ
  const cacheKey = buildRecallCacheKey(chat, cfg);
  const cached = cacheKey ? loadRecallCache() : null;
  if (cacheKey && cached && cached.key === cacheKey) {
    fn(RECALL_INJECT_KEY, cached.text, IN_CHAT, RECALL_INJECT_DEPTH, false, ROLE_SYSTEM, null);
    restoreRecallDebug(cached.debug);
    setRecallStatus(`${cached.debug.status}(хдНчФич╝УхнШ)`);
    return;
  }

  recalling = true;
  try {
    // х╝Аф╕АцмбцЦ░ш░ГшпХх┐лчЕз(ш┐ЫхЕецЬЙцХИхПмхЫЮш╖пх╛ДцЙНшо░х╜Х,щБ┐хЕНуАМхКЯшГ╜цЬкхРпчФиуАНцЧ╢хПНхдНц╕Ечй║ф╕Кцмбч╗УцЮЬ)
    resetRecallDebug();

    // хПмхЫЮхЙНхЕИшбещ╜РчкЧхПгхдЦч╝║хд▒чЪДхРСщЗПч┤вх╝Х(ш╜╜хЕешАБшБКхдй/хРСщЗПхРОх╝А тЖТ цЧзхП╢хнРхПпшГ╜ф╗ОцЬкч┤вх╝Х),
    // хРжхИЩш┐Щф║ЫцЧзхЙзцГЕф╝ЪчЫ┤цОец╝ПхПмхЫЮуАВхПкщШ╗хбЮчкЧхПгхдЦ,чкЧхПгхЖЕф║дч╗ЩщШ▓цКЦхвЮщЗПуАВ
    await ensureRecallIndex(signal);

    // 1) цЯешпвщЗНхЖЩ(х╝║хИ╢хРпчФи,цЧащЩНч║з):х╛ЧхдЪцЭб query хРСщЗП + rerank чФичЪД query цЦЗцЬмуАВ
    // щЗНхЖЩхд▒ш┤е/цЧа query ф╝ЪцКЫщФЩ тЖТ шР╜хИ░хдЦх▒В catch,ц╕Ечй║ц│ихЕецз╜уАБч╗УцЭЯцЬмцмбхПмхЫЮуАВ
    const { queryVectors, rerankQuery } = await resolveQueryVectors(signal);
    if (!queryVectors.length) {
      setRecallStatus('цЬкхПмхЫЮ:цЯешпвщЗНхЖЩцЬкф║зхЗ║ query');
      clearRecallInjection();
      return;
    }

    // 2) хРОчлпцгАч┤в:хдЪш╖пхЬишМГхЫ┤хЖЕч║пцМЙ embedding х╛ЧхИЖхПЦхЙН rerankCandidates(хРОчлп max шЮНхРИ,ф╕НхеЧщШИхА╝),цОТщЩдчкЧхПгхЖЕхП╢хнР
    const exclude = windowLeafIds(chat);
    const selfScope = currentChatScope();
    const { results } = await vecSearch(database, scopes, queryVectors, {
      topK: Math.max(1, cfg.rerankCandidates),
      excludeLeafIds: exclude,
    });
    setRecallEmbedding(
      results.map(h => ({
        leafId: h.leafId,
        similarity: h.similarity,
        queryIndex: h.queryIndex ?? -1,
        source: sourceLabel(h, selfScope),
        storyTime: compactTimeLabel((h.storyTime || '').trim()),
        preview: previewOf(h.document),
      })),
    );
    if (!results.length) {
      setRecallStatus('цЬкхПмхЫЮ:цгАч┤вцЧахАЩщАЙ');
      clearRecallInjection();
      return;
    }

    // 3) rerank(чФи INTENT/щЗНхЖЩ query;ц╕ащБУцЬкщЕН тЖТ щЩНч║з:чФи embedding х║П,score хдНчФи similarity)
    const ranked = await rerankCandidates(rerankQuery, results, signal);

    // 4) хИЖцбг + ф╕КщЩР(now = цХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤,ф╜ЬчЫ╕хп╣цЧ╢щЧ┤хПВчЕзчВ╣,хп╣щ╜РхОЖхП▓цСШшжБц│ихЕе)
    const now = latestStoryTime(chat);
    const { text, tiers } = buildRecallText(ranked, cfg, selfScope, now);
    recordRerankDebug(ranked, tiers, selfScope);
    fn(RECALL_INJECT_KEY, text, IN_CHAT, RECALL_INJECT_DEPTH, false, ROLE_SYSTEM, null);
    setRecallInjected(text);
    setRecallStatus(text ? 'хПмхЫЮхоМцИР' : 'хПмхЫЮхоМцИР:цЧахЖЕхо╣ш╛╛цаЗ,цЬмхЫЮхРИцЬкц│ихЕе');
    // хоЮчоЧцИРхКЯцЙНшР╜ч╝УхнШ(хд▒ш┤е/щЩНч║зш╖пх╛Дф╕Нч╝УхнШ,ф╕ЛцмбщЗНшпХ)уАВхнШш░ГшпХх┐лчЕзф╛ЫхС╜ф╕нцЧ╢ш┐ШхОЯщЭвцЭ┐уАВ
    if (cacheKey) saveRecallCache({ key: cacheKey, text, debug: snapshotRecallDebug() });
  } catch (e) {
    console.warn('[цЯПхоЭф╣жхРСщЗП] хПмхЫЮхд▒ш┤е(щЩНч║зф╕║ф╕НхПмхЫЮ):', e);
    setRecallStatus(`хд▒ш┤е:${e instanceof Error ? e.message : String(e)}`);
    clearRecallInjection();
  } finally {
    recalling = false;
  }
}

/** цККхИЖцбгч╗УцЮЬхЖЩхЕеш░ГшпХх┐лчЕз:цМЙ leaf_id хО╗щЗН(ф┐ЭчХЩщжЦцЭб),tier хПЦ buildRecallText цаЗшо░,ч╝║чЬБ dropуАВ */
function recordRerankDebug(
  ranked: RankedHit[],
  tiers: Map<string, 'full' | 'brief'>,
  selfScope: string | null,
): void {
  const seen = new Set<string>();
  const hits: RecallDebugRerankHit[] = [];
  for (const h of ranked) {
    if (seen.has(h.leafId)) continue;
    seen.add(h.leafId);
    hits.push({
      leafId: h.leafId,
      rerankScore: h.rerankScore,
      similarity: h.similarity,
      tier: tiers.get(h.leafId) ?? 'drop',
      source: sourceLabel(h, selfScope),
      storyTime: compactTimeLabel((h.storyTime || '').trim()),
      preview: previewOf(h.document),
    });
  }
  setRecallRerank(hits);
}

/**
 * шзгцЮРцгАч┤вчФичЪДхдЪцЭб query хРСщЗП + rerank чФичЪД query цЦЗцЬмуАВ
 * цЯешпвщЗНхЖЩ**х╝║хИ╢хРпчФиуАБцЧащЩНч║з**:rewrite х╛Ч INTENT + хдЪцЭб Q,хРДшЗк embed;rerank query чФи INTENT(цЧахИЩщжЦцЭб Q)уАВ
 * щЗНхЖЩхд▒ш┤е / цЧа query тЖТ чЫ┤цОецКЫщФЩ,чФ▒ runVectorRecall ч╗УцЭЯцЬмцмбхПмхЫЮ(ф╕НхЖНщЩНч║зф╕║хНХ query)уАВ
 */
async function resolveQueryVectors(
  signal?: AbortSignal,
): Promise<{ queryVectors: string[]; rerankQuery: string }> {
  const { intent, queries } = await rewriteQuery(signal);
  setRecallRewrite(intent, queries);
  if (!queries.length) throw new Error('цЯешпвщЗНхЖЩцЬкф║зхЗ║ф╗╗ф╜Х query');
  // цгАч┤вхРСщЗП:хдЪцЭб Q(INTENT хБПщХ┐хБПхЕицЦЗ,чХЩч╗Щ rerank,ф╕Нш┐ЫцгАч┤вхРСщЗПф╗ехЕНчиАщЗК)
  const vecs = await embedTexts(queries, signal);
  const queryVectors = vecs.map(v => encodeFloat32Base64(v));
  return { queryVectors, rerankQuery: intent || queries[0] };
}

interface RankedHit extends VecHit {
  rerankScore: number; // цЧа rerank цЧ╢ = similarity
}

/** хп╣хАЩщАЙхБЪ rerank;хд▒ш┤е/цЬкщЕНч╜охИЩчФи embedding чЫ╕ф╝╝х║жх║ПщЩНч║зуАВ */
async function rerankCandidates(query: string, hits: VecHit[], signal?: AbortSignal): Promise<RankedHit[]> {
  // rerank ц╕ащБУцЬкщЕНч╜о тЖТ чЫ┤цОещЩНч║з(embedTexts/resolveVectorModel хЬи rerank ч╝║ц╕ащБУцЧ╢ф╝ЪцКЫщФЩ)
  try {
    // хЕицЦЗч▓╛цОТ:хПСце╝х▒ВхОЯцЦЗ(mesFull,х╖▓хРлхЖЕх╡Мш╡╖цнвцЧ╢щЧ┤)ч╗Щ rerank,шпнф╣ЙцпФцСШшжБцЫ┤хЕи;
    // цЧахОЯцЦЗ(хжВчзНхнРхП╢хнР)щААцСШшжБ document,цндцЧ╢шбе уАРцХЕф║ЛцЧ╢щЧ┤уАСхд┤ч╗ЩцЧ╢щЧ┤ф╕Кф╕ЛцЦЗуАВ
    // (ш╢ЕщХ┐чФ▒ rerankDocuments хЖЕщГицМЙ token цИкцЦн/хИЖцЙ╣)
    const docs = hits.map(h => {
      // mesFull чО░хнШхОЯцЦЗ,хПСч╗Щ rerank хЙНш┐З cleanBody(хЙФщЩдчК╢цАБцаП/цАЭч╗┤щУ╛/шЗкхоЪф╣ЙцаЗчн╛чнЙ,
      // ф┐ЭчХЩхЖЕх╡Мш╡╖цнвцЧ╢щЧ┤);шАБч┤вх╝ХхнШчЪДцШпх╖▓ц╕Ец┤ЧцЦЗцЬм,хЖНц┤Чх╣ВчнЙцЧахЙпф╜ЬчФиуАВ
      const full = h.mesFull ? cleanBody(h.mesFull).trim() : '';
      if (full) return full;
      const body = (h.document || '').trim();
      const t = (h.storyTime || '').trim();
      return t ? `уАР${t}уАС\n${body}` : body;
    });
    const order = await rerankDocuments(query, docs, hits.length, signal);
    // order цШп {index, score} щЩНх║П;цШах░ДхЫЮ hit
    return order
      .filter(o => hits[o.index])
      .map(o => ({ ...hits[o.index], rerankScore: o.score }));
  } catch {
    // щЩНч║з:ф┐ЭцМБ embedding х║П,rerankScore хдНчФи similarity
    return hits.map(h => ({ ...h, rerankScore: h.similarity }));
  }
}

/**
 * цМЙхИЖцбгшзДхИЩцЛ╝ц│ихЕецЦЗцЬм:
 *  - хЕицЦЗцбг:rerankScore тЙе rerankThreshold,хПЦхЙН fullTextCount,хПС mes_full(цЧахИЩщАА document)уАВ
 *  - цСШшжБцбг:rerankScore < rerankThreshold ф╜Ж similarity тЙе embeddingThreshold,хПС documentуАВ
 *  - цА╗цХ░ тЙд finalRecallCount;цМЙ leaf_id хО╗щЗН(х╖▓хЬихРОчлпш╖и scope хРИх╣╢,ш┐ЩщЗМхЖНхЕЬх║Х)уАВ
 *
 * ш┐ФхЫЮцЛ╝хе╜чЪДц│ихЕецЦЗцЬм + цпПцЭбшвлщЗЗч║│хП╢хнРчЪДхИЖцбг(full/brief),ф╛Ыш░ГшпХщЭвцЭ┐цаЗц│и tierуАВ
 */
function buildRecallText(
  ranked: RankedHit[],
  cfg: typeof apiSettings.vector.recall,
  selfScope: string | null,
  now: string,
): { text: string; tiers: Map<string, 'full' | 'brief'> } {
  const seen = new Set<string>();
  const tiers = new Map<string, 'full' | 'brief'>();
  const fullChunks: string[] = [];
  const briefChunks: string[] = [];
  let fullUsed = 0;

  for (const h of ranked) {
    if (seen.size >= cfg.finalRecallCount) break;
    if (seen.has(h.leafId)) continue;

    const isFull = h.rerankScore >= cfg.rerankThreshold && fullUsed < cfg.fullTextCount;
    if (isFull) {
      // хЕицЦЗцбгф╝ШхЕИхПС mesFull(хОЯцЦЗ,ш┐З cleanBody ц╕Ец┤ЧхРОх╖▓хРлхЖЕх╡Мш╡╖цнвцЧ╢щЧ┤),цЧахИЩщАА document
      const cleanFull = h.mesFull ? cleanBody(h.mesFull).trim() : '';
      const useMesFull = !!cleanFull;
      const body = cleanFull || (h.document || '').trim();
      if (!body) continue;
      seen.add(h.leafId);
      tiers.set(h.leafId, 'full');
      fullUsed++;
      // mesFull шЗкх╕ж (ш╡╖хзЛцЧ╢щЧ┤тАж)/(ч╗УцЭЯцЧ╢щЧ┤тАж),ф╕НхЖНхКа уАРуАСхд┤щБ┐хЕНцЧ╢щЧ┤щЗНхдН;щААхИ░ document цЧ╢цЙНшбехд┤
      fullChunks.push(fmtChunk(h, body, useMesFull, selfScope, now));
    } else if (h.similarity >= cfg.embeddingThreshold) {
      const body = (h.document || '').trim();
      if (!body) continue;
      seen.add(h.leafId);
      tiers.set(h.leafId, 'brief');
      briefChunks.push(fmtChunk(h, body, false, selfScope, now)); // цСШшжБцбгцЧахЖЕх╡МцЧ╢щЧ┤,шбе уАР(чЫ╕хп╣) хМ║щЧ┤уАСхд┤
    }
    // ф╕дцбгщГ╜ф╕Нш╛╛цаЗ:ф╕вх╝Г
  }

  const chunks = [...fullChunks, ...briefChunks];
  if (!chunks.length) return { text: '', tiers };
  // щжЦх░╛чзБхпЖчоАцКецбЖхоЪ,щБ┐хЕНф╕╗цибхЮЛцККхПмхЫЮхЫЮх┐Жх╜УцИРшжБхдНш┐░/ш╛УхЗ║чЪДцибцЭ┐
  return { text: `${MEMORY_BRIEFING_NOTE}\n[чЫ╕хЕ│хЫЮх┐Ж]\n${chunks.join('\n\n')}\n${MEMORY_BRIEFING_END}`, tiers };
}

/**
 * цККч┤вх╝ХцЧ╢хнШчЪДуАМцЬкхОЛч╝йш╡╖цнвцо╡уАНца╝х╝ПхМЦцИРх▒Хчд║чФицЧ╢щЧ┤хд┤:уАР(чЫ╕хп╣) ш╡╖ - цнвуАСуАВ
 *  - хОЛч╝йцИРхМ║щЧ┤цШ╛чд║(compactTimeLabel:хИач╗УцЭЯчлпщЗНхдНцЧецЬЯ);
 *  - чФич╗УцЭЯцЧ╢щЧ┤чЫ╕хп╣уАМчО░хЬиуАН(цХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤ now)чоЧчЫ╕хп╣хЙНч╝А(хп╣щ╜РхОЖхП▓цСШшжБчЪД inject.ts)уАВ
 * цЧацЧ╢щЧ┤ тЖТ чй║ф╕▓уАВ
 */
function fmtStoryTimeHead(storyTime: string, now: string): string {
  const t = storyTime.trim();
  if (!t) return '';
  const shown = compactTimeLabel(t);
  const end = splitTimeLabel(t).end ?? '';
  const rel = relativeTimeLabel(end, now);
  return rel ? `уАР(${rel}) ${shown}уАС` : `уАР${shown}уАС`;
}

/**
 * хНХцЭбхПмхЫЮчЙЗцо╡:шбМщжЦхКацЭец║РцаЗшо░(цЬмшБКхдйуАМ#5уАН/ цЧзцбг),шойф╕╗цибхЮЛчЯещБУш┐Щцо╡хЫЮх┐ЖхЗ║хдД;
 * body цЬкшЗкх╕жхЖЕх╡МцЧ╢щЧ┤цЧ╢хЖНшбеф╕Аф╕кцХЕф║ЛцЧ╢щЧ┤хд┤уАР(чЫ╕хп╣) ш╡╖ - цнвуАС(шЛецЬЙ)уАВ
 */
function fmtChunk(h: RankedHit, body: string, bodyHasInlineTime: boolean, selfScope: string | null, now: string): string {
  const src = `[${sourceLabel(h, selfScope)}]`;
  if (bodyHasInlineTime) return `${src} ${body}`;
  const head = fmtStoryTimeHead(h.storyTime || '', now);
  return head ? `${src}${head}${body}` : `${src} ${body}`;
}
