import { getContext, type STMessage } from '@/st/context';
import { reactive } from 'vue';
import { deriveMemory, getLeaf, leafValid } from './apply';
import { isAiFloor, pendingAiFloors } from './engine';
import { latestStoryTime } from './timeTag';
import type { BaibaiMemory, LeafExtra, MemSummary, StoredDelta } from './types';
import { createEmptyMemory, MEMORY_KEY, MEMORY_VERSION } from './types';

/**
 * хУНх║Фх╝Пшо░х┐ЖщХЬхГПуАВ
 * чЬЯц║Р:тСа хОЛч╝йшКВчВ╣цгоцЮЧ = chat_metadata[MEMORY_KEY].summaries;тСб хП╢хнР = chat хРДц╢ИцБп extra.bbs_leafуАВ
 * state / items / plans цШпф╗О chat щЗНцФ╛хЗ║чЪДц┤╛чФЯч╝УхнШ,ф╛Ы Vue ц╕▓цЯУуАВ
 */
export const memory = reactive<BaibaiMemory>(createEmptyMemory());

/**
 * ч╗Щщб╡щЭвшп╗чЪДц┤╛чФЯхЕГф┐бцБп(chat щЭЮ reactive,UI х┐Ещб╗ч╗Пцнд reactive щАЪщБУ):
 *  - hasLeaf:цШпхРжцЬЙф╗╗ф╕АцЬЙцХИхП╢хнР(цЧахИЩчжБчФицЙЛхКиц╖╗хКа)уАВ
 *  - leaves:ф╛Ы summary щб╡х▒Хчд║чЪДхП╢хнРхИЧшби(хРлщЩИцЧзцаЗшо░)уАВ
 */
export interface LeafView {
  id: string;
  text: string;
  timeStart?: string;
  timeEnd?: string;
  timeLabel?: string; // цЧзцХ░цНохЫЮщАА
  createdAt: number;
  msgIndex: number;
  active: boolean; // цЙАхЬиц╢ИцБпх╖▓щЪРшЧП(is_system)
  stale: boolean; // цнгцЦЗх╖▓хПШуАБх░ЪцЬкщЗНцСШ
}
export const derivedMeta = reactive<{ hasLeaf: boolean; leaves: LeafView[]; pendingFloors: number[]; latestStoryTime: string }>({
  hasLeaf: false,
  leaves: [],
  pendingFloors: [],
  // цХЕф║ЛхЖЕцЬАцЦ░цЧ╢щЧ┤:ф╗ОцнгцЦЗцаЗчн╛хоЮцЧ╢шп╗(ф╕Нф╛Эш╡ЦцШпхРжх╖▓цСШ),ф╛ЫцСШшжБщб╡х▒Хчд║ф╕ОчЫ╕хп╣цЧ╢щЧ┤хПВчЕз
  latestStoryTime: '',
});

/** щЗНцФ╛ chat х╛ЧхИ░ state/items/plans,хОЯхЬ░хЖЩхЫЮ;х╣╢хИ╖цЦ░ derivedMeta */
export function recomputeDerived(): void {
  const ctx = getContext();
  // цмвш┐Ощб╡(цЬкш┐ЫхЕеф╗╗ф╜ХшБКхдй)getCurrentChatId ф╕║чй║,ф╜Ж chat щЗМхПпшГ╜цоЛчХЩф╕КцмбчЪД #0,
  // ф╕Нх▒Юф║Оф╗╗ф╜ХшБКхдйчЪДце╝х▒Вф╕НшпешвлхИдф╕║уАМцЬкцСШшжБуАН,цХЕцндцЧ╢шзЖф╜ЬцЧа chatуАВ
  const chat = ctx?.getCurrentChatId?.() ? ctx.chat ?? null : null;
  const d = deriveMemory(chat);
  memory.state.time = d.state.time;
  memory.state.location = d.state.location;
  memory.state.locationPath = d.state.locationPath;
  memory.items.splice(0, memory.items.length, ...d.items);
  memory.plans.splice(0, memory.plans.length, ...d.plans);
  memory.scenes.splice(0, memory.scenes.length, ...d.scenes);
  memory.npcs.splice(0, memory.npcs.length, ...d.npcs);
  memory.itemLog.splice(0, memory.itemLog.length, ...d.itemLog);

  // derivedMeta:цЙл chat цФ╢щЫЖхП╢хнР(хРлщЩИцЧз)
  const leaves: LeafView[] = [];
  if (chat) {
    for (let i = 0; i < chat.length; i++) {
      const m = chat[i];
      const leaf = getLeaf(m);
      if (!leaf) continue;
      const valid = leafValid(m);
      leaves.push({
        id: leaf.id,
        text: leaf.text,
        timeStart: leaf.timeStart,
        timeEnd: leaf.timeEnd,
        timeLabel: leaf.timeLabel,
        createdAt: leaf.createdAt,
        msgIndex: i,
        active: m.is_system === true,
        stale: !valid,
      });
    }
  }
  derivedMeta.leaves = leaves;
  derivedMeta.hasLeaf = leaves.some(l => !l.stale);
  derivedMeta.latestStoryTime = latestStoryTime(chat);
  // х╛ЕцСШшжБце╝х▒В(AI це╝ф╕ФцЧацЬЙцХИхП╢хнР),ф╛ЫцСШшжБщб╡уАМцЬкцСШшжБце╝х▒ВуАНхИЧшбищАРце╝шбецСШ
  derivedMeta.pendingFloors = chat ? pendingAiFloors(chat) : [];
}

/* ============ шР╜чЫШ:хП╢хнРхЬи chat цЦЗф╗╢,цгоцЮЧхЬи metadata ============ */

let flushTimer: ReturnType<typeof setTimeout> | null = null;

/** щШ▓цКЦшР╜чЫШхП╢хнР(хЖЩш┐Ы chat цЦЗф╗╢)уАВхРИх╣╢ш┐Юч╗нхдЪце╝цСШшжБф╕║ф╕Ацмб saveChatуАВ */
export function scheduleLeafFlush(): void {
  const ctx = getContext();
  if (!ctx?.saveChat) return;
  if (flushTimer) clearTimeout(flushTimer);
  flushTimer = setTimeout(() => {
    flushTimer = null;
    void ctx.saveChat();
  }, 1500);
}

/** члЛхН│шР╜чЫШ(хИЗшБКхдй/хН╕ш╜╜хЙНш░ГчФи,щБ┐хЕНф╕вцЬкшР╜чЫШхП╢хнР) */
export function flushLeavesNow(): void {
  if (flushTimer) {
    clearTimeout(flushTimer);
    flushTimer = null;
  }
  const ctx = getContext();
  void ctx?.saveChat?.();
}

/** цККцгоцЮЧ(хОЛч╝йшКВчВ╣)хЖЩхЫЮ chat_metadata х╣╢цМБф╣ЕхМЦуАВхП╢хнРф╕НхЬиш┐ЩщЗМуАВ */
export function saveMemory() {
  const ctx = getContext();
  if (!ctx?.chatMetadata) return;
  const snapshot: { version: number; summaries: MemSummary[] } = {
    version: MEMORY_VERSION,
    summaries: JSON.parse(JSON.stringify(memory.summaries)),
  };
  (ctx.chatMetadata as Record<string, unknown>)[MEMORY_KEY] = snapshot;
  ctx.saveMetadataDebounced?.();
}

/* ============ ш┐Бчз╗ v2 тЖТ v3 ============ */

/**
 * v2(хП╢хнРхЬицгоцЮЧуАБх╕ж coveredIndices+delta)тЖТ v3(хП╢хнРцРмхИ░ц╢ИцБп extra)уАВ
 * щЬА chat ф╕Кф╕ЛцЦЗ;цЧа chat цЧ╢ш┐ФхЫЮ null(х╗╢хРО,ф╕Лцмб CHAT_CHANGED щЗНш╖С)уАВ
 * цРмф╕НхКичЪДхП╢хнР(ч┤вх╝Хш╢КчХМ/ц╢ИцБпх╖▓хИа)хЕ╢ delta хРИх╣╢ш┐Ыф╕АцЭбхЕЬх║ХхП╢хнРцМВхИ░цЬАхРО AI це╝,ф┐Эч╗УцЮДхМЦ 1:1уАВ
 */
function migrateV2toV3(raw: Record<string, unknown>, chat: STMessage[] | null): BaibaiMemory | null {
  if (!chat || chat.length === 0) return null; // х╗╢хРО

  const out = createEmptyMemory();
  out.version = MEMORY_VERSION;
  const oldSums = (Array.isArray(raw.summaries) ? raw.summaries : []) as Array<Record<string, unknown>>;

  const orphanDeltas: StoredDelta[] = [];

  // 1) цЧзхП╢хнР(level0)тЖТ цРмхИ░хп╣х║Ф AI це╝чЪД extra(ф┐ЭчХЩхОЯ id)
  for (const s of oldSums) {
    if ((typeof s.level === 'number' ? s.level : 0) !== 0) continue;
    const cov = (Array.isArray(s.coveredIndices) ? s.coveredIndices : []) as number[];
    const delta = (s.delta ?? {}) as StoredDelta;

    // хоЪф╜НцМВщЭачЪД AI це╝:coveredIndices щЗМцЬАхРОф╕Аф╕к isAiFloor;щААшАМц▒ВхЕ╢цмбхПЦцЬАхРОф╕Аф╕кхнШхЬичЪД
    let target = -1;
    for (let k = cov.length - 1; k >= 0; k--) {
      if (isAiFloor(chat[cov[k]])) {
        target = cov[k];
        break;
      }
    }
    if (target < 0) {
      for (let k = cov.length - 1; k >= 0; k--) {
        if (chat[cov[k]]) {
          target = cov[k];
          break;
        }
      }
    }
    if (target < 0 || !chat[target] || chat[target].extra?.bbs_leaf) {
      orphanDeltas.push(delta); // цРмф╕НхКи/чЫоцаЗх╖▓хНачФи тЖТ хЕЬх║Х
      continue;
    }
    const leaf: LeafExtra = {
      id: String(s.id),
      text: String(s.text ?? ''),
      delta,
      timeLabel: s.timeLabel as string | undefined,
      createdAt: typeof s.createdAt === 'number' ? s.createdAt : Date.now(),
      v: 1,
    };
    chat[target].extra = { ...(chat[target].extra ?? {}), bbs_leaf: leaf };
  }

  // 1b) хЕЬх║ХхП╢хнР:цККцРмф╕НхКичЪД delta хРИх╣╢цМВхИ░цЬАхРОф╕АцЭб AI це╝
  if (orphanDeltas.length) {
    let last = -1;
    for (let i = chat.length - 1; i >= 0; i--) {
      if (isAiFloor(chat[i])) {
        last = i;
        break;
      }
    }
    if (last >= 0 && !chat[last].extra?.bbs_leaf) {
      const merged: StoredDelta = {};
      for (const d of orphanDeltas) mergeStoredDelta(merged, d);
      chat[last].extra = {
        ...(chat[last].extra ?? {}),
        bbs_leaf: {
          id: `leaf_migrate_${Date.now().toString(36)}`,
          text: '(ш┐Бчз╗:хОЖхП▓ч╗УцЮДхМЦчК╢цАБ)',
          delta: merged,
          createdAt: Date.now(),
          v: 1,
        },
      };
    }
  }

  // 2) хОЛч╝йшКВчВ╣(levelтЙе1)хОЯца╖ф┐ЭчХЩш┐ЫцгоцЮЧ
  for (const s of oldSums) {
    if ((typeof s.level === 'number' ? s.level : 0) < 1) continue;
    out.summaries.push({
      id: String(s.id),
      text: String(s.text ?? ''),
      level: s.level as number,
      createdAt: typeof s.createdAt === 'number' ? s.createdAt : Date.now(),
      auto: s.auto !== false,
      timeLabel: s.timeLabel as string | undefined,
      childIds: Array.isArray(s.childIds) ? (s.childIds as string[]) : [],
    });
  }
  return out;
}

/** ш┐Бчз╗ш╛ЕхКй:цКК delta b хРИх╣╢ш┐Ы a(чФиф║ОхЕЬх║ХхП╢хнР,чоАхНХцЛ╝цОе add/op цХ░ч╗Д,resolve чФичи│хоЪ id) */
function mergeStoredDelta(a: StoredDelta, b: StoredDelta): void {
  if (b.time) a.time = b.time;
  if (b.location) a.location = b.location;
  if (b.items) {
    const ai = (a.items ??= {});
    if (b.items.add?.length) (ai.add ??= []).push(...b.items.add);
    if (b.items.update?.length) (ai.update ??= []).push(...b.items.update);
    if (b.items.remove?.length) (ai.remove ??= []).push(...b.items.remove);
  }
  if (b.scenes) {
    const as = (a.scenes ??= {});
    if (b.scenes.add?.length) (as.add ??= []).push(...b.scenes.add);
    if (b.scenes.update?.length) (as.update ??= []).push(...b.scenes.update);
    if (b.scenes.reparent?.length) (as.reparent ??= []).push(...b.scenes.reparent);
    if (b.scenes.remove?.length) (as.remove ??= []).push(...b.scenes.remove);
  }
  if (b.plans) {
    const ap = (a.plans ??= {});
    if (b.plans.add?.length) (ap.add ??= []).push(...b.plans.add);
    if (b.plans.resolve?.length) (ap.resolve ??= []).push(...b.plans.resolve);
    if (b.plans.remove?.length) (ap.remove ??= []).push(...b.plans.remove);
    if (b.plans.reopen?.length) (ap.reopen ??= []).push(...b.plans.reopen);
  }
}

/* ============ ш╜╜хЕе / ф┐ЭхнШ ============ */

function assignForest(target: BaibaiMemory, summaries: MemSummary[]) {
  target.version = MEMORY_VERSION;
  target.summaries = summaries;
}

/** ф╗Ох╜УхЙНшБКхдйш╜╜хЕецгоцЮЧ + щЗНчоЧц┤╛чФЯ(х┐ЕшжБцЧ╢ш┐Бчз╗) */
export function loadMemory() {
  const ctx = getContext();
  const meta = ctx?.chatMetadata as Record<string, unknown> | undefined;
  const raw = meta?.[MEMORY_KEY] as Record<string, unknown> | undefined;
  const chat = ctx?.chat ?? null;

  if (raw && typeof raw === 'object') {
    const version = typeof raw.version === 'number' ? raw.version : 1;
    if (version >= MEMORY_VERSION) {
      assignForest(memory, (Array.isArray(raw.summaries) ? raw.summaries : []) as MemSummary[]);
    } else {
      const migrated = migrateV2toV3(raw, chat);
      if (migrated) {
        assignForest(memory, migrated.summaries);
        // хЕИцККхП╢хнРшР╜чЫШ(saveChat)цИРхКЯ,хЖНхНЗ version хЖЩ metadata,ф┐ЭшпБхПпщЗНхЕе
        flushLeavesNow();
        saveMemory();
      } else {
        // х╗╢хРОш┐Бчз╗:цЪВчФицЧзцгоцЮЧщЗМчЪДхОЛч╝йшКВчВ╣(levelтЙе1),хП╢хнРчнЙф╕Лцмб chat х░▒ч╗кхЖНцРм
        const comps = (Array.isArray(raw.summaries) ? raw.summaries : []).filter(
          (s: Record<string, unknown>) => (typeof s.level === 'number' ? s.level : 0) >= 1,
        ) as MemSummary[];
        assignForest(memory, comps);
      }
    }
  } else {
    assignForest(memory, []);
  }
  recomputeDerived();
}

/** чЫСхРмшБКхдйхИЗцНв:хИЗш╡░хЙН flush цЬкшР╜чЫШхП╢хнР,хИЗцЭехРОщЗНш╜╜ */
export function bindChatLifecycle() {
  const ctx = getContext();
  if (!ctx?.eventSource || !ctx?.eventTypes) return;
  ctx.eventSource.on(ctx.eventTypes.CHAT_CHANGED, () => {
    flushLeavesNow();
    loadMemory();
  });
  // щжЦцмбш╜╜хЕе
  loadMemory();
}
