/**
 * цгАц╡ЛцЫ┤цЦ░:хп╣цпФуАМцЬмхЬ░ manifest.json чЪД versionуАНф╕ОуАМш┐Ьчлп GitHub ф╗Ух║У manifest.json чЪД versionуАН,
 * цЬЙцЦ░чЙИцЬмхИЩхЬишо╛ч╜о tab ф║ошзТцаЗ + шо╛ч╜ощб╡ч╗ЩуАМчлЛхН│цЫ┤цЦ░уАНхЕехПг,чбошодхРОш╡░ ST цЙйх▒ХцЫ┤цЦ░ API шЗкхКицЫ┤цЦ░х╣╢хИ╖цЦ░уАВ
 *
 * тЪая╕П хИ╗цДПф╕НцМБф╣ЕхМЦуАМцЬЙцЫ┤цЦ░уАНч╗УцЮЬ(ф╕НхЖЩ localStorage):
 *   цЧзхБЪц│ХцКК updateAvailable ч╝УхнШш┐Ы localStorage,хПкцЬЙчВ╣цЫ┤цЦ░цМЙщТоцЙНц╕ЕтАФтАФч╗УцЮЬцШпцЫ┤цЦ░хоМф╗НцПРчд║цЬЙцЫ┤цЦ░,
 *   х┐Ещб╗цЙЛчВ╣ф╕АцмбцЙНц╢ИуАВш┐ЩщЗМцФ╣ф╕║цпПцмбщГ╜хоЮцЧ╢цпФхп╣ф╕дф╗╜ manifest чЪД version:цЬмхЬ░шгЕф╕КцЦ░чЙИхРО version шЗкчД╢хПШхдз,
 *   ф╕ЛцмбцпФхп╣хН│ф╕НхЖНцПРчд║уАВхПкчФихЖЕхнШцаЗшо░ checkedThisSession щШ▓ф╕Ацмбф╝ЪшпЭхЖЕщЗНхдНшп╖ц▒В,щб╡щЭвф╕АхИ╖цЦ░х░▒щЗНцЯеуАВ
 */

import { reactive } from 'vue';
import { getContext } from '@/st/context';

/**
 * цЬмхЬ░чЙИцЬмхП╖:чЫ┤цОехЖЩцн╗хЬиф╗гчаБщЗМ(хПСчЙИцЧ╢ф╕О manifest.json чЪД version ф╕Ах╣╢цФ╣)уАВ
 * цпФ fetch цЬмхЬ░ manifest чЬБф╕Ацмбшп╖ц▒ВуАБцЧаш╖пх╛Д/ч╝УхнШхЭС;цЫ┤цЦ░шгЕф╕КцЦ░чЙИхРОш┐Щф╕▓шЗкчД╢хПШхдз,ф╕ЛцмбцпФхп╣хН│ф╕НхЖНцПРчд║уАВ
 */
const CURRENT_VERSION = '0.6';

/** ш┐Ьчлп manifest:GitHub raw(х╕жцЧ╢щЧ┤цИ│ч╗Хч╝УхнШ)уАВhomePage цМЗхРС baibai-git/ST-BaiBai-BookуАВ */
const REMOTE_MANIFEST_URL = 'https://raw.githubusercontent.com/baibai-git/ST-BaiBai-Book/main/manifest.json';

/** хп╣хдЦхУНх║Фх╝ПчК╢цАБ:щй▒хКишо╛ч╜о tab шзТцаЗф╕Ошо╛ч╜ощб╡чЙИцЬмхМ║хЭЧуАВ */
export const updateState = reactive<{
  current: string; // цЬмхЬ░чЙИцЬм(ф╗гчаБхЖЕх╕╕щЗП)
  latest: string; // ш┐ЬчлпчЙИцЬм(чй║=цЬкцЯехИ░/шп╖ц▒Вхд▒ш┤е)
  available: boolean; // ш┐Ьчлп > цЬмхЬ░
  checking: boolean;
  updating: boolean;
}>({
  current: CURRENT_VERSION,
  latest: '',
  available: false,
  checking: false,
  updating: false,
});

// ф╕Ацмбф╝ЪшпЭхЖЕхПкф╕╗хКицЯеф╕Ацмб(хИ╖цЦ░щб╡щЭвхН│щЗНч╜о тЖТ щЗНцЯе),щБ┐хЕНщЗНхдНцЙУ GitHubуАВ
let checkedThisSession = false;

/** шзгцЮРуАМa цШпхРжцпФ b цЦ░уАН:цМЙ . хИЖцо╡цпФш╛ГцХ░хнЧ,ч╝║цо╡шбе 0(хжВ 0.0.1 vs 0.1)уАВщЭЮцХ░хнЧцо╡цМЙ 0 хдДчРЖуАВ */
function isNewer(a: string, b: string): boolean {
  if (!a || !b) return false;
  const pa = a.split('.').map(n => Number.parseInt(n, 10) || 0);
  const pb = b.split('.').map(n => Number.parseInt(n, 10) || 0);
  const len = Math.max(pa.length, pb.length);
  for (let i = 0; i < len; i++) {
    const x = pa[i] ?? 0;
    const y = pb[i] ?? 0;
    if (x > y) return true;
    if (x < y) return false;
  }
  return false;
}

/** шп╗ш┐Ьчлп manifest.json чЪД versionуАВшп╖ц▒Вхд▒ш┤е/ш╢ЕцЧ╢ш┐ФхЫЮчй║ф╕▓(щЭЩщ╗Ш,ф╕НцЙУцЙ░чФицИ╖)уАВ */
async function readRemoteVersion(): Promise<string> {
  try {
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 8000);
    try {
      const resp = await fetch(`${REMOTE_MANIFEST_URL}?t=${Date.now()}`, {
        method: 'GET',
        cache: 'no-store',
        signal: ctrl.signal,
      });
      if (!resp.ok) return '';
      const json = (await resp.json()) as { version?: string };
      return String(json?.version ?? '').trim();
    } finally {
      clearTimeout(timer);
    }
  } catch {
    return '';
  }
}

/**
 * цгАц╡ЛцЫ┤цЦ░:хоЮцЧ╢цпФхп╣цЬмхЬ░ф╕Ош┐Ьчлп manifest чЙИцЬм,хИ╖цЦ░ updateStateуАВ
 * ф╕Ацмбф╝ЪшпЭхПкф╕╗хКицЯеф╕Ацмб;force=true ш╖│ш┐ЗшпещЩРхИ╢(ф╛ЫуАМщЗНцЦ░цгАцЯеуАНцЙЛхКишзжхПС)уАВ
 */
export async function checkForUpdate(force = false): Promise<void> {
  if (updateState.checking) return;
  if (checkedThisSession && !force) return;
  updateState.checking = true;
  try {
    const latest = await readRemoteVersion();
    if (latest) {
      updateState.latest = latest;
      updateState.available = isNewer(latest, CURRENT_VERSION);
    }
    // ш┐ЬчлпцЛ┐ф╕НхИ░хИЩф┐ЭцМБф╕Кцмбч╗Ушо║(ф╕НшппцКеуАБф╕Ншппц╕Е)уАВ
    checkedThisSession = true;
  } finally {
    updateState.checking = false;
  }
}

/** цЬмцЙйх▒ХцЦЗф╗╢хд╣хРН(third-party ф╕ЛчЪДчЫох╜ХхРН)уАВцНоцибхЭЧ URL шзгцЮР,хПЦф╕НхИ░хЫЮщААх╖▓чЯехРНуАВ */
function extensionFolderName(): string {
  try {
    const path = new URL(import.meta.url).pathname;
    const marker = '/third-party/';
    const idx = path.indexOf(marker);
    if (idx >= 0) {
      const rest = path.slice(idx + marker.length);
      const folder = rest.split('/')[0];
      if (folder) return folder;
    }
  } catch {
    /* шзгцЮРхд▒ш┤ехЫЮщАА */
  }
  return 'ST-BaiBai-Book';
}

/** цОвц╡ЛцЬмцЙйх▒ХхоЙшгЕч▒╗хЮЛ(global/local/system),хЖ│хоЪцЫ┤цЦ░ API чЪД global хПВцХ░уАВхПЦф╕НхИ░х╜У localуАВ */
async function discoverExtensionType(folder: string): Promise<'global' | 'local' | 'system' | null> {
  try {
    const headers = getContext()?.getRequestHeaders?.() ?? {};
    const resp = await fetch('/api/extensions/discover', { method: 'GET', headers, cache: 'no-store' });
    if (!resp.ok) return null;
    const list = (await resp.json()) as Array<{ name?: string; type?: string }>;
    if (!Array.isArray(list)) return null;
    const target = `third-party/${folder}`;
    const hit = list.find(x => x?.name === target);
    const type = hit?.type;
    return type === 'global' || type === 'local' || type === 'system' ? type : null;
  } catch {
    return null;
  }
}

/**
 * цЙзшбМцЫ┤цЦ░:ш░Г ST чЪД /api/extensions/update цЛЙхПЦцЬАцЦ░ф╗гчаБ,цИРхКЯхРОхИ╖цЦ░щб╡щЭвчФЯцХИуАВ
 * хд▒ш┤ецКЫщФЩ(чФ▒ш░ГчФицЦ╣цПРчд║)уАВхЕих▒АцЙйх▒ХщЬАчобчРЖхСШцЭГщЩР,хРОчлпф╝ЪшЗкшбМцабщкМх╣╢ш┐ФхЫЮщФЩшппцЦЗцбИуАВ
 */
export async function performUpdate(): Promise<void> {
  if (updateState.updating) return;
  updateState.updating = true;
  try {
    const folder = extensionFolderName();
    const type = await discoverExtensionType(folder);
    const headers = getContext()?.getRequestHeaders?.() ?? { 'Content-Type': 'application/json' };
    const resp = await fetch('/api/extensions/update', {
      method: 'POST',
      headers,
      body: JSON.stringify({ extensionName: folder, global: type === 'global' }),
    });
    if (!resp.ok) {
      const text = await resp.text().catch(() => '');
      throw new Error(text || resp.statusText || `HTTP ${resp.status}`);
    }
    // цЫ┤цЦ░цИРхКЯ:цЬмхЬ░ф╗гчаБх╖▓цНвцЦ░чЙИ,хИ╖цЦ░щб╡щЭвхКаш╜╜цЦ░ф║зчЙй(хИ╖цЦ░хРОцпФхп╣шЗкчД╢ф╕НхЖНцПРчд║)уАВ
    updateState.available = false;
    setTimeout(() => location.reload(), 800);
  } finally {
    updateState.updating = false;
  }
}
