<script setup lang="ts">
/**
 * щАЪчФичбошодх╝╣чкЧуАВцЫ┐ф╗гц╡ПшзИхЩихОЯчФЯ confirm()тАФтАФхОЯчФЯх╝╣чкЧхЬи Shadow DOM хдЦуАБца╖х╝Пф╕Нч╗Яф╕АуАВ
 * хПЧцОз:чФи v-model:open цОзхИ╢цШ╛щЪР;чВ╣чбохоЪ emit confirm,чВ╣хПЦц╢И/щБоч╜й/хЕ│щЧн emit cancelуАВ
 *
 * ф╕НчФи Teleport:хЖЕхо╣щб╗чХЩхЬи shadow root хЖЕцЙНшГ╜цЛ┐хИ░ scoped ца╖х╝Пф╕О --bbs-* хПШщЗП
 * (шзБ base.css щАЪчФих╝╣чкЧц│ищЗК)уАВхЯ║чбА .bbs-modal* ца╖х╝ПцШпхЕих▒АчЪД,ш┐ЩщЗМхПкшбечбошодх╝╣чкЧчЙ╣цЬЙчЪДуАВ
 */
import Icon from '@/components/Icon.vue';

withDefaults(
  defineProps<{
    open: boolean;
    title: string;
    /** чбохоЪцМЙщТоцЦЗцбИ */
    confirmText?: string;
    /** хПЦц╢ИцМЙщТоцЦЗцбИ */
    cancelText?: string;
    /** чбохоЪцМЙщТощгОца╝:primary=ф╕╗шЙ▓,danger=хН▒щЩй(ф╜Ош░ГцППш╛╣,hover цШ╛ч║в) */
    tone?: 'primary' | 'danger';
    /** чбохоЪцМЙщТохЙНчЪДхЫ╛цаЗхРН(хПпщАЙ,хжВ trash) */
    confirmIcon?: string;
    /** х┐ЩчвМф╕н:чжБчФичбохоЪцМЙщТох╣╢цШ╛чд║ busyText(ф╛ЫуАМцЫ┤цЦ░ф╕нтАжуАНш┐Щч▒╗щЬАф┐ЭцМБх╝╣чкЧчЪДх╝ВцнецУНф╜Ь) */
    busy?: boolean;
    /** х┐ЩчвМцЧ╢чбохоЪцМЙщТоцЦЗцбИ */
    busyText?: string;
    /** хПахКахЬихЕ╢хоГх╝╣чкЧф╣Лф╕К(цЫ┤щлШ z-index),хжВц╕ащБУх╝╣чкЧщЗМхЖНх╝АхИащЩдчбошод */
    topLayer?: boolean;
  }>(),
  {
    confirmText: 'чбохоЪ',
    cancelText: 'хПЦц╢И',
    tone: 'primary',
    confirmIcon: '',
    busy: false,
    busyText: '',
    topLayer: false,
  },
);

const emit = defineEmits<{
  (e: 'update:open', v: boolean): void;
  (e: 'confirm'): void;
  (e: 'cancel'): void;
}>();

function cancel() {
  emit('update:open', false);
  emit('cancel');
}
function confirm() {
  emit('confirm');
}
</script>

<template>
  <div
    v-if="open"
    class="bbs-modal-mask"
    :class="{ 'bbs-modal-mask-top': topLayer }"
    @click.self="cancel"
  >
    <div class="bbs-modal bbs-modal-confirm" role="dialog" aria-modal="true" :aria-label="title">
      <header class="bbs-modal-head">
        <span class="bbs-modal-title">{{ title }}</span>
      </header>
      <p class="bbs-confirm-text">
        <slot />
      </p>
      <footer class="bbs-modal-foot">
        <span class="bbs-modal-foot-spacer"></span>
        <button class="bbs-btn" type="button" @click="cancel">{{ cancelText }}</button>
        <button
          class="bbs-btn"
          :class="tone === 'danger' ? 'bbs-btn-danger' : 'bbs-btn-primary'"
          type="button"
          :disabled="busy"
          @click="confirm"
        >
          <Icon v-if="confirmIcon" :name="confirmIcon" />
          {{ busy && busyText ? busyText : confirmText }}
        </button>
      </footer>
    </div>
  </div>
</template>

