import { getContext } from '@/st/context';
import type { ApiChannel } from './settings';

/**
 * щАЪш┐З SillyTavern чЪДцЬНхКбчлпф╗гчРЖш░ГчФиф╗╗цДП OpenAI хЕ╝хо╣члпчВ╣уАВ
 *
 * хЕ│щФо:ф╗е chat_completion_source='openai' + reverse_proxy(base url)+ proxy_password(key)
 * ш╡░ /api/backends/chat-completions/generateуАВшп╖ц▒ВчФ▒ ST цЬНхКбчлпш╜мхПС,
 * хЫацндц▓бцЬЙц╡ПшзИхЩи CORS щЧощвШ,ф╣ЯцЧащЬАцККхпЖщТехнШш┐Ы ST чЪД secretsуАВ
 */

const GENERATE_URL = '/api/backends/chat-completions/generate';

export interface ChatMsg {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

export class ApiError extends Error {}

/** шзДшМГхМЦ base url:чбоф┐Эф╗е /v1 ч╗Ух░╛(хдЪцХ░ OpenAI хЕ╝хо╣цЬНхКбщЬАшжБ) */
function normalizeUrl(url: string): string {
  let u = url.trim().replace(/\/+$/, '');
  if (!u) return u;
  if (!/\/v\d+$/.test(u) && !/\/chat\/completions$/.test(u)) {
    u += '/v1';
  }
  // члпчВ╣цЬЯцЬЫ base(ф╕НхРл /chat/completions),хО╗цОЙхоГ
  u = u.replace(/\/chat\/completions$/, '');
  return u;
}

export interface RequestOptions {
  signal?: AbortSignal;
}

/**
 * хПСш╡╖ф╕АцмбшбехЕишп╖ц▒В,ш┐ФхЫЮцЦЗцЬмхЖЕхо╣уАВ
 */
export async function requestCompletion(
  channel: ApiChannel,
  messages: ChatMsg[],
  opts: RequestOptions = {},
): Promise<string> {
  const ctx = getContext();
  if (!ctx) throw new ApiError('SillyTavern ф╕Кф╕ЛцЦЗф╕НхПпчФи');
  if (!channel.url || !channel.model) throw new ApiError('хЙп API ц╕ащБУцЬкщЕНч╜охоМцХ┤(ч╝║ url цИЦ model)');

  const stream = channel.stream ?? false;
  // щвДхблхЕЕх╝АхЕ│(щ╗Шшодх╝А):хЕ│щЧнцЧ╢ф╕вцОЙцЬлх░╛щВгцЭб assistant щвДхблхЕЕц╢ИцБпуАВ
  // цСШшжБ/цЙ╣щЗПшп╖ц▒Вф╝ЪхЬицЬлх░╛ш┐╜хКаф╕АцЭб assistant щвДхблхЕЕх╝Ххп╝цАЭч╗┤щУ╛;хп╣ф╕НцФпцМБщвДхблхЕЕ(ф╕Нч╗нхЖЩ)чЪДчлпчВ╣
  // х╜вхРМц╡кш┤╣уАБф╕кхИлчлпчВ╣ш┐ШшжБц▒ВуАМцЬАхРОф╕АцЭбщб╗ф╕║ userуАНуАВхЕ│цОЙхПкцШпф╕НхПСхоГ,цАЭч╗┤щУ╛х╝Ххп╝ф╗НчФ▒ system ц╕ЕхНХцЙ┐цЛЕуАВ
  const outMessages =
    channel.prefill === false && messages[messages.length - 1]?.role === 'assistant'
      ? messages.slice(0, -1)
      : messages;
  const body: Record<string, unknown> = {
    chat_completion_source: 'openai',
    reverse_proxy: normalizeUrl(channel.url),
    proxy_password: channel.key || '',
    model: channel.model,
    messages: outMessages,
    temperature: channel.temperature ?? 1.0,
    max_tokens: channel.maxTokens ?? 8192,
    stream,
    // щЭЩщ╗Ш:ф╕Нх╜▒хУНф╕╗хп╣шпЭчК╢цАБ
    presence_penalty: 0,
    frequency_penalty: 0,
  };

  // цОТщЩдхПВцХ░:цККчФицИ╖цМЗхоЪчЪДхнЧцо╡ф╗О body хИацОЙ,шзДщБ┐ф╕НцОехПЧш┐Щф║ЫхПВцХ░чЪДхЕ╝хо╣члпчВ╣цКещФЩуАВ
  // ц│и:хЫ║хоЪш╖пчФ▒хнЧцо╡(chat_completion_source/reverse_proxy чнЙ)ф╕Нх║ФшвлхИа,ф╜ЖхЕихЗнчФицИ╖хблхЖЩ,
  // ш┐ЩщЗМхПкхБЪх┐ахоЮхЙФщЩдтАФтАФцЦЗцбИф╝ЪцПРчд║хблщЗЗца╖хПВцХ░хРН(temperature/max_tokens/...)уАВ
  for (const p of channel.excludeParams ?? []) {
    const key = p.trim();
    if (key) delete body[key];
  }

  const resp = await fetch(GENERATE_URL, {
    method: 'POST',
    headers: ctx.getRequestHeaders(),
    body: JSON.stringify(body),
    signal: opts.signal,
  });

  if (!resp.ok) {
    const text = await resp.text().catch(() => '');
    throw new ApiError(`хЙп API шп╖ц▒Вхд▒ш┤е (${resp.status}): ${text.slice(0, 300)}`);
  }

  // ц╡Бх╝П:цМЙ SSE хвЮщЗПцЛ╝цОе;щЭЮц╡Бх╝П:чЫ┤цОешзгцЮР JSONуАВ
  if (stream) {
    const content = await readSseContent(resp);
    if (!content) throw new ApiError('хЙп API ш┐ФхЫЮчй║хЖЕхо╣');
    return content;
  }

  const data = await resp.json();
  if (data?.error) {
    throw new ApiError(data.error.message || 'хЙп API ш┐ФхЫЮщФЩшпп');
  }

  const content = extractContent(data);
  if (!content) throw new ApiError('хЙп API ш┐ФхЫЮчй║хЖЕхо╣');
  return content;
}

/**
 * шп╗хПЦ SSE ц╡Б(text/event-stream),цЛ╝цОе delta.contentуАВ
 * ST чЪД generate члпчВ╣хЬи stream=true цЧ╢щАПф╝аф╕Кц╕╕ SSE:цпПшбМ `data: {json}`,ф╗е `data: [DONE]` ч╗УцЭЯуАВ
 */
async function readSseContent(resp: Response): Promise<string> {
  const reader = resp.body?.getReader();
  if (!reader) {
    // цЧац│Хц╡Бх╝Пшп╗хПЦ(чРЖшо║ф╕Кф╕Нф╝Ъ):щААхЫЮх╜Уф╜ЬцХ┤ф╜У JSON хдДчРЖ
    const data = await resp.json().catch(() => null);
    return data ? extractContent(data) : '';
  }
  const decoder = new TextDecoder();
  let buf = '';
  let out = '';
  for (;;) {
    const { done, value } = await reader.read();
    if (done) break;
    buf += decoder.decode(value, { stream: true });
    // цМЙшбМшзгцЮР,ф┐ЭчХЩцЬАхРОф╕Ацо╡ф╕НхоМцХ┤чЪДшбМхИ░ф╕Лцмб
    const lines = buf.split('\n');
    buf = lines.pop() ?? '';
    for (const line of lines) {
      const t = line.trim();
      if (!t || !t.startsWith('data:')) continue;
      const payload = t.slice(5).trim();
      if (payload === '[DONE]') continue;
      try {
        const json = JSON.parse(payload);
        if (json?.error) throw new ApiError(json.error.message || 'хЙп API ш┐ФхЫЮщФЩшпп');
        const delta = json?.choices?.[0]?.delta?.content ?? json?.choices?.[0]?.message?.content ?? json?.choices?.[0]?.text;
        if (typeof delta === 'string') out += delta;
      } catch (e) {
        if (e instanceof ApiError) throw e;
        // хНХшбМшзгцЮРхд▒ш┤ех┐╜чХе(хПпшГ╜цШпц│ищЗКшбМ/х┐Гш╖│)
      }
    }
  }
  return out.trim();
}

/** ф╗ОцаЗхЗЖ OpenAI хУНх║Фф╜УцПРхПЦцЦЗцЬм */
function extractContent(data: any): string {
  return (
    data?.choices?.[0]?.message?.content ??
    data?.choices?.[0]?.text ??
    data?.content ??
    ''
  ).trim();
}

/* ============ ш╖ЯщЪПф╕╗ API(ф╕╗чХМщЭвх╜УхЙНхЬичФичЪД API шо╛ч╜о) ============ */

/** цСШшжБ/цА╗ч╗Уш╖ЯщЪПф╕╗ API цЧ╢чЪДхУНх║Фф╕КщЩР:хдЯшгЕф╕ЛцАЭч╗┤щУ╛ + JSON,щБ┐хЕНшвлф╕╗ API щ╗Шшод max tokens цИкцЦнуАВ */
const MAIN_API_RESPONSE_LENGTH = 8192;

/**
 * цШпхРжхЕ╖хдЗуАМш╖ЯщЪПф╕╗ APIуАНчЪДцЭбф╗╢:ST цЪ┤щЬ▓ф║Ж generateRaw(чи│хоЪ API)хН│хПпуАВ
 * ф╕НхЖНф╛Эш╡Цш┐ЮцОечобчРЖ/ш┐ЮцОецбгтАФтАФчЫ┤цОехАЯчФиф╕╗чХМщЭвх╜УхЙНцнгхЬичФичЪД APIуАВ
 */
export function mainApiAvailable(): boolean {
  return typeof getContext()?.generateRaw === 'function';
}

/**
 * чФиуАМх╜УхЙНф╕╗ APIуАН(ф╕╗чХМщЭвцнгхЬичФичЪДшБКхдйшбехЕи/цЦЗцЬмшбехЕишо╛ч╜о)хПСф╕АцмбшбехЕиуАВ
 * ш╡░ ST чЪД generateRaw:хПкхПСцИСф╗мч╗ЩчЪДш┐ЩхЗацЭбц╢ИцБп,ф╕Нх╕жшБКхдйхОЖхП▓/шзТшЙ▓хНб;цЧащЬАш┐ЮцОецбгуАВ
 * quiet ч▒╗хЮЛхЖЕщГих╝║хИ╢щЭЮц╡Бх╝П,ш┐ФхЫЮц╕Ец┤ЧхРОчЪДцХ┤цо╡цЦЗцЬм;хд▒ш┤ецКЫ ApiErrorуАВ
 */
export async function requestViaMainApi(messages: ChatMsg[], _opts: RequestOptions = {}): Promise<string> {
  const ctx = getContext();
  if (typeof ctx?.generateRaw !== 'function') {
    throw new ApiError('х╜УхЙН ST чЙИцЬмф╕НцФпцМБ generateRaw,цЧац│Хш╖ЯщЪПф╕╗ API');
  }
  const content = (await ctx.generateRaw({ prompt: messages, responseLength: MAIN_API_RESPONSE_LENGTH }))?.trim();
  if (!content) throw new ApiError('ф╕╗ API ш┐ФхЫЮчй║хЖЕхо╣');
  return content;
}

/** ш┐ЮщАЪцАзц╡ЛшпХ:хПСф╕АцЭбцЮБчЯншп╖ц▒В */
export async function testChannel(channel: ApiChannel): Promise<{ ok: boolean; message: string }> {
  try {
    const reply = await requestCompletion(channel, [{ role: 'user', content: 'хЫЮхдН"ok"ф╕дф╕кхнЧчмжхН│хПпуАВ' }]);
    return { ok: true, message: `ш┐ЮщАЪцнгх╕╕,ш┐ФхЫЮ:${reply.slice(0, 40)}` };
  } catch (e) {
    return { ok: false, message: e instanceof Error ? e.message : String(e) };
  }
}

const STATUS_URL = '/api/backends/chat-completions/status';

/**
 * цЛЙхПЦц╕ащБУхПпчФичЪДцибхЮЛхИЧшби(ш╡░ ST чЪД /status ф╗гчРЖ,цаЗхЗЖ /v1/models)уАВ
 * хПкщЬА url + key,ф╕НщЬАшжБхЕИхбл modelуАВ
 */
export async function fetchModels(channel: Pick<ApiChannel, 'url' | 'key'>): Promise<string[]> {
  const ctx = getContext();
  if (!ctx) throw new ApiError('SillyTavern ф╕Кф╕ЛцЦЗф╕НхПпчФи');
  if (!channel.url) throw new ApiError('шп╖хЕИхблхЖЩ API хЬ░хЭА');

  const body = {
    chat_completion_source: 'openai',
    reverse_proxy: normalizeUrl(channel.url),
    proxy_password: channel.key || '',
  };

  const resp = await fetch(STATUS_URL, {
    method: 'POST',
    headers: ctx.getRequestHeaders(),
    body: JSON.stringify(body),
  });

  if (!resp.ok) {
    const text = await resp.text().catch(() => '');
    throw new ApiError(`цЛЙхПЦцибхЮЛхд▒ш┤е (${resp.status}): ${text.slice(0, 200)}`);
  }

  const data = await resp.json();
  if (data?.error && !Array.isArray(data?.data)) {
    throw new ApiError(data?.message || 'цЛЙхПЦцибхЮЛхд▒ш┤е');
  }

  const list: unknown = data?.data ?? data?.models ?? [];
  if (!Array.isArray(list)) return [];
  return list
    .map((m: any) => (typeof m === 'string' ? m : m?.id))
    .filter((x: unknown): x is string => typeof x === 'string' && x.length > 0)
    .sort();
}
