/**
 * щб╢х▒Вшо░х┐Жхп╣ш▒буАВ
 * **хПкцЬЙ version + summaries цШпчЬЯц║Рх╣╢цМБф╣ЕхМЦ**;state / items / plans цШпф╗О summaries
 * щЗНцФ╛чоЧхЗ║чЪДц┤╛чФЯч╝УхнШ(ф╛Ыщб╡щЭвхУНх║Фх╝Пшп╗хПЦ,saveMemory ф╕НхЖЩхоГф╗м)уАВ
 */
export interface BaibaiMemory {
  version: number;
  /** ц┤╛чФЯч╝УхнШ:щЗНцФ╛хП╢хнР delta х╛ЧхИ░ */
  state: MemState;
  /** ц┤╛чФЯч╝УхнШ */
  items: MemItem[];
  /** ц┤╛чФЯч╝УхнШ */
  plans: MemPlan[];
  /** ц┤╛чФЯч╝УхнШ:ш╡░ш┐ЗчЪДхЬ░чВ╣(хЬ░чРЖх╡МхеЧцаС,ф╗ОхП╢хнР delta щЗНцФ╛) */
  scenes: MemScene[];
  /** ц┤╛чФЯч╝УхнШ:чЩ╗хЬ║ш┐ЗчЪД NPC(ф╗ОхП╢хнР delta щЗНцФ╛) */
  npcs: MemNpc[];
  /** ц┤╛чФЯч╝УхнШ:ш┐СцЬЯчЙйхУБхПШхКицЧех┐Ч(щЗНцФ╛цЧ╢ф║зхЗ║,хПкчХЩцЬАш┐СшЛех╣▓цЭб) */
  itemLog: ItemLogEntry[];
  /** чЬЯц║Р:хП╢хнРцСШшжБцгоцЮЧ */
  summaries: MemSummary[];
}

export function createEmptyMemory(): BaibaiMemory {
  return {
    version: MEMORY_VERSION,
    state: { time: '', location: '' },
    items: [],
    plans: [],
    scenes: [],
    npcs: [],
    itemLog: [],
    summaries: [],
  };
}

