/* тАФтАФ ц╕ащБУ:хИЧшбихПкшп╗х▒Хчд║,ч╝Цш╛С/цЦ░х╗║щГ╜хЬих╝╣чкЧщЗМш┐ЫшбМ,щБ┐хЕНф╕АщХ┐хИЧшбих╣│щУ║шппшзжуАВ
   ф╕дхеЧчЛмчлЛц╕ащБУ:'api'=хЙп API(цСШшжБ/цА╗ч╗У),'vector'=хРСщЗПшо░х┐ЖуАВх╝╣чкЧцМЙ scope цУНф╜Ьхп╣х║ФхИЧшбиуАВ тАФтАФ */
type ChannelScope = 'api' | 'vector';
// editingId:цнгхЬич╝Цш╛СчЪДуАМх╖▓цЬЙц╕ащБУуАНid;цЦ░х╗║цЧ╢ф╕║ nullуАВф╗ЕчФиф║ОуАМхоМцИРуАНцЧ╢хоЪф╜НхЖЩхЫЮчЫоцаЗуАВ
const editingId = ref<string | null>(null);
const editingScope = ref<ChannelScope>('api');
// х╜УхЙН scope хп╣х║ФчЪДц╕ащБУцХ░ч╗Д(хвЮхИа/цЯецЙ╛щГ╜ш╡░хоГ)уАВхРСщЗПх╖▓цФ╣цЙБх╣│члпчВ╣,хПкхЙйхЙп API чФиц╕ащБУуАВ
function channelsOf(_scope: ChannelScope): ApiChannel[] {
  return apiSettings.channels;
}
// ч╝Цш╛СчФиуАМшНЙчи┐хЙпцЬмуАН:v-model хЕицФ╣хЬишНЙчи┐ф╕К,хПкцЬЙчВ╣уАМхоМцИРуАНцЙНхЖЩхЫЮ apiSettings(щБ┐хЕНцпПцХ▓ф╕АхнЧх░▒шзжхПСхнШчЫШ)уАВ
// х╝╣чкЧх╝АхЕ│ф╣Яф╗ехоГф╕║хЗЖ:шНЙчи┐хнШхЬи = х╝╣чкЧцЙУх╝АуАВ
const editingChannel = ref<ApiChannel | null>(null);
// ц╖▒цЛ╖ш┤Эц╕ащБУ(ч║пцХ░цНо,JSON хН│хПп),хИЗцЦнф╕О apiSettings чЬЯш║лчЪДх╝ХчФи
function cloneChannel(ch: ApiChannel): ApiChannel {
  return JSON.parse(JSON.stringify(ch)) as ApiChannel;
}
// хпЖщТещ╗ШшодщЪРшЧП;цпПцмбцЙУх╝А/хЕ│щЧнх╝╣чкЧщГ╜хдНф╜Н,щБ┐хЕНхпЖщТецДПхдЦф┐ЭцМБцШОцЦЗ
const showKey = ref(false);

// цОТщЩдхПВцХ░:хЖЕщГихнШ string[],ч╝Цш╛СцЧ╢чФищАЧхП╖хИЖщЪФчЪДхНХшбМцЦЗцЬмцЙ┐ш╜╜,шп╗/хЖЩф╕дхРСш╜мцНвуАВ
const excludeParamsText = computed<string>({
  get: () => editingChannel.value?.excludeParams.join(', ') ?? '',
  set: v => {
    const ch = editingChannel.value;
    if (!ch) return;
    ch.excludeParams = v
      .split(',')
      .map(s => s.trim())
      .filter(Boolean);
  },
});

function addChannel(scope: ChannelScope = 'api') {
  showKey.value = false;
  editingScope.value = scope;
  editingId.value = null; // null = цЦ░х╗║,хоМцИРцЧ╢ push
  editingChannel.value = newChannel(); // шНЙчи┐,х░ЪцЬкш┐Ы apiSettings
}
function openChannel(id: string, scope: ChannelScope = 'api') {
  const src = channelsOf(scope).find(c => c.id === id);
  if (!src) return;
  showKey.value = false;
  editingScope.value = scope;
  editingId.value = id;
  editingChannel.value = cloneChannel(src); // ч╝Цш╛СшНЙчи┐хЙпцЬм,ф╕НхКичЬЯш║л
}
/** хПЦц╢И(├Ч / чВ╣щБоч╜й):ф╕вх╝ГшНЙчи┐,ф╕НхЖЩхЫЮ apiSettings(цЧашо║цЦ░х╗║ш┐ШцШпч╝Цш╛С,цФ╣хКищГ╜ф╜Ьх║Я)уАВ */
function closeChannel() {
  showKey.value = false;
  editingId.value = null;
  editingChannel.value = null;
}
/** хоМцИР:цККшНЙчи┐хЖЩхЫЮ apiSettings тАФтАФ цЦ░х╗║хИЩ push,ч╝Цш╛СхИЩцМЙ id шжЖчЫЦуАВцндцЧ╢цЙНшзжхПСхнШчЫШуАВ */
function confirmChannel() {
  const draft = editingChannel.value;
  if (draft) {
    const list = channelsOf(editingScope.value);
    if (editingId.value) {
      const idx = list.findIndex(c => c.id === editingId.value);
      if (idx >= 0) list[idx] = draft;
      else list.push(draft); // ч╝Цш╛СцЬЯщЧ┤хОЯц╕ащБУшвлхИачнЙх╝Вх╕╕ тЖТ хЕЬх║Хф╕║цЦ░хвЮ
    } else {
      list.push(draft);
    }
  }
  showKey.value = false;
  editingId.value = null;
  editingChannel.value = null;
}
// хИащЩдц╕ащБУхЙНчЪДф║Мцмбчбошод:чВ╣хИащЩдхЕИх╝Ачбошодх╝╣чкЧ,чбошодхРОцЙНчЬЯцнгхИауАВ
const confirmDeleteOpen = ref(false);
function askRemoveChannel() {
  confirmDeleteOpen.value = true;
}
function confirmRemoveChannel() {
  confirmDeleteOpen.value = false;
  // хИащЩдщТИхп╣уАМх╖▓цЬЙц╕ащБУуАН(editingId);цЦ░х╗║шНЙчи┐х░ЪцЬкхЕех║У,чнЙхРМчЫ┤цОеф╕вх╝ГшНЙчи┐
  if (editingId.value) removeChannel(editingId.value);
  editingId.value = null;
  editingChannel.value = null;
}
function removeChannel(id: string) {
  const scope = editingScope.value;
  const list = channelsOf(scope);
  const idx = list.findIndex(c => c.id === id);
  if (idx >= 0) list.splice(idx, 1);
  // ц╕ЕчРЖцМЗц┤╛:хЙп API ц╕Еф╕дч▒╗цСШшжБцМЗц┤╛(хРСщЗПх╖▓цФ╣цЙБх╣│члпчВ╣,ф╕НхЖНш╡░ц╕ащБУч│╗ч╗Я)
  if (scope === 'api') {
    if (apiSettings.assignments.summary === id) apiSettings.assignments.summary = '';
    if (apiSettings.assignments.resummary === id) apiSettings.assignments.resummary = '';
  }
}

const testing = ref<Record<string, string>>({});
async function doTest(ch: ApiChannel) {
  testing.value[ch.id] = 'ц╡ЛшпХф╕нтАж';
  const r = await testChannel(ch);
  testing.value[ch.id] = r.message;
}

// хРДц╕ащБУцЛЙхПЦхИ░чЪДцибхЮЛхИЧшби + цЛЙхПЦчК╢цАБ
const models = ref<Record<string, string[]>>({});
const loadingModels = ref<Record<string, boolean>>({});
async function pullModels(ch: ApiChannel) {
  loadingModels.value[ch.id] = true;
  testing.value[ch.id] = '';
  try {
    const list = await fetchModels(ch);
    models.value[ch.id] = list;
    if (list.length && !ch.model) ch.model = list[0];
    if (!list.length) testing.value[ch.id] = 'цЬкш┐ФхЫЮф╗╗ф╜ХцибхЮЛ';
  } catch (e) {
    testing.value[ch.id] = e instanceof Error ? e.message : String(e);
  } finally {
    loadingModels.value[ch.id] = false;
  }
}

/* тАФтАФ цибхЮЛхПпцРЬч┤вф╕ЛцЛЙ(combobox):ш╛УхЕецбЖцЧвцШпх╜УхЙНхА╝ф╣ЯцШпш┐Зц╗дшпН,шБЪчДжх╝╣хЗ║ш┐Зц╗дхИЧшби тАФтАФ */
const modelMenuOpen = ref(false);
const modelQuery = ref(''); // шБЪчДжхРОчФицИ╖ш╛УхЕечЪДш┐Зц╗дшпН;хд▒чДжцЧ╢ц╕Ечй║
// х╖▓цЛЙхПЦхИ░чЪДх╜УхЙНц╕ащБУцибхЮЛхИЧшби
const modelList = computed<string[]>(() => {
  const id = editingChannel.value?.id;
  return id ? models.value[id] ?? [] : [];
});
// ш┐Зц╗д:цЬЙ query цМЙхнРф╕▓(хдзх░ПхЖЩф╕НцХПцДЯ)ш┐Зц╗д;ф╕║чй║хИЩцШ╛чд║хЕищГиуАВцАзшГ╜ф╕КщЩР 200 цЭб,щБ┐хЕНш╢ЕщХ┐хИЧшбихНбщб┐уАВ
const filteredModels = computed<string[]>(() => {
  const q = modelQuery.value.trim().toLowerCase();
  const list = modelList.value;
  const out = q ? list.filter(m => m.toLowerCase().includes(q)) : list;
  return out.slice(0, 200);
});
function openModelMenu() {
  modelQuery.value = '';
  modelMenuOpen.value = true;
}
function pickModel(m: string) {
  if (editingChannel.value) editingChannel.value.model = m;
  modelMenuOpen.value = false;
  modelQuery.value = '';
}
// хд▒чДжх╗╢ш┐ЯхЕ│щЧн,шой option чЪД mousedown/click хЕИчФЯцХИ
function closeModelMenuSoon() {
  setTimeout(() => {
    modelMenuOpen.value = false;
    modelQuery.value = '';
  }, 150);
}

/* тАФтАФ шЗкхоЪф╣ЙцПРчд║шпН:хИЧшби(цСШшжБ/цА╗ч╗У/ча┤щЩР/цЧ╢щЧ┤цаЗчн╛),чВ╣х╝АхЬих╝╣чкЧщЗМч╝Цш╛СхдзцЦЗцЬм тАФтАФ */
