  {
    key: 'summary',
    label: 'цСШшжБцПРчд║шпН',
    hint: 'цККхНХце╝хп╣шпЭцХ┤чРЖцИРч╗УцЮДхМЦшо░х┐Ж(цСШшжБцнгцЦЗ + цЧ╢щЧ┤/хЬ░чВ╣/чЙйхУБ/шобхИТ)уАВ',
    builtin: SUMMARY_PROMPT,
    macros: SUMMARY_MACROS,
  },
  {
    key: 'resummary',
    label: 'цА╗ч╗УцПРчд║шпН',
    hint: 'цККхдЪцЭбце╝х▒ВцСШшжБхОЛцИРф╕АцЭб L1 цА╗ч╗У(цЩощАЪцА╗ч╗У,хЫ║хоЪ 300-500 хнЧ)уАВ',
    builtin: RESUMMARY_PROMPT,
    macros: RESUMMARY_MACROS,
  },
  {
    key: 'resummary2',
    label: 'ф║МцмбцА╗ч╗УцПРчд║шпН',
    hint: 'цККхдЪцЭбцА╗ч╗УхЖНхОЛф╕Ах▒В(L1+ тЖТ цЫ┤ф╕Кх▒В)уАВчЫоцаЗхнЧцХ░цМЙш╛УхЕешзДцибхКицАБцФ╛хо╜({{target}}),х░Сф╕вф┐бцБпуАВ',
    builtin: RESUMMARY2_PROMPT,
    macros: RESUMMARY2_MACROS,
  },
  {
    key: 'jailbreak',
    label: 'ча┤щЩРцПРчд║шпН',
    hint: 'ф╜Ьф╕║ч╜ощб╢ system щЩДхКахЬицСШшжБ/цА╗ч╗Ушп╖ц▒ВщЗМ,щЩНф╜ОхЙп API цЛТчнФчОЗуАВчХЩчй║хИЩчФихЖЕч╜ощ╗ШшодуАВ',
    builtin: JAILBREAK_PROMPT,
    macros: [],
  },
  {
    key: 'timeTag',
    label: 'хЫ║хоЪцПРчд║шпН(цЧ╢щЧ┤цаЗчн╛)',
    hint: 'ц│ихЕеф╕╗хп╣шпЭ,шжБц▒В AI цпПцЭбцнгцЦЗхЙНхРОш╛УхЗ║цЧ╢щЧ┤цаЗчн╛,ф╜Ьф╕║хЙзцГЕцЧ╢щЧ┤щФЪчВ╣(цСШшжБф╕ОцЦ░хЙзцГЕцНоцндхп╣щ╜Р,ф╕НхЖНщФЩф╣▒)уАВщЬАх╝АхРпф╕ЛцЦ╣уАМцнгцЦЗцЧ╢щЧ┤цаЗчн╛уАНх╝АхЕ│уАВчХЩчй║чФихЖЕч╜ощ╗ШшодуАВ',
    builtin: TIME_TAG_PROMPT,
    macros: [],
  },
];

// цнгхЬич╝Цш╛СчЪДцПРчд║шпН;draft цШпшНЙчи┐,чВ╣уАМхоМцИРуАНцЙНхЖЩхЫЮ apiSettings(хПЦц╢ИхИЩф╕вх╝Г)уАВ
const editingPrompt = ref<PromptMeta | null>(null);
const promptDraft = ref('');
const promptArea = ref<HTMLTextAreaElement | null>(null);

// шпеф╗╗хКбцШпхРжх╖▓шЗкхоЪф╣Й(щЭЮчй║хН│шзЖф╕║х╖▓шжЖчЫЦхЖЕч╜о)
function isCustom(key: PromptKey): boolean {
  return apiSettings.prompts[key].trim().length > 0;
}

function openPrompt(meta: PromptMeta) {
  editingPrompt.value = meta;
  // х╖▓шЗкхоЪф╣ЙтЖТш╜╜хЕечФицИ╖хЖЕхо╣;цЬкшЗкхоЪф╣ЙтЖТщвДхблхЖЕч╜оцибцЭ┐,цЦ╣ф╛┐чЫ┤цОехЬихЕ╢ф╕КцФ╣
  promptDraft.value = apiSettings.prompts[meta.key].trim() || meta.builtin;
}
function closePrompt() {
  editingPrompt.value = null;
  promptDraft.value = '';
}
function savePrompt() {
  const meta = editingPrompt.value;
  if (!meta) return;
  // шНЙчи┐ф╕ОхЖЕч╜охоМхЕиф╕АшЗ┤тЖТхнШчй║ф╕▓(хЫЮшР╜хЖЕч╜о),щБ┐хЕНцККцибцЭ┐хЖЧф╜ЩхнШш┐Ышо╛ч╜оуАБф╣Яф╛┐ф║ОцШ╛чд║уАМщ╗ШшодуАН
  const v = promptDraft.value.trim();
  apiSettings.prompts[meta.key] = v === meta.builtin.trim() ? '' : promptDraft.value;
  closePrompt();
}
// уАМцБвхдНщ╗ШшодуАН:цККшНЙчи┐щЗНч╜охЫЮхЖЕч╜оцибцЭ┐(ф┐ЭхнШхРОхН│хЫЮшР╜хЖЕч╜о)
function resetPrompt() {
  if (editingPrompt.value) promptDraft.value = editingPrompt.value.builtin;
}

/* тАФтАФ хРСщЗПшо░х┐Ж:ф╕Йф╕кцибхЮЛшзТшЙ▓,embedding ф╕║хЯ║хЗЖ,хРОф╕дшАЕчХЩчй║хдНчФихоГ тАФтАФ */
type VectorRole = 'embedding' | 'rerank' | 'queryRewrite';
interface VectorRoleMeta {
  key: VectorRole;
  label: string;
}
const VECTOR_ROLES: VectorRoleMeta[] = [
  { key: 'embedding', label: 'Embedding(хРСщЗПхМЦ,х┐Ехбл)' },
  { key: 'rerank', label: 'Rerank(щЗНцОТ)' },
  { key: 'queryRewrite', label: 'Query щЗНхЖЩ' },
];

/* тАФтАФ хРСщЗПчлпчВ╣:цпПшзТшЙ▓чЫ┤цОехбл хЬ░хЭА/хпЖщТе/цибхЮЛ;цибхЮЛхПпф╕АщФоцЛЙхПЦ(combobox)уАВ тАФтАФ */
const vecShowKey = ref<Record<VectorRole, boolean>>({ embedding: false, rerank: false, queryRewrite: false });
const vecModels = ref<Record<VectorRole, string[]>>({ embedding: [], rerank: [], queryRewrite: [] });
const vecLoadingModels = ref<Record<VectorRole, boolean>>({ embedding: false, rerank: false, queryRewrite: false });
const vecModelMsg = ref<Record<VectorRole, string>>({ embedding: '', rerank: '', queryRewrite: '' });
// combobox:х╜УхЙНх▒Хх╝АчЪДшзТшЙ▓(null=щГ╜цФ╢ш╡╖)+ ш┐Зц╗дшпН
const vecModelMenuOpen = ref<VectorRole | null>(null);
const vecModelQuery = ref('');

async function pullVecModels(role: VectorRole) {
  // шзгцЮРхЫЮшР╜хРОчЪДхЬ░хЭА/хпЖщТе:rerank/query чХЩчй║цЧ╢шЗкхКичФи Embedding чЪДхО╗цЛЙ(цибхЮЛф╗НхЖЩхЫЮцЬмшзТшЙ▓)
  const ep = resolveVectorModel(role);
  if (!ep.url.trim()) {
    vecModelMsg.value[role] = role === 'embedding' ? 'шп╖хЕИхбл Embedding хЬ░хЭА' : 'шп╖хЕИхблцЬмшзТшЙ▓цИЦ Embedding чЪДхЬ░хЭА';
    return;
  }
  vecLoadingModels.value[role] = true;
  vecModelMsg.value[role] = '';
  try {
    const list = await fetchModels({ url: ep.url, key: ep.key });
    vecModels.value[role] = list;
    if (list.length && !apiSettings.vector[role].model) apiSettings.vector[role].model = list[0];
    if (!list.length) vecModelMsg.value[role] = 'цЬкш┐ФхЫЮф╗╗ф╜ХцибхЮЛ';
  } catch (e) {
    vecModelMsg.value[role] = e instanceof Error ? e.message : String(e);
  } finally {
    vecLoadingModels.value[role] = false;
  }
}
function filteredVecModels(role: VectorRole): string[] {
  const q = vecModelQuery.value.trim().toLowerCase();
  const list = vecModels.value[role] ?? [];
  const out = q ? list.filter(m => m.toLowerCase().includes(q)) : list;
  return out.slice(0, 200);
}
function openVecModelMenu(role: VectorRole) {
  vecModelQuery.value = '';
  vecModelMenuOpen.value = role;
}
function pickVecModel(role: VectorRole, m: string) {
  apiSettings.vector[role].model = m;
  vecModelMenuOpen.value = null;
  vecModelQuery.value = '';
}
