/* тАФтАФ цОТщЩдшзТшЙ▓:хЛ╛щАЙчЪДшзТшЙ▓хРН(хРлщЗНхРНхНб)чЪДшБКхдйщЗМ,шо░х┐Жч│╗ч╗ЯцЙАцЬЙхКЯшГ╜щГ╜ф╕НчФЯцХИуАВ
   цМЙуАМхРНхнЧуАНцОТщЩд,цЙАф╗ехРМхРНхНбцШпф╕АцЙ╣ф╕Аш╡╖цОТщЩдуАВхИЧшбих╛ИщХ┐цЧ╢цШУхНб,цХЕ:тСа ф╗ЕхЬих╝╣чкЧцЙУх╝АцЧ╢хПЦ/хО╗щЗНшзТшЙ▓хРН;
   тСб х╕жцРЬч┤вцбЖш┐Зц╗д;тСв чФи v-show + хнРф╕▓хМ╣щЕН,ц╕▓цЯУщЗПщЪПцРЬч┤вцФ╢цХЫуАВ тАФтАФ */
const excludeOpen = ref(false);
const excludeSearch = ref('');

// х╝╣чкЧцЙУх╝АцЧ╢ф╕АцмбцАзчоЧхЗ║хО╗щЗНхРОчЪДшзТшЙ▓хРН(цМЙхРНцОТх║П),хЕ│щЧнхРОф╕НхЖНцМБцЬЙ,щБ┐хЕНх╕╕щй╗хдзхИЧшбиуАВ
const charNames = computed<string[]>(() => {
  if (!excludeOpen.value) return [];
  const chars = getContext()?.characters ?? [];
  const seen = new Set<string>();
  for (const c of chars) {
    const n = c?.name?.trim();
    if (n) seen.add(n);
  }
  return [...seen].sort((a, b) => a.localeCompare(b, 'zh'));
});

// ш┐Зц╗д:чй║цРЬч┤вцШ╛чд║хЕищГи;хРжхИЩхдзх░ПхЖЩф╕НцХПцДЯхнРф╕▓хМ╣щЕН
const filteredCharNames = computed<string[]>(() => {
  const q = excludeSearch.value.trim().toLowerCase();
  if (!q) return charNames.value;
  return charNames.value.filter(n => n.toLowerCase().includes(q));
});

function openExclude() {
  excludeSearch.value = '';
  excludeOpen.value = true;
}
function closeExclude() {
  excludeOpen.value = false;
}
function isExcluded(name: string): boolean {
  return apiSettings.excludedChars.includes(name);
}
function toggleExcluded(name: string) {
  const list = apiSettings.excludedChars;
  const idx = list.indexOf(name);
  if (idx >= 0) list.splice(idx, 1);
  else list.push(name);
}

/* тАФтАФ шЗкхоЪф╣Йц╕Ец┤ЧцаЗчн╛:чФицИ╖хблцаЗчн╛хРН(хжВ snow),ц╕Ец┤ЧцнгцЦЗцЧ╢цКК <snow>тАж</snow> цХ┤хЭЧхИацОЙ тАФтАФ */
const stripTagDraft = ref('');
function addStripTag() {
  const tag = sanitizeTagName(stripTagDraft.value);
  if (!tag) {
    stripTagDraft.value = '';
    return;
  }
  if (!apiSettings.customStripTags.includes(tag)) apiSettings.customStripTags.push(tag);
  stripTagDraft.value = '';
}
function removeStripTag(tag: string) {
  const idx = apiSettings.customStripTags.indexOf(tag);
  if (idx >= 0) apiSettings.customStripTags.splice(idx, 1);
}

// чВ╣хоПцаЗчн╛ тЖТ цПТхЕехИ░цЦЗцЬмцбЖхЕЙцаЗхдД(цЧачДжчВ╣хИЩш┐╜хКахИ░цЬлх░╛)
function insertMacro(token: string) {
  const el = promptArea.value;
  if (!el) {
    promptDraft.value += token;
    return;
  }
  const start = el.selectionStart ?? promptDraft.value.length;
  const end = el.selectionEnd ?? start;
  promptDraft.value = promptDraft.value.slice(0, start) + token + promptDraft.value.slice(end);
  // чнЙ v-model хЫЮхблхРОцККхЕЙцаЗчз╗хИ░цПТхЕехЖЕхо╣ф╣ЛхРО
  void nextTick(() => {
    el.focus();
    const pos = start + token.length;
    el.setSelectionRange(pos, pos);
  });
}

/* тАФтАФ ф╕КцмбхПмхЫЮшпжцГЕ(ш░ГшпХщЭвцЭ┐):ч║пхПкшп╗х▒Хчд║ recallDebug,reactive шЗкхКихИ╖цЦ░ тАФтАФ */
function fmtRecallTime(at: number): string {
  if (!at) return '';
  const d = new Date(at);
  const p = (n: number) => String(n).padStart(2, '0');
  return `${p(d.getHours())}:${p(d.getMinutes())}:${p(d.getSeconds())}`;
}
// цЭец║Р Q цаЗчн╛:хРОчлпхЫЮф╝а -1(цЧзхРОчлпцЬкцФпцМБ)цЧ╢цШ╛чд║хНаф╜Нчмж
function qLabel(queryIndex: number): string {
  return queryIndex >= 0 ? `Q${queryIndex + 1}` : 'тАФ';
}
const TIER_LABEL: Record<'full' | 'brief' | 'drop', string> = { full: 'хЕицЦЗ', brief: 'цСШшжБ', drop: 'ф╕вх╝Г' };
// чК╢цАБшпнц░Ф:хЖ│хоЪцикх╣Ех╖жф╛зхЬЖчВ╣чЪДщЕНшЙ▓(цИРхКЯ/шнжчд║/хд▒ш┤е/ш┐ЫшбМф╕н)
const recallStatusKind = computed<'ok' | 'warn' | 'fail' | 'pending'>(() => {
  const s = recallDebug.status;
  if (s.includes('хд▒ш┤е')) return 'fail';
  if (s.includes('ш┐ЫшбМф╕н')) return 'pending';
  if (s.includes('цЬкхПмхЫЮ') || s.includes('цЬкц│ихЕе')) return 'warn';
  return 'ok';
});
// хИЖцХ░(0~1)тЖТ ш┐Ых║жцЭбхо╜х║жчЩ╛хИЖцпФ;ш┤ЯхИЖ(хжВцЬкчЯе)цМЙ 0 хдДчРЖ
function scorePct(score: number): number {
  return Math.max(0, Math.min(1, score)) * 100;
}
</script>

