/* ц╕ащБУ:ч┤зхЗСхПкшп╗хИЧшби,цпПц╕ащБУф╕АшбМ,чВ╣шбМш┐Ых╝╣чкЧч╝Цш╛С */
.bbs-channel-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.bbs-channel-item {
  display: flex;
  align-items: stretch;
  gap: 8px;
}
/* шбМф╕╗ф╜У:цХ┤хЭЧхПпчВ╣,х╖жхРНхнЧхП│цибхЮЛ */
.bbs-channel-open {
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 10px 14px;
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius);
  background: var(--bbs-surface-2);
  color: var(--bbs-ink);
  font-family: var(--bbs-font-sans);
  cursor: pointer;
  text-align: left;
  transition: border-color var(--bbs-dur) var(--bbs-ease), background var(--bbs-dur) var(--bbs-ease);
}
.bbs-channel-open:hover {
  border-color: var(--bbs-accent);
  background: var(--bbs-surface);
}
/* ц╕ащБУхРН:хоМцХ┤цШ╛чд║,хЕБшо╕цНвшбМ,хНацНохЙйф╜Щчй║щЧ┤ */
.bbs-channel-item-name {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 14px;
  font-weight: 600;
  word-break: break-word;
}
/* цибхЮЛхРН:цмбшжБф┐бцБп,ш┐ЗщХ┐хИЩцИкцЦн,ф╕НцМдхНахРНхнЧ */
.bbs-channel-item-model {
  flex: 0 1 auto;
  min-width: 0;
  font-size: 12px;
  color: var(--bbs-ink-muted);
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
/* х╝╣чкЧх║ХщГи:spacer цККхИащЩдщФоцОихИ░цЬАх╖ж,ф╕ОхП│ф╛зцУНф╜ЬхИЖщЪФ */
.bbs-modal-foot-spacer {
  flex: 1 1 auto;
}
/* хН▒щЩйцУНф╜ЬцМЙщТо:цППш╛╣ф╜Ош░Г,hover цЙНцШ╛ч║в,щБ┐хЕНшппшзж */
.bbs-btn-danger {
  color: var(--bbs-danger);
  border-color: var(--bbs-line-strong);
}
.bbs-btn-danger:hover {
  color: var(--bbs-danger);
  border-color: var(--bbs-danger);
  background: var(--bbs-danger-soft);
}

.bbs-model-row {
  display: flex;
  gap: 8px;
  align-items: center;
}
.bbs-model-row .bbs-input {
  flex: 1;
}
.bbs-icon-mini:disabled {
  opacity: 0.5;
  cursor: default;
}
.bbs-icon-mini {
  flex: 0 0 auto;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border: 1px solid var(--bbs-line-strong);
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-surface);
  color: var(--bbs-ink-soft);
  cursor: pointer;
  font-size: 14px;
}
.bbs-icon-mini:hover {
  color: var(--bbs-accent);
  border-color: var(--bbs-accent);
}
.bbs-channel-row {
  display: flex;
  gap: 10px;
}
.bbs-mini-field {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-size: 12px;
  color: var(--bbs-ink-muted);
}
.bbs-channel-test {
  margin: 2px 0 0;
  font-size: 12px;
  color: var(--bbs-ink-soft);
  word-break: break-all;
}

/* цСШшжБшо╛ч╜оцОзф╗╢ */
.bbs-switch-row,
.bbs-num-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 8px 0;
}
.bbs-checkbox {
  width: 18px;
  height: 18px;
  accent-color: var(--bbs-accent);
  cursor: pointer;
}
.bbs-num {
  max-width: 110px;
  text-align: right;
}
/* чЯнщАЙщб╣ф╕ЛцЛЙ(хжВхнЧцХ░цбгф╜Н):ш┤┤хРИцЦЗхнЧчЪДчкДхо╜,хТМхП│ф╛зцХ░хнЧцбЖхп╣щ╜Р,ф╕НхЖНцТСц╗бхНКшбМ */
.bbs-select-narrow {
  width: auto;
  min-width: 65px;
  max-width: 150px;
}

/* тАФтАФ цА╗х╝АхЕ│ф╕╗цОзхНб тАФтАФ */
/* х╖жч╝Шф╕АщБУщЗСшЙ▓ф╣жшДК,хС╝х║ФуАМф╣жуАНчЪДхУБчЙМ;хБЬчФицЧ╢цХ┤хНбшдкшЙ▓уАБф╣жшДКш╜мчБ░,чК╢цАБф╕АчЬ╝хПпш╛и */
.bbs-master {
  display: flex;
  align-items: center;
  gap: 14px;
  margin-bottom: 16px;
  padding: 16px 18px 16px 16px;
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius);
  background: var(--bbs-surface);
  box-shadow: var(--bbs-shadow);
  transition: opacity var(--bbs-dur) var(--bbs-ease);
}
.bbs-master-spine {
  flex: 0 0 auto;
  align-self: stretch;
  width: 4px;
  border-radius: var(--bbs-radius-pill);
  background: var(--bbs-accent);
  transition: background var(--bbs-dur) var(--bbs-ease);
}
.bbs-master.is-off .bbs-master-spine {
  background: var(--bbs-line-strong);
}
.bbs-master.is-off .bbs-master-text {
  opacity: 0.7;
}
.bbs-master-text {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 3px;
}
.bbs-master-title {
  font-size: 15px;
  font-weight: 600;
  color: var(--bbs-ink);
}

/* тАФтАФ щАЪчФиц╗СхКих╝АхЕ│(цА╗х╝АхЕ│чФи,хРОч╗нхИлхдДф╣ЯхПпхдНчФи) тАФтАФ */
.bbs-toggle {
  flex: 0 0 auto;
  position: relative;
  width: 46px;
  height: 26px;
  padding: 0;
  border: 0;
  border-radius: var(--bbs-radius-pill);
  background: var(--bbs-line-strong);
  cursor: pointer;
  transition: background var(--bbs-dur) var(--bbs-ease);
}
.bbs-toggle.is-on {
  background: var(--bbs-accent);
}
.bbs-toggle:focus-visible {
  outline: 2px solid var(--bbs-accent);
  outline-offset: 2px;
}
.bbs-toggle-knob {
  position: absolute;
  top: 3px;
  left: 3px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: var(--bbs-surface);
  box-shadow: 0 1px 3px oklch(0 0 0 / 0.25);
  transition: transform var(--bbs-dur) var(--bbs-ease);
}
.bbs-toggle.is-on .bbs-toggle-knob {
  transform: translateX(20px);
}

/* тАФтАФ хРСщЗПшо░х┐Ж:цпПф╕кцибхЮЛшзТшЙ▓ф╕Ач╗ДхНбчЙЗ(ц╕ащБУ + цибхЮЛхРНф╕дхИЧ) тАФтАФ */
/* хРСщЗПчлпчВ╣хНбчЙЗ(Embedding/Rerank/Query хРДф╕АхЭЧ,цЙБх╣│хблхЬ░хЭА/хпЖщТе/цибхЮЛ) */
.bbs-vec-ep {
  margin-top: 12px;
  padding: 12px 14px;
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius);
  background: var(--bbs-surface-2);
  transition: opacity var(--bbs-dur) var(--bbs-ease);
}
.bbs-vec-ep.is-disabled {
  opacity: 0.5;
}
/* хПмхЫЮхПВцХ░/ч┤вх╝Хч╗┤цКдцХ┤ч╗ДхЬихЕ│щЧнхРСщЗПшо░х┐ЖцЧ╢ф╕Ах╣╢ч╜очБ░ */
.bbs-vec-recall.is-disabled {
  opacity: 0.5;
}
.bbs-vec-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 10px;
}
/* уАМхдНчФи Embedding / чЛмчлЛчлпчВ╣уАНчК╢цАБх░ПцаЗчн╛ */
.bbs-vec-reuse-tag {
  font-size: 11px;
  color: var(--bbs-ink-muted);
  padding: 1px 8px;
  border: 1px solid var(--bbs-line);
  border-radius: 999px;
  white-space: nowrap;
}
/* хРСщЗПхРОчлпч▒╗хЮЛцаЗчн╛:ф╕ОцСШшжБхИЧшбичЪДуАМцА╗ч╗УуАНцаЗчн╛хРМцм╛(хоЮх┐ГхблхЕЕуАБчЩ╜хнЧ),хРОчлп=х╝║ш░ГшЙ▓,цЬмхЬ░щЩНч║з=шнжхСКшЙ▓ */
.bbs-vec-backend {
  box-sizing: border-box;
  height: 22px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0 10px;
  font-size: 11px;
  font-weight: 600;
  border-radius: var(--bbs-radius-sm);
  white-space: nowrap;
}
.bbs-vec-backend.is-backend {
  color: var(--bbs-accent-ink);
  background: var(--bbs-accent);
  border: 1px solid var(--bbs-accent);
}
.bbs-vec-backend.is-local {
  color: var(--bbs-accent-ink);
  background: var(--bbs-warning);
  border: 1px solid var(--bbs-warning);
}

/* тАФтАФ ф╕КцмбхПмхЫЮшпжцГЕ(ш░ГшпХщЭвцЭ┐):чК╢цАБцикх╣Е + цнещкдхИЖхМ║ + хИЖцХ░цЭбхНбчЙЗ тАФтАФ */
.bbs-dbg {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

/* чК╢цАБцикх╣Е:х╖жшЙ▓чВ╣ + цЦЗцбИ + цЧ╢щЧ┤ */
.bbs-dbg-banner {
  display: flex;
  align-items: center;
  gap: 9px;
  padding: 9px 12px;
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-surface-2);
  border-left: 3px solid var(--bbs-line-strong);
}
.bbs-dbg-dot {
  flex: 0 0 auto;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--bbs-ink-muted);
}
.bbs-dbg-banner.is-ok {
  border-left-color: var(--bbs-accent);
}
.bbs-dbg-banner.is-ok .bbs-dbg-dot {
  background: var(--bbs-accent);
}
.bbs-dbg-banner.is-warn {
  border-left-color: var(--bbs-warning);
}
.bbs-dbg-banner.is-warn .bbs-dbg-dot {
  background: var(--bbs-warning);
}
.bbs-dbg-banner.is-fail {
  border-left-color: var(--bbs-danger);
}
.bbs-dbg-banner.is-fail .bbs-dbg-dot {
  background: var(--bbs-danger);
}
.bbs-dbg-banner.is-pending .bbs-dbg-dot {
  background: var(--bbs-ink-soft);
}
.bbs-dbg-status-text {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 13px;
  font-weight: 600;
  color: var(--bbs-ink);
  word-break: break-word;
}
.bbs-dbg-time {
  flex: 0 0 auto;
  font-size: 11px;
  color: var(--bbs-ink-muted);
  font-variant-numeric: tabular-nums;
}

.bbs-dbg-empty {
  margin: 0;
  font-size: 12px;
  color: var(--bbs-ink-muted);
}

/* ч┤вх╝Хч╗┤цКд:щЗНх╗║/ц╕Ечй║цМЙщТох╣╢цОТ,чкДх▒ПшЗкхКицНвшбМ */
.bbs-vec-index-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 4px;
}

/* щЗНхЖЩ:INTENT щлШф║о + Q хИЧшби */
.bbs-dbg-intent {
  display: flex;
  gap: 7px;
  margin: 0 0 10px;
  padding: 8px 10px;
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-accent-soft);
  font-size: 12px;
  line-height: 1.6;
}
.bbs-dbg-intent-text {
  flex: 1 1 auto;
  min-width: 0;
  color: var(--bbs-ink);
  word-break: break-word;
}
.bbs-dbg-tag {
  flex: 0 0 auto;
  align-self: flex-start;
  padding: 1px 6px;
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-accent);
  color: var(--bbs-accent-ink);
  font-family: var(--bbs-font-mono);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.3px;
}
.bbs-dbg-qlist {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.bbs-dbg-qitem {
  display: flex;
  gap: 8px;
  font-size: 12px;
  line-height: 1.55;
  color: var(--bbs-ink);
}
.bbs-dbg-qno {
  flex: 0 0 auto;
  min-width: 22px;
  font-family: var(--bbs-font-mono);
  font-size: 11px;
  font-weight: 700;
  color: var(--bbs-accent);
}
.bbs-dbg-qtext {
  flex: 1 1 auto;
  min-width: 0;
  word-break: break-word;
}

/* хС╜ф╕нхНбчЙЗхИЧшби:хЫ║хоЪщлШх║жхЖЕц╗СхКи,щХ┐хИЧшбиф╕НцККцКШхПахМ║цТСх╛Чх╛ИщХ┐уАВ */
.bbs-dbg-cards {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 8px;
  max-height: 320px;
  overflow-y: auto;
}
.bbs-dbg-card {
  padding: 8px 10px;
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius-sm);
  background: var(--bbs-surface-2);
}
.bbs-dbg-card.is-dropped {
  opacity: 0.55;
}
.bbs-dbg-card-top {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}
/* цЭец║Р Q х╛╜цаЗ */
.bbs-dbg-src {
  flex: 0 0 auto;
  min-width: 38px; /* ф╕Оце╝х▒ВхП╖цаЗчн╛чнЙхо╜,хНХцХ░ Q ф╣Яф╕НшЗ│ф║ОхдкчкД */
  text-align: center;
  padding: 1px 7px;
  border-radius: var(--bbs-radius-pill);
  background: var(--bbs-accent-soft);
  color: var(--bbs-accent);
  font-family: var(--bbs-font-mono);
  font-size: 11px;
  font-weight: 700;
}
/* цЭец║РцаЗшо░:цЬмшБКхдйце╝х▒ВхП╖(ф╕нцАз)/ цЧзцбг(цППш╛╣цПРчд║шЙ▓) */
.bbs-dbg-from {
  flex: 0 0 auto;
  min-width: 38px; /* це╝х▒ВхП╖ф╕кф╜НцХ░(#5)ф╣Яф╕НшЗ│ф║ОхдкчкД,ф╕О Q цаЗчн╛шзЖшзЙчнЙхо╜ */
  text-align: center;
  padding: 1px 7px;
  border-radius: var(--bbs-radius-pill);
  font-family: var(--bbs-font-mono);
  font-size: 11px;
  font-weight: 600;
  color: var(--bbs-ink-soft);
  background: var(--bbs-surface);
  border: 1px solid var(--bbs-line-strong);
}
.bbs-dbg-from.is-bundle {
  color: var(--bbs-warning);
  background: var(--bbs-warning-soft);
  border-color: transparent;
}
.bbs-dbg-when {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 11px;
  color: var(--bbs-ink-soft);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.bbs-dbg-num {
  flex: 0 0 auto;
  margin-left: auto;
  font-family: var(--bbs-font-mono);
  font-size: 12px;
  font-weight: 600;
  color: var(--bbs-ink);
  font-variant-numeric: tabular-nums;
}
/* хИЖцХ░цЭб:ч╗Жш╜и + хблхЕЕ;щ╗Шшодх╝║ш░ГшЙ▓,rerank хРДцбгхИЖшЙ▓ */
.bbs-dbg-bar {
  height: 4px;
  border-radius: var(--bbs-radius-pill);
  background: var(--bbs-line);
  overflow: hidden;
}
.bbs-dbg-bar > i {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: var(--bbs-accent);
  transition: width var(--bbs-dur) var(--bbs-ease);
}
.bbs-dbg-bar.tier-brief > i {
  background: var(--bbs-ink-soft);
}
.bbs-dbg-bar.tier-drop > i {
  background: var(--bbs-ink-muted);
}
.bbs-dbg-prev {
  margin: 6px 0 0;
  font-size: 12px;
  line-height: 1.5;
  color: var(--bbs-ink-muted);
  word-break: break-word;
}
/* хИЖцбгх╛╜цаЗ:хЕицЦЗ(х╝║ш░ГхоЮх║Х)/цСШшжБ(ф╕нцАз)/ф╕вх╝Г(цППш╛╣шдкшЙ▓) */
.bbs-dbg-tier {
  flex: 0 0 auto;
  min-width: 32px;
  text-align: center;
  padding: 1px 8px;
  border-radius: var(--bbs-radius-pill);
  font-size: 11px;
  font-weight: 700;
}
.bbs-dbg-tier.is-full {
  color: var(--bbs-accent-ink);
  background: var(--bbs-accent);
}
.bbs-dbg-tier.is-brief {
  color: var(--bbs-ink-soft);
  background: var(--bbs-surface);
  border: 1px solid var(--bbs-line-strong);
}
.bbs-dbg-tier.is-drop {
  color: var(--bbs-ink-muted);
  background: transparent;
  border: 1px solid var(--bbs-line);
}
/* ц│ихЕецЦЗцЬмцбЖ:чнЙхо╜уАБщЩРщлШц╗ЪхКи */
.bbs-dbg-pre {
  margin: 0;
  padding: 10px 12px;
  max-height: 320px;
  overflow: auto;
  background: var(--bbs-surface-2);
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius-sm);
  font-family: var(--bbs-font-mono);
  font-size: 12px;
  line-height: 1.6;
  white-space: pre-wrap;
  overflow-wrap: anywhere;
  color: var(--bbs-ink);
}

/* тАФтАФ шЗкхоЪф╣ЙцПРчд║шпНхИЧшби тАФтАФ */
.bbs-prompt-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 8px;
}
/* цХ┤шбМхПпчВ╣ш┐Ых╝╣чкЧч╝Цш╛С;х╕Гх▒Ац▓┐чФиц╕ащБУхИЧшбичЪДшзВцДЯ(цППш╛╣уАБhover цШ╛х╝║ш░ГшЙ▓) */
.bbs-prompt-open {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  border: 1px solid var(--bbs-line);
  border-radius: var(--bbs-radius);
  background: var(--bbs-surface-2);
  color: var(--bbs-ink);
  font-family: var(--bbs-font-sans);
  cursor: pointer;
  text-align: left;
  transition: border-color var(--bbs-dur) var(--bbs-ease), background var(--bbs-dur) var(--bbs-ease);
}
.bbs-prompt-open:hover {
  border-color: var(--bbs-accent);
  background: var(--bbs-surface);
}
.bbs-prompt-name {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 13px;
  font-weight: 600;
}
/* чК╢цАБшНпф╕╕:щ╗Шшод muted,х╖▓шЗкхоЪф╣Йш╜мщЗСх╝║ш░Г */
.bbs-prompt-state {
  flex: 0 0 auto;
  font-size: 11px;
  font-weight: 600;
  padding: 2px 9px;
  border-radius: var(--bbs-radius-pill);
  color: var(--bbs-ink-muted);
  background: var(--bbs-surface);
  border: 1px solid var(--bbs-line);
}
