/**
 * ф╗ОцЧзчЙИ Horae ш┐Бчз╗шо░х┐ЖцХ░цНоуАВ
 *
 * хЕ│щФоф║ЛхоЮ:Horae ф╕ОцЯПхоЭф╣жхЕ▒чФи**хРМф╕АцЙ╣шБКхдйцЦЗф╗╢чЪДхРМф╕АцЙ╣ц╢ИцБпхп╣ш▒б**тАФтАФHorae цККцХ░цНоцМВхЬи
 * `chat[i].horae_meta`,цЯПхоЭф╣жцМВхЬи `chat[i].extra.bbs_leaf`,ф╕дшАЕх╣╢хнШф║ОхРМф╕АцЭб msg ф╕КуАВ
 * цЙАф╗еш┐Бчз╗чЫ┤цОешп╗уАМх╜УхЙНцЙУх╝АшБКхдйуАНчЪД `ctx.chat[i].horae_meta` ф║зхЗ║цЯПхоЭф╣жцХ░цНо,ф╕Нш╖ицЦЗф╗╢уАВ
 * шМГх╝ПчЕзцРм carryover.ts:шп╗ц║Р тЖТ щАахП╢хнР(цМВ extra)+ цгоцЮЧ(хЖЩ metadata)+ цККцЬАч╗ИчК╢цАБч╝ЦчаБцИРчзНхнР deltaуАВ
 *
 * цибхЮЛцШах░Д(шпжшзБ memory щЗМчЪД horae-migration-feature):
 *  - цпПф╕кцЬЙхПЩф║ЛчЪД AI це╝ тЖТ ф╕АчЙЗхП╢хнР;text = шпеце╝щЭЮцСШшжБ events чЪД summary цЛ╝цОеуАВ
 *  - Horae цЧ╢щЧ┤цШп**цЧ╢щЧ┤чВ╣**(цпПх▒Вф╕Аф╕к),цЯПхоЭф╣жцШп**цЧ╢щЧ┤цо╡**:хП╢хнР timeEnd = цЬмх▒ВцЧ╢щЧ┤чВ╣,
 *    timeStart = ф╕Кф╕Ах╖▓чЯецЧ╢щЧ┤чВ╣(цо╡чЪДх╖жчХМ);ч╝║хд▒хИЩц▓┐чФиф╕Кф╕Ах╖▓чЯехА╝(carry-forward)уАВ
 *  - Horae autoSummaries(х╕ж range/depthуАБх╡МхеЧ mergedSummaries)тЖТ цЯПхоЭф╣жцгоцЮЧ comp шКВчВ╣:
 *    щАТх╜Т flatten,depthтЖТlevel,childIds чФ▒уАМчЫ┤цОехнРцЭбчЫо + шМГхЫ┤хЖЕцЬкшвлхнРцЭбчЫошжЖчЫЦчЪДхП╢хнРуАНщЗНх╗║уАВ
 *  - чЙйхУБ/шобхИТцШп Horae чЪД**щАРх▒Вх┐лчЕз**(щЭЮхвЮщЗП),цМЙце╝х║ПцКШхПахЗ║цЬАч╗ИцАБ,цХ┤хМЕф╜Ьф╕║ add-delta цМВхИ░
 *    цЬАхРОф╕АчЙЗхП╢хнР(щБ┐хЕНщАРх▒ВщЗНцФ╛щЗНхдНч┤пхКа)уАВ
 *  - х╝ГцОЙцЯПхоЭф╣жц▓бцЬЙчЪД:affection / npcs / costumes / mood / relationships / RPG / customTablesуАВ
 */

import { getContext, type STMessage } from '@/st/context';
import { toast } from '@/st/toast';
import { isAiFloor, syncHiddenNow } from './engine';
import { makeLeafId } from './apply';
import { flushLeavesNow, memory, recomputeDerived, saveMemory } from './store';
import type { ItemDelta, LeafExtra, MemSummary, StoredDelta } from './types';

/* ============ Horae ц║РцХ░цНох╜вчК╢(хПкхПЦш┐Бчз╗чФих╛ЧхИ░чЪДхнЧцо╡) ============ */

interface HoraeTimestamp {
  story_date?: string;
  story_time?: string;
  absolute?: string;
}
interface HoraeEvent {
  level?: string;
  summary?: string;
  isSummary?: boolean;
  _summaryId?: string;
}
interface HoraeItemInfo {
  holder?: string;
  location?: string;
  description?: string;
}
interface HoraeAgendaItem {
  type?: string;
  date?: string;
  text?: string;
  done?: boolean;
}
interface HoraeSummaryEntry {
  id?: string;
  range?: [number, number];
  summaryText?: string;
  depth?: number;
  createdAt?: string;
  auto?: boolean;
  mergedSummaries?: HoraeSummaryEntry[];
}
interface HoraeMeta {
  timestamp?: HoraeTimestamp;
  scene?: { location?: string };
  items?: Record<string, HoraeItemInfo>;
  deletedItems?: string[];
  events?: HoraeEvent[];
  event?: HoraeEvent; // цЧзца╝х╝П:хНХф╕к event
  agenda?: HoraeAgendaItem[];
  deletedAgenda?: string[];
  _deletedAgendaTexts?: string[];
  _skipHorae?: boolean;
  autoSummaries?: HoraeSummaryEntry[];
}

/* ============ х░Пх╖ехЕ╖ ============ */

/** хПЦф╕АцЭбц╢ИцБпф╕КчЪД horae_meta(хПпшГ╜ц▓бцЬЙ) */
function horaeMeta(m: STMessage | undefined): HoraeMeta | undefined {
  return (m as unknown as { horae_meta?: HoraeMeta } | undefined)?.horae_meta;
}

/** хРИцИРцЧ╢щЧ┤чВ╣хнЧчмжф╕▓:date + time(хРДшЗкхПпч╝║)уАВф╕дшАЕчЪЖчй║ тЖТ ''уАВ */
function combineTime(ts: HoraeTimestamp | undefined): string {
  const d = (ts?.story_date ?? '').trim();
  const t = (ts?.story_time ?? '').trim();
  return [d, t].filter(Boolean).join(' ').trim();
}

/** хПЦф╕Ах▒ВчЪДхПЩф║ЛцЦЗцЬм:щЭЮцСШшжБхНб events чЪД summary цЛ╝цОе(цСШшжБхНб level='цСШшжБ'/isSummary ш╖│ш┐З)уАВ */
function narrativeOf(meta: HoraeMeta | undefined): string {
  if (!meta) return '';
  const events = meta.events ?? (meta.event ? [meta.event] : []);
  return events
    .filter(e => e && !e.isSummary && e.level !== 'цСШшжБ')
    .map(e => (e.summary ?? '').trim())
    .filter(Boolean)
    .join('\n\n')
    .trim();
}

// Horae getItemBaseName чФичЪДщЗПшпНщЫЖхРИ(хЙеуАМ(щЗПшпН)уАНхРОч╝А);ф┐ЭцМБф╕Оц║Рф╕АшЗ┤уАВ
const COUNTING_CLASSIFIERS = 'ф╕кцККцЭбхЭЧх╝аца╣хПгф╗╜цЮЪхПкщвЧцФпф╗╢хеЧхПМхп╣чвЧцЭпчЫШчЫЖф╕▓цЭЯцЙО';
const RE_QTY_PAREN = /[(я╝И]\s*(\d+(?:\.\d+)?)\s*[a-zA-Zф╕А-щ┐┐]*\s*[)я╝Й]\s*$/; // (3) (3ф╕к) (500g)
const RE_PURE_CLASSIFIER = new RegExp(`[(я╝И][${COUNTING_CLASSIFIERS}][)я╝Й]\\s*$`);
// ц╢ИшАЧ/х╜ТщЫ╢цаЗшо░:хЗ║чО░хН│шзЖф╕║шпечЙйхУБх╖▓ц▓б
const RE_CONSUMED = /[(я╝И](х╖▓ц╢ИшАЧ|х╖▓чФихоМ|х╖▓щФАцпБ|х╖▓щК╖цпА|ц╢ИшАЧцоЖх░╜|ц╢ИшАЧцоЖчЫб|ц╢ИшАЧ|чФих░╜|чФичЫб|consumed|used\s*up|destroyed|depleted)[)я╝Й]/i;
const RE_ZERO = /[(я╝И]\s*0\s*[a-zA-Zф╕А-щ┐┐]*\s*[)я╝Й]\s*$/;

/** ф╗О Horae чЙйхУБхРНшзгцЮРхЗ║хЯ║чбАхРН + цХ░щЗПуАВцХ░щЗПч╝ЦчаБхЬихРНхнЧцЛмхП╖щЗМ(хжВуАМшЛ╣цЮЬ(3)уАН)уАВ */
function parseHoraeItemName(raw: string): { name: string; qty?: number; consumed: boolean } {
  let name = String(raw ?? '').trim();
  if (RE_ZERO.test(name) || RE_CONSUMED.test(name)) return { name: name, consumed: true };
  let qty: number | undefined;
  const m = name.match(RE_QTY_PAREN);
  if (m) {
    const n = Number(m[1]);
    if (Number.isFinite(n)) qty = n;
    name = name.replace(RE_QTY_PAREN, '').trim();
  }
  name = name.replace(RE_PURE_CLASSIFIER, '').trim();
  return { name, qty, consumed: false };
}

/* ============ ш┐Бчз╗шобхИТ(щвДшзИ,ч║пхПкшп╗) ============ */

export interface MigrationPlan {
  /** цШпхРжцгАц╡ЛхИ░ф╗╗ф╜Х Horae цХ░цНо */
  hasData: boolean;
  /** цЬЙхПЩф║ЛхПпх╗║хП╢хнРчЪД AI це╝цХ░ */
  leafFloors: number;
  /** хПпш┐Бчз╗чЪДцА╗ч╗У(хОЛч╝йшКВчВ╣)цХ░ */
  summaryCount: number;
  /** цЬАч╗Их║УхнШчЙйхУБцХ░ */
  itemCount: number;
  /** цЬкф║Жч╗УшобхИТ/цВмх┐╡цХ░ */
  planCount: number;
  /** х╜УхЙНцЯПхоЭф╣жцШпхРжх╖▓цЬЙцгоцЮЧцХ░цНо(х░ЖшвлшжЖчЫЦ) */
  willOverwrite: boolean;
}

/** цКК chat цКШхПацИРцЬАч╗Их║УхнШ(щАРх▒Вх┐лчЕзхЙНхРСхРИх╣╢ + хдДчРЖхИащЩд/ц╢ИшАЧ)уАВ */
function foldFinalItems(chat: STMessage[]): ItemDelta[] {
  // цМЙхЯ║чбАхРНх╜Тх╣╢(Horae хРМчЙйхПпшГ╜цНвхЖЩц│Х),ф┐ЭчХЩцЬАхРОф╕АцмбхЗ║чО░чЪДцППш┐░/хЬ░чВ╣уАВ
  const byKey = new Map<string, ItemDelta>();
  const keyOf = (name: string) => name.trim().toLowerCase();

  for (let i = 0; i < chat.length; i++) {
    const meta = horaeMeta(chat[i]);
    if (!meta || meta._skipHorae) continue;

    if (meta.items) {
      for (const [rawName, info] of Object.entries(meta.items)) {
        const { name, qty, consumed } = parseHoraeItemName(rawName);
        if (!name) continue;
        const k = keyOf(name);
        if (consumed) {
          byKey.delete(k);
          continue;
        }
        const loc = (info?.location ?? '').trim();
        const desc = (info?.description ?? '').trim();
        const entry: ItemDelta = byKey.get(k) ?? { name };
        entry.name = name; // ф╗ецЬАцЦ░хЖЩц│Хф╕║хЗЖ
        if (qty !== undefined) entry.qty = qty;
        if (desc) entry.desc = desc;
        if (loc) {
          entry.location = loc;
          entry.carried = false;
        }
        byKey.set(k, entry);
      }
    }
    // цШ╛х╝ПхИащЩд
    for (const del of meta.deletedItems ?? []) {
      const { name } = parseHoraeItemName(del);
      byKey.delete(keyOf(name));
    }
  }
  return [...byKey.values()];
}

/** цКК chat цКШхПацИРцЬАч╗ИуАМцЬкф║Жч╗УшобхИТ/цВмх┐╡уАНуАВ */
function foldOpenPlans(chat: STMessage[]): StoredDelta['plans'] {
  const deleted = new Set<string>();
  const norm = (s: unknown) => String(s ?? '').trim();
  // хЕИцФ╢щЫЖцЙАцЬЙхИащЩдцаЗшо░(хРДх▒В deletedAgenda + chat[0]._deletedAgendaTexts)
  for (const m of chat) {
    const meta = horaeMeta(m);
    for (const d of meta?.deletedAgenda ?? []) if (norm(d)) deleted.add(norm(d));
    for (const d of meta?._deletedAgendaTexts ?? []) if (norm(d)) deleted.add(norm(d));
  }
  // хЙНхРСхРИх╣╢ agenda(цМЙ text хО╗щЗН,хРОхЗ║чО░чЪДшжЖчЫЦ)
  const byText = new Map<string, HoraeAgendaItem>();
  for (const m of chat) {
    const meta = horaeMeta(m);
    for (const a of meta?.agenda ?? []) {
      const text = norm(a?.text);
      if (!text) continue;
      byText.set(text, a);
    }
  }
  const add: NonNullable<StoredDelta['plans']>['add'] = [];
  for (const [text, a] of byText) {
    if (a.done) continue;
    if (deleted.has(text)) continue;
    const kind = a.type === 'цВмх┐╡' || a.type === 'цЗ╕х┐╡' ? 'suspense' : 'plan';
    add.push({ kind, content: text, createdTime: norm(a.date) || undefined });
  }
  return add.length ? { add } : undefined;
}

/** щАТх╜Т flatten Horae autoSummaries(х╡МхеЧ mergedSummaries),ш┐ФхЫЮ [цЭбчЫо, чИ╢id]уАВ */
function flattenHoraeSummaries(
  tops: HoraeSummaryEntry[],
): Array<{ entry: HoraeSummaryEntry; parentId: string | null }> {
  const out: Array<{ entry: HoraeSummaryEntry; parentId: string | null }> = [];
  const walk = (entry: HoraeSummaryEntry, parentId: string | null) => {
    if (!entry?.id) return;
    out.push({ entry, parentId });
    for (const child of entry.mergedSummaries ?? []) walk(child, entry.id);
  };
  for (const t of tops) walk(t, null);
  return out;
}

/** шобчоЧш┐Бчз╗шобхИТ(хПкшп╗,ф╕Нф║зчФЯхЙпф╜ЬчФи),ф╛Ы UI щвДшзИф╕ОцМЙщТохРпхБЬуАВ */
export function computeMigrationPlan(): MigrationPlan {
  const ctx = getContext();
  const chat = ctx?.getCurrentChatId?.() ? ctx?.chat ?? [] : [];

  let leafFloors = 0;
  for (let i = 0; i < chat.length; i++) {
    if (!isAiFloor(chat[i])) continue;
    if (narrativeOf(horaeMeta(chat[i]))) leafFloors++;
  }

  const tops = (chat[0] && horaeMeta(chat[0])?.autoSummaries) || [];
  const summaryCount = flattenHoraeSummaries(tops).length;

  const items = foldFinalItems(chat);
  const plans = foldOpenPlans(chat);

  const hasData =
    leafFloors > 0 || summaryCount > 0 || items.length > 0 || !!plans?.add?.length;

  return {
    hasData,
    leafFloors,
    summaryCount,
    itemCount: items.length,
    planCount: plans?.add?.length ?? 0,
    willOverwrite: memory.summaries.length > 0 || hasAnyLeaf(chat),
  };
}

/** chat ф╕КцШпхРжх╖▓цЬЙцЯПхоЭф╣жхП╢хнР(чФиф║ОуАМх░ЖшжЖчЫЦуАНцПРчд║)уАВ */
function hasAnyLeaf(chat: STMessage[]): boolean {
  return chat.some(m => !!m?.extra?.bbs_leaf);
}

/* ============ цЙзшбМш┐Бчз╗ ============ */

/**
 * цККх╜УхЙНшБКхдйщЗМчЪД Horae цХ░цНош┐Бчз╗цИРцЯПхоЭф╣жцХ░цНоуАВш┐ФхЫЮцШпхРжцИРхКЯуАВ
 * чЫ┤цОехЖЩх╜УхЙН chat чЪДц╢ИцБп extra(хП╢хнР)ф╕О chatMetadata(цгоцЮЧ),шР╜чЫШхРОхИ╖цЦ░уАВ
 */
export async function runHoraeMigration(): Promise<boolean> {
  const ctx = getContext();
  if (!ctx) {
    toast('SillyTavern ф╕Кф╕ЛцЦЗф╕НхПпчФи', 'error');
    return false;
  }
  if (!ctx.getCurrentChatId?.()) {
    toast('шп╖хЕИш┐ЫхЕеф╕Аф╕кшБКхдйхЖНш┐Бчз╗', 'warning');
    return false;
  }
  const chat = ctx.chat ?? [];
  if (!chat.length) {
    toast('х╜УхЙНшБКхдйф╕║чй║,цЧахПпш┐Бчз╗цХ░цНо', 'warning');
    return false;
  }

  const plan = computeMigrationPlan();
  if (!plan.hasData) {
    toast('цЬкхЬих╜УхЙНшБКхдйцгАц╡ЛхИ░ Horae цЧзцХ░цНо', 'warning');
    return false;
  }

  try {
    // ===== 1. ф╕║цпПф╕кцЬЙхПЩф║ЛчЪД AI це╝щАахП╢хнР(цЧ╢щЧ┤чВ╣тЖТцЧ╢щЧ┤цо╡) =====
    // aiFloors:цМЙце╝х║ПчЪД AI це╝ч┤вх╝Х;цпПх▒В timeEnd=цЬмх▒ВцЧ╢щЧ┤чВ╣,timeStart=ф╕Кф╕Ах▒ВцЧ╢щЧ┤чВ╣уАВ
    const aiFloors: number[] = [];
    for (let i = 0; i < chat.length; i++) if (isAiFloor(chat[i])) aiFloors.push(i);

    // хЕИчоЧцпПф╕к AI це╝чЪДуАМцЧ╢щЧ┤чВ╣уАН(carry-forward:цЬмх▒ВцЧахИЩц▓┐чФиф╕Кф╕Ах╖▓чЯе)
    const floorTime = new Map<number, string>();
    let lastKnown = '';
    for (const idx of aiFloors) {
      const t = combineTime(horaeMeta(chat[idx])?.timestamp);
      if (t) lastKnown = t;
      floorTime.set(idx, lastKnown);
    }

    // це╝ idx тЖТ цЦ░х╗║хП╢хнР id(ф╛ЫцгоцЮЧ childIds х╝ХчФи);ф╗ЕцЬЙхПЩф║ЛчЪДце╝х╗║хП╢хнРуАВ
    const leafIdByFloor = new Map<number, string>();
    let prevTime = '';
    let lastLeafFloor = -1;
    for (let k = 0; k < aiFloors.length; k++) {
      const idx = aiFloors[k];
      const text = narrativeOf(horaeMeta(chat[idx]));
      const end = floorTime.get(idx) || '';
      // цо╡х╖жчХМ:ф╕Кф╕Ах╖▓чЯецЧ╢щЧ┤чВ╣;щжЦх▒ВчФицЬмх▒В(start=end)уАВ
      const start = prevTime || end;
      if (text) {
        const leaf: LeafExtra = {
          id: makeLeafId(),
          text,
          delta: {},
          timeStart: start || undefined,
          timeEnd: end || undefined,
          createdAt: Date.now() + k, // хНХш░ГщАТхвЮ,ф┐ЭшпБ tie-break ф╕Оце╝х║Пф╕АшЗ┤
          swipe: typeof chat[idx].swipe_id === 'number' ? chat[idx].swipe_id : 0,
          v: 1,
        };
        chat[idx].extra = { ...(chat[idx].extra ?? {}), bbs_leaf: leaf };
        leafIdByFloor.set(idx, leaf.id);
        lastLeafFloor = idx;
      }
      if (end) prevTime = end;
    }

    // ===== 2. цККцЬАч╗ИчК╢цАБ(чЙйхУБ/шобхИТ/цЧ╢щЧ┤/хЬ░чВ╣)ч╝ЦчаБцИРчзНхнР delta,цМВхИ░цЬАхРОф╕АчЙЗхП╢хнР =====
    // шЛец▓бцЬЙф╗╗ф╜ХхПЩф║ЛхП╢хнРф╜ЖцЬЙчК╢цАБ,щАаф╕АцЭбчй║цЦЗцЬмхП╢хнРцМВхИ░цЬАхРОф╕Аф╕к AI це╝цЙ┐ш╜╜хоГуАВ
    const items = foldFinalItems(chat);
    const plans = foldOpenPlans(chat);
    const finalState = computeFinalState(chat);

    if (lastLeafFloor < 0 && aiFloors.length) {
      const idx = aiFloors[aiFloors.length - 1];
      const leaf: LeafExtra = {
        id: makeLeafId(),
        text: '',
        delta: {},
        timeEnd: floorTime.get(idx) || undefined,
        timeStart: floorTime.get(idx) || undefined,
        createdAt: Date.now() + aiFloors.length,
        swipe: typeof chat[idx].swipe_id === 'number' ? chat[idx].swipe_id : 0,
        v: 1,
      };
      chat[idx].extra = { ...(chat[idx].extra ?? {}), bbs_leaf: leaf };
      leafIdByFloor.set(idx, leaf.id);
      lastLeafFloor = idx;
    }

    if (lastLeafFloor >= 0) {
      const seedLeaf = chat[lastLeafFloor].extra!.bbs_leaf as LeafExtra;
      const delta: StoredDelta = seedLeaf.delta ?? (seedLeaf.delta = {});
      if (items.length) delta.items = { add: items };
      if (plans) delta.plans = plans;
      if (finalState.time) delta.time = finalState.time;
      if (finalState.location) delta.location = finalState.location;
    }

    // ===== 3. щЗНх╗║цгоцЮЧ(autoSummaries тЖТ comp шКВчВ╣) =====
    const tops = (chat[0] && horaeMeta(chat[0])?.autoSummaries) || [];
    const flat = flattenHoraeSummaries(tops);

    // хнРцЭбчЫощЫЖхРИ:ф╛ЫуАМчЫ┤цОешжЖчЫЦшМГхЫ┤хЖЕуАБцЬкшвлхнРцЭбчЫошжЖчЫЦчЪДхП╢хнРуАНшобчоЧ childIdsуАВ
    const childEntriesByParent = new Map<string, HoraeSummaryEntry[]>();
    for (const { entry, parentId } of flat) {
      if (parentId) {
        const arr = childEntriesByParent.get(parentId) ?? [];
        arr.push(entry);
        childEntriesByParent.set(parentId, arr);
      }
    }

    const newSummaries: MemSummary[] = [];
    let order = 0;
    for (const { entry } of flat) {
      const id = String(entry.id);
      const level = normalizeDepth(entry.depth);
      const childEntries = childEntriesByParent.get(id) ?? [];
      const childRanges = childEntries.map(c => c.range).filter(Boolean) as [number, number][];

      // childIds:тСа чЫ┤цОехнРцЭбчЫо id(ф╕Лх▒В comp);тСб цЬмшМГхЫ┤хЖЕуАБцЬкшвлф╗╗ф╜ХхнРцЭбчЫошМГхЫ┤шжЖчЫЦчЪДхП╢хнР idуАВ
      const childIds: string[] = childEntries.map(c => String(c.id));
      const range = entry.range;
      if (range) {
        for (let i = range[0]; i <= range[1]; i++) {
          const leafId = leafIdByFloor.get(i);
          if (!leafId) continue;
          if (childRanges.some(([a, b]) => i >= a && i <= b)) continue; // х╖▓х▒ЮцЯРхнРцЭбчЫо
          childIds.push(leafId);
        }
      }
      if (!childIds.length) continue; // чй║хг│шКВчВ╣(шМГхЫ┤хЖЕхП╢хнРхЕиц▓бф║Ж)ш╖│ш┐З

      // цЧ╢щЧ┤цо╡:шМГхЫ┤хЖЕщжЦх░╛хП╢хнРчЪДш╡╖цнв
      const { start, end } = rangeTimeSpan(range, floorTime, leafIdByFloor);
      newSummaries.push({
        id,
        text: (entry.summaryText ?? '').trim(),
        level,
        createdAt: Date.now() + order++,
        auto: entry.auto !== false,
        timeStart: start || undefined,
        timeEnd: end || undefined,
        childIds,
      });
    }

    // ===== 4. хЖЩхЫЮ:цгоцЮЧшжЖчЫЦ,хП╢хнРх╖▓хЖЩш┐Ы extra;шР╜чЫШ + щЗНчоЧ =====
    memory.summaries.splice(0, memory.summaries.length, ...newSummaries);
    recomputeDerived();
    saveMemory();
    flushLeavesNow();
    if (typeof ctx.saveMetadata === 'function') await ctx.saveMetadata();
    // цгАц╡Лф╕АцмбщЪРшЧП:цККх╖▓швлцСШшжБшжЖчЫЦуАБц╗ЪхЗ║ф┐ЭчХЩчкЧхПгчЪДцЧзце╝х▒ВщЪРшЧПцОЙ(хдНчФицСШшжБцФ╢х░╛хРМцм╛щА╗ш╛С),
    // щБ┐хЕНш┐Бчз╗хРОхЕицЦЗф╕ОцСШшжБхЬиф╕Кф╕ЛцЦЗщЗМщЗНхдН;хЖЕщГих╖▓хРлхИ╖цЦ░ц│ихЕеуАВ
    await syncHiddenNow();

    toast(
      `ш┐Бчз╗хоМцИР:хП╢хнР ${leafIdByFloor.size} чЙЗ / цА╗ч╗У ${newSummaries.length} цЭб / чЙйхУБ ${items.length} / шобхИТ ${plans?.add?.length ?? 0}`,
      'success',
    );
    return true;
  } catch (e) {
    toast(`ш┐Бчз╗хд▒ш┤е:${e instanceof Error ? e.message : String(e)}`, 'error');
    console.error('[цЯПхоЭф╣ж] Horae ш┐Бчз╗хд▒ш┤е:', e);
    return false;
  }
}

/** шзДцХ┤ depth тЖТ цЯПхоЭф╣ж level(тЙе1)уАВ */
function normalizeDepth(depth: unknown): number {
  const n = typeof depth === 'number' ? depth : parseInt(String(depth ?? ''), 10);
  return Number.isFinite(n) && n >= 1 ? n : 1;
}

/** цЯР comp шМГхЫ┤хЖЕчЪДцЧ╢щЧ┤цо╡:хПЦшМГхЫ┤хЖЕцЬЙхП╢хнРчЪДцЬАцЧйш╡╖хзЛф╕ОцЬАцЩЪч╗УцЭЯуАВ */
function rangeTimeSpan(
  range: [number, number] | undefined,
  floorTime: Map<number, string>,
  leafIdByFloor: Map<number, string>,
): { start: string; end: string } {
  if (!range) return { start: '', end: '' };
  let start = '';
  let end = '';
  for (let i = range[0]; i <= range[1]; i++) {
    if (!leafIdByFloor.has(i)) continue;
    const t = floorTime.get(i) || '';
    if (t && !start) start = t;
    if (t) end = t;
  }
  return { start, end };
}

/** цКШхПахЗ║цЬАч╗ИцЧ╢щЧ┤/хЬ░чВ╣(щАРх▒ВхЙНхРСшжЖчЫЦ)уАВ */
function computeFinalState(chat: STMessage[]): { time: string; location: string } {
  let time = '';
  let location = '';
  for (const m of chat) {
    const meta = horaeMeta(m);
    if (!meta || meta._skipHorae) continue;
    const t = combineTime(meta.timestamp);
    if (t) time = t;
    const loc = (meta.scene?.location ?? '').trim();
    if (loc) location = loc;
  }
  return { time, location };
}
