<script setup lang="ts">
import Icon from '@/components/Icon.vue';
import ConfirmDialog from '@/components/ConfirmDialog.vue';
import { editNpc, removeNpc, setNpcFollow, setNpcImportant, upsertNpc } from '@/memory/apply';
import { derivedMeta, memory } from '@/memory/store';
import type { MemNpc, MemScene } from '@/memory/types';
import { computed, nextTick, ref } from 'vue';

// NPC цШпф╗ОхП╢хнРцСШшжБщЗНцФ╛хЗ║чЪДц┤╛чФЯцХ░цНо,цЙЛхКицУНф╜ЬхЖЩхЕеуАМцЬАцЦ░ф╕АцЭбцЬЙцХИхП╢хнРуАН;цЧацЬЙцХИхП╢хнРцЧ╢цЧахдДцМВш╜╜уАВ
const hasLeaf = computed(() => derivedMeta.hasLeaf);

// шзжх▒ПхИдхоЪ:ш╖│ш┐Зх╝╣чкЧшЗкхКишБЪчДж(чз╗хКичлпшЗкхКишБЪчДжф╝Ъх╝╣ш╛УхЕец│ХцМбчХМщЭв),ф╕ОхЬ║цЩп/цСШшжБщб╡ф╕АшЗ┤уАВ
const isTouch = typeof window !== 'undefined' && window.matchMedia?.('(hover: none)').matches;

/* тАФтАФ хЬихЬ║хИдхоЪ:хдНхИ╗ц│ихЕечлп inject.ts чЪДхПгх╛Д,чбоф┐ЭуАМчХМщЭвцШ╛чд║чЪД = AI цФ╢хИ░чЪДуАН тАФтАФ
   щЪПшбМ(follow)ц░╕ш┐ЬхЬихЬ║;хРжхИЩцМЙ location ф╕ОуАМх╜УхЙНхЬ░чВ╣ + чеЦхЕИщУ╛уАНхМЕхРлх╝ПхПпш╛╛уАВ */
function match(a: string | undefined, b: string): boolean {
  const x = (a ?? '').trim();
  const y = b.trim();
  if (!x || !y) return false;
  return x.includes(y) || y.includes(x);
}

// х╜УхЙНцЙАхЬихЬ║цЩпшКВчВ╣(ф╕ОхЬ║цЩпщб╡ / ц│ихЕечлп findCurrentScene хРМхПгх╛Д:хМЕхРлх╝ПхМ╣щЕНуАБхПЦцЬАц╖▒)
const currentScene = computed<MemScene | null>(() => {
  const here = (memory.state.location || '').trim();
  if (!here) return null;
  let best: MemScene | null = null;
  for (const s of memory.scenes) {
    const hit = match(s.name, here) || s.path.some(seg => match(seg, here));
    if (hit && (!best || s.path.length > best.path.length)) best = s;
  }
  return best;
});

// х╜УхЙНцЙАхЬихЬ░чВ╣ + хЕ╢чеЦхЕИщУ╛чЪДуАМхПпхМ╣щЕНхРНуАНщЫЖхРИ(цЬмч║зхРН + хоМцХ┤ш╖пх╛ДцЛ╝цОе),ф╛Ы NPC location цпФхп╣
const reachableNames = computed<string[]>(() => {
  const names: string[] = [];
  const here = (memory.state.location || '').trim();
  if (here) names.push(here);
  const byId = new Map(memory.scenes.map(s => [s.id, s]));
  let cur = currentScene.value;
  const seen = new Set<string>();
  while (cur && !seen.has(cur.id)) {
    seen.add(cur.id);
    names.push(cur.name, cur.path.join(''));
    cur = cur.parentId ? byId.get(cur.parentId) ?? null : null;
  }
  return names;
});

function onScene(npc: MemNpc): boolean {
  if (npc.follow === true) return true;
  const loc = (npc.location ?? '').trim();
  if (!loc) return false;
  // цЧахЬ║цЩпцХ░цНоцЧ╢щААхЫЮч║пх╜УхЙНхЬ░чВ╣хнЧчмжф╕▓цпФхп╣(ф╕Оц│ихЕечлп itemReachableInScene чЪДхЕЬх║Хф╕АшЗ┤)
  if (!reachableNames.value.length) return false;
  return reachableNames.value.some(n => match(loc, n));
}

// хИЖф╕Йч╗Д:ф╕╗шжБшзТшЙ▓(ч╜ощб╢,ф╕Ншо║хЬихЬ║)/ хЬихЬ║(щЪПшбМ/цЙАхЬихЬ░хПпш╛╛)/ ф╕НхЬихЬ║уАВхРДч╗ДцМЙхИЫх╗║х║Пчи│хоЪцОТхИЧуАВ
// хдНхИ╗ц│ихЕечлп fmtNpcContext хПгх╛Д:important хНХхИЧ,ф╕НхЖНш┐ЫхЬихЬ║/ф╕НхЬихЬ║хИдхоЪ тАФтАФ чбоф┐ЭцЙАшзБхН│цЙАхПСуАВ
const sortByCreated = (a: MemNpc, b: MemNpc) => a.createdAt - b.createdAt;
const mains = computed(() => memory.npcs.filter(n => n.important).sort(sortByCreated));
const present = computed(() =>
  memory.npcs.filter(n => !n.important && onScene(n)).sort(sortByCreated),
);
const absent = computed(() =>
  memory.npcs.filter(n => !n.important && !onScene(n)).sort(sortByCreated),
);

/* тАФтАФ щЪПшбМф╕АщФох╝АхЕ│:щЪПшбМтЖТхПЦц╢И(чХЩхЬих╜УхЙНхЬ░чВ╣);щЭЮщЪПшбМтЖТцаЗшо░щЪПшбМ тАФтАФ */
function toggleFollow(npc: MemNpc) {
  if (npc.follow === true) {
    // хПЦц╢ИщЪПшбМ:чХЩхЬих╜УхЙНцЙАхЬихЬ░(цЧахИЩчХЩчй║,цИРф╕║цЧаф╜Нч╜очЪДц╕╕чж╗ NPC)
    setNpcFollow(npc.name, false, memory.state.location || '');
  } else {
    setNpcFollow(npc.name, true);
  }
}

/* тАФтАФ ф╕╗шжБшзТшЙ▓ф╕АщФохНЗ/щЩН тАФтАФ */
function toggleImportant(npc: MemNpc) {
  setNpcImportant(npc.name, !npc.important);
}

function askRemove(npc: MemNpc) {
  removing.value = npc;
}

/* тАФтАФ цЦ░хвЮх╝╣чкЧ тАФтАФ */
const composerOpen = ref(false);
const nameInput = ref<HTMLInputElement | null>(null);
interface NpcDraft {
  name: string;
  title: string;
  personality: string;
  desc: string;
  outfit: string;
  condition: string;
  important: boolean;
  follow: boolean;
  location: string;
}
function emptyDraft(): NpcDraft {
  return { name: '', title: '', personality: '', desc: '', outfit: '', condition: '', important: false, follow: false, location: memory.state.location || '' };
}
const draft = ref<NpcDraft>(emptyDraft());

function openComposer() {
  if (!hasLeaf.value) return;
  draft.value = emptyDraft();
  composerOpen.value = true;
  if (!isTouch) void nextTick(() => nameInput.value?.focus());
}
function closeComposer() {
  composerOpen.value = false;
}
function addNpc() {
  const d = draft.value;
  if (!d.name.trim()) return;
  const ok = upsertNpc({
    name: d.name,
    title: d.title,
    personality: d.personality,
    desc: d.desc,
    outfit: d.outfit,
    condition: d.condition,
    important: d.important,
    follow: d.follow,
    location: d.follow ? '' : d.location,
  });
  if (!ok) return;
  composerOpen.value = false;
}

/* тАФтАФ ч╝Цш╛Сх╝╣чкЧ тАФтАФ */
interface NpcEditing extends NpcDraft {
  oldName: string;
}
const editing = ref<NpcEditing | null>(null);

function openEdit(npc: MemNpc) {
  editing.value = {
    oldName: npc.name,
    name: npc.name,
    title: npc.title ?? '',
    personality: npc.personality ?? '',
    desc: npc.desc ?? '',
    outfit: npc.outfit ?? '',
    condition: npc.condition ?? '',
    important: npc.important === true,
    follow: npc.follow === true,
    location: npc.location ?? '',
  };
}
function cancelEdit() {
  editing.value = null;
}
function saveEdit() {
  const e = editing.value;
  if (!e || !e.name.trim()) return;
  editNpc(e.oldName, {
    name: e.name,
    title: e.title,
    personality: e.personality,
    desc: e.desc,
    outfit: e.outfit,
    condition: e.condition,
    important: e.important,
    follow: e.follow,
    location: e.follow ? '' : e.location,
  });
  editing.value = null;
}

/* тАФтАФ хИащЩдчбошод тАФтАФ */
const removing = ref<MemNpc | null>(null);
function confirmRemove() {
  if (removing.value) removeNpc(removing.value.name);
  removing.value = null;
}
</script>

