/**
 * цХЕф║ЛхЖЕцЧ╢щЧ┤чЪДуАМчЫ╕хп╣цЧ╢щЧ┤уАНцОицЦн тАФтАФ чз╗цдНшЗкцЧзцПТф╗╢ Horae чЪД timeUtils,хПкф┐ЭчХЩф╕нцЦЗуАБхО╗цОЙхдЪшпншиАх▒ВуАВ
 *
 * чФищАФ:хОЖхП▓цСШшжБц│ихЕеф╕ОцСШшжБщб╡х▒Хчд║цЧ╢,хЬич╗Эхп╣цЧ╢щЧ┤хЙНхКаф╕Аф╕кчЫ╕хп╣хЙНч╝А(хжВуАМцШихдйуАНуАМ3хдйхЙНуАН),
 * шойф╕╗цибхЮЛф╕ОчФицИ╖щГ╜шГ╜чЫ┤шзВцДЯчЯеуАМш┐Щцо╡хЙзцГЕш╖Эчж╗чО░хЬихдЪф╣ЕуАНуАВ
 *
 * шо╛шобх║Хч║┐(ц▓┐чФи Horae):цЧ╢щЧ┤цШп AI хЖЩчЪДшЗкчФ▒цЦЗцЬмуАВ
 *  - цХ░хнЧцЧехОЖ(1988/9/29уАБ1988х╣┤9цЬИ29цЧеуАБ9/29уАБх╕жхОЖц│ХхЙНч╝АчЪД Xх╣┤MцЬИDцЧе)тЖТ ч▓╛чбочоЧхдйцХ░х╖оуАВ
 *  - цЮ╢чй║цЧехОЖ(щЬЬцЬИ3цЧе ш┐Щч▒╗щЭЮцХ░хнЧцЬИхРНуАБхРл XX/?? чЪДхНаф╜Н)тЖТ ф╗ЕхРМцЬИхПпчоЧ,ш╖ицЮ╢чй║цЬИцФ╛х╝ГуАВ
 *  - ч║пцЧ╢ш╛░цЧацЧецЬЯуАБх╜╗х║ХшзгцЮРф╕НхЗ║ тЖТ ш┐ФхЫЮчй║ф╕▓,ш░ГчФицЦ╣щЩНч║зф╕║уАМф╕НхКахЙНч╝АуАНуАВ
 * ф╕АхПешпЭ:хоБхПпф╕НцаЗ,ч╗Эф╕НцаЗщФЩуАВ
 */

/** ф╕нцЦЗхСихЗа(0=хСицЧе) */
const WEEKDAY_NAMES = ['цЧе', 'ф╕А', 'ф║М', 'ф╕Й', 'хЫЫ', 'ф║Ф', 'хЕн'];

/** шзгцЮРхЗ║чЪДцХЕф║ЛцЧецЬЯ:standard хПпч▓╛чбоцНвчоЧ,fantasy ф╗ЕхРМцЬИхПпцпФ */
interface StoryDate {
  type: 'standard' | 'fantasy';
  year?: number;
  month?: number;
  day?: number | null;
  /** цЮ╢чй║цЬИцаЗшпЖ(хжВуАМщЬЬцЬИуАН),fantasy ш╖ицЬИцпФхп╣чФи */
  monthId?: string;
  /** хОЖц│ХхЙНч╝А(хжВуАМх║ЖхОЖуАН),ф╗Ех▒Хчд║чФи,ф╕НхПВф╕ОцНвчоЧ */
  calendarPrefix?: string;
  raw?: string;
}

const DAY_MS = 24 * 60 * 60 * 1000;
const WEEK_MS = 7 * DAY_MS;

/** цККхЕишзТ/ф╕нцЦЗхПечВ╣чнЙцЧецЬЯхИЖщЪФчмжшзДшМГцИР /,ф╛┐ф║ОхРОч╗нцнгхИЩч╗Яф╕АхдДчРЖ */
function normalizeNumericDateSeparators(dateStr: string): string {
  if (!dateStr) return dateStr;
  return dateStr
    // щХ┐ца╝х╝П(4 ф╜Нх╣┤ш╡╖):цЧецХ░хРОхПкшжБф╕НхЖНш╖ЯцХ░хнЧ/чВ╣хН│шод,хо╣х┐НхРОцОещАЧхП╖уАБф╕нцЦЗуАБцЛмхП╖чнЙ
    //(хжВуАМ2025.11.1, хдЪф║СуАНуАМ2025.11.1цЩ┤уАН);4 ф╜Нх╣┤х╝Ахд┤хЗаф╣Оф╕Нф╝ЪцШпх░ПцХ░/чЙИцЬмхП╖,цФ╛хо╜х╛ИхоЙхЕиуАВ
    .replace(/^(\d{4,})[.я╝ОуАВя╣Т](\d{1,2})[.я╝ОуАВя╣Т](\d{1,2})(?![\d.я╝ОуАВя╣Т])/, '$1/$2/$3')
    // чЯнца╝х╝П(M.D):цнзф╣Йхдз(уАМ1.5ф╕кх░ПцЧ╢уАНцШпх░ПцХ░щЭЮцЧецЬЯ),ф╗НшжБц▒ВхРОцОечй║чЩ╜цИЦч╗Ух░╛,ф┐ЭхоИуАВ
    .replace(/^(\d{1,2})[.я╝ОуАВя╣Т](\d{1,2})(?=$|\s)/, '$1/$2');
}

/** чЬЛш╡╖цЭецШпч╗УцЮДхМЦцХ░хнЧцЧецЬЯ(чФиф║ОцОТщЩдуАМщЬЬцЬИ3цЧеуАНшппхИдф╕║цЮ╢чй║) */
function looksLikeStructuredNumericDate(dateStr: string): boolean {
  if (!dateStr) return false;
  return (
    /^(?:\d{4,}[/.\-я╝ОуАВя╣Т]\d{1,2}[/.\-я╝ОуАВя╣Т]\d{1,2}|\d{1,2}[/.\-я╝ОуАВя╣Т]\d{1,2})(?=$|\s)/.test(dateStr) ||
    /^\d+\s*х╣┤\s*\d{1,2}\s*цЬИ\s*\d{1,2}\s*цЧе?(?=$|\s)/.test(dateStr) ||
    /^\d{1,2}\s*цЬИ\s*\d{1,2}\s*цЧе?(?=$|\s)/.test(dateStr)
  );
}

/** ф╗ОцЮ╢чй║цЧецЬЯф╕▓щЗМцК╜уАМцЧецХ░уАН(щШ┐цЛЙф╝пф╝ШхЕИ,цЧахИЩхПЦщжЦф╕кцХ░хнЧ) */
function extractDayNumber(dateStr: string): number | null {
  if (!dateStr) return null;
  const m = dateStr.match(/(\d+)\s*[цЧехП╖]/) || dateStr.match(/чмм\s*(\d+)/);
  if (m) return parseInt(m[1], 10);
  const any = dateStr.match(/(\d+)/);
  if (any) return parseInt(any[1], 10);
  return null;
}

/** ф╗ОцЮ╢чй║цЧецЬЯф╕▓щЗМцК╜уАМцЬИцаЗшпЖуАН(хжВуАМщЬЬцЬИуАН) */
function extractMonthIdentifier(dateStr: string): string | null {
  if (!dateStr) return null;
  const m = dateStr.match(/([^\s\d]+цЬИ)/);
  if (m) return m[1];
  const num = dateStr.match(/(?:\d{4}[/\-])?(\d{1,2})[/\-]\d{1,2}/);
  if (num) return num[1] + 'цЬИ';
  return null;
}

/** ф╕нцЦЗцХ░хнЧхнЧщЭв тЖТ хА╝(0-9);уАМф╕дуАНцМЙ 2,уАМуАЗ/щЫ╢уАНцМЙ 0 */
const CN_DIGIT: Record<string, number> = {
  уАЗ: 0, щЫ╢: 0, ф╕А: 1, ф║М: 2, ф╕д: 2, ф╕Й: 3, хЫЫ: 4, ф║Ф: 5, хЕн: 6, ф╕Г: 7, хЕл: 8, ф╣Э: 9,
};

/** ф╕нцЦЗцХ░хнЧхнЧчмжщЫЖ(ф╛ЫцнгхИЩцЛ╝цОе;хРлуАМх╗┐уАН=20уАБуАМхНЕуАН=30) */
const CN_NUM_CLASS = '[ф╕Аф║Мф╕ЙхЫЫф║ФхЕнф╕ГхЕлф╣ЭхНБф╕дщЫ╢уАЗх╗┐хНЕ]';

/**
 * шзгцЮР 1-99 чЪДф╕нцЦЗцХ░хнЧ(хНБуАБхНБф╕АуАБф║МхНБуАБф║МхНБф╕АуАБх╗┐ф╕АуАБхНЕ чнЙ);ч║пщШ┐цЛЙф╝пцХ░хнЧчЫ┤цОе parseIntуАВ
 * ф╗ЕшжЖчЫЦцЧецЬЯ/цЬИф╗╜/х░Пх╣┤ф╗╜цЙАщЬАшМГхЫ┤,хд▒ш┤еш┐ФхЫЮ nullуАВ
 */
function cnNumToInt(raw: string): number | null {
  if (!raw) return null;
  const s = raw.trim();
  if (/^\d+$/.test(s)) return parseInt(s, 10);
  // хЖЬхОЖуАМхИЭуАНхЙНч╝А:хИЭф╕А~хИЭф╣Э=ф╕кф╜НуАБхИЭхНБ=10уАВхЙецОЙуАМхИЭуАНхРОхЙйуАМф╕ГуАНуАМхНБуАНф║дч╗Щф╕ЛщЭвцнгх╕╕шзгцЮРуАВ
  const str = s
    .replace(/^хИЭ/, '')
    .replace(/х╗┐/g, 'ф║МхНБ')
    .replace(/хНЕ/g, 'ф╕ЙхНБ'); // х╗┐/хНЕ х▒Хх╝АцИРуАМф║МхНБ/ф╕ЙхНБуАН
  if (!str) return null; // ф╗ЕуАМхИЭуАНцЧацХ░хнЧ
  // хРлуАМхНБуАН:хЕИхдДчРЖ,шжЖчЫЦуАМхНБуАН(=10)уАБуАМхНБф║ФуАНуАБуАМф║МхНБуАНуАБуАМф║МхНБф╕АуАНчнЙ;хНХхнЧуАМхНБуАНф╣Яш╡░ш┐ЩщЗМ
  const shiIdx = str.indexOf('хНБ');
  if (shiIdx >= 0) {
    // уАМхНБXуАН=1X(хНБхЬищжЦф╜Н тЖТ хНБф╜Нф╕║ 1);уАМXхНБуАНуАМXхНБYуАНтЖТ хНБф╜НхПЦхЙНф╕АхнЧ
    const tens = shiIdx === 0 ? 1 : CN_DIGIT[str[shiIdx - 1]];
    const onesPart = str.slice(shiIdx + 1);
    const ones = onesPart ? CN_DIGIT[onesPart] : 0;
    if (tens === undefined || ones === undefined) return null;
    return tens * 10 + ones;
  }
  if (str.length === 1) return CN_DIGIT[str] ?? null; // ч║пф╕кф╜Н(хРлуАЗ/ф╕д)
  return null; // цЧауАМхНБуАНхПИщЭЮхНХхнЧ тЖТ ф╕НхЬицФпцМБшМГхЫ┤
}

/** шзгцЮРцХЕф║ЛхЖЕцЧецЬЯхнЧчмжф╕▓;шзгцЮРф╕НхЗ║ш┐ФхЫЮ null */
export function parseStoryDate(dateStr: string): StoryDate | null {
  if (!dateStr) return null;
  let s = dateStr.trim();
  // хО╗цОЙ AI хЖЩчЪДхСихЗацаЗц│иуАМ(ф╕Й)уАН
  s = s.replace(/\s*\([цЧеф╕Аф║Мф╕ЙхЫЫф║ФхЕн]\)\s*/g, ' ').trim();
  s = normalizeNumericDateSeparators(s);

  // хРл XX/?? хНаф╜Н тЖТ цЮ╢чй║
  if (/[xX]{2}|[?я╝Я]{2}/.test(s)) {
    return { type: 'fantasy', raw: dateStr.trim() };
  }

  // цаЗхЗЖ:YYYY/M/D
  const full = s.match(/^(\d{4,})[/\-](\d{1,2})[/\-](\d{1,2})/);
  if (full) {
    const year = parseInt(full[1], 10);
    const month = parseInt(full[2], 10);
    const day = parseInt(full[3], 10);
    if (month >= 1 && month <= 12 && day >= 1 && day <= 31) return { year, month, day, type: 'standard' };
  }

  // цаЗхЗЖ:M/D
  const short = s.match(/^(\d{1,2})[/\-](\d{1,2})(?:\s|$)/);
  if (short) {
    const month = parseInt(short[1], 10);
    const day = parseInt(short[2], 10);
    if (month >= 1 && month <= 12 && day >= 1 && day <= 31) return { month, day, type: 'standard' };
  }

  // цХ░хнЧхнЧцо╡:щШ┐цЛЙф╝пцХ░хнЧцИЦф╕нцЦЗцХ░хнЧ(хРлхНБ/х╗┐/хНЕ),чФ▒ cnNumToInt ч╗Яф╕АшзгцЮРуАВ
  const NUM = `(?:\\d+|${CN_NUM_CLASS}+)`;
  // цЧехнЧцо╡щвЭхдЦхЕБшо╕хЖЬхОЖуАМхИЭуАНхЙНч╝А(хИЭф╕ГуАБхИЭхНБ);cnNumToInt ф╝ЪхЙецОЙуАМхИЭуАНхЖНшзгцЮРуАВ
  const DAY = `(?:хИЭ)?${NUM}`;

  // цаЗхЗЖ:Xх╣┤MцЬИDцЧе(х╣┤/цЬИ/цЧехЭЗхПпф╕нцЦЗ,х╕жхПпщАЙхОЖц│ХхЙНч╝А,хжВуАМхЕГцМБхНБф║Мх╣┤хЕлцЬИф║МхНБф╕АцЧеуАНуАМц░╕хТМхНБф║Фх╣┤хЕлцЬИхИЭф╕ГуАН)
  const yearCn = s.match(new RegExp(`(${NUM})х╣┤\\s*(${NUM})цЬИ\\s*(${DAY})цЧе?`));
  if (yearCn) {
    const year = cnNumToInt(yearCn[1]);
    const month = cnNumToInt(yearCn[2]);
    const day = cnNumToInt(yearCn[3]);
    if (year != null && month != null && day != null && month >= 1 && month <= 12 && day >= 1 && day <= 31) {
      const prefixEnd = s.indexOf(yearCn[0]);
      const calendarPrefix = s.substring(0, prefixEnd).trim() || undefined;
      return { year, month, day, type: 'standard', calendarPrefix };
    }
  }

  // цаЗхЗЖ:MцЬИDцЧе(цЬИ/цЧехПпф╕нцЦЗ,цЧехПпх╕жуАМхИЭуАН)
  const cn = s.match(new RegExp(`(${NUM})цЬИ\\s*(${DAY})цЧе?`));
  if (cn) {
    const month = cnNumToInt(cn[1]);
    const day = cnNumToInt(cn[2]);
    if (month != null && day != null && month >= 1 && month <= 12 && day >= 1 && day <= 31) {
      return { month, day, type: 'standard' };
    }
  }

  // цЮ╢чй║цЧехОЖ
  if (looksLikeStructuredNumericDate(s)) return null;
  const monthId = extractMonthIdentifier(s);
  const dayNum = extractDayNumber(s);
  if (monthId || dayNum !== null) {
    return { monthId: monthId ?? undefined, day: dayNum, type: 'fantasy', raw: dateStr.trim() };
  }

  return null;
}

/**
 * шобчоЧ fromтЖТto чЪДхдйцХ░х╖о(to - from,цнг=to цЫ┤цЩЪ)уАВ
 * шзгцЮРф╕НхЗ║цИЦш╖ицЮ╢чй║цЬИцЧац│ХхИдхоЪ тЖТ ш┐ФхЫЮ nullуАВ
 */
export function calculateRelativeDays(fromDate: string, toDate: string): number | null {
  if (!fromDate || !toDate) return null;

  // хЕИхЙецОЙх░╛щГицЧ╢хИ╗(15:00 / ф╕ЛхНИ / щЕЙцЧ╢тАж),хПкцпФцЧецЬЯ
  const stripTime = (x: string): string =>
    normalizeNumericDateSeparators(
      x
        .trim()
        .replace(/\s+\d{1,2}[:я╝Ъ]\d{2}.*$/, '')
        .replace(/\s+(хЗМцЩи|цЧйф╕К|ф╕КхНИ|ф╕нхНИ|ф╕ЛхНИ|хВНцЩЪ|цЩЪф╕К|ц╖▒хдЬ|хнРцЧ╢|ф╕СцЧ╢|хпЕцЧ╢|хНпцЧ╢|ш╛░цЧ╢|х╖│цЧ╢|хНИцЧ╢|цЬкцЧ╢|чФ│цЧ╢|щЕЙцЧ╢|цИМцЧ╢|ф║ецЧ╢).*$/i, '')
        .trim(),
    );
  if (stripTime(fromDate) === stripTime(toDate)) return 0;

  const from = parseStoryDate(fromDate);
  const to = parseStoryDate(toDate);
  if (!from || !to) return null;

  // цаЗхЗЖцЧехОЖ:ч▓╛чбочоЧ(чФи setFullYear щБ┐х╝А Date хп╣х░Пх╣┤ф╗╜чЪДхБПчз╗)
  if (from.type === 'standard' && to.type === 'standard') {
    const defaultYear = 2024;
    const fromYear = from.year || to.year || defaultYear;
    const toYear = to.year || from.year || defaultYear;
    const fromObj = new Date(0);
    fromObj.setFullYear(fromYear, (from.month ?? 1) - 1, from.day ?? 1);
    const toObj = new Date(0);
    toObj.setFullYear(toYear, (to.month ?? 1) - 1, to.day ?? 1);
    return Math.round((toObj.getTime() - fromObj.getTime()) / DAY_MS);
  }

  // цЮ╢чй║цЧехОЖ:ф╗ЕхРМцЬИхПпчоЧ,ш╖ицЮ╢чй║цЬИхРНцШУшппхИд тЖТ цФ╛х╝Г
  if (from.type === 'fantasy' || to.type === 'fantasy') {
    const fromMonth = from.monthId ?? from.month;
    const toMonth = to.monthId ?? to.month;
    if (from.day != null && to.day != null) {
      if (fromMonth && toMonth && fromMonth !== toMonth) return null;
      return to.day - from.day;
    }
    return null;
  }

  return null;
}

/** цаЗхЗЖцЧехОЖчЪДф╕дчлпш╜мцИР Date(ф╛ЫхСи/цЬИ/х╣┤шпнф╣ЙхИдхоЪ);ф╗╗ф╕АщЭЮцаЗхЗЖхИЩш┐ФхЫЮ null */
function toDatePair(fromDate: string, toDate: string): { from: Date; to: Date } | null {
  const from = parseStoryDate(fromDate);
  const to = parseStoryDate(toDate);
  if (from?.type !== 'standard' || to?.type !== 'standard') return null;
  const defaultYear = new Date().getFullYear();
  const fromYear = from.year || to.year || defaultYear;
  const toYear = to.year || from.year || defaultYear;
  const f = new Date(0);
  f.setFullYear(fromYear, (from.month ?? 1) - 1, from.day ?? 1);
  const t = new Date(0);
  t.setFullYear(toYear, (to.month ?? 1) - 1, to.day ?? 1);
  return { from: f, to: t };
}

/** ф╗еуАМхСиф╕АуАНф╕║хСиш╡╖чВ╣чоЧхСих╖о */
function weekDiffByMonday(from: Date, to: Date): number {
  const weekStart = (d: Date): number => {
    const wd = d.getDay();
    const offset = wd === 0 ? -6 : 1 - wd;
    return Date.UTC(d.getFullYear(), d.getMonth(), d.getDate() + offset);
  };
  return Math.round((weekStart(to) - weekStart(from)) / WEEK_MS);
}

/** шЗкчД╢цЬИх╖о */
function monthDiff(from: Date, to: Date): number {
  return (to.getFullYear() - from.getFullYear()) * 12 + (to.getMonth() - from.getMonth());
}

/**
 * цККуАМф║Лф╗╢цЧ╢щЧ┤ eventуАНчЫ╕хп╣уАМчО░хЬи nowуАНца╝х╝ПхМЦцИРчЫ╕хп╣хЙНч╝АцЦЗцЬмуАВ
 * шзгцЮРф╕НхЗ║ / цЧац│ХхИдхоЪ тЖТ ш┐ФхЫЮчй║ф╕▓(ш░ГчФицЦ╣цНоцндф╕НхКахЙНч╝А)уАВ
 */
export function relativeTimeLabel(eventTime?: string, nowTime?: string): string {
  const ev = eventTime?.trim();
  const now = nowTime?.trim();
  if (!ev || !now) return '';

  // days = now - event,цнг=ф║Лф╗╢хЬиш┐ЗхО╗
  const days = calculateRelativeDays(ev, now);
  if (days === null || days === undefined) return '';

  if (days === 0) return 'ф╗Кхдй';
  if (days === 1) return 'цШихдй';
  if (days === 2) return 'хЙНхдй';
  if (days === 3) return 'хдзхЙНхдй';
  if (days === -1) return 'цШОхдй';
  if (days === -2) return 'хРОхдй';
  if (days === -3) return 'хдзхРОхдй';

  // уАМф╕КхСиX/ф╕Кф╕кцЬИXхП╖/хО╗х╣┤XцЬИXцЧеуАНчнЙцШпхЕмхОЖхПгшпн,хеЧхИ░х╕жхОЖц│ХхЙНч╝АчЪДхПдщгО/ш╡ЫхНЪцЧ╢щЧ┤(хЕГцМБ/х║ЖхОЖ/цШЯхОЖтАж)ф╕К
  // цЧвхЗ║цИПуАБхп╣х░Пх╣┤ф╗╜чЪД getDay() ш┐ШцШпф╣▒чоЧчЪДуАВцХЕх╕жхЙНч╝АцЧ╢ф╕НхПЦ pair тЖТ ш╖│ш┐Зш┐Щф║Ыцбг,щЩНч║зф╕║щАЪчФиуАМNхдйхЙН/Nф╕кцЬИхЙН/Nх╣┤хЙНуАНуАВ
  // ч║пцХ░хнЧцЧецЬЯ(хРл 2099/12/31 ш┐Щч▒╗ш╡ЫхНЪцЧ╢щЧ┤)цЧахЙНч╝А,цМЙхЕмхОЖчЕзх╕╕цШ╛чд║хПгшпнцбгуАВ
  const fromHasPrefix = !!parseStoryDate(ev)?.calendarPrefix;
  const toHasPrefix = !!parseStoryDate(now)?.calendarPrefix;
  const pair = fromHasPrefix || toHasPrefix ? null : toDatePair(ev, now);

  if (days > 0) {
    // ш┐ЗхО╗цЦ╣хРС
    if (days < 4) return `${days}хдйхЙН`;
    if (days >= 4 && days <= 13 && pair) {
      const wd = weekDiffByMonday(pair.from, pair.to);
      if (wd === 1) return `ф╕КхСи${WEEKDAY_NAMES[pair.from.getDay()]}`;
      if (wd === 2) return `ф╕Кф╕КхСи${WEEKDAY_NAMES[pair.from.getDay()]}`;
    }
    if (days >= 7 && days < 60 && pair && monthDiff(pair.from, pair.to) === 1) {
      return `ф╕Кф╕кцЬИ${pair.from.getDate()}хП╖`;
    }
    if (days >= 300 && pair) {
      const yearDiff = pair.to.getFullYear() - pair.from.getFullYear();
      if (yearDiff === 1) return `хО╗х╣┤${pair.from.getMonth() + 1}цЬИ${pair.from.getDate()}цЧе`;
      if (yearDiff === 2) return `хЙНх╣┤${pair.from.getMonth() + 1}цЬИ${pair.from.getDate()}цЧе`;
    }
    if (days < 30) return `${days}хдйхЙН`;
    if (days < 365) {
      const md = pair ? monthDiff(pair.from, pair.to) : 0;
      const months = md > 0 ? md : Math.floor(days / 30);
      return `${months}ф╕кцЬИхЙН`;
    }
    const years = Math.floor(days / 365);
    const remainMonths = Math.round((days % 365) / 30);
    if (remainMonths > 0 && years < 5) return `${years}х╣┤${remainMonths}ф╕кцЬИхЙН`;
    return `${years}х╣┤хЙН`;
  }

  // цЬкцЭецЦ╣хРС
  const abs = Math.abs(days);
  if (abs < 4) return `${abs}хдйхРО`;
  if (abs >= 4 && abs <= 13 && pair) {
    const wd = weekDiffByMonday(pair.from, pair.to);
    if (wd === -1) return `ф╕ЛхСи${WEEKDAY_NAMES[pair.from.getDay()]}`;
    if (wd === -2) return `ф╕Лф╕ЛхСи${WEEKDAY_NAMES[pair.from.getDay()]}`;
  }
  if (abs >= 7 && abs < 60 && pair && monthDiff(pair.from, pair.to) === -1) {
    return `ф╕Лф╕кцЬИ${pair.from.getDate()}хП╖`;
  }
  if (abs < 30) return `${abs}хдйхРО`;
  if (abs < 365) {
    const md = pair ? monthDiff(pair.from, pair.to) : 0;
    const months = md < 0 ? Math.abs(md) : Math.floor(abs / 30);
    return `${months}ф╕кцЬИхРО`;
  }
  const years = Math.floor(abs / 365);
  const remainMonths = Math.round((abs % 365) / 30);
  if (remainMonths > 0 && years < 5) return `${years}х╣┤${remainMonths}ф╕кцЬИхРО`;
  return `${years}х╣┤хРО`;
}
